window.HADITH_CACHE["abu-dawud_5"] = {"2501":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ أَنَا أَوْلَى بِكُلِّ مُؤْمِنٍ مِنْ نَفْسِهِ فَأَيُّمَا رَجُلٍ مَاتَ وَتَرَكَ دَيْنًا فَإِلَيَّ وَمَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq], dari [Ma'mar] dari [Az Zuhri], dari [Abu Salamah] dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku adalah orang yang lebih utama terhadap setiap mukmin daripada dirinya sendiri. Siapapun laki-laki yang meninggal dunia dan ia meninggalkan hutang maka kembalinya kepadaku, dan barang siapa yang meninggalkan harta, maka untuk para pewarisnya.\""},"2502":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُرِضَهُ يَوْمَ أُحُدٍ وَهُوَ ابْنُ أَرْبَعَ عَشْرَةَ فَلَمْ يُجِزْهُ وَعُرِضَهُ يَوْمَ الْخَنْدَقِ وَهُوَ ابْنُ خَمْسَ عَشْرَةَ سَنَةً فَأَجَازَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam ditawari Ibnu Umar agar ikut perang pada waktu perang Uhud sementara ia berumur empat belas tahun, kemudian beliau tidak memperbolehkannya dan ditawari Ibnu Umar agar ikut perang pada waktu perang Khandaq, kemudian beliau memperbolehkannya. "},"2503":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي الْحَوَارِيِّ حَدَّثَنَا سُلَيْمُ بْنُ مُطَيْرٍ شَيْخٌ مِنْ أَهْلِ وَادِي الْقُرَى قَالَ حَدَّثَنِي أَبِى مُطَيْرٌأَنَّهُ خَرَجَ حَاجًّا حَتَّى إِذَا كَانَ بِالسُّوَيْدَاءِ إِذَا بِرَجُلٍ قَدْ جَاءَ كَأَنَّهُ يَطْلُبُ دَوَاءً وَحُضُضًا فَقَالَ أَخْبَرَنِي مَنْ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ وَهُوَ يَعِظُ النَّاسَ وَيَأْمُرُهُمْ وَيَنْهَاهُمْ فَقَالَ يَا أَيُّهَا النَّاسُ خُذُوا الْعَطَاءَ مَا كَانَ عَطَاءً فَإِذَا تَجَاحَفَتْ قُرَيْشٌ عَلَى الْمُلْكِ وَكَانَ عَنْ دِينِ أَحَدِكُمْ فَدَعُوهُقَالَ أَبُو دَاوُد وَرَوَاهُ ابْنُ الْمُبَارَكِ عَنْ مُحَمَّدِ بْنِ يَسَارٍ عَنْ سُلَيْمِ بْنِ مُطَيْرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Al Hawari], telah menceritakan kepada kami [Sulaim bin Muthair], seorang syekh dari penduduk Bukit Qura, ia berkata; telah menceritakan kepadaku [ayahku yaitu Muthair], bahwa ia keluar untuk melakukan haji hingga setelah sampai di As Suwaida` ternyata terdapat [seorang laki-laki] yang datang sepertinya ia mencari obat, serta hudhadh (semacam obat), kemudian ia berkata; telah mengabarkan kepadaku [orang] yang telah mendengar Rasulullah shallallahu 'alaihi wasallam pada saat haji wada' sedang memberi nasehat kepada orang-orang serta memerintahkan dan melarang mereka. Beliau berkata: \"Wahai manusia, ambillah pemberian selama merupakan pemberian. Dan apabila orang-orang Quraisy berselisih memperebutkan kerajaan, dan pemberian yang diberikan raja sebagai ganti agama salah seorang diantara kalian, maka janganlah engkau ambil.\" Abu Daud berkata; dan telah meriwayatkannya [Ibnu Mubarok] dari [Muhammad bin Yasar] dari [Salim bin Muthair] "},"2504":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُلَيْمُ بْنُ مُطَيْرٍ مِنْ أَهْلِ وَادِي الْقُرَى عَنْ أَبِيهِ أَنَّهُ حَدَّثَهُ قَالَ سَمِعْتُ رَجُلًا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَأَمَرَ النَّاسَ وَنَهَاهُمْ ثُمَّ قَالَ اللَّهُمَّ هَلْ بَلَّغْتُ قَالُوا اللَّهُمَّ نَعَمْ ثُمَّ قَالَ إِذَا تَجَاحَفَتْ قُرَيْشٌ عَلَى الْمُلْكِ فِيمَا بَيْنَهَا وَعَادَ الْعَطَاءُ أَوْ كَانَ رِشًا فَدَعُوهُ فَقِيلَ مَنْ هَذَا قَالُوا هَذَا ذُو الزَّوَائِدِ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], telah menceritakan kepada kami [Sulaim bin Muthair] yang merupakan diantara penduduk Bukit Qura, dari [ayahnya], bahwa ia telah menceritakan kepadanya, ia berkata; aku telah mendengar [seorang laki-laki] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam pada saat haji wada', beliau memerintahkan dan melarang manusia, kemudian berkata: \"Saksikanlah ya Allah, apakah aku telah menyampaikan?\" mereka berkata; ya. Kemudian beliau berkata: \"Apabila orang-orang Quraisy berselisih memperebutkan kerajaan diantara mereka dan pemberian kembali menjadi suap maka jangan engkau ambil!\" kemudian ditanyakan; siapakah orang ini? Mereka berkata; ini adalah Dzu Az Zawaid, sahabat Rasulullah shallallahu 'alaihi wasallam. "},"2505":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ الْأَنْصَارِيِّأَنَّ جَيْشًا مِنْ الْأَنْصَارِ كَانُوا بِأَرْضِ فَارِسَ مَعَ أَمِيرِهِمْ وَكَانَ عُمَرُ يُعْقِبُ الْجُيُوشَ فِي كُلِّ عَامٍ فَشُغِلَ عَنْهُمْ عُمَرُ فَلَمَّا مَرَّ الْأَجَلُ قَفَلَ أَهْلُ ذَلِكَ الثَّغْرِ فَ��شْتَدَّ عَلَيْهِمْ وَتَوَاعَدَهُمْ وَهُمْ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا عُمَرُ إِنَّكَ غَفَلْتَ عَنَّا وَتَرَكْتَ فِينَا الَّذِي أَمَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِعْقَابِ بَعْضِ الْغَزِيَّةِ بَعْضًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Ibrahim bin Sa'd], telah menceritakan kepada kami [Ibnu Syihab] dari [Abdullah bin Ka'b bin Malik Al Anshari], bahwa sebuah pasukan anshar berada di negeri Persia bersama pemimpin mereka, dan Umar mengirimkan pasukan menggantikan pasukan yang lain pada setiap tahun, kemudian ia tersibukkan dari hal tersebut. Kemudian tatkala telah lewat waktunya pasukan tersebut kembali dan merasakan takut, Umar mengancam mereka sementara mereka adalah para sahabat Rasulullah shallallahu 'alaihi wasallam. Lalu [mereka] berkata; wahai Umar, sesungguhnya engkau telah lalai dari kami, dan engkau tinggalkan pada kami apa yang telah diperintahkan Rasulullah shallallahu 'alaihi wasallam yaitu menggantikan pasukan dengan pasukan yang lain. "},"2506":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَائِذٍ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنِي فِيمَا حَدَّثَهُ ابْنٌ لِعَدِيِّ بْنِ عَدِيٍّ الْكِنْدِيِّ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ كَتَبَإِنَّ مَنْ سَأَلَ عَنْ مَوَاضِعِ الْفَيْءِ فَهُوَ مَا حَكَمَ فِيهِ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فَرَآهُ الْمُؤْمِنُونَ عَدْلًا مُوَافِقًا لِقَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ اللَّهُ الْحَقَّ عَلَى لِسَانِ عُمَرَ وَقَلْبِهِ فَرَضَ الْأَعْطِيَةَ لِلْمُسْلِمِينَ وَعَقَدَ لِأَهْلِ الْأَدْيَانِ ذِمَّةً بِمَا فَرَضَ عَلَيْهِمْ مِنْ الْجِزْيَةِ لَمْ يَضْرِبْ فِيهَا بِخُمُسٍ وَلَا مَغْنَمٍ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Muhammad bin 'Aidz], telah menceritakan kepada kami [Al Walid], telah menceritakan kepada kami [Isa bin Yunus], telah menceritakan kepadaku [diantara yang telah diceritakan Ibnu Adi bin Adi Al Kindi] bahwa [Umar bin Abdul Aziz] telah menulis: Sesunguhnya barang siapa yang menanyakan tempat-tempat penyaluran far` maka hal itu adalah apa yang telah diputuskan oleh [Umar bin Al Khathab] radliallahu 'anhu, dan telah dilihat orang-orang mukmin sebagai keadilan yang sesuai dengan sabda Nabi shallallahu 'alaihi wasallam: \"Allah telah menjadikan kebenaran berada pada lisan Umar dan hatinya.\" Ia telah mewajibkan pemberian kepada orang-orang muslim, dna menjalin hubungan keamanan bagi para pemeluk agama dengan apa ganti jizyah yang telah ia wajibkan atas mereka. Ia tidak memperlakukan seperlima pada jizyah tersebut juga bukan sebagai rampasan perang. "},"2507":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مَكْحُولٍ عَنْ غُضَيْفِ بْنِ الْحَارِثِ عَنْ أَبِي ذَرٍّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ وَضَعَ الْحَقَّ عَلَى لِسَانِ عُمَرَ يَقُولُ بِهِ","id":"Telah menceritakan kepada kami [Ahmad Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Makhul] dari [Ghudhaif bin Al Harits] dari [Abu Dzar], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Sesungguhnya Allah telah meletakkan hak (kebenaran) pada lisan Umar, ia berkata dengan kebenaran tersebut.\""},"2508":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ الْمَعْنَى قَالَا حَدَّثَنَا بِشْرُ بْنُ عُمَرَ الزَّهْرَانِيُّ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَالَأَرْسَلَ إِلَيَّ عُمَرُ حِينَ تَعَالَى النَّهَارُ فَجِئْتُهُ فَوَجَدْتُهُ جَالِسًا عَلَى سَرِيرٍ مُفْضِيًا إِلَى رِمَالِهِ فَقَالَ حِينَ دَخَلْتُ عَلَيْهِ يَا مَالِ إِنَّهُ قَدْ دَفَّ أَهْلُ أَبْيَاتٍ مِنْ قَوْمِكَ وَإِنِّي قَدْ أَمَرْتُ فِيهِمْ بِشَيْءٍ فَأَقْسِمْ فِيهِمْ قُلْتُ لَوْ أَمَرْتَ غَيْرِي بِذَلِكَ فَقَالَ خُذْهُ فَجَاءَهُ يَرْفَأُ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ هَلْ لَكَ فِي عُثْمَانَ بْنِ عَفَّانَ وَعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَالزُّبَيْرِ بْنِ الْعَوَّامِ وَسَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَ نَعَمْ فَأَذِنَ لَهُمْ فَدَخَلُوا ثُمَّ جَاءَهُ يَرْفَأُ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ هَلْ لَكَ فِي الْعَبَّاسِ وَعَلِيٍّ قَالَ نَعَمْ فَأَذِنَ لَهُمْ فَدَخَلُوا فَقَالَ الْعَبَّاسُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا يَعْنِي عَلِيًّا فَقَالَ بَعْضُهُمْ أَجَلْ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْهُمَا قَالَ مَالِكُ بْنُ أَوْسٍ خُيِّلَ إِلَيَّ أَنَّهُمَا قَدَّمَا أُولَئِكَ النَّفَرَ لِذَلِكَ فَقَالَ عُمَرُ رَحِمَهُ اللَّهُ اتَّئِدَا ثُمَّ أَقْبَلَ عَلَى أُولَئِكَ الرَّهْطِ فَقَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالُوا نَعَمْ ثُمَّ أَقْبَلَ عَلَى عَلِيٍّ وَالْعَبَّاسِ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ أَنْشُدُكُمَا بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ فَقَالَا نَعَمْ قَالَ فَإِنَّ اللَّهَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَاصَّةٍ لَمْ يَخُصَّ بِهَا أَحَدًا مِنْ النَّاسِ فَقَالَ اللَّهُ تَعَالَى{ وَمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ وَلَكِنَّ اللَّهَ يُسَلِّطُ رُسُلَهُ عَلَى مَنْ يَشَاءُ وَاللَّهُ عَلَى كُلِّ شَيْءٍ قَدِيرٌ }وَكَانَ اللَّهُ أَفَاءَ عَلَى رَسُولِهِ بَنِي النَّضِيرِ فَوَاللَّهِ مَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ وَلَا أَخَذَهَا دُونَكُمْ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُ مِنْهَا نَفَقَةَ سَنَةٍ أَوْ نَفَقَتَهُ وَنَفَقَةَ أَهْلِهِ سَنَةً وَيَجْعَلُ مَا بَقِيَ أُسْوَةَ الْمَالِ ثُمَّ أَقْبَلَ عَلَى أُولَئِكَ الرَّهْطِ فَقَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ أَقْبَلَ عَلَى الْعَبَّاسِ وَعَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ أَنْشُدُكُمَا بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ فَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْتَ أَنْتَ وَهَذَا إِلَى أَبِي بَكْرٍ تَطْلُبُ أَنْتَ مِيرَاثَكَ مِنْ ابْنِ أَخِيكَ وَيَطْلُبُ هَذَا مِيرَاثَ امْرَأَتِهِ مِنْ أَبِيهَا فَقَالَ أَبُو بَكْرٍ رَحِمَهُ اللَّهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ وَاللَّهُ يَعْلَمُ إِنَّهُ لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ فَوَلِيَهَا أَبُو بَكْرٍ فَلَمَّا تُوُفِّيَ أَبُو بَكْرٍ قُلْتُ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَلِيُّ أَبِي بَكْرٍ فَوَلِيتُهَا مَا شَاءَ اللَّهُ أَنْ أَلِيَهَا فَجِئْتَ أَنْتَ وَهَذَا وَأَنْتُمَا جَمِيعٌ وَأَمْرُكُمَا وَاحِدٌ فَسَأَلْتُمَانِيهَا فَقُلْتُ إِنْ شِئْتُمَا أَنْ أَدْفَعَهَا إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ أَنْ تَلِيَاهَا بِالَّذِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلِيهَا فَأَخَذْتُمَاهَا مِنِّي عَلَى ذَلِكَ ثُمَّ جِئْتُمَانِي لِأَقْضِيَ بَيْنَكُمَا بِغَيْرِ ذَلِكَ وَاللَّهِ لَا أَقْضِي بَيْنَكُمَا بِغَيْرِ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهَا فَرُدَّاهَا إِلَيَّقَالَ أَبُو دَاوُد إِنَّمَا سَأَلَاهُ أَنْ يَكُونَ يُصَيِّرُهُ بَيْنَهُمَا نِصْفَيْنِ لَا أَنَّهُمَا جَهِلَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ فَإِنَّهُمَا كَانَا لَا يَطْلُبَانِ إِلَّا الصَّوَابَ فَقَالَ عُمَرُ لَا أُوقِعُ عَلَيْهِ اسْمَ الْقَسْمِ أَدَعُهُ عَلَى مَا هُوَ عَلَيْهِ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسٍ بِهَذِهِ الْقِصَّةِ قَالَ وَهُمَا يَعْنِي عَلِيًّا وَالْعَبَّاسَ رَضِيَ اللَّهُ عَنْهُمَا يَخْتَصِمَانِ فِيمَا أَفَاءَ اللَّهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَمْوَالِ بَنِي النَّضِيرِ قَالَ أَبُو دَاوُد أَرَادَ أَنْ لَا يُوقَعَ عَلَيْهِ اسْمُ قَسْمٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] dan [Muhammad bin Yahya bin Faris] secara makna, keduanya berkata; telah menceritakan kepada kami [Bisyr bin Umar Az Zahrani], telah menceritakan kepadaku [Malik bin Anas] dari [Ibnu Syihab] dari [Malik bin Aus bin Al Hadatsan], ia berkata; [Umar] mengirim surat kepadaku ketika siang telah meninggi, kemudian aku datang kepadanya dan aku mendapatinya sedang duduk di atas dipan yang bersentuhan langsung dengan pasir. Kemudian ia berkata ketika aku menemuinya; Wahai Malik, sesungguhnya penghuni beberapa rumah diantara kaummu telah berjalan lemas dan sesungguhnya aku telah memerintahkan agar memberikan sedikit pemberian kepada mereka. Aku katakan; seandainya engkau memerintahkan selainku untuk melakukan hal tersebut maka lebih baik. Kemudian ia berkata; ambillah! Kemudian penjaga Umar datang kepadanya, kemudian penjaga tersebut berkata; wahai Amirul mukminin apakah anda mau menemui [Utsman bin Affan], [Abdurrahman bin 'Auf], [Az Zubair bin Al 'Awwam], dan [Sa'd bin Abu Waqqash]? Ia berkata; ya. kemudian mereka diberi izin maka merekapun masuk. Kemudian penjaganya datang dan berkata; wahai Amirul mukminin apakah anda mau menemui [Al Abbas], dan [Ali]? Ia berkata; ya. kemudian ia memberikan izin kepada mereka, lalu mereka masuk. Al Abbas berkata; wahai amirul mukminin, putuskan antaraku dan antara orang ini, yaitu Ali! Kemudian sebagian orang berata; ya wahai amirul mukminin, putuskan antara keduanya! Dan hentikan mereka dari bertikai. [Malik bin Aus] berkata; aku berfikir bahwa mereka berdua mendatangkan orang-orang tersebut untuk hal tersebut. Kemudian Umar rahimahullah berkata; bersabarlah kalian berdua! Kemudian ia menghadap kepada orang-orang tersebut dan berkata; aku bertanya kepada kalian dengan nama Allah yang dengan seizinnya langit dan bumi berdiri; apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah.\" Mereka berkata; ya. kemudian ia menghadap kepada Ali dan Al Abbas radhiyallallahu 'anhuma dan berkata; aku bertanya kepada kalian dengan nama Allah yang dengan seizinnya langit dan bumi berdiri; apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah.\" Mereka berkata; ya. ia berkata; sesungguhnya Allah telah mengkhususkan Rasulnya shallallahu 'alaihi wasallam dengan kekhususan yang tidak dikhususkan kepada seorangpun diantara manusia. Allah berfirman: \"Dan apa saja harta rampasan (fai-i) yang diberikan Allah kepada RasulNya (dari harta benda) mereka, maka untuk mendapatkan itu kamu tidak mengerahkan seekor kudapun dan (tidak pula) seekor untapun, tetapi Allah yang memberikan kekuasaan kepada RasulNya terhadap apa saja yang dikehendakiNya. Dan Allah Maha Kuasa atas segala sesuatu.\" Dan Allah telah memberikan fai` Bani Nadhir kepada RasulNya. Demi Allah beliau tidak mementingkan diri sendiri atas kalian, dan tidak mengambilnya sendiri tanpa memberikan kepada kalian. Rasulullah shallallahu 'alaihi wasallam mengambil sebagian darinya sebagai nafkah satu tahun, atau nafkahnya dan nafkah keluargannya, dan menjadian sisanya sebagai sedekah. Kemudian ia menghadap kepada orang-orang tersebut dan berkata; aku bertanya kepada kalian dengan nama Allah yang dengan seizinnya langit dan bumi berdiri; apakah kalian mengetahui hal tersebut? Mereka mengatakan; ya. kemudian ia menghadap kepada [Al Abbas] dan [Ali] radliallahu 'anhuma dan berkata; aku bertanya kepada kalian dengan nama Allah yang dengan seizinnya langit dan bumi berdiri; apakah kalian mengetahui hal tersebut? Mereka mengatakan; ya. kemudian tatkala Rasulullah shallallahu 'alaihi wasallam wafat [Abu Bakr] berkata; aku adalah wali Rasulullah shallallahu 'alaihi wasallam kemudian engkau datang bersama orang ini engkau meminta warisanmu dari anak saudaramu, dan orang ini meminta warisan isterinya dari ayahnya. Kemudian Abu Bakr rahimahullah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah.\" Allah mengetahui bahwa ia adalah orang yang jujur dan baik, berakal dan mengikuti kebenaran. Kemudian Abu Bakr mengurusinya. Kemudian tatkala Abu Bakr meninggal, aku katakan; aku adalah wali Rasulullah shallallahu 'alaihi wasallam dan wali Abu Bakr, maka aku mengurusnya sesuai dengan kehendak Allah agar aku mengurusnya, kemudian engkau dan orang ini datang dan urusan kalian adalah sama. Kalian berdua memintanya kepadaku. maka aku katakan; apabila kalian menghendaki untuk aku serahkan harta tersebut kepada kalian berdua dengan syarat kalian berjanji dengan perjanjian Allah yaitu agar kalian mengurusnya dengan dengan kepengurusan yang dilakukan Rasulullah shallallahu 'alaihi wasallam. Maka kalian mengambilnya dariku dengan syarat hal tersebut. Kemudian kalian berdua datang kepadaku agar aku memberikan keputusan diantara kalian berdua dengan cara tidak seperti itu. Demi Allah aku tidak akan memutuskan diantara kalian berdua dengan cara tidak seperti itu hingga bangkitnya hari kiamat. Maka apabila kalian berdua tidak mampu maka kembalikanlah kepadaku. Abu Daud berkata; sesungguhnya mereka berdua meminta kepadanya agar ia membagi diantara mereka berdua menjadi dua bagian, bukannya mereka tidak mengetahui bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Kami tidak diwarisi, dan apa yang kami tinggalkan adalah sedekah.\" Sesungguhnya mereka berdua tidak menuntut kecuali kebenaran. Kemudian Umar berkata; aku tidak memberinya nama pembagian, aku membiarkannya sebagaimana adanya. Telah menceritakan kepada kami [Muhammad bin 'ubaid] telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Az Zuhri] dari [Malik bin Aus] dengan kisah ini. Ia berkata; dan mereka yaitu Ali dan Al Abbas radliallahu 'anhuma berselisih mengenai apa yang Allah berikan kepada RasulNya sebagai fai` dari harta Bani Nadhir. Abu Daud berkata; Umar menghendaki agar tidak diberi nama pembagian."},"2509":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَأَحْمَدُ بْنُ عَبْدَةَ الْمَعْنَى أَنَّ سُفْيَانَ بْنَ عُيَيْنَةَ أَخْبَرَهُمْ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ عَنْ عُمَرَ قَالَكَانَتْ أَمْوَالُ بَنِي النَّضِيرِ مِمَّا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِمَّا لَمْ يُوجِفْ الْمُسْلِمُونَ عَلَيْهِ بِخَيْلٍ وَلَا رِكَابٍ كَانَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالِصًا يُنْفِقُ عَلَى أَهْلِ بَيْتِهِ قَالَ ابْنُ عَبْدَةَ يُنْفِقُ عَلَى أَهْلِهِ قُوتَ سَنَةٍ فَمَا بَقِيَ جَعَلَ فِي الْكُرَاعِ وَعُدَّةً فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّقَالَ ابْنُ عَبْدَةَ فِي الْكُرَاعِ وَالسِّلَاحِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?] dan [Ahmad bin 'Abdah] secara makna bahwa [Sufyan bin 'Uyainah] telah mengabarkan kepada mereka dari ['Amr bin Dinar] dari [Az Zuhri] dari [Malik bin Aus bin Al Hadatsan] dari [Umar] ia berkata; harta Bani Nadhir adalah diantara fa` yang Allah berikan kepada RasulNya, diantara sesuatu yang diperoleh tanpa orang-orang muslimin mengerahkan kuda dan tunggangan. Harta tersebut adalah murni untuk Rasulullah shallallahu 'alaihi wasallam yang beliau nafkahkan kepada keluarganya. Ibnu 'Abdah berkata; beliau nafkahkan kepada keluarganya sebagai makanan selama satu tahun. Dan yang tersisa beliau gunakan untuk mengadakan kuda dan peralatan di jalan Allah 'azza wajalla. Ibnu 'Abdah berkata; untuk mengadakan kuda dan senjata. "},"2510":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَيُّوبُ عَنْ الزُّهْرِيِّ قَالَ قَالَ عُمَرُ{ وَمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ }قَالَ الزُّهْرِيُّ قَالَ عُمَرُ هَذِهِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاصَّةً قُرَى عُرَيْنَةَ فَدَكَ وَكَذَا وَكَذَا{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْ أَهْلِ الْقُرَى فَلِلَّهِ وَلِلرَّسُولِ وَلِذِي الْقُرْبَى وَالْيَتَامَى وَالْمَسَاكِينِ وَابْنِ السَّبِيلِ }وَلَلْفُقَرَاءِ الَّذِينَ أُخْرِجُوا مِنْ دِيَارِهِمْ وَأَمْوَالِهِمْ{ وَالَّذِينَ تَبَوَّءُوا الدَّارَ وَالْإِيمَانَ مِنْ قَبْلِهِمْ }{ وَالَّذِينَ جَاءُوا مِنْ بَعْدِهِمْ }فَاسْتَوْعَبَتْ هَذِهِ الْآيَةُ النَّاسَ فَلَمْ يَبْقَ أَحَدٌ مِنْ الْمُسْلِمِينَ إِلَّا لَهُ فِيهَا حَقٌّ قَالَ أَيُّوبُ أَوْ قَالَ حَظٌّ إِلَّا بَعْضَ مَنْ تَمْلِكُونَ مِنْ أَرِقَّائِكُمْ","id":"Telah menceritakan kepada kami [Musaddad], Telah menceritakan kepada kami [Isma'il bin Ibrahim], telah mengabarkan kepada kami [Ayyub] dari [Az Zuhri], ia berkata; [Umar] berkata: \"Dan apa saja harta rampasan (fai`) yang diberikan Allah kepada RasulNya (dari harta benda) mereka, maka untuk mendapatkan itu kamu tidak mengerahkan seekor kudapun dan (tidak pula) seekor untapun.\" Az Zuhri berkata; Umar berkata; ini adalah untuk Rasulullah shallallahu 'alaihi wasallam, khususnya kampong 'Urainah, Fadak, dan ini, serta ini.\"Apa saja harta rampasan (fai-i) yang diberikan Allah kepada RasulNya (dari harta benda) yang berasal dari penduduk kota-kota maka adalah untuk Allah, untuk Rasul, kaum kerabat, anak-anak yatim, orang-orang miskin dan orang-orang yang dalam perjalanan.\" \"(Juga) bagi orang fakir yang berhijrah yang diusir dari kampung halaman dan dari harta benda mereka.\" \"Dan orang-orang yang telah menempati kota Madinah dan telah beriman (Anshor) sebelum (kedatangan) mereka (Muhajirin).\" \"Dan orang-orang yang datang sesudah mereka (Muhajirin dan Anshor).\" Maka ayat ini mencakup seluruh orang, dan tidak ada seorang pun dari kalangan muslimin melainkan ia memiliki hak padanya. Ayyub berkata; atau ia mengatakan; bagian. Kecuali sebagian apa yang kalian miliki berupa budak-budak kalian. "},"2511":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ ح و حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ ح و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى وَهَذَا لَفْظُ حَدِيثِهِ كُلُّهُمْ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَالَكَانَ فِيمَا احْتَجَّ بِهِ عُمَرُ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَ كَانَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثُ صَفَايَا بَنُو النَّضِيرِ وَخَيْبَرُ وَفَدَكُ فَأَمَّا بَنُو النَّضِيرِ فَكَانَتْ حُبُسًا لِنَوَائِبِهِ وَأَمَّا فَدَكُ فَكَانَتْ حُبُسًا لِأَبْنَاءِ السَّبِيلِ وَأَمَّا خَيْبَرُ فَجَزَّأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَجْزَاءٍ جُزْأَيْنِ بَيْنَ الْمُسْلِمِينَ وَجُزْءًا نَفَقَةً لِأَهْلِهِ فَمَا فَضُلَ عَنْ نَفَقَةِ أَهْلِهِ جَعَلَهُ بَيْنَ فُقَرَاءِ الْمُهَاجِرِينَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], telah menceritakan kepada kami [Hatim bin Isma'il], dan telah diriwayatkan melalui jalur yang lain: Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Abdul Aziz bin Muhammad], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Nashr bin Ali], telah menceritakan kepada kami [Shafwan bin Isa], dan ini adalah lafazh haditsnya. Seluruh mereka berasal dari [Usamah bin Zaid] dari [Az Zuhri], dari [Malik bin Aus bin Al Hadatsan], ia berkata; diantara yang dijadikan hujjah [Umar] radliallahu 'anhu adalah bahwa ia mengatakan; Rasulullah shallallahu 'alaihi wasallam memiliki tiga bagian yang khusus untuknya, yaitu: Bani Nadhir, Khaibar, dan Fadak. Adapun Bani Nadhir, maka harta mereka dikhususkan untuk keperluan-keperluan beliau, adapun Fadak, maka harta mereka dikhususkan untuk Ibnu Sabil, adapun Khaibar maka Rasulullah shallallahu 'alaihi wasallam telah membagi harta mereka menjadi tiga bagian, dua bagian dibagikan diantara orang-orang muslim, dan satu bagian untuk memberikan nafkah kepada keluarganya. Dan yang tersisa dari pemberian nafkah keluarganya beliau bagikan diantara orang-orang muhajirin yang fakir. "},"2512":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهِبٍ الْهَمْدَانِيُّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عُقَيْلِ بْنِ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا أَخْبَرَتْهُأَنَّ فَاطِمَةَ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَتْ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُ تَسْأَلُهُ مِيرَاثَهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا أَفَاءَ اللَّهُ عَلَيْهِ بِالْمَدِينَةِ وَفَدَكَ وَمَا بَقِيَ مِنْ خُمُسِ خَيْبَرَ فَقَالَ أَبُو بَكْرٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ إِنَّمَا يَأْكُلُ آلُ مُحَمَّدٍ مِنْ هَذَا الْمَالِ وَإِنِّي وَاللَّهِ لَا أُغَيِّرُ شَيْئًا مِنْ صَدَقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ حَالِهَا الَّتِي كَانَتْ عَلَيْهَا فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَأَعْمَلَنَّ فِيهَا بِمَا عَمِلَ بِهِ رَسُول�� اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبَى أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ أَنْ يَدْفَعَ إِلَى فَاطِمَةَ عَلَيْهَا السَّلَام مِنْهَا شَيْئًاحَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ الْحِمْصِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ بِهَذَا الْحَدِيثِ قَالَ وَفَاطِمَةُ عَلَيْهَا السَّلَام حِينَئِذٍ تَطْلُبُ صَدَقَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي بِالْمَدِينَةِ وَفَدَكَ وَمَا بَقِيَ مِنْ خُمُسِ خَيْبَرَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ وَإِنَّمَا يَأْكُلُ آلُ مُحَمَّدٍ فِي هَذَا الْمَالِ يَعْنِي مَالَ اللَّهِ لَيْسَ لَهُمْ أَنْ يَزِيدُوا عَلَى الْمَأْكَلِ حَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُ بِهَذَا الْحَدِيثِ قَالَ فِيهِ فَأَبَى أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ عَلَيْهَا ذَلِكَ وَقَالَ لَسْتُ تَارِكًا شَيْئًا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْمَلُ بِهِ إِلَّا عَمِلْتُ بِهِ إِنِّي أَخْشَى إِنْ تَرَكْتُ شَيْئًا مِنْ أَمْرِهِ أَنْ أَزِيغَ فَأَمَّا صَدَقَتُهُ بِالْمَدِينَةِ فَدَفَعَهَا عُمَرُ إِلَى عَلِيٍّ وَعَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَغَلَبَهُ عَلِيٌّ عَلَيْهَا وَأَمَّا خَيْبَرُ وَفَدَكُ فَأَمْسَكَهُمَا عُمَرُ وَقَالَ هُمَا صَدَقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتَا لِحُقُوقِهِ الَّتِي تَعْرُوهُ وَنَوَائِبِهِ وَأَمْرُهُمَا إِلَى مَنْ وَلِيَ الْأَمْرَ قَالَ فَهُمَا عَلَى ذَلِكَ إِلَى الْيَوْمِ","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Abdullah bin Mauhib Al Hamdani] telah menceritakan kepada kami [Al Laits bin Sa'd] dari ['Aqil bin Khalid] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahw ia telah mengabarkan kepadanya bahwa Fathimah binti Rasulullah shallallahu 'alaihi wasallam telah mengirimkan utusan kepada Abu Bakr Ash Shiddiq radliallahu 'anhu, ia meminta kepadanya warisannya dari Rasulullah shallallahu 'alaihi wasallam diantara fa` yang Allah berikan kepdanya di Madinah, dan Fadak, dan apa yang tersisa dari seperlima Khaibar. Kemudian [Abu Bakr] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah.\" Sesungguhnya keluarga Muhammad makan dari harta ini, dan sesungguh aku demi Allah tidak akan mengubah sedikitpun dari sedekah Rasulullah shallallahu 'alaihi wasallam dari kondirinya yang ada pada zaman Rasulullah shallallahu 'alaihi wasallam. Sungguh aku akan berbuat seperti yang diperbuat Rasulullah shallallahu 'alaihi wasallam. Maka Abu Bakr enggan untuk menyerahkan sesuatupun dari harta tersebut kepada Fathimah radliallahu 'anha. Telah menceritakan kepada kami [Amr bin Utsman Al Himshi], telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'aib bin Abu Hamzah] dari [Az Zuhri] telah menceritakan kepadaku ['Urwah bin Az Zubair] bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam telah mengabaran kepadanya hadits ini. Ia berkata; dan Fathimah pada saat itu meminta sedekah Rasulullah shallallahu 'alaihi wasallam yang berada di Madinah dan Fudak, serta yang tersisa dari seperlima Khaibar. Aisyah radliallahu 'anha berkata; kemudian Abu Bakr berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam berkata: \"Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah.\" Sesungguhnya keluarga Muhammad makan dari harta ini, yaitu dari harta Allah, mereka tidak berha untuk menambah melebihi apa yang mereka makan. Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd], telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku ['Urwah] bahwa [Aisyah] radliallahu 'anha telah mengabarkan kepadanya dengan hadits ini. Ia berkata dalam hadits ini; kemudian Abu Bakr radliallahu 'anhu enggan memberikan hal tersebut kepadanya. dan ia berkata; aku tidak akan meninggalkan sesuatu yang dahulu dilakukan Rasulullah shallallahu 'alaihi wasallam, melainkan aku akan melakukannya. Sesungguhnya aku khawatir jika aku meninggalkan sesuatu dari urusan beliau maka aku akan tersesat. Adapun sedekah beliau di Madinah maka Umar telah menyerahkannya kepada Ali dan Abbas radliallahu 'anhuma. Kemudian Ali mengalahkannya dalam mengurusnya. Adapun Khaibar dan Fadak maka Umar menahan keduanya dan berkata; keduanya adalah sedekah Rasulullah shallallahu 'alaihi wasallam, keduanya adalah untuk hak-hak beliau serta musibah-musibah yang kemungkinan terjadi. Dan urusan keduanya kembali kepada orang yang mengurui perkara tersebut. Ia berkata; keduanya berada dalam kondisi seperti itu hingga saat ini. "},"2513":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّفِي قَوْلِهِ{ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ }قَالَ صَالَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلَ فَدَكَ وَقُرًى قَدْ سَمَّاهَا لَا أَحْفَظُهَا وَهُوَ مُحَاصِرٌ قَوْمًا آخَرِينَ فَأَرْسَلُوا إِلَيْهِ بِالصُّلْحِ قَالَ{ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ }يَقُولُ بِغَيْرِ قِتَالٍ قَالَ الزُّهْرِيُّ وَكَانَتْ بَنُو النَّضِيرِ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالِصًا لَمْ يَفْتَحُوهَا عَنْوَةً افْتَتَحُوهَا عَلَى صُلْحٍ فَقَسَمَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْمُهَاجِرِينَ لَمْ يُعْطِ الْأَنْصَارَ مِنْهَا شَيْئًا إِلَّا رَجُلَيْنِ كَانَتْ بِهِمَا حَاجَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Ibnu Tsaur] dari [Ma'mar] dari [Az Zuhri] mengenai firman Allah: \"Maka untuk mendapatkan itu kamu tidak mengerahkan seekor kudapun dan (tidak pula) seekor untapun.\" Ia berkata; Rasulullah shallallahu 'alaihi wasallam telah membuat kesepatakan dengan orang-orang Fadak dan berbagari kota yang telah beliau sebutkan dan tidak aku hafal, dan beliau mengepung kaum yang lain. Kemudian mereka mengirimkan utusan kepada beliau dengan membawa perjanjian perdamaian. Allah berfirman: \"Maka untuk mendapatkan itu kamu tidak mengerahkan seekor kudapun dan (tidak pula) seekor untapun.\" Ia berkata; yaitu tanpa berperang. Az Zuhri berkata; Harta Bani Nadhir adalah khusus untuk Nabi shallallahu 'alaihi wasallam. Mereka tidak menundukkannya dengan kekerasan, mereka menundukkannya dengan perjanjian damai. Kemudian Nabi shallallahu 'alaihi wasallam membaginya diantara orang-orang muhajirin dan tidak memberi orang-orang anshar kecuali dua orang yang membutuhkan. "},"2514":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ حَدَّثَنَا جَرِيرٌ عَنْ الْمُغِيرَةِ قَالَ جَمَعَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ بَنِي مَرْوَانَ حِينَ اسْتُخْلِفَ فَقَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتْ لَهُ فَدَكُ فَكَانَ يُنْفِقُ مِنْهَا وَيَعُودُ مِنْهَا عَلَى صَغِيرِ بَنِي هَاشِمٍ وَيُزَوِّجُ مِنْهَا أَيِّمَهُمْ وَإِنَّ فَاطِمَةَ سَأَلَتْهُ أَنْ يَجْعَلَهَا لَهَا فَأَبَى فَكَانَتْ كَذَلِكَ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى مَضَى لِسَبِيلِهِ فَلَمَّا أَنْ وُلِّيَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ عَمِلَ فِيهَا بِمَا عَمِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَيَاتِهِ حَتَّى مَضَى لِسَبِيلِهِ فَلَمَّا أَنْ وُلِّيَ عُمَرُ عَمِلَ فِيهَا بِمِثْلِ مَا عَمِلَا حَتَّى مَضَى لِسَبِيلِهِ ثُمَّ أَقْطَعَهَا مَرْوَانُ ثُمَّ صَارَتْ لِعُمَرَ بْنِ عَبْدِ الْعَزِيزِ قَالَ عُمَرُ يَعْنِي ابْنَ عَبْدِ الْعَزِيزِ فَرَأَيْتُ أَمْرًا مَنَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاطِمَةَ عَلَيْهَا السَّلَام لَيْسَ لِي بِحَقٍّ وَأَنَا أُشْهِدُكُمْ أَنِّي قَدْ رَدَدْتُهَا عَلَى مَا كَانَتْ يَعْنِي عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو دَاوُد وَلِيَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ الْخِلَافَةَ وَغَلَّتُهُ أَرْبَعُونَ أَلْفَ دِينَارٍ وَتُوُفِّيَ وَغَلَّتُهُ أَرْبَعُ مِائَةِ دِينَارٍ وَلَوْ بَقِيَ لَكَانَ أَقَلَّ","id":"Telah menceritakan kepada kami [Abdullah bin Al Jarrah], telah menceritakan kepada kami [Jarir], dari [Al Mughirah], ia berkata; [Umar bin Abdul Aziz] telah mengumpulkan anak-anak Marwan ketika ia ditunjuk sebagai khalifah, kemudian ia berkata; Sesungguhnya dahulu Fadak adalah untuk Rasulullah shallallahu 'alaihi wasallam, dahulu beliau memberikan nafkah dari harta tersebut dan kembali memberikan nafkah kepada anak-anak kecil Bani Hasyim, dan beliau menikahkan janda mereka dari harta tersebut. Dan sesungguhnya Fathimah meminta beliau agar memberikan bagian untuknya, kemudian beliau menolak. Maka demikianlah pada masa hidupnya Rasulullah shallallahu 'alaihi wasallam hingga beliau meninggal, kemudian tatkala Abu Bakr radliallahu 'anhu terpilih menjadi khalifah ia berbuat seperti yang diperbuat Nabi shallallahu 'alaihi wasallam pada masa hidupnya hingga meninggal, kemudian tatkala Umar terpilih menjadi khalifah ia berbuat seperti yang mereka perbuat hingga meninggal. Kemudian Marwan mengalokasikannya (untuk dirinya dan orang-orang yang mengikutinya), kemudian Lahan tersebut menjadi milik Umar bin Abdul 'Aziz, kemudian aku melihat suatu perkara yang tidak diberikan Rasulullah shallallahu 'alaihi wasallam kepada Fathimah bukanlah hak bagiku. Dan aku meminta persaksian kalian bahwa aku telah mengembalikannya kepada kondisinya terdahulu, yaitu pada masa Rasulullah shallallahu 'alaihi wasallam. Abu Daud berkata; Umar bin Abdul Aziz menjabat sebagai khalifah sementara penghasilannya adalah empat puluh ribu dinar, dan beliau meninggal sementara penghasilan beliau adalah empat ratus dinar, dan seandainya ada yang tersisa maka hal tersebut berjumlah lebih sedikit. "},"2515":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ عَنْ الْوَلِيدِ بْنِ جُمَيْعٍ عَنْ أَبِي الطُّفَيْلِ قَالَجَاءَتْ فَاطِمَةُ رَضِيَ اللَّهُ عَنْهَا إِلَى أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ تَطْلُبُ مِيرَاثَهَا مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ إِذَا أَطْعَمَ نَبِيًّا طُعْمَةً فَهِيَ لِلَّذِي يَقُومُ مِنْ بَعْدِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Muhammad bin Al Fudhail], dari [Al Walid bin Jumai'] dari [Abu Ath Thufail], ia berkata; Fathimah radliallahu 'anhu datang kepada Abu Bakr radliallahu 'anhu, ia meminta warisannya dari Nabi shallallahu 'alaihi wasallam, kemudian [Abu Bakr] radliallahu 'anhu berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah apabila memberikan makan kepada seorang nabi maka makanan tersebut adalah untuk orang menggantikan setelahnya.\""},"2516":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّقَالَ سَمِعْتُ حَدِيثًا مِنْ رَجُلٍ فَأَعْجَبَنِي فَقُلْتُ اكْتُبْهُ لِي فَأَتَى بِهِ مَكْتُوبًا مُذَبَّرًا دَخَلَ الْعَبَّاسُ وَعَلِيٌّ عَلَى عُمَرَ وَعِنْدَهُ طَلْحَةُ وَالزُّبَيْرُ وَعَبْدُ الرَّحْمَنِ وَسَعْدٌ وَهُمَا يَخْتَصِمَانِ فَقَالَ عُمَرُ لِطَلْحَةَ وَالزُّبَيْرِ وَعَبْدِ الرَّحْمَنِ وَسَعْدٍ أَلَمْ تَعْلَمُوا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مَالِ النَّبِيِّ صَدَقَةٌ إِلَّا مَا أَطْعَمَهُ أَهْلَهُ وَكَسَاهُمْ إِنَّا لَا نُورَثُ قَالُوا بَلَى قَالَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ مِنْ مَالِهِ عَلَى أَهْلِهِ وَيَتَصَدَّقُ بِفَضْلِهِ ثُمَّ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَلِيَهَا أَبُو بَكْرٍ سَنَتَيْنِ ��َكَانَ يَصْنَعُ الَّذِي كَانَ يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ذَكَرَ شَيْئًا مِنْ حَدِيثِ مَالِكِ بْنِ أَوْسٍ","id":"Telah menceritakan kepada kami ['Amr bin Marzuq], telah mengabarkan kepada kami [Syu'bah] dari ['Amr bin Murrah] dari [Abu Al Bakhtari], ia berkata; saya mendengar sebuah hadits dari [seorang laki-laki], dan hadits tersebut menarik bagiku. Kemudian aku katakan; tuliskan untukku! Kemudian ia datang dengan membawanya dalam keadaan tertulis dan mudah dibaca; Al Abbas dan Ali menemui Umar dan di sisinya terdapat Thalhah serta Az Zubair, Abdurrahman, dan Sa'd, dan keduanya sedang berselisih. Kemudian [Umar] berkata kepada Thalhah dan Az Zubair, Abdurrahman dan Sa'd; bukankah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Seluruh harta Nabi adalah sedekah, kecuali makanan yang diberikan kepada keluargannya dan pakaian yang diberikan kepada mereka. Sesungguhnya kami tidak diwarisi.\" Mereka berkata; benar. Umar berkata; dahulu Rasulullah shallallahu 'alaihi wasallam memberi nafkah keluarganya dari hartanya dan bersedekah dengan kelebihannya. Kemudian Rasulullah shallallahu 'alaihi wasallam meninggal dan Abu Bakr menjabat khalifah selama dua tahun, dan ia melakukan apa yang Rasulullah shallallahu 'alaihi wasallam lakukan. Kemudian ia menyebutkan sebagian dari hadits Malik bin Aus. "},"2517":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْإِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَدْنَ أَنْ يَبْعَثْنَ عُثْمَانَ بْنَ عَفَّانَ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ فَيَسْأَلْنَهُ ثُمُنَهُنَّ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ لَهُنَّ عَائِشَةُ أَلَيْسَ قَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُورَثُ مَا تَرَكْنَا فَهُوَ صَدَقَةٌحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ ابْنِ شِهَابٍ بِإِسْنَادِهِ نَحْوَهُ قُلْتُ أَلَا تَتَّقِينَ اللَّهَ أَلَمْ تَسْمَعْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا نُورَثُ مَا تَرَكْنَا فَهُوَ صَدَقَةٌ وَإِنَّمَا هَذَا الْمَالُ لِآلِ مُحَمَّدٍ لِنَائِبَتِهِمْ وَلِضَيْفِهِمْ فَإِذَا مُتُّ فَهُوَ إِلَى وَلِيِّ الْأَمْرِ مِنْ بَعْدِي","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] bahwa ia berkata; sesungguhnya isteri-isteri Nabi shallallahu 'alaihi wasallam ketika Rasulullah shallallahu 'alaihi wasallam meninggal, mereka hendak mengirim Utsman bin 'Affan datang kepada Abu Bakr Ash Shiddiq dan bertanya kepadanya mengenai bagian seperdelapan mereka dari Nabi shallallahu 'alaihi wasallam. Kemudian Aisyah berkata; bukankah Rasulullah shallallahu 'alaihi wasallam telah mengatakan: \"Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada kami [Ibrahim bin Hamzah], telah menceritakan kepada kami [Hatim bin Isma'il] dari [Usamah bin Zaid] dari [Ibnu Syihab] dengan sanadnya seperti itu. Aku katakan; tidakkah kalian bertakwa kepada Allah? Bukankah kalian telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah.\" Sesungguhnya harta ini untuk keluarga Muhammad, untuk kebutuhan mereka dan tamu mereka. Kemudian apabila meninggal maka urusannya kepada pemimpin setelahku. "},"2518":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيِّبِ أَخْبَرَنِي جُبَيْرُ بْنُ مُطْعِمٍأَنَّهُ جَاءَ هُوَ وَعُثْمَانُ بْنُ عَفَّانَ يُكَلِّمَانِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا قَسَمَ مِنْ الْخُمُسِ بَيْنَ بَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِ فَقُلْتُ يَا رَسُولَ اللَّهِ قَسَمْتَ لِإِخْوَانِنَا بَنِي الْمُطَّلِبِ وَلَمْ تُعْطِنَا شَيْئًا وَقَرَابَتُنَا وَقَرَابَتُهُمْ مِنْكَ وَاحِدَةٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا بَنُو هَاشِمٍ وَبَنُو الْمُطَّلِبِ شَيْءٌ وَاحِدٌ قَالَ جُبَيْرٌ وَلَمْ يَقْسِمْ لِبَنِي عَبْدِ شَمْسٍ وَلَا لِبَنِي نَوْفَلٍ مِنْ ذَلِكَ الْخُمُسِ كَمَا قَسَمَ لِبَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِقَالَ وَكَانَ أَبُو بَكْرٍ يَقْسِمُ الْخُمُسَ نَحْوَ قَسْمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ أَنَّهُ لَمْ يَكُنْ يُعْطِي قُرْبَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِيهِمْ قَالَ وَكَانَ عُمَرُ بْنُ الْخَطَّابِ يُعْطِيهِمْ مِنْهُ وَعُثْمَانُ بَعْدَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah], telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Abdullah bin Al Mubarak] dari [Yunus bin Yazid?] dari [Az Zuhri], telah mengabarkan kepadaku [Sa'id bin Al Musayyab], telah mengabarkan kepadaku [Jubair bin Muth'im] bahwa ia bersama Utsman bin 'Affan datang untuk berbicara kepada Rasulullah shallallahu 'alaihi wasallam mengenai seperlima bagian yang beliau bagikan diantara Bani Hasyim dan Bani Al Muththalib. Kemudian aku katakan; wahai Rasulullah, anda telah membagi untuk saudara-saudara kami Bani Al Muththalib, dan anda tidak memberikan sesuatupun kepada kami, padahal kerabat kami dan kerabat mereka bagi anda adalah satu. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bani Hasyim dan Bani Abdul Muththalib adalah sesuatu yang satu.\" Jubair berkata; beliau tidak membagikan kepada Bani Abdusy Syams dan Bani Naufal dari seperlima tersebut sebagaimana beliau membagikan kepada Bani Hasyim dan Bani Al Muththalib. Ia berkata; dan Abu Bakr membagikan seperti pembagian Rasulullah shallallahu 'alaihi wasallam hanya saja ia tidak memberikan kepada kaum kerabat Rasulullah shallallahu 'alaihi wasallam, sebagaimana Rasulullah shallallahu 'alaihi wasallam memberikan kepada mereka. Ia berkata; dan Umar bin Al Khaththab memberikan kepada mereka dari bagian tersebut begitu juga Utsman setelahnya. "},"2519":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنِي يُونُسُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ حَدَّثَنَا جُبَيْرُ بْنُ مُطْعِمٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَقْسِمْ لِبَنِي عَبْدِ شَمْسٍ وَلَا لِبَنِي نَوْفَلٍ مِنْ الْخُمُسِ شَيْئًا كَمَا قَسَمَ لِبَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِقَالَ وَكَانَ أَبُو بَكْرٍ يَقْسِمُ الْخُمُسَ نَحْوَ قَسْمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ أَنَّهُ لَمْ يَكُنْ يُعْطِي قُرْبَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا كَانَ يُعْطِيهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ عُمَرُ يُعْطِيهِمْ وَمَنْ كَانَ بَعْدَهُ مِنْهُمْ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar], telah menceritakan kepada kami [Utsman bin Umar], telah mengabarkan kepadaku [Yunus] dari [Az Zuhri] dari [Sa'id bin Al Musayyab], telah menceritakan kepada kami [Jubair bin Muth'im] bahwa Rasulullah shallallahu 'alaihi wasallam tidak membagikan kepada Bani Abdu Syams dan Bani Naufal sedikitpun dari seperima tersebut sebagaimana beliau membagikan kepada Bani Hasyim dan Bani Al Muththalib. Ia berkata; dan Abu Bakr membagikan sepersepuluh tersebut seperti pembagian Rasulullah shallallahu 'alaihi wasallam hanya saja ia tidak memberikan kepada kaum kerabat Rasulullah shallallahu 'alaihi wasallam, sebagaimana Rasulullah shallallahu 'alaihi wasallam memberikan kepada mereka. Ia berkata; dan Umar bin Al Khaththab memberikan kepada mereka begitu juga orang yang datang setelahnya."},"2520":{"ar":"حَدَّثَنَا مُسَدِّدٌ حَدَّثَنَا هُشَيْمٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ أَخْبَرَنِي جُبَيْرُ بْنُ مُطْعِمٍ قَالَلَمَّا كَانَ يَوْمُ خَيْبَرَ وَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَهْمَ ذِي الْقُرْبَى فِي بَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِ وَتَرَكَ بَنِي نَوْفَلٍ وَبَنِي عَبْدِ شَمْسٍ فَانْطَلَقْتُ أَنَا وَعُثْمَانُ بْنُ عَفَّانَ حَتَّى أَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو هَاشِمٍ لَا نُنْكِرُ فَضْلَهُمْ لِلْمَوْضِعِ الَّذِي وَضَعَكَ اللَّهُ بِهِ مِنْهُمْ فَمَا بَالُ إِخْوَانِنَا بَنِي الْمُطَّلِبِ أَعْطَيْتَهُمْ وَتَرَكْتَنَا وَقَرَابَتُنَا وَاحِدَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا وَبَنُو الْمُطَّلِبِ لَا نَفْتَرِقُ فِي جَاهِلِيَّةٍ وَلَا إِسْلَامٍ وَإِنَّمَا نَحْنُ وَهُمْ شَيْءٌ وَاحِدٌ وَشَبَّكَ بَيْنَ أَصَابِعِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Husyaim] dari [Muhammad bin Ishaq], dari [Az Zuhri] dari [Sa'id bin Al Musayyab], telah mengabarkan kepadaku [Jubair bin Muth'im], ia berkata; tatkala pada saat perang Khaibar, Rasulullah shallallahu 'alaihi wasallam meletakkan saham kaum kerabat pada Bani Hasyim dan Bani Abdul Muththalib, dan beliau meninggalkan Bani Naufal serta Bani Abdu Syams. Kemudian aku dan Utsman bin Affan pergi hingga datang kepada Nabi shallallahu 'alaihi wasallam, lalu kami berkata; wahai Rasulullah, mereka Bani Hasyim, kami tidak mengingkari keutamaan mereka karena posisi yang Allah tempatkan anda diantara mereka, namun bagaimana dengan saudara-saudara kami Bani Abdul Muththalib? Anda telah memberikan kepada mereka dan meninggalkan kami, sementara kerabat kami adalah satu. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kami dan Bani Al Muththalib tidak berpisah pada masa jahiliyah dan pada masa Islam, sesungguhnya kami dan mereka adalah sesuatu yang satu.\" Dan beliau menjalin jari-jari beliau shallallahu 'alaihi wasallam. "},"2521":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْعِجْلِيُّ حَدَّثَنَا وَكِيعٌ عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ السُّدِّيِّفِي ذِي الْقُرْبَى قَالَ هُمْ بَنُو عَبْدِ الْمُطَّلِبِ","id":"Telah menceritakan kepada kami [Husain bin Ali Al 'Ajli], telah menceritakan kepada kami [Waki'], dari [Al Hasan bin Shalih] dari [As Suddi] mengenai kaum kerabat. Ia berkata; mereka adalah Bani Abdul Muththalib. "},"2522":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي يَزِيدُ بْنُ هُرْمُزَ أَنَّ نَجْدَةَ الْحَرُورِيَّحِينَ حَجَّ فِي فِتْنَةِ ابْنِ الزُّبَيْرِ أَرْسَلَ إِلَى ابْنِ عَبَّاسٍ يَسْأَلُهُ عَنْ سَهْمِ ذِي الْقُرْبَى وَيَقُولُ لِمَنْ تَرَاهُ قَالَ ابْنُ عَبَّاسٍ لِقُرْبَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَسَمَهُ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ كَانَ عُمَرُ عَرَضَ عَلَيْنَا مِنْ ذَلِكَ عَرْضًا رَأَيْنَاهُ دُونَ حَقِّنَا فَرَدَدْنَاهُ عَلَيْهِ وَأَبَيْنَا أَنْ نَقْبَلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami ['Anbasah], telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab], telah mengabarkan kepadaku [Yazid? bin Hurmuz], bahwa Najdah Al Haruri ketika berhaji disaat terjadinya fitnah terhadap Ibnu Az Zubair, ia mengirimkan surat kepada Ibnu Abbas, bertanya kepadanya mengenai saham kaum kerabat, ia berkata; untuk siapakah menurutmu? [Ibnu Abbas] berkata; untuk kerabat Rasulullah shallallahu 'alaihi wasallam, Rasulullah shallallahu 'alaihi wasallam telah membagikan kepada mereka. Dan Umar telah menawarkan kepada kami dari saham tersebut, dan kami melihat saham tersebut bukan hak kami. Kemudian kami mengembalikannya dan kami menolak untuk menerimanya. "},"2523":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ مُطَرِّفٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ سَمِعْتُ عَلِيًا يَقُولُوَلَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُمُسَ الْخُمُسِ فَوَضَعْتُهُ مَوَاضِعَهُ حَيَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَيَاةَ أَبِي بَكْرٍ وَحَيَاةَ عُمَرَ فَأُتِيَ بِمَالٍ فَدَعَانِي فَقَالَ خُذْهُ فَقُلْتُ لَا أُرِيدُهُ قَالَ خُذْهُ فَأَنْتُمْ أَحَقُّ بِهِ قُلْتُ قَدْ اسْتَغْنَيْنَا عَنْهُ فَجَعَلَهُ فِي بَيْتِ الْمَالِ","id":"Telah menceritakan kepada kami [Abbas bin Abdul 'Azhim], telah menceritakan kepada kami [Yahya bin Abu Bukair], telah menceritakan kepada kami [Abu Ja'far Ar Razi], dari [Mutharrif] dari [Abdurrahman bin Abu Laila], ia berkata; saya mendengar [Ali] berkata; Rasulullah shallallahu 'alaihi wasallam menunjukku untuk mengurusi bagian seperdua puluh lima, kemudian aku meletakkannya pada tempatnya pada masa hidup Rasulullah shallallahu 'alaihi wasallam dan pada masa hidup Abu Bakr serta Umar. Kemudian ia diberi harta, lalu ia memanggilku dan berkata; ambillah! Kemudian aku katakan; aku tidak mau. Umar berkata; ambillah, kalian lebih berhak terhadapnya. Aku katakan; kami telah merasa tidak membutuhkannya. Kemudian Umar menyimpannya di Baitul Mal. "},"2524":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا هَاشِمُ بْنُ الْبَرِيدِ حَدَّثَنَا حُسَيْنُ بْنُ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ سَمِعْتُ عَلِيًّا عَلَيْهِ السَّلَام يَقُولُاجْتَمَعْتُ أَنَا وَالْعَبَّاسُ وَفَاطِمَةُ وَزَيْدُ بْنُ حَارِثَةَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنْ رَأَيْتَ أَنْ تُوَلِّيَنِي حَقَّنَا مِنْ هَذَا الْخُمُسِ فِي كِتَابِ اللَّهِ فَأَقْسِمْهُ حَيَاتَكَ كَيْ لَا يُنَازِعَنِي أَحَدٌ بَعْدَكَ فَافْعَلْ قَالَ فَفَعَلَ ذَلِكَ قَالَ فَقَسَمْتُهُ حَيَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وَلَّانِيهِ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ حَتَّى إِذَا كَانَتْ آخِرُ سَنَةٍ مِنْ سِنِي عُمَرَ رَضِيَ اللَّهُ عَنْهُ فَإِنَّهُ أَتَاهُ مَالٌ كَثِيرٌ فَعَزَلَ حَقَّنَا ثُمَّ أَرْسَلَ إِلَيَّ فَقُلْتُ بِنَا عَنْهُ الْعَامَ غِنًى وَبِالْمُسْلِمِينَ إِلَيْهِ حَاجَةٌ فَارْدُدْهُ عَلَيْهِمْ فَرَدَّهُ عَلَيْهِمْ ثُمَّ لَمْ يَدْعُنِي إِلَيْهِ أَحَدٌ بَعْدَ عُمَرَ فَلَقِيتُ الْعَبَّاسَ بَعْدَمَا خَرَجْتُ مِنْ عِنْدِ عُمَرَ فَقَالَ يَا عَلِيُّ حَرَمْتَنَا الْغَدَاةَ شَيْئًا لَا يُرَدُّ عَلَيْنَا أَبَدًا وَكَانَ رَجُلًا دَاهِيًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Ibnu Numair], telah menceritakan kepada kami [Hasyim bin Al Barid], telah menceritakan kepada kami [Husain bin Maimun], dari [Abdullah bin Abdullah], dari [Abdurrahman bin Abu Laila], ia berkata; saya mendengar [Ali] berkata; aku berkumpul bersama Al 'Abbas, Fathimah, dan Zaid bin Haritsah di sisi Nabi shallallahu 'alaihi wasallam, kemudian aku katakan; wahai Rasulullah, apabila anda memandang perlu untuk anda serahkan kepadaku hak kami dari seperlima yang ada dalam kitab Allah ini dan aku membaginya di masa hidup anda agar tidak ada seorangpun yang menyelisihiku setelahmu, maka lakukanlah! Ali berkata; kemudian beliau melakukan hal tersebut. Kemudian aku membaginya pada masa hidup Rasulullah shallallahu 'alaihi wasallam, kemudian Abu Bakr menyerahkannya kepadaku hingga setelah akhir tahun kekhilafahan Umar radliallahu 'anhu maka sesungguhnya telah datang kepadanya harta yang banyak kemudian ia melepas hak kami kemudian mengirimkan sebagian harta tersebut kepadaku. Lalu aku katakan; pada tahun ini kami tidak butuh kepadanya dan orang-orang muslim membutuhkan kepadanya, maka kembalikan kepada mereka! Kemudian Umar mengembalikan harta tersebut kepada mereka, kemudian tidak ada seorangpun yang mengundangku untuk mengambil harta tersebut setelah Umar. Kemudian aku menemui Ibnu Abbas setelah aku keluar dari sisi Umar, lalu ia berkata; wahai Ali, sungguh pagi ini engkau telah menghalangi kita mengambil sesuatu yang tidak akan dikembalikan kepada kita selamanya. Dan ia adalah laki-laki yang memiliki pemikiran yang baik. "},"2525":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ الْحَارِثِ ابْنِ نَوْفَلٍ الْهَاشِمِيُّ أَنَّ عَبْدَ الْمُطَّلِبِ بْنَ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ أَخْبَرَهُأَنَّ أَبَاهُ رَبِيعَةَ بْنَ الْحَارِثِ وَعَبَّاسَ بْنَ عَبْدِ الْمُطَّلِبِ قَالَا لِعَبْدِ الْمُطَّلِبِ بْنِ رَبِيعَةَ وَلِلْفَضْلِ بْنِ عَبَّاسٍ ائْتِيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُولَا لَهُ يَا رَسُولَ اللَّهِ قَدْ بَلَغْنَا مِنْ السِّنِّ مَا تَرَى وَأَحْبَبْنَا أَنْ نَتَزَوَّجَ وَأَنْتَ يَا رَسُولَ اللَّهِ أَبَرُّ النَّاسِ وَأَوْصَلُهُمْ وَلَيْسَ عِنْدَ أَبَوَيْنَا مَا يُصْدِقَانِ عَنَّا فَاسْتَعْمِلْنَا يَا رَسُولَ اللَّهِ عَلَى الصَّدَقَاتِ فَلْنُؤَدِّ إِلَيْكَ مَا يُؤَدِّي الْعُمَّالُ وَلْنُصِبْ مَا كَانَ فِيهَا مِنْ مَرْفَقٍ قَالَ فَأَتَى عَلِيُّ بْنُ أَبِي طَالِبٍ وَنَحْنُ عَلَى تِلْكَ الْحَالِ فَقَالَ لَنَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا وَاللَّهِ لَا نَسْتَعْمِلُ مِنْكُمْ أَحَدًا عَلَى الصَّدَقَةِ فَقَالَ لَهُ رَبِيعَةُ هَذَا مِنْ أَمْرِكَ قَدْ نِلْتَ صِهْرَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ نَحْسُدْكَ عَلَيْهِ فَأَلْقَى عَلِيٌّ رِدَاءَهُ ثُمَّ اضْطَجَعَ عَلَيْهِ فَقَالَ أَنَا أَبُو حَسَنٍ الْقَرْمُ وَاللَّهِ لَا أَرِيمُ حَتَّى يَرْجِعَ إِلَيْكُمَا ابْنَايَ بِجَوَابِ مَا بَعَثْتُمَا بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَبْدُ الْمُطَّلِبِ فَانْطَلَقْتُ أَنَا وَالْفَضْلُ إِلَى بَابِ حُجْرَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نُوَافِقَ صَلَاةَ الظُّهْرِ قَدْ قَامَتْ فَصَلَّيْنَا مَعَ النَّاسِ ثُمَّ أَسْرَعْتُ أَنَا وَالْفَضْلُ إِلَى بَابِ حُجْرَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَوْمَئِذٍ عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ فَقُمْنَا بِالْبَابِ حَتَّى أَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ بِأُذُنِي وَأُذُنِ الْفَضْلِ ثُمَّ قَالَ أَخْرِجَا مَا تُصَرِّرَانِ ثُمَّ دَخَلَ فَأَذِنَ لِي وَلِلْفَضْلِ فَدَخَلْنَا فَتَوَاكَلْنَا الْكَلَامَ قَلِيلًا ثُمَّ كَلَّمْتُهُ أَوْ كَلَّمَهُ الْفَضْلُ قَدْ شَكَّ فِي ذَلِكَ عَبْدُ اللَّهِ قَالَ كَلَّمَهُ بِالْأَمْرِ الَّذِي أَمَرَنَا بِهِ أَبَوَانَا فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاعَةً وَرَفَعَ بَصَرَهُ قِبَلَ سَقْفِ الْبَيْتِ حَتَّى طَالَ عَلَيْنَا أَنَّهُ لَا يَرْجِعُ إِلَيْنَا شَيْئًا حَتَّى رَأَيْنَا زَيْنَبَ تَلْمَعُ مِنْ وَرَاءِ الْحِجَابِ بِيَدِهَا تُرِيدُ أَنْ لَا تَعْجَلَا وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَمْرِنَا ثُمَّ خَفَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ فَقَالَ لَنَا إِنَّ هَذِهِ الصَّدَقَةَ إِنَّمَا هِيَ أَوْسَاخُ النَّاسِ وَإِنَّهَا لَا تَحِلُّ لِمُحَمَّدٍ وَلَا لِآلِ مُحَمَّدٍ ادْعُوا لِي نَوْفَلَ بْنَ الْحَارِثِ فَدُعِيَ لَهُ نَوْفَلُ بْنُ الْحَارِثِ فَقَالَ يَا نَوْفَلُ أَنْكِحْ عَبْدَ الْمُطَّلِبِ فَأَنْكَحَنِي نَوْفَلٌ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْعُوا لِي مَحْمِئَةَ بْنَ جَزْءٍ وَهُوَ رَجُلٌ مِنْ بَنِي زُبَيْدٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَهُ عَلَى الْأَخْمَاسِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَحْمِئَةَ أَنْكِحْ الْفَضْلَ فَأَنْكَحَهُ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُمْ فَأَصْدِقْ عَنْهُمَا مِنْ الْخُمُسِ كَذَا وَكَذَا لَمْ يُسَمِّهِ لِي عَبْدُ اللَّهِ بْنُ الْحَارِثِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami ['Anbasah], telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab], telah mengabarkan kepadaku [Abdullah bin Al Harits Ibnu Naufal Al Hasyimi], bahwa [Abdul Muththalib bin Rabi'ah bin Al Harits bin Abdul Muththalib] telah mengabarkan kepadanya bahwa Ayahnya yaitu Rabi'ah bin Al Harits dan 'Abbas bin Abdul Muththalib mereka berdua berkata kepada Abdul Muththalib bin Rabi'ah dan Al Fadhl bin 'Abbas; datanglah kalian kepada Rasulullah shallallahu 'alaihi wasallam, dan katakan kepadanya; wahai Rasulullah, kami telah mencapai umur yang anda lihat, dan kami ingin menikah, sedangkan anda wahai Rasulullah, adalah orang yang paling baik dan orang yang paling sering menyambung hubungan kekerabatan, dan kedua orang tua kami tidak memiliki sesuatu yang dapat mereka berikan sebagai mahar untu kami, maka pekerjakan kami untuk mengurusi zakat, sehingga kami tunaikan kepadamu sebagaimana yang ditunaikan para pegawai, dan kami mendapatkan sebagian manfaat. Abdul Muththalib bin Rabi'ah berkata; kemudian Ali bin Abu Thalib datang sementara kami dalam keadaan seperti itu. Kemudian ia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah berkata: \"Tidak, demi Allah. Kami tidak akan mempekerjakan seorangpun diantara kalian untuk mengurusi zakat.\" Kemudian Rabi'ah berkata; ini urusanmu, engkau telah mendapatkan kemulian menjadi menantu Rasulullah shallallahu 'alaihi wasallam, maka kami tidak iri kepadamu. Kemudian Ali melemparkan selendangnya kemudian menindihnya, lalu berkata; aku adalah Abu Hasan wahai kaum! Aku tidak akan meninggalkannya hingga kedua anakku kembali kepada kalian dengan membawa jawaban apa yang kalian kirimkan kepada Nabi shallallahu 'alaihi wasallam. Abdul Muththalib berkata; kemudian aku dan Al Fadhl pergi menuju ke pintu kamar Nabi shallallahu 'alaihi wasallam hingga kami bertepatan shalat Zhuhur telah didirikan, kemudian kami melakukan shalat bersama orang-orang. Kemudian aku dan Al Fadhl cepat-cepat menuju ke pintu kamar Nabi shallallahu 'alaihi wasallam, dan pada saat itu beliau berada di Rumah Zainab binti Jahsy. Kemudian kami berdiri di depan pintu hingga Rasulullah shallallahu 'alaihi wasallam datang. Kemudian beliau menjewer telingaku dan telinga Al Fadhl. Kemudian beliau berkata: \"Keluarkan apa yang hendak kalian katakan!\" kemudian beliau masuk rumah dan mengizinkanku dan Al Fadhl untuk masuk. Lalu kami masuk kemudian tidak lama kami saling menyerahkan untuk berbicara, kemudian aku berbicara -atau Al Fadhl berbicara. Abdullah merasa ragu dalam hal tersebut- kepada beliau, ia berbicara kepada beliau mengenai perintah yang diberikan kedua ayah kami. Kemudian Rasulullah shallallahu 'alaihi wasallam terdiam sesaat, dan mengangkat pandangan beliau ke atap rumah, hingga kami menyangka bahwa beliau tidak memberikan jawaban sedikitpun kepada kami, kemudian kami melihat Zainab memberikan isyarat kepada kami dari balik hijab dengan tangannya, ia ingin agar kami tidak terburu-buru, dan Rasulullah shallallahu 'alaihi wasallam berada dalam urusan kami. Kemudian Rasulullah shallallahu 'alaihi wasallam merendahkan kepalanya dan berkata kepada kami: \"Sesungguhnya sedekah ini hanyalah kotoran orang-orang dan sesungguhnya sedekah tersebut tidak halal bagi Muhammad dan keluarga Muhammad. Panggilkan Naufal bin Al Harits!\" kemudian Naufal bin Al Harits dipanggil, lalu beliau berkata: \"Wahai Naufal, nikahkanlah Abdul Muththalib!\" Lalu Naufal menikahkanku. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Panggilkan Mahma-ah bin Juz`, \" dan ia adalah seorang laki-laki dari Bani Zubaid, dahulu Rasulullah shallallahu 'alaihi wasallam mempekerjakannya untuk mengurusi bagian seperlima. Kemduian Rasulullah shallallahu 'alaihi wasallam berkata kepada Mahmi-ah: \"Wahai Al Fadhl!\" Lalu ia menikahkannya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berdirilah, dan berilah mahar untuk keduanya dari bagian seperlima sekian dan sekian!\" Abdullah bin Al Harits tidak menyebutkan jumlah tersebut kepadaku. "},"2526":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي عَيَّاشُ بْنُ عُقْبَةَ الْحَضْرَمِيُّ عَنْ الْفَضْلِ بْنِ الْحَسَنِ الضَّمْرِيِّ أَنَّ أُمَّ الْحَكَمِ أَوْ ضُبَاعَةَ ابْنَتَيْ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِ حَدَّثَتْهُعَنْ إِحْدَاهُمَا أَنَّهَا قَالَتْ أَصَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْيًا فَذَهَبْتُ أَنَا وَأُخْتِي وَفَاطِمَةُ بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَوْنَا إِلَيْهِ مَا نَحْنُ فِيهِ وَسَأَلْنَاهُ أَنْ يَأْمُرَ لَنَا بِشَيْءٍ مِنْ السَّبْيِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَقَكُنَّ يَتَامَى بَدْرٍ لَكِنْ سَأَدُلُّكُنَّ عَلَى مَا هُوَ خَيْرٌ لَكُنَّ مِنْ ذَلِكَ تُكَبِّرْنَ اللَّهَ عَلَى إِثْرِ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ تَكْبِيرَةً وَثَلَاثًا وَثَلَاثِينَ تَسْبِيحَةً وَثَلَاثًا وَثَلَاثِينَ تَحْمِيدَةً وَلَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌقَالَ عَيَّاشٌ وَهُمَا ابْنَتَا عَمِّ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdullah bin Wahb], telah menceritakan kepadaku ['Ayyasy bin 'Uqbah Al Hadhrami], dari [Al Fadhl bin Al Hasan Adh Dhamri], bahwa [Ummu Al Hakam atau Dhuba'ah] dua anak wanita Az Zubair bin Abdul Muththalib telah menceritakan kepadanya dari salah seorang dari mereka berdua bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam telah mendapatkan tawanan perang, kemudian aku pergi bersama saudariku dan Fathimah binti Rasulullah shallallahu 'alaihi wasallam. Kemudian kami mengeluhkan kepada beliau apa yang kami alami, dan kami meminta beliau agar memerintahkan agar kami diberi sebagian tawanan tersebut. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian telah didahului anak-anak yatim Badr. Akan tetapi akan aku tunjukkan kepada kalian sesuatu yang lebih baik bagi kalian daripada hal tersebut. Kalian bertakbir kepada Allah setiap selesai sholat sebanyak tiga puluh tiga kali, bertasbih tiga puluh tiga kali, bertahmid tiga puluh tiga kali, dan LAA ILAAHA ILLALLAAHU WAHDAHU LAA SYARIIKALAH LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAI-IN QADIIR.\" 'Ayyasy berkata; mereka berdua adalah anak wanita paman Nabi shallallahu 'alaihi wasallam. "},"2527":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ يَعْنِي الْجُرَيرِيَّ عَنْ أَبِي الْوَرْدِ عَنْ ابْنِ أَعْبُدَ قَالَقَالَ لِي عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ أَلَا أُحَدِّثُكَ عَنِّي وَعَنْ فَاطِمَةَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ مِنْ أَحَبِّ أَهْلِهِ إِلَيْهِ قُلْتُ بَلَى قَالَ إِنَّهَا جَرَّتْ بِالرَّحَى حَتَّى أَثَّرَ فِي يَدِهَا وَاسْتَقَتْ بِالْقِرْبَةِ حَتَّى أَثَّرَ فِي نَحْرِهَا وَكَنَسَتْ الْبَيْتَ حَتَّى اغْبَرَّتْ ثِيَابُهَا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَدَمٌ فَقُلْتُ لَوْ أَتَيْتِ أَبَاكِ فَسَأَلْتِيهِ خَادِمًا فَأَتَتْهُ فَوَجَدَتْ عِنْدَهُ حُدَّاثًا فَرَجَعَتْ فَأَتَاهَا مِنْ الْغَدِ فَقَالَ مَا كَانَ حَاجَتُكِ فَسَكَتَتْ فَقُلْتُ أَنَا أُحَدِّثُكَ يَا رَسُولَ اللَّهِ جَرَّتْ بِالرَّحَى حَتَّى أَثَّرَتْ فِي يَدِهَا وَحَمَلَتْ بِالْقِرْبَةِ حَتَّى أَثَّرَتْ فِي نَحْرِهَا فَلَمَّا أَنْ جَاءَكَ الْخَدَمُ أَمَرْتُهَا أَنْ تَأْتِيَكَ فَتَسْتَخْدِمَكَ خَادِمًا يَقِيهَا حَرَّ مَا هِيَ فِيهِ قَالَ اتَّقِي اللَّهَ يَا فَاطِمَةُ وَأَدِّي فَرِيضَةَ رَبِّكِ وَاعْمَلِي عَمَلَ أَهْلِكِ فَإِذَا أَخَذْتِ مَضْجَعَكِ فَسَبِّحِي ثَلَاثًا وَثَلَاثِينَ وَاحْمَدِي ثَلَاثًا وَثَلَاثِينَ وَكَبِّرِي أَرْبَعًا وَثَلَاثِينَ فَتِلْكَ مِائَةٌ فَهِيَ خَيْرٌ لَكِ مِنْ خَادِمٍ قَالَتْ رَضِيتُ عَنْ اللَّهِ عَزَّ وَجَلَّ وَعَنْ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ بِهَذِهِ الْقِصَّةِ قَالَ وَلَمْ يُخْدِمْهَا","id":"Telah menceritakan kepada kami [Yahya bin Khalaf], telah menceritakan kepada kami [Abdul A'la] dari [Sa'id Al Jurairi], dari [Abu Al Ward], dari [Ibnu A'bud], ia berkata; [Ali radliallahu 'anhu] berkata kepadaku; maukah aku ceritakan kepadamu dariku dan Fathimah anak Rasulullah shallallahu 'alaihi wasallam? Ia termasuk keluarga yang paling beliau cintai. Aku katakan; ya. Ia berkata; sesungguhnya ia menarik alat untuk menyiram tanaman hingga membekas di tangannya, ia menyiram menggunakan geriba hingga membekas di lehernya, ia menyapu rumah hingga debu mengotori pakaiannya. Kemudian telah datang kepada Nabi shallallahu 'alaihi wasallam beberapa orang pembantu, lalu aku katakan; seandainya engkau datang kepada ayahmu dan meminta pembantu kepadanya maka hal tersebut adalah lebih baik. Kemudian ia mendapati di sisi beliau terdapat sekelompok orang yang sedang berbincang-bincang. Lalu ia kembali, kemudian keesokan hari beliau datang kepadanya dan berkata: \"Apakah keperluanmu?\" kemudian Fathimah terdiam, lalu aku katakan; aku akan menceritkan kepada anda wahai Rasulullah, ia menarik alat untuk menyirami tanaman hingga membekas pada tangannya, ia menggendong geriba hingga membekas pada lehernya. Kemudian tatkala terdapat beberapa orang pembantu kepada anda maka aku memerintahkannya agar datang kepada anda dan minta pembantu kepada anda yang akan melindungi panas yang ia alami. Beliau berkata: \"Bertakwalah engkau kepada Allah wahai Fathimah, dan tunaikanlah kewajiban Tuhanmu, dan laksanakanlah pekerjaan keluagamu. Kemudian apabila engkau bersiap untuk tidur maka bertasbihlah tiga puluh tiga kali, bertahmidlah tiga puluh tiga kali, dan bertakbirlah tiga puluh empat kali, sehingga berjumlah seratus. Maka hal tersebut lebih baik bagimu daripada seorang pembantu.\" Fathimah berkata; aku ridha kepada Allah dan rasulNya shallallahu 'alaihi wasallam. Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri], dari [Ali bin Husain], dengan kisah ini. ia berkata; dan beliau tidak memberikan pembantu kepadanya. "},"2528":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ الشَّعْبِيِّ قَالَكَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَهْمٌ يُدْعَى الصَّفِيَّ إِنْ شَاءَ عَبْدًا وَإِنْ شَاءَ أَمَةً وَإِنْ شَاءَ فَرَسًا يَخْتَارُهُ قَبْلَ الْخُمُسِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Mutharrif] dari ['Amir Asy Sya'bi], ia berkata; dahulu Nabi shallallahu 'alaihi wasallam memiliki saham yang disebut Shafi, apabila beliau menghendaki maka beliau mengambil budak laki-laki, dan apabila beliau menghendaki maka beliau mengambil budak perempuan dan apabila beliau menghendaki maka beliau mengambil kuda yang beliau pilih sebelum seperlima. "},"2529":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ وَأَزْهَرُ قَالَا حَدَّثَنَا ابْنُ عَوْنٍ قَالَ سَأَلْتُ مُحَمَّدًاعَنْ سَهْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّفِيِّ قَالَ كَانَ يُضْرَبُ لَهُ بِسَهْمٍ مَعَ الْمُسْلِمِينَ وَإِنْ لَمْ يَشْهَدْ وَالصَّفِيُّ يُؤْخَذُ لَهُ رَأْسٌ مِنْ الْخُمُسِ قَبْلَ كُلِّ شَيْءٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abu 'Ashim], dan [Azhar], mereka berkata; telah menceritakan kepada kami [Ibnu 'Aun] ia berkata; saya bertanya kepada [Muhammad] mengenai saham Nabi shallallahu 'alaihi wasallam serta shafi. Ia berkata; dahulu beliau diberi satu saham bersama orang-orang muslim walaupun beliau tidak menghadiri peperangan. Sedangkan shafi diambilkan untuk beliau pokok dari seperlima sebelum segala sesuatu. "},"2530":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ السُّلَمِيُّ حَدَّثَنَا عُمَرُ يَعْنِي ابْنَ عَبْدِ الْوَاحِدِ عَنْ سَعِيدٍ يَعْنِي ابْنَ بَشِيرٍ عَنْ قَتَادَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا غَزَا كَانَ لَهُ سَهْمٌ صَافٍ يَأْخُذُهُ مِنْ حَيْثُ شَاءَهُ فَكَانَتْ صَفِيَّةُ مِنْ ذَلِكَ السَّهْمِ وَكَانَ إِذَا لَمْ يَغْزُ بِنَفْسِهِ ضُرِبَ لَهُ بِسَهْمِهِ وَلَمْ يُخَيَّرْ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid As Sulami], telah menceritakan kepada kami [Umar bin Abdul Wahid], dari [Sa'id bin Basyir] dari [Qatadah], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila berperang maka baginya saham murni yang beliau ambil dari sisi manapun yang beliau kehendaki. Dan Shafiyyah adalah termasuk dari saham tersebut. Dan apabila beliau tidak berperang sendiri beliau diberi sahamnya dan tidak diberi pilihan. "},"2531":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أَحْمَدَ أَخْبَرَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَتْ صَفِيَّةُ مِنْ الصَّفِيِّ","id":"Telah menceritakan kepada kami [Nashr bin Ali], telah menceritakan kepada kami [Abu Ahmad], telah mengabarkan kepada kami [Sufyan] dari [Hisyam bin 'Urwah], dari [ayahnya], dari [Aisyah], ia berkata; Shafiyyah termasuk bagian khusus (untuk Rasulullah shallallahu 'alaihi wasallam). "},"2532":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ الزُّهْرِيُّ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَدِمْنَا خَيْبَرَ فَلَمَّا فَتَحَ اللَّهُ تَعَالَى الْحِصْنَ ذُكِرَ لَهُ جَمَالُ صَفِيَّةَ بِنْتِ حُيَيٍّ وَقَدْ قُتِلَ زَوْجُهَا وَكَانَتْ عَرُوسًا فَاصْطَفَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِنَفْسِهِ فَخَرَجَ بِهَا حَتَّى بَلَغْنَا سُدَّ الصَّهْبَاءِ حَلَّتْ فَبَنَى بِهَا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Ya'qub bin Abdurrahman Az Zuhri] dari ['Amr bin Abu 'Amr] dari [Anas bin Malik], ia berkata; kami datang ke Khaibar, kemudian tatkala Allah ta'ala telah menaklukkan benteng tersebut diceritakan kepada Rasulullah shallallahu 'alaihi wasallam kecantikan Shafiyyah binti Huyai, sementara suaminya telah terbunuh. Dan ia adalah seorang pengantin. Kemudian Rasulullah shallallahu 'alaihi wasallam memilihnya untuk dirinya, kemudian beliau keluar bersamanya hingga setelah kami sampai di Suddu Ash Shahba` Shafiyyah telah keluar dari 'iddah, kemudian beliau mencampurinya. "},"2533":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَارَتْ صَفِيَّةُ لِدِحْيَةَ الْكَلْبِيِّ ثُمَّ صَارَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Hammad bin Zaid] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik], ia berkata; Shafiyyah telah menjadi milik Dihyah Al Kalbi, kemudian menjadi milik Rasulullah shallallahu 'alaihi wasallam. "},"2534":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَوَقَعَ فِي سَهْمِ دِحْيَةَ جَارِيَةٌ جَمِيلَةٌ فَاشْتَرَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعَةِ أَرْؤُسٍ ثُمَّ دَفَعَهَا إِلَى أُمِّ سُلَيْمٍ تَصْنَعُهَا وَتُهَيِّئُهَا قَالَ حَمَّادٌ وَأَحْسَبُهُ قَالَ وَتَعْتَدُّ فِي بَيْتِهَا صَفِيَّةُ بِنْتُ حُيَيٍّ","id":"Telah menceritakan kepada kami [Muhammad bin Khallad Al Bahili], telah menceritakan kepada kami [Bahz bin Asad], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Tsabit], dari [Anas], ia berkata; telah jatuh di saham Dihyah seorang budak cantik, kemudian Rasulullah shallallahu 'alaihi wasallam membelinya dengan tujuh ar-us, kemudian beliau menyerahkannya kepada Ummu Sulaim, agar ia mempersiapkannya. Hammad berkata; dan aku yakin Anas berkata; dan Shafiyyah binti Huyai ber'iddah di rumahnya. "},"2535":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ مُعَاذٍ حَدَّثَنَا عَبْدُ الْوَارِثِ ح و حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الْمَعْنَى قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ قَالَجُمِعَ السَّبْيُ يَعْنِي بِخَيْبَرَ فَجَاءَ دِحْيَةُ فَقَالَ يَا رَسُولَ اللَّهِ أَعْطِنِي جَارِيَةً مِنْ السَّبْيِ قَالَ اذْهَبْ فَخُذْ جَارِيَةً فَأَخَذَ صَفِيَّةَ بِنْتَ حُيَيٍّ فَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ أَعْطَيْتَ دِحْيَةَ قَالَ يَعْقُوبُ صَفِيَّةَ بِنْتَ حُيَيٍّ سَيِّدَةَ قُرَيْظَةَ وَالنَّضِيرِ ثُمَّ اتَّفَقَا مَا تَصْلُحُ إِلَّا لَكَ قَالَ ادْعُوهُ بِهَا فَلَمَّا نَظَرَ إِلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْ��ِ وَسَلَّمَ قَالَ لَهُ خُذْ جَارِيَةً مِنْ السَّبْيِ غَيْرَهَا وَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَهَا وَتَزَوَّجَهَا","id":"Telah menceritakan kepada kami [Daud bin Mu'adz], telah menceritakan kepada kami [Abdul Warits]. Dan telah diriwayatkan dari jalur yang lain: telah menceritakan kepada kami [Ya'qub bin Ibrahim] secara makna, ia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Abdul 'Aziz bin Shuhaib] dari [Anas], ia berkata; para tawanan telah dikumpulkan di Khaibar, kemudian Dihyah datang dan berkata; wahai Rasulullah, berikan kepadaku seorang budak wanita dari tawanan tersebut. Beliau berkata; pergi dan ambillah seorang budak wanita. Kemudian ia mengambil Shafiyyah binti Huyai. Lalu terdapat seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Nabi Allah, anda telah memberi Dihyah -Ya'qub mengatakan; Shafiyyah binti Huyai seorang wanita pemimpin Quraizhah, dan Nadhir-. kemudian mereka berdua sama lafazhnya; tidaklah ia layak kecuali untukmu. Beliau berkata: \"Panggilkan dia dengan membawanya!\" kemudian tatkala Nabi shallallahu 'alaihi wasallam melihat kepada Shafiyyah beliau berkata: \"Ambillah budak dari tawanan tersebut selainnya!\" Dan sesungguhnya Nabi shallallahu 'alaihi wasallam membebaskan Shafiyyah dan menikahinya. "},"2536":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا قُرَّةُ قَالَ سَمِعْتُ يَزِيدَ بْنَ عَبْدِ اللَّهِ قَالَكُنَّا بِالْمِرْبَدِ فَجَاءَ رَجُلٌ أَشْعَثُ الرَّأْسِ بِيَدِهِ قِطْعَةُ أَدِيمٍ أَحْمَرَ فَقُلْنَا كَأَنَّكَ مِنْ أَهْلِ الْبَادِيَةِ فَقَالَ أَجَلْ قُلْنَا نَاوِلْنَا هَذِهِ الْقِطْعَةَ الْأَدِيمَ الَّتِي فِي يَدِكَ فَنَاوَلَنَاهَا فَقَرَأْنَاهَا فَإِذَا فِيهَا مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ إِلَى بَنِي زُهَيْرِ بْنِ أُقَيْشٍ إِنَّكُمْ إِنْ شَهِدْتُمْ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَأَقَمْتُمْ الصَّلَاةَ وَآتَيْتُمْ الزَّكَاةَ وَأَدَّيْتُمْ الْخُمُسَ مِنْ الْمَغْنَمِ وَسَهْمَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّفِيَّ أَنْتُمْ آمِنُونَ بِأَمَانِ اللَّهِ وَرَسُولِهِ فَقُلْنَا مَنْ كَتَبَ لَكَ هَذَا الْكِتَابَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Qurrah], ia berkata; saya mendengar [Yazid bin Abdullah], ia berkata; dahulu kami pernah berada di tempat penambatan unta, kemudian terdapat [seorang laki-laki] yang datang dalam keadaan berambut acak-acakan. Di tangannya terdapat selembar kulit merah, kemudian kami katakan; sepertinya engkau berasal dari pelosok. Kemudian ia berkata; benar. Kami katakan; berikan selembar kulit yang ada di tanganmu ini! Lalu ia memberikan kulit tersebut kepada kami dan kami membacanya. Ternyata isinya adalah: Dari Muhammad Rasulullah kepada Bani Zuhair bin Uqaisy. Sesungguhnya apabila kalian bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah dan Muhammad adalah Rasulullah, kalian tegakkan shalat dan kalian berikan zakat serta kalian tunaikan seperlima dari rampasan perang dan kalian berikan saham Nabi shallallahu 'alaihi wasallam yang khusus, maka kalian adalah aman dengan keamanan dari Allah dan rasulNya. Kemudian kami katakan; siapakah yang menulis surat ini untukmu? Ia berkata; Rasulullah shallallahu 'alaihi wasallam. "},"2537":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ أَنَّ الْحَكَمَ بْنَ نَافِعٍ حَدَّثَهُمْ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِوَكَانَ أَحَدَ الثَّلَاثَةِ الَّذِينَ تِيبَ عَلَيْهِمْ وَكَانَ كَعْبُ بْنُ الْأَشْرَفِ يَهْجُو النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُحَرِّضُ عَلَيْهِ كُفَّارَ قُرَيْشٍ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَدِمَ الْمَدِينَةَ وَأَهْلُهَا أَخْلَاطٌ مِنْهُمْ الْمُسْلِمُونَ وَالْمُشْرِكُونَ يَعْبُدُونَ الْأَوْثَانَ وَالْيَهُودُ وَكَانُوا يُؤْذُونَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ فَأَمَرَ اللَّهُ عَزَّ وَجَلَّ نَبِيَّهُ بِالصَّبْرِ وَالْعَفْوِ فَفِيهِمْ أَنْزَلَ اللَّهُ{ وَلَتَسْمَعُنَّ مِنْ الَّذِينَ أُوتُوا الْكِتَابَ مِنْ قَبْلِكُمْ }الْآيَةَ فَلَمَّا أَبَى كَعْبُ بْنُ الْأَشْرَفِ أَنْ يَنْزِعَ عَنْ أَذَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَعْدَ بْنَ مُعَاذٍ أَنْ يَبْعَثَ رَهْطًا يَقْتُلُونَهُ فَبَعَثَ مُحَمَّدَ بْنَ مَسْلَمَةَ وَذَكَرَ قِصَّةَ قَتْلِهِ فَلَمَّا قَتَلُوهُ فَزَعَتْ الْيَهُودُ وَالْمُشْرِكُونَ فَغَدَوْا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا طُرِقَ صَاحِبُنَا فَقُتِلَ فَذَكَرَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي كَانَ يَقُولُ وَدَعَاهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَنْ يَكْتُبَ بَيْنَهُ كِتَابًا يَنْتَهُونَ إِلَى مَا فِيهِ فَكَتَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُ وَبَيْنَهُمْ وَبَيْنَ الْمُسْلِمِينَ عَامَّةً صَحِيفَةً","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] bahwa [Al Hakam bin Nafi'] telah menceritakan kepada mereka, ia berkata; telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri], dari [Abdurrahman bin Abdullah bin Ka'b bin Malik], dari [ayahnya], dan ia adalah salah satu dari tiga orang yang mendapatkan taubat. Dan dahulu Ka'b bin Al Asyraf mencaci Nabi shallallahu 'alaihi wasallam dan mendorong orang-orang kafir Quraisy untuk menyerang beliau. Dan pada saat Nabi shallallahu 'alaihi wasallam datang ke Madinah, penduduknya adalah campur. Diantara mereka orang-orang muslim, orang-orang musyrik yang menyembah berhala serta orang-orang yahudi. Dan mereka menyakiti Nabi shallallahu 'alaihi wasallam serta para sahabatnya. Kemudian Allah 'azza wajalla memerintahkan NabiNya agar bersabar dan memaafkan. Dan Allah mengirimkan ayat mengenai mereka: \"Dan (juga) kamu sungguh-sungguh akan mendengar dari orang-orang yang diberi kitab sebelum kamu…\" kemudian tatkala Ka'b bin Al Asyraf enggan untuk menghentikan gangguannya kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam memerintahkan Sa'd bin Mu'adz agar mengirim beberapa orang yang akan membunuhnya. Kemudian ia mengutus Muhammad bin Maslamah. - dan ia menyebutkan kisah terbunuhnya Ka'b. kemudian tatkala mereka telah membunuhnya maka orang-orang yahudi dan musyrik kaget. Kemudian mereka mendatangi Nabi shallallahu 'alaihi wasallam dan berkata; sahabat kami telah diketuk kemudian dibunuh. Kemudian Nabi shallallahu 'alaihi wasallam menyebutkan kepada mereka sesuatu yang Ka'b ucapkan. Dan Nabi shallallahu 'alaihi wasallam mengajak mereka agar beliau menulis perjanjian yang mereka taati isinya. Nabi shallallahu 'alaihi wasallam menulis antara beliau, dan mereka serta orang-orang muslim sebuah perjanjian dalam kertas. "},"2538":{"ar":"حَدَّثَنَا مُصَرِّفُ بْنُ عَمْرٍو الْأَيَامِيُّ حَدَّثَنَا يُونُسُ يَعْنِي ابْنَ بُكَيْرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي مُحَمَّدٍ مَوْلَى زَيْدِ بْنِ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَعِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا أَصَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُرَيْشًا يَوْمَ بَدْرٍ وَقَدِمَ الْمَدِينَةَ جَمَعَ الْيَهُودَ فِي سُوقِ بَنِي قَيْنُقَاعَ فَقَالَ يَا مَعْشَرَ يَهُودَ أَسْلِمُوا قَبْلَ أَنْ يُصِيبَكُمْ مِثْلُ مَا أَصَابَ قُرَيْشًا قَالُوا يَا مُحَمَّدُ لَا يَغُرَّنَّكَ مِنْ نَفْسِكَ أَنَّكَ قَتَلْتَ نَفَرًا مِنْ قُرَيْشٍ كَانُوا أَغْمَارًا لَا يَعْرِفُونَ الْقِتَالَ إِنَّكَ لَوْ قَاتَلْتَنَا لَعَرَفْتَ أَنَّا نَحْنُ النَّاسُ وَأَنَّكَ لَمْ تَلْقَ مِثْلَنَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِي ذَلِكَ{ قُلْ لِلَّذِينَ كَفَرُوا سَتُغْلَبُونَ }قَرَأَ مُصَرِّفٌ إِلَى قَوْلِهِ{ فِئَةٌ تُقَاتِلُ فِي سَبِيلِ اللَّهِ }بِبَدْرٍ{ وَأُخْرَى كَافِرَةٌ }","id":"Telah menceritakan kepada kami [Musharrif bin 'Amr Al Ayami], telah menceritakan kepada kami [Yunus bin Bukair] ia berkata; telah menceritakan kepada kami [Muhammad bin Ishaq], telah menceritakan kepadaku [Muhammad bin Abu Muhammad] mantan budak Zaid bin Tsabit, dari [Sa'id bin Jubair], dan [Ikrimah], dari [Ibnu Abbas], ia berkata; tatkala Rasulullah shallallahu 'alaihi wasallam mengalahkah orang-orang Quraisy pada perang Badr, dan telah datang ke Madinah, beliau mengumpulkan orang-orang yahudi di pasar Bani Qainuqa' kemudian berkata; wahai orang-orang yahudi, masuklah Islam sebelum kalian tertimpa seperti apa yang menimpa orang-orang Quraisy. Mereka berkata; wahai Muhammad. Janganlah engkau berbangga diri terhadapmu karena engkau telah mampu membunuh beberapa orang Quraisy. Mereka adalah orang-orang yang tidak berpengalaman, mereka tidak pandai berperang. Sesungguhnya apabila engkau memerangi kami maka sungguh engkau akan mengerti bahwa kami adalah orang-orang yang menang dan engkau belum pernah bertemu dengan orang seperti kami. Kemudian Allah 'azza wajalla menurunkan ayat mengenai hal tersebut: \"Katakanlah kepada orang-orang yang kafir: \"Kamu pasti akan dikalahkan (di dunia ini)..\" Musharrif membaca hingga firmanNya: \"Segolongan berperang di jalan Allah dan (segolongan) yang lain kafir.\""},"2539":{"ar":"حَدَّثَنَا مُصَرِّفُ بْنُ عَمْرٍو حَدَّثَنَا يُونُسُ قَالَ ابْنُ إِسْحَقَ حَدَّثَنِي مَوْلًى لِزَيْدِ بْنِ ثَابِتٍ حَدَّثَتْنِي ابْنَةُ مُحَيْصَةَ عَنْ أَبِيهَا مُحَيْصَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ظَفِرْتُمْ بِهِ مِنْ رِجَالِ يَهُودَ فَاقْتُلُوهُ فَوَثَبَ مُحَيْصَةُ عَلَى شَبِيبَةَ رَجُلٍ مِنْ تُجَّارِ يَهُودَ كَانَ يُلَابِسُهُمْ فَقَتَلَهُ وَكَانَ حُوَيْصَةُ إِذْ ذَاكَ لَمْ يُسْلِمْ وَكَانَ أَسَنَّ مِنْ مُحَيْصَةَ فَلَمَّا قَتَلَهُ جَعَلَ حُوَيْصَةُ يَضْرِبُهُ وَيَقُولُ يَا عَدُوَّ اللَّهِ أَمَا وَاللَّهِ لَرُبَّ شَحْمٍ فِي بَطْنِكَ مِنْ مَالِهِ","id":"Telah menceritakan kepada kami [Musharrif bin 'Amr], telah menceritakan kepada kami [Yunus], [Ibnu Ishaq] berkata; telah menceritakan kepadaku [mantan budak Zaid bin Tsabit], telah menceritakan kepadaku [Anak wanita Muhaishah] dari [ayahnya yaitu Muhaishah], bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Barang siapa yang kalian tangkap dari laki-laki Yahudi maka bunuhlah!\" kemudian Muhaishah melompat kepada Syabibah seorang laki-laki diantara pedagang yahudi, dahulu ia pernah menyamarkan hidup bersama dengan mereka, kemudian ia membunuhnya. Dan pada saat itu Huwaishah belum masuk Islam. Dan ia lebih tua daripada Muhaishah, tatkata ia telah membunuhnya kemudian Huwaishah memukulnya dan mengatakan; wahai musuh Allah, ketahuilah demi Allah, sungguh betapa banyak lemak yang ada pada perutmu yang berasal dari hartanya. "},"2540":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ أَخْبَرَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَبَيْنَا نَحْنُ فِي الْمَسْجِدِ إِذْ خَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْطَلِقُوا إِلَى يَهُودَ فَخَرَجْنَا مَعَهُ حَتَّى جِئْنَاهُمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَاهُمْ فَقَالَ يَا مَعْشَرَ يَهُودَ أَسْلِمُوا تَسْلَمُوا فَقَالُوا قَدْ بَلَّغْتَ يَا أَبَا الْقَاسِمِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلِمُوا تَسْلَمُوا فَقَالُوا قَدْ بَلَّغْتَ يَا أَبَا الْقَاسِمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ أُرِيدُ ثُمَّ قَالَهَا الثَّالِثَةَ اعْلَمُوا أَنَّمَا الْأَرْضُ لِلَّهِ وَرَسُولِهِ وَإِنِّي أُرِيدُ أَنْ أُجْلِيَكُمْ مِنْ هَذِهِ الْأَرْضِ فَمَنْ وَجَدَ مِنْكُمْ بِمَالِهِ شَيْئًا فَلْيَبِعْهُ وَإِلَّا فَاعْلَمُوا أَنَّمَا الْأَرْضُ لِلَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah mengabarkan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id], dari [ayahnya], dari [Abu Hurairah] bahwa ia berkata; ketika kami berada di Masjid, tiba-tiba Rasulullah shallallahu 'alaihi wasallam keluar menuju kepada kami kemudian berkata: \"Pergilah kalian kepada orang-orang yahudi!\" kemudian kami keluar bersama beliau hingga kami mendatangi mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri dan menyeru mereka. Beliau berkata: \"Wahai orang-orang yahudi, masuk Islamlah kalian maka kalian akan selamat.\" Mereka berkata; sungguh engkau telah menyampaikan wahai Abu Al Qasim. Kemudian beliau berkata kepada mereka: \"Masuklah Islam maka kalian akan selamat!\" Mereka berkata; sungguh engkau telah menyampaikan wahai Abu Al Qasim. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"itulah yang aku inginkan.\" Kemudian beliau mengucapkannya ketiga kalinya, dan berkata: \"Ketahuilah bahwa bumi adalah milik Allah dan RasulNya, dan aku ingin mengusir kalian dari negeri ini. Maka barang siapa diantara kalian mendapati sebagian dari hartanya maka hendaknya ia menjualnya, jika tidak maka ketahuilah bahwa bumi adalah milik Allah dan RasulNya shallallahu 'alaihi wasallam.\""},"2541":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ كُفَّارَ قُرَيْشٍ كَتَبُوا إِلَى ابْنِ أُبَيٍّ وَمَنْ كَانَ يَعْبُدُ مَعَهُ الْأَوْثَانَ مِنْ الْأَوْسِ وَالْخَزْرَجِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ بِالْمَدِينَةِ قَبْلَ وَقْعَةِ بَدْرٍ إِنَّكُمْ آوَيْتُمْ صَاحِبَنَا وَإِنَّا نُقْسِمُ بِاللَّهِ لَتُقَاتِلُنَّهُ أَوْ لَتُخْرِجُنَّهُ أَوْ لَنَسِيرَنَّ إِلَيْكُمْ بِأَجْمَعِنَا حَتَّى نَقْتُلَ مُقَاتِلَتَكُمْ وَنَسْتَبِيحَ نِسَاءَكُمْ فَلَمَّا بَلَغَ ذَلِكَ عَبْدَ اللَّهِ بْنَ أُبَيٍّ وَمَنْ كَانَ مَعَهُ مِنْ عَبَدَةِ الْأَوْثَانِ اجْتَمَعُوا لِقِتَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا بَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِيَهُمْ فَقَالَ لَقَدْ بَلَغَ وَعِيدُ قُرَيْشٍ مِنْكُمْ الْمَبَالِغَ مَا كَانَتْ تَكِيدُكُمْ بِأَكْثَرَ مِمَّا تُرِيدُونَ أَنْ تَكِيدُوا بِهِ أَنْفُسَكُمْ تُرِيدُونَ أَنْ تُقَاتِلُوا أَبْنَاءَكُمْ وَإِخْوَ��نَكُمْ فَلَمَّا سَمِعُوا ذَلِكَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَفَرَّقُوا فَبَلَغَ ذَلِكَ كُفَّارَ قُرَيْشٍ فَكَتَبَتْ كُفَّارُ قُرَيْشٍ بَعْدَ وَقْعَةِ بَدْرٍ إِلَى الْيَهُودِ إِنَّكُمْ أَهْلُ الْحَلْقَةِ وَالْحُصُونِ وَإِنَّكُمْ لَتُقَاتِلُنَّ صَاحِبَنَا أَوْ لَنَفْعَلَنَّ كَذَا وَكَذَا وَلَا يَحُولُ بَيْنَنَا وَبَيْنَ خَدَمِ نِسَائِكُمْ شَيْءٌ وَهِيَ الْخَلَاخِيلُ فَلَمَّا بَلَغَ كِتَابُهُمْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْمَعَتْ بَنُو النَّضِيرِ بِالْغَدْرِ فَأَرْسَلُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْرُجْ إِلَيْنَا فِي ثَلَاثِينَ رَجُلًا مِنْ أَصْحَابِكَ وَلْيَخْرُجْ مِنَّا ثَلَاثُونَ حَبْرًا حَتَّى نَلْتَقِيَ بِمَكَانِ الْمَنْصَفِ فَيَسْمَعُوا مِنْكَ فَإِنْ صَدَّقُوكَ وَآمَنُوا بِكَ آمَنَّا بِكَ فَقَصَّ خَبَرَهُمْ فَلَمَّا كَانَ الْغَدُ غَدَا عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْكَتَائِبِ فَحَصَرَهُمْ فَقَالَ لَهُمْ إِنَّكُمْ وَاللَّهِ لَا تَأْمَنُونَ عِنْدِي إِلَّا بِعَهْدٍ تُعَاهِدُونِي عَلَيْهِ فَأَبَوْا أَنْ يُعْطُوهُ عَهْدًا فَقَاتَلَهُمْ يَوْمَهُمْ ذَلِكَ ثُمَّ غَدَا الْغَدُ عَلَى بَنِي قُرَيْظَةَ بِالْكَتَائِبِ وَتَرَكَ بَنِي النَّضِيرِ وَدَعَاهُمْ إِلَى أَنْ يُعَاهِدُوهُ فَعَاهَدُوهُ فَانْصَرَفَ عَنْهُمْ وَغَدَا عَلَى بَنِي النَّضِيرِ بِالْكَتَائِبِ فَقَاتَلَهُمْ حَتَّى نَزَلُوا عَلَى الْجَلَاءِ فَجَلَتْ بَنُو النَّضِيرِ وَاحْتَمَلُوا مَا أَقَلَّتْ الْإِبِلُ مِنْ أَمْتِعَتِهِمْ وَأَبْوَابِ بُيُوتِهِمْ وَخَشَبِهَا فَكَانَ نَخْلُ بَنِي النَّضِيرِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاصَّةً أَعْطَاهُ اللَّهُ إِيَّاهَا وَخَصَّهُ بِهَا فَقَالَ{ وَمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ }يَقُولُ بِغَيْرِ قِتَالٍ فَأَعْطَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَهَا لِلْمُهَاجِرِينَ وَقَسَمَهَا بَيْنَهُمْ وَقَسَمَ مِنْهَا لِرَجُلَيْنِ مِنْ الْأَنْصَارِ وَكَانَا ذَوِي حَاجَةٍ لَمْ يَقْسِمْ لِأَحَدٍ مِنْ الْأَنْصَارِ غَيْرِهِمَا وَبَقِيَ مِنْهَا صَدَقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي فِي أَيْدِي بَنِي فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Daud bin Sufyan], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar], dari [Az Zuhri] dari [Abdurrahman bin Ka'b bin Malik], dari [seorang sahabat Nabi shallallahu 'alaihi wasallam], bahwa orang-orang kafir Quraisy telah menulis surat kepada Ubay dan orang-orang yang menyembah berhala bersamanya dari kalangan Aus serta Khazraj. Sementara pada saat itu Rasulullah shallallahu 'alaihi wasallam berada di Madinah sebelum terjadi perang Badr: sesungguhnya kalian telah melindungi sahabat kami, dan kami bersumpah dengan nama Allah, sungguh kalian memeranginya atau kalian mengeluarkannya atau kami akan menuju kepada kalian dengan seluruh kami hingga kami bunuh orang yang berperang diantara kalian dan kami akan menawan wanita-wanita kalian. Kemudian tatkala hal tersebut sampai kepada Abdullah bin Ubai dan orang-orang yang bersamanya dari kalangan para penyembah berhala, mereka berkumpul untuk memerangi Nabi shallallahu 'alaihi wasallam. Kemudian tatkala hal tersebut sampai kepada Nabi shallallahu 'alaihi wasallam maka beliau menemuai mereka dan berkata: \"Sungguh ancaman orang-orang Quraisy kepada kalain telah sampai pada tempat yang belum pernah menipu kalian melebihi apa yang kalian inginkan untuk menipu diri kalian sendiri. Kalian hendak memerangi anak-anak kalian serta saudara-saudara kalian.\" Kemudian tatkala mereka mendengar hal tersebut dari Nabi shallallahu 'alaihi wasallam mereka bubar. Kemudian hal tersebut sampai kepada orang-orang kafir Quraisy, lalu orang-orang Kafir Quraisy setelah perang Badr menulis surat kepada orang-orang yahudi: sesungguhnya kalian adalah para pemilik senjata dan benteng, sesungguhnya kalian akan memerangi sahabat kami atau kami akan melakukan demikian dan demikian dan tidak ada sesuatupun yang menghalangi antara kami dan khadam wanita-wanita kalian -yaitu gelang kaki mereka. Kemudian tatkala surat mereka telah sampai kepada Nabi shallallahu 'alaihi wasallam Bani Nadhir bertekat untuk berkhianat, kemudian mereka mengirimkan utusan kepada Rasulullah shallallahu 'alaihi wasallam, mereka mengatakan; keluarlah kepada kami bersama tiga puluh orang diantara para sahabatmu dan diantara kami akan keluar tiga puluh ulama hingga kita bertemu di tempat pertengahan, kemudian mereka mendengar darimu. Seandainya mereka membenarkanmu dan beriman kepadamu maka kami akan beriman. Kemudian beliau menceritakan berita mereka. Kemudian pada keesokan hari beliau pergi kepada mereka dengan beberapa pasukan, kemudian beliau mengepung mereka dan berkata kepada mereka: \"Sesungguhnya kalian demi Allah, tidak akan aman di sisiku kecuali dengan perjanjian yang kalian berikan kepadaku.\" Kemudian mereka menolak untuk memberikan perjanjian kepada beliau. Maka beliau memerangi mereka pada hari itu. kemudian keesokannya beliau pergi kepada Bani Quraizhah dengan beberapa pasukan dan membiarkan Bani Nazhir, dan beliau menyeru mereka agar memberikan perjanjian kepada beliau, kemudian mereka memberikan perjanjian kepadanya. Kemudian beliau pergi dari mereka dan menuju kepada Bani Nadhir dengan beberapa pasukan kemudian memerangi mereka hingga keluar dari negeri, maka mereka keluar dan membawa apa yang mampu dibawa unta berupa barang-barang dan pintu rumah mereka serta kayunya. Pohon kurma Bani Nadhir adalah khusus untuk Rasulullah shallallahu 'alaihi wasallam, Allah memberikan dan mengkhususkannya kepada beliau. Allah berfirman: \"Dan apa saja harta rampasan (fai`) yang diberikan Allah kepada RasulNya (dari harta benda) mereka, maka untuk mendapatkan itu kamu tidak mengerahkan seekor kudapun dan (tidak pula) seekor untapun.\" Yaitu tanpa peperangan, kemudian Nabi memberikan sebagian besar kepada orang-orang muhajirin dan membagikan diantara mereka serta kepada dua orang anshar membutuhkan, beliau tidak membagikan kepada seorangpun dari kalangan anshar selain mereka berdua. Dan tersisa darinya sedekah Rasulullah shallallahu 'alaihi wasallam yang ada di tangan anak-anak Fathimah radliallahu 'anha. "},"2542":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ يَهُودَ النَّضِيرِ وَقُرَيْظَةَ حَارَبُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَجْلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنِي النَّضِيرِ وَأَقَرَّ قُرَيْظَةَ وَمَنَّ عَلَيْهِمْ حَتَّى حَارَبَتْ قُرَيْظَةُ بَعْدَ ذَلِكَ فَقَتَلَ رِجَالَهُمْ وَقَسَمَ نِسَاءَهُمْ وَأَوْلَادَهُمْ وَأَمْوَالَهُمْ بَيْنَ الْمُسْلِمِينَ إِلَّا بَعْضَهُمْ لَحِقُوا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَّنَهُمْ وَأَسْلَمُوا وَأَجْلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَهُودَ الْمَدِينَةِ كُلَّهُمْ بَنِي قَيْنُقَاعَ وَهُمْ قَوْمُ عَبْدِ اللَّهِ بْنِ سَلَامٍ وَيَهُودَ بَنِي حَارِثَةَ وَكُلَّ يَهُودِيٍّ كَانَ بِالْمَدِينَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar], bahwa orang-orang yahudi Bani Nadhir dan Quraizhah memerangi Rasulullah shallallahu 'alaihi wasallam, kemudian beliau mengusir Bani Nadhir dan membiarkan Quraizhah dan memberikan kebebasan kepada mereka hingga orang-orang Bani Quraizhah setelah itu memerangi beliau. Maka beliau membunuh laki-laki mereka dan membagikan para wanita dan anak-anak mereka serta harta mereka diantara orang-orang muslim, kecuali sebagiannya kembali kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau memberikan kebebasan kepada mereka hingga mereka masuk Islam. Dan Rasulullah shallallahu 'alaihi wasallam mengusir orang-orang seluruh orang yahudi Bani Qainuqa' dari Madinah. Mereka adalah kaumnya Abdullah bin Salam, dan yahudi Bani Haritsah serta seluruh orang yahudi di Manidah. "},"2543":{"ar":"حَدَّثَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ حَدَّثَنَا أَبِي حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ أَحْسَبُهُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاتَلَ أَهْلَ خَيْبَرَ فَغَلَبَ عَلَى النَّخْلِ وَالْأَرْضِ وَأَلْجَأَهُمْ إِلَى قَصْرِهِمْ فَصَالَحُوهُ عَلَى أَنَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّفْرَاءَ وَالْبَيْضَاءَ وَالْحَلْقَةَ وَلَهُمْ مَا حَمَلَتْ رِكَابُهُمْ عَلَى أَنْ لَا يَكْتُمُوا وَلَا يُغَيِّبُوا شَيْئًا فَإِنْ فَعَلُوا فَلَا ذِمَّةَ لَهُمْ وَلَا عَهْدَ فَغَيَّبُوا مَسْكًا لِحُيَيِّ بْنِ أَخْطَبَ وَقَدْ كَانَ قُتِلَ قَبْلَ خَيْبَرَ كَانَ احْتَمَلَهُ مَعَهُ يَوْمَ بَنِي النَّضِيرِ حِينَ أُجْلِيَتْ النَّضِيرُ فِيهِ حُلِيُّهُمْ قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِسَعْيَةَ أَيْنَ مَسْكُ حُيَيِّ بْنِ أَخْطَبَ قَالَ أَذْهَبَتْهُ الْحُرُوبُ وَالنَّفَقَاتُ فَوَجَدُوا الْمَسْكَ فَقَتَلَ ابْنَ أَبِي الْحُقَيْقِ وَسَبَى نِسَاءَهُمْ وَذَرَارِيَّهُمْ وَأَرَادَ أَنْ يُجْلِيَهُمْ فَقَالُوا يَا مُحَمَّدُ دَعْنَا نَعْمَلْ فِي هَذِهِ الْأَرْضِ وَلَنَا الشَّطْرُ مَا بَدَا لَكَ وَلَكُمْ الشَّطْرُ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِي كُلَّ امْرَأَةٍ مِنْ نِسَائِهِ ثَمَانِينَ وَسْقًا مِنْ تَمْرٍ وَعِشْرِينَ وَسْقًا مِنْ شَعِيرٍ","id":"Telah menceritakan kepada kami [Harun bin Zaid bin Abu Az Zarqa`], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Hammad bin Salamah], dari ['Ubaidullah bin Umar], ia berkata; -saya kira berasal dari [Nafi'] - dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam memerangi Khaibar dan menguasai pohon kurma serta lahan mereka dan memaksa mereka berlindung di benteng mereka. Kemudian mereka mengadakan perjanjian damai dengan beliau dengan syarat bahwa untuk Rasulullah shallallahu 'alaihi wasallam emas dan perak serta senjata, dan bagi mereka apa yang dapat dimuat unta mereka dengan syarat mereka tidak menyembunyikan sesuatu. Apabila mereka melakukan hal tersebut maka tidak ada jaminan dan perjanjian bagi mereka. Kemudian mereka menyembunyikan sebuah kulit milik Huyai bin Akhthab yang telah terbunuh sebelum Khaibar. Ia membawanya pada saat perang Bani Nadhir ketika Bani Nadhir terusir. Di dalam kulit tersebut terdapat perhiasan mereka. Kemudian Nabi shallallahu 'alaihi wasallam berkata kepada Sa'yah: \"Dimanakah kulit Huyai bin Akhthab?\" Perang dan nafkah telah menghabiskannya. Kemudian mereka mendapatkan kulit tersebut. Kemudian beliau membunuh Ibnu Abu Abu Al Haqiq dan menawan para wanita serta anak-anak mereka, dan beliau berniat untuk mengusir mereka. Kemudian mereka berkata; wahai Muhammad! Biarkan kami bekerja di lahan ini, dan kami mendapatkan setengahnya terserah engkau, dan kalian mendapatkan setengah. Dan Rasulullah shallallahu 'alaihi wasallam memberikan setiap isterinya delapan puluh wasaq kurma dan dua puluh wasaq gandum. "},"2544":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي نَافِعٌ مَوْلَى عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ عُمَرَ قَالَأَيُّهَا النَّاسُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عَامَلَ يَهُودَ خَيْبَرَ عَلَى أَنَّا نُخْرِجُهُمْ إِذَا شِئْنَا فَمَنْ كَانَ لَهُ مَالٌ فَلْيَلْحَقْ بِهِ فَإِنِّي مُخْرِجٌ يَهُودَ فَأَخْرَجَهُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Ya'qub bin Ibrahim], telah menceritakan kepada kami [ayahku], dari [Ibnu Ishaq], telah menceritakan kepadaku [Nafi'] mantan budak Abdullah bin Umar, dari [Abdullah bin Umar], bahwa [Umar] berkata; wahai manusia, sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah mempekerjakan orang-orang Yahudi Khaibar dengan syarat kita dapat mengeluarkan mereka apabila kami menghendaki. Barang siapa yang memiliki harta maka hendaknya ia mengambilnya karena sesungguhnya aku akan mengeluarkan orang-orang Yahudi. Kemudian Umar mengeluarkan mereka. "},"2545":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ مُعَاذٍ حَدَّثَنَا عَبْدُ الْوَارِثِ ح و حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ وَزِيَادُ بْنُ أَيُّوبَ أَنَّ إِسْمَعِيلَ بْنَ إِبْرَاهِيمَ حَدَّثَهُمْ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا خَيْبَرَ فَأَصَبْنَاهَا عَنْوَةً فَجُمِعَ السَّبْيُ","id":"Telah menceritakan kepada kami [Daud bin Mu'adz], telah menceritakan kepada kami [Abdul Warits]. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ya'qub bin Ibrahim], dan [Ziyad bin Ayyub], bahwa [Isma'il bin Ibrahim] telah menceritakan kepada mereka dari [Abdul Aziz bin Shuhaib], dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam memerangi Khaibar dan mendapatkannya dengan kekerasan, kemudian dikumpulkan tawanannya. "},"2546":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ الْمُؤَذِّنُ حَدَّثَنَا أَسَدُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا حَدَّثَنِي سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ نِصْفَيْنِ نِصْفًا لِنَوَائِبِهِ وَحَاجَتِهِ وَنِصْفًا بَيْنَ الْمُسْلِمِينَ قَسَمَهَا بَيْنَهُمْ عَلَى ثَمَانِيَةَ عَشَرَ سَهْمًاحَدَّثَنَا حُسَيْنُ بْنُ عَلِيِّ بْنِ الْأَسْوَدِ أَنَّ يَحْيَى بْنَ آدَمَ حَدَّثَهُمْ عَنْ أَبِي شِهَابٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ أَنَّهُ سَمِعَ نَفَرًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا فَذَكَرَ هَذَا الْحَدِيثَ قَالَ فَكَانَ النِّصْفُ سِهَامَ الْمُسْلِمِينَ وَسَهْمَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَزَلَ النِّصْفَ لِلْمُسْلِمِينَ لِمَا يَنُوبُهُ مِنْ الْأُمُورِ وَالنَّوَائِبِ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Sulaiman Al Muadzdzin], telah menceritakan kepada kami [Asad bin Musa], telah menceritakan kepada kami [Yahya bin Zakariya], telah menceritakan kepadaku [Sufyan] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah membagi Khaibar menjadi dua bagian, setengah bagian untuk musibah-musibah yang kemungkinan menimpa, dan kebutuhan beliau dan setengah bagian dibagikan diantara orang-orang muslim yang beliau bagikan diantara mereka dengan delapan belas saham. Telah menceritakan kepada kami [Husain bin Ali bin Al Aswad] bahwa [Yahya bin Adam] telah menceritakan kepada mereka dari [Ibnu Syihab] dari [Yahya bin Sa'id], dari [Busyair bin Yasar], bahwa ia telah mendengar [beberapa orang] sahabat Nabi shallallahu 'alaihi wasallam berkata; …. Kemudian ia menyebutkan hadits tersebut. Ia berkata; setengah bagian adalah saham orang-orang muslim dan saham Rasulullah shallallahu 'alaihi wasallam. Dan beliau mememisahkannya untuk orang-orang muslimin untuk perkara-perkara yang kemungkinan menimpa mereka. "},"2547":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا أَبُو خَالِدٍ يَعْنِي سُلَيْمَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ قَالَلَمَّا أَفَاءَ اللَّهُ عَلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ قَسَمَهَا عَلَى سِتَّةٍ وَثَلَاثِينَ سَهْمًا جَمَعَ كُلُّ سَهْمٍ مِائَةَ سَهْمٍ فَعَزَلَ نِصْفَهَا لِنَوَائِبِهِ وَمَا يَنْزِلُ بِهِ الْوَطِيحَةَ وَالْكُتَيْبَةَ وَمَا أُحِيزَ مَعَهُمَا وَعَزَلَ النِّصْفَ الْآخَرَ فَقَسَمَهُ بَيْنَ الْمُسْلِمِينَ الشِّقَّ وَالنَّطَاةَ وَمَا أُحِيزَ مَعَهُمَا وَكَانَ سَهْمُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا أُحِيزَ مَعَهُمَا","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi], telah menceritakan kepada kami [Abu Khalid yaitu Sulaiman] dari [Yahya bin Sa'id] dari [Busyair bin Yasar], ia berkata; tatkala Allah telah memberikan fai` kepada NabiNya shallallahu 'alaihi wasallam yang berupa Khaibar, maka beliau membaginya menjadi tiga puluh enam saham, setiap saham menghimpun seratus saham. Dan beliau memisahkan setengahnya untuk musibah yang kemungkinan menimpa apa yang terjadi padanya. Setengah bagian tersebut adalah Benteng Wathihah, serta Desa Kutaibah, dan yang tergabung bersama keduanya. Dan beliau memisahkan setengahnya yang lain, beliau membaginya diantara orang-orang muslimin daerah Syiqq dan Nathah dan yang tergabung bersama keduanya. Dan saham Rasulullah shallallahu 'alaihi wasallam adalah pada bagian yang tergabung bersama keduanya. "},"2548":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِسْكِينٍ الْيَمَامِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا أَفَاءَ اللَّهُ عَلَيْهِ خَيْبَرَ قَسَمَهَا سِتَّةً وَثَلَاثِينَ سَهْمًا جَمْعُ فَعَزَلَ لِلْمُسْلِمِينَ الشَّطْرَ ثَمَانِيَةَ عَشَرَ سَهْمًا يَجْمَعُ كُلُّ سَهْمٍ مِائَةً النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُمْ لَهُ سَهْمٌ كَسَهْمِ أَحَدِهِمْ وَعَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِيَةَ عَشَرَ سَهْمًا وَهُوَ الشَّطْرُ لِنَوَائِبِهِ وَمَا يَنْزِلُ بِهِ مِنْ أَمْرِ الْمُسْلِمِينَ فَكَانَ ذَلِكَ الْوَطِيحَ وَالْكُتَيْبَةَ وَالسَّلَالِمَ وَتَوَابِعَهَا فَلَمَّا صَارَتْ الْأَمْوَالُ بِيَدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمِينَ لَمْ يَكُنْ لَهُمْ عُمَّالٌ يَكْفُونَهُمْ عَمَلَهَا فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَهُودَ فَعَامَلَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Miskin Al Yamami], telah menceritakan kepada kami [Yahya bin Hassan], telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] bahwa Rasulullah shallallahu 'alaihi wasallam tatkala Allah memberikan fa` yang berupa Khaibar kepadanya beliau membaginya menjadi tiga puluh enam saham. Kemudian beliau memisahkan setengah yaitu delapan belas saham untuk orang-orang muslim, setiap saham menghimpun seratus saham. Nabi shallallahu 'alaihi wasallam bersama mereka, beliau mendapatkan saham seperti saham salah seorang diantara mereka. Dan Rasulullah shallallahu 'alaihi wasallam memisahkan delapan belas saham yang merukan setengah bagian untuk musibah-musibah yang kemungkinan menimpa dan urusan muslimin yang terjadi. Setengah bagian tersebut adalah benteng Wathih, daerah Kutaibah, Salalim dan yang mengikutinya. Kemudian tatkala harta tersebut telah berada di tangan Nabi shallallahu 'alaihi wasallam dan muslimin, mereka tidak memiliki pekerja yang mengerjakan pekerjaannya untuk mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam memanggil orang-orang yahudi dan mempekerjakan mereka. "},"2549":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُجَمِّعُ بْنُ يَعْقُوبَ بْنِ مُجَمِّعِ بْنِ يَزِيدَ الْأَنْصَارِيُّ قَالَ سَمِعْتُ أَبِي يَعْقُوبَ بْنَ مُجَمِّعٍ يَذْكُرُ لِي عَنْ عَمِّهِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ الْأَنْصَارِيِّ عَنْ عَمِّهِ مُجَمِّعِ بْنِ جَارِيَةَ الْأَنْصَارِيِّ وَكَانَ أَحَدَ الْقُرَّاءِ الَّذِينَ قَرَءُوا الْقُرْآنَ قَالَقُسِمَتْ خَيْبَرُ عَلَى أَهْلِ الْحُدَيْبِيَةِ فَقَسَمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ثَمَانِيَةَ عَشَرَ سَهْمًا وَكَانَ الْجَيْشُ أَلْفًا وَخَمْسَ مِائَةٍ فِيهِمْ ثَلَاثُ مِائَةِ فَارِسٍ فَأَعْطَى الْفَارِسَ سَهْمَيْنِ وَأَعْطَى الرَّاجِلَ سَهْمًا","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Mujammi' bin Ya'qub bin Mujammi' bin Yazid? Al Anshari], ia berkata; saya mendengar ayahku [Ya'qub bin Mujammi'] menceritakan kepadanya mengenai [pamannya yaitu Abdurrahman bin Yazid? Al Anshari], dari [pamannya yaitu Mujammi' bin Jariyah Al Anshari], dan ia adalah salah satu ahli penghafal Al Qur'an yang telah hafal Al Qur'an. Ia berkata; Khaibar dibagi kepada orang-orang yang menyaksikan perjanjian Hudaibiyah. Rasulullah shallallahu 'alaihi wasallam membaginya menjadi delapan belas saham. Dan pasukan tersebut berjumalah seribu lima ratus, diantara mereka terdapat tiga ratus tiga penunggang kuda, beliau memberikan dua saham kepada penunggang kuda dan memberikan satu saham kepada pasukan yang berjalan kaki. "},"2550":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ عَنْ جُوَيْرِيَةَ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَنَّ سَعِيدَ بْنَ الْمُسَيِّبِ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَتَحَ بَعْضَ خَيْبَرَ عَنْوَةًقَالَ أَبُو دَاوُد وَقُرِئَ عَلَى الْحَارِثِ بْنِ مِسْكِينٍ وَأَنَا شَاهِدٌ أَخْبَرَكُمْ ابْنُ وَهْبٍ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ أَنَّ خَيْبَرَ كَانَ بَعْضُهَا عَنْوَةً وَبَعْضُهَا صُلْحًا وَالْكَتِيبَةُ أَكْثَرُهَا عَنْوَةً وَفِيهَا صُلْحٌ قُلْتُ لِمَالِكٍ وَمَا الْكَتِيبَةُ قَالَ أَرْضُ خَيْبَرَ وَهِيَ أَرْبَعُونَ أَلْفَ عَذْقٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah mengabarkan kepada kami [Abdullah bin Muhammad] dari [Juwairiyah] dari [Malik] dari [Az Zuhri] bahwa [Sa'id bin Al Musayyab] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam telah menaklukkan sebagian besar Khaibar dengan kekerasan. Abu Daud berkata; dan telah dibacakan riwayat kepada [Al Harits bin Miskin] sementara aku menyaksikan. [Ibnu Wahb] telah mengabarkan kepada kalian, ia berkata; telah menceritakan kepadaku [Malik], dari [Ibnu Syihab] bahwa Khaibar sebagianya diperoleh dengan kekerasan dan sebagiannya dengan perjanjian. Daerah Kutaibah kebanyakan dengan cara kekerasan, dan padanya terdapat perjanjain damai. Aku katakan kepada Malik, apakah Kutaibah itu? Ia berkata; tanah Khaibar yaitu empat puluh ribu tandan kurma. "},"2551":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَبَلَغَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَتَحَ خَيْبَرَ عَنْوَةً بَعْدَ الْقِتَالِ وَنَزَلَ مَنْ نَزَلَ مِنْ أَهْلِهَا عَلَى الْجَلَاءِ بَعْدَ الْقِتَالِ","id":"Telah menceritakan kepada kami [Ibnu As Sarh], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus bin Yazid?] dari [Ibnu Syihab], ia berkata; telah sampai kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam telah menaklukkan Khaibar dengan paksaan setelah terjadi peperangan. "},"2552":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ قَالَلَوْلَا آخِرُ الْمُسْلِمِينَ مَا فُتِحَتْ قَرْيَةٌ إِلَّا قَسَمْتُهَا كَمَا قَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrahman], dari [Malik], dari [Zaid bin Aslam], dari [ayahnya], dari [Umar], ia berkata; seandainya tidak ada orang-orang muslim terakhir maka tidak ada sebuh desa yang ditaklukkan kecuali aku akan membagikannya sebagaimana Rasulullah shallallahu 'alaihi wasallam membagikan Khaibar. "},"2553":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ جَاءَهُ الْعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ بِأَبِي سُفْيَانَ بْنِ حَرْبٍ فَأَسْلَمَ بِمَرِّ الظَّهْرَانِ فَقَالَ لَهُ الْعَبَّاسُ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ يُحِبُّ هَذَا الْفَخْرِ فَلَوْ جَعَلْتَ لَهُ شَيْئًا قَالَ نَعَمْ مَنْ دَخَلَ دَارَ أَبِي سُفْيَانَ فَهُوَ آمِنٌ وَمَنْ أَغْلَقَ عَلَيْهِ بَابَهُ فَهُوَ آمِنٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Yahya bin Adam], telah menceritakan kepada kami [Ibnu Idris] dari [Muhammad bin Ishaq] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pada saat penaklukan Mekkah beliau didatangi Al Abbas bin Abdul Muththalib dengan membawa Abu Sufyan bin Harb, kemudian Abu Sufyan masuk Islam di daerah Marru Azh zhahran. Al Abbas berkata kepada beliau; wahai Rasulullah, sesungguhnya Abu Sufyan adalah orang yang senang berbangga diri, seandainya anda memberikan sesuatu kepadanya maka lakukanlah! Beliau berkata: \"Ya, barang siapa yang memasuki rumah Abu Sufyan maka ia aman dan barang siapa yang menutup pintu rumahnya maka ia aman.\""},"2554":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ الْفَضْلِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الْعَبَّاسِ بْنِ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ عَنْ بَعْضِ أَهْلِهِ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ الظَّهْرَانِ قَالَ الْعَبَّاسُ قُلْتُ وَاللَّهِ لَئِنْ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ عَنْوَةً قَبْلَ أَنْ يَأْتُوهُ فَيَسْتَأْمِنُوهُ إِنَّهُ لَهَلَاكُ قُرَيْشٍ فَجَلَسْتُ عَلَى بَغْلَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَعَلِّي أَجِدُ ذَا حَاجَةٍ يَأْتِي أَهْلَ مَكَّةَ فَيُخْبِرُهُمْ بِمَكَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَخْرُجُوا إِلَيْهِ فَيَسْتَأْمِنُوهُ فَإِنِّي لَأَسِيرُ إِذْ سَمِعْتُ كَلَامَ أَبِي سُفْيَانَ وَبُدَيْلِ بْنِ وَرْقَاءَ فَقُلْتُ يَا أَبَا حَنْظَلَةَ فَعَرَفَ صَوْتِي فَقَالَ أَبُو الْفَضْلِ قُلْتُ نَعَمْ قَالَ مَا لَكَ فِدَاكَ أَبِي وَأُمِّي قُلْتُ هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ قَالَ فَمَا الْحِيلَةُ قَالَ فَرَكِبَ خَلْفِي وَرَجَعَ صَاحِبُهُ فَلَمَّا أَصْبَحَ غَدَوْتُ بِهِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ يُحِبُّ هَذَا الْفَخْرَ فَاجْعَلْ لَهُ شَيْئًا قَالَ نَعَمْ مَنْ دَخَلَ دَارَ أَبِي سُفْيَانَ فَهُوَ آمِنٌ وَمَنْ أَغْلَقَ عَلَيْهِ دَارَهُ فَهُوَ آمِنٌ وَمَنْ دَخَلَ الْمَسْجِدَ فَهُوَ آمِنٌ قَالَ فَتَفَرَّقَ النَّاسُ إِلَى دُورِهِمْ وَإِلَى الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amr Ar Razi], telah menceritakan kepada kami [Salamah bin Al Fadhl] dari [Muhammad bin Ishaq] dari [Al Abbas bin Abdullah bin Ma'bad] dari [sebagian keluarganya], dari [Ibnu Abbas], ia berkata; tatkala Rasulullah shallallahu 'alaihi wasallam singgah di Marru Azh Zhahran aku katakan; demi Allah, seandainya Rasulullah shallallahu 'alaihi wasallam memasuki Mekkah dengan paksa sebelum mereka mendatangi beliau dan meminta keamanan maka sesungguhnya hal itu adalah kebinasaan orang-orang Quraisy. Aku duduk di atas Bighal Rasulullah shallallahu 'alaihi wasallam, kemudian aku katakan kepada Ali; aku mendapati orang yang memiliki hajat datang kepada penduduk Mekkah kemudian mengabarkan kepada mereka tempat Rasulullah shallallahu 'alaihi wasallam agar mereka keluar menuju kepadanya dan meminta keamanan. Sesungguhnya aku sedang berjalan kemudian tiba-tiba aku mendengar perkataan Abu Sufyan serta Budail bin Warqa`, lalu aku katakan; wahai Abu Hanzhalah! Kemudian ia mengenal suaraku, lalu ia berkata; Abu Al Fadhl? Aku katakan; ya. Ia berkata; ada denganmu? Aku katakan; ini, Rasulullah dan orang-orang telah datang. Ia berkata; bagaimana siasatnya? Kemudian ia naik di belakangku sedangkan sahabatnya kembali. Kemudian setelah pagi hari aku membawanya kepada Rasulullah shallallahu 'alaihi wasallam, lalu ia masuk Islam. Aku katakan; wahai Rasulullah, sesungguhnya Abu Sufyan adalah orang yang suka berbangga diri, maka berikanlah sesuatu kepadanya! Beliau berkata: \"Ya, barang siapa yang memasuki rumah Abu Sufyan, maka ia aman dan barang siapa yang menutup rumahnya maka ia aman, and barang siapa yang masuk masjid maka dia aman.\" Kemudian orang-orang berpencaran menuju rumah-rumah mereka serta menuju ke masjid. "},"2555":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ عَبْدِ الْكَرِيمِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ عَقِيلِ بْنِ مَعْقِلٍ عَنْ أَبِيهِ عَنْ وَهْبِ بْنِ مُنَبِّهٍ قَالَسَأَلْتُ جَابِرًا هَلْ غَنِمُوا يَوْمَ الْفَتْحِ شَيْئًا قَالَ لَا","id":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah], telah menceritakan kepada kami [Isma'il bin Abdul Karim], telah menceritakan kepadaku [Ibrahim bin 'Aqil bin Ma'qil], dari [ayahnya], dari [Wahb bin Munabbih], ia berkata; aku bertanya kepada [Jabir]; apakah mereka mendapatkan rampasan perang pada saat penaklukan Mekkah? Ia berkata; tidak. "},"2556":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا سَلَّامُ بْنُ مِسْكِينٍ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ الْأَنْصَارِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا دَخَلَ مَكَّةَ سَرَّحَ الزُّبَيْرَ بْنَ الْعَوَّامِ وَأَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ وَخَالِدَ بْنَ الْوَلِيدِ عَلَى الْخَيْلِ وَقَالَ يَا أَبَا هُرَيْرَةَ اهْتِفْ بِالْأَنْصَارِ قَالَ اسْلُكُوا هَذَا الطَّرِيقَ فَلَا يَشْرُفَنَّ لَكُمْ أَحَدٌ إِلَّا أَنَمْتُمُوهُ فَنَادَى مُنَادٍ لَا قُرَيْشَ بَعْدَ الْيَوْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دَخَلَ دَارًا فَهُوَ آمِنٌ وَمَنْ أَلْقَى السِّلَاحَ فَهُوَ آمِنٌ وَعَمَدَ صَنَادِيدُ قُرَيْشٍ فَدَخَلُوا الْكَعْبَةَ فَغَصَّ بِهِمْ وَطَافَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَّى خَلْفَ الْمَقَامِ ثُمَّ أَخَذَ بِجَنْبَتَيْ الْبَابِ فَخَرَجُوا فَبَايَعُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِقَالَ أَبُو دَاوُد سَمِعْتُ أَحْمَدَ بْنَ حَنْبَلٍ سَأَلَهُ رَجُلٌ قَالَ مَكَّةُ عَنْوَةً هِيَ قَالَ إِيشْ يَضُرُّكَ مَا كَانَتْ قَالَ فَصُلْحٌ قَالَ لَا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Sallam bin Miskin], telah menceritakan kepada kami [Tsabit Al Bunani], dari [Abdullah bin Rabah Al Anshari], dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam tatkala memasuki Mekkah, beliau mengirim Az Zubair bin Al Awwam dan Abu 'Ubaidah bin Al Jarrah, serta Khalid bin Al Walid dengan menunggangi kuda, beliau berkata; wahai Abu Hurairah: \"Serulah orang-orang anshar!\" Beliau berkata: \"Telusuri jalan ini, maka tidak ada yang seorangpun yang menampakkan diri kepada kalian kecuali kalian bunuh.\" Kemudian terdapat orang yang menyeru; tidak ada Quraisy setelah hari ini. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Barang siapa yang memasuki rumah maka ia aman dan barang siapa yang menjatuhkan senjata maka ia aman.\" Dan para pemimpin Quraisy pergi menuju Ka'bah hingga penuh, Nabi shallallahu 'alaihi wasallam berkeliling di belakang Maqam kemudian memegang dua sisi pintu, kemudian mereka keluar dan membai'at Nabi shallallahu 'alaihi wasallam untuk masuk Islam. Abu Daud berkata; saya mendengar Ahmad bin Hanbal ditanya oleh seseorang; apakah Mekkah ditaklukkan dengan kekerasan? Ia berkata; tidak yang merugikanmu apa yang telah terjadi. Ia berkata; dengan perjanjian damai? Ahmad berkata; tidak. "},"2557":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ عَبْدِ الْكَرِيمِ حَدَّثَنِي إِبْرَاهِيمُ يَعْنِي ابْنَ عَقِيلِ بْنِ مُنَبِّهٍ عَنْ أَبِيهِ عَنْ وَهْبٍ قَالَسَأَلْتُ جَابِرًا عَنْ شَأْنِ ثَقِيفٍ إِذْ بَايَعَتْ قَالَ اشْتَرَطَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا صَدَقَةَ عَلَيْهَا وَلَا جِهَادَ وَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ يَقُولُ سَيَتَصَدَّقُونَ وَيُجَاهِدُونَ إِذَا أَسْلَمُوا","id":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah], telah menceritakan kepada kami [Isma'il bin Abdul Karim], telah menceritakan kepadaku [Ibrahim bin 'Aqil bin Munabbih], dari [ayahnya], dari [Wahb], ia berkata; aku bertanya kepada [Jabir], mengenai kondisi Tsaqif ketika berbai'at. Ia berkata; mereka mensyaratkan kepada Nabi shallallahu 'alaihi wasallam bahwa tidak ada kewajiban bersedekah atas mereka dan tidak pula wajib berjihad. Dan Jabir mendengar Nabi shallallahu 'alaihi wasallam setelah itu berkata: \"Mereka akan bersedekah dan berjihad apabila mereka masuk Islam.\""},"2558":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَلِيِّ بْنِ سُوَيْدٍ يَعْنِي ابْنَ مَنْجُوفٍ حَدَّثَنَا أَبُو دَاوُدَ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِأَنَّ وَفْدَ ثَقِيفٍ لَمَّا قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْزَلَهُمْ الْمَسْجِدَ لِيَكُونَ أَرَقَّ لِقُلُوبِهِمْ فَاشْتَرَطُوا عَلَيْهِ أَنْ لَا يُحْشَرُوا وَلَا يُعْشَرُوا وَلَا يُجَبَّوْا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكُمْ أَنْ لَا تُحْشَرُوا وَلَا تُعْشَرُوا وَلَا خَيْرَ فِي دِينٍ لَيْسَ فِيهِ رُكُوعٌ","id":"Telah menceritakan kepada kami [Ahmad bin Ali bin Suwaid bin Ibnu Manjuf], Telah menceritakan kepada kami [Abu Daud] dari [Hammad bin Salamah], dari [Humaid] dari [Al Hasan] dari [Utsmat bin Abu Al 'Ash], bahwa utusan Tsaqif tatkala datang kepada Rasulullah shallallahu 'alaihi wasallam beliau menempatkannya di Masjid agar menjadi lebih lembut bagi hati mereka, dan mereka mensyaratkan kepada beliau agar tidak diseru untuk berperang, dan tidak diambil sepersepuluh dari harta mereka, dan tidak melakukan shalat. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagi kalian untuk tidak diseru melakukan perang, tidak diambil sepersepuluh dari harta kalian, dan tidak ada kebaikan dalam agama yang tidak ada ruku'nya.\""},"2559":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي أُسَامَةَ عَنْ مُجَالِدٍ عَنْ الشَّعْبِيِّ عَنْ عَامِرِ بْنِ شَهْرٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ لِي هَمْدَانُ هَلْ أَنْتَ آتٍ هَذَا الرَّجُلَ وَمُرْتَادٌ لَنَا فَإِنْ رَضِيتَ لَنَا شَيْئًا قَبِلْنَاهُ وَإِنْ كَرِهْتَ شَيْئًا كَرِهْنَاهُ قُلْتُ نَعَمْ فَجِئْتُ حَتَّى قَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضِيتُ أَمْرَهُ وَأَسْلَمَ قَوْمِي وَكَتَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْكِتَابَ إِلَى عُمَيْرٍ ذِي مَرَّانٍ قَالَ وَبَعَثَ مَالِكَ بْنَ مِرَارَةَ الرَّهَاوِيَّ إِلَى الْيَمَنِ جَمِيعًا فَأَسْلَمَ عَكٌّ ذُو خَيْوَانَ قَالَ فَقِيلَ لِعَكٍّ انْطَلِقْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخُذْ مِنْهُ الْأَمَانَ عَلَى قَرْيَتِكَ وَمَالِكَ فَقَدِمَ وَكَتَبَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ لِعَكٍّ ذِي خَيْوَانَ إِنْ كَانَ صَادِقًا فِي أَرْضِهِ وَمَالِهِ وَرَقِيقِهِ فَلَهُ الْأَمَانُ وَذِمَّةُ اللَّهِ وَذِمَّةُ مُحَمَّدٍ رَسُولِ اللَّهِ وَكَتَبَ خَالِدُ بْنُ سَعِيدِ بْنِ الْعَاصِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari], dari [Abu Usamah] dari [Mujalid] dari [Asy Sya'bi] dari ['Amir bin Syahr], ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar, orang-orang Hamdan berkata kepadaku; apakah engkau mau pergi kepada orang ini, dan mencari untuk kami? Apabila engkau merelakan sesuatu untuk kami maka kami akan menerima dan apabila engkau tidak menyukai sesuatu maka kami pun tidak menyukainya. Aku katakan; ya. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam kemudian aku menyukai urusan beliau dan kaumku pun masuk Islam. Rasulullah shallallahu 'alaihi wasallam menulis surat ini kepada 'Umair Dzi Marran. Dan beliau mengutus Malik bin Mirarah Ar Rahawi ke seluruh Yaman. Kemudian 'Akku Dzu Khaiwan masuk Islam, lalu dikatakan kepada 'Akku; pergilah kepada Rasulullah shallallahu 'alaihi wasallam dan ambillah keamanan untuk kampong dan hartamu! Kemudian ia datang dan Rasulullah shallallahu 'alaihi wasallam menuliskan surat untuknya: \"Bismillahirrahmanirrahim, dari Muhammad Rasulullah, untuk 'Akku Dzu Khaiwan: Apabila ia jujur untuk negeri, harta, dan budaknya maka baginya keamanan dan jaminan Allah dan jaminan Muhammad Rasulullah.\" Dan Khalid bin Sa'id bin Al 'Ash menulis hal tersebut. "},"2560":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَحْمَدَ الْقُرَشِيُّ وَهَارُونُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُمْ قَالَ حَدَّثَنَا فَرَجُ بْنُ سَعِيدٍ حَدَّثَنِي عَمِّي ثَابِتُ بْنُ سَعِيدٍ عَنْ أَبِيهِ سَعِيدٍ يَعْنِي ابْنَ أَبْيَضَ عَنْ جَدِّهِ أَبْيَضَ بْنِ حَمَّالٍأَنَّهُ كَلَّمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّدَقَةِ حِينَ وَفَدَ عَلَيْهِ فَقَالَ يَا أَخَا سَبَأٍ لَا بُدَّ مِنْ صَدَقَةٍ فَقَالَ إِنَّمَا زَرَعْنَا الْقُطْنَ يَا رَسُولَ اللَّهِ وَقَدْ تَبَدَّدَتْ سَبَأٌ وَلَمْ يَبْقَ مِنْهُمْ إِلَّا قَلِيلٌ بِمَأْرِبَ فَصَالَحَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سَبْعِينَ حُلَّةً بَزٍّ مِنْ قِيمَةِ وَفَاءِ بَزِّ الْمَعَافِرِ كُلَّ سَنَةٍ عَمَّنْ بَقِيَ مِنْ سَبَأٍ بِمَأْرِبَ فَلَمْ يَزَالُوا يَؤُدُّونَهَا حَتَّى قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّ الْعُمَّالَ انْتَقَضُوا عَلَيْهِمْ بَعْدَ قَبْضِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا صَالَحَ أَبْيَضُ بْنُ حَمَّالٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحُلَلِ السَّبْعِينَ فَرَدَّ ذَلِكَ أَبُو بَكْرٍ عَلَى مَا وَضَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى مَاتَ أَبُو بَكْرٍ فَلَمَّا مَاتَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ انْتَقَضَ ذَلِكَ وَصَارَتْ عَلَى الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ahmad Al Qurasyi], dan [Harun bin Abdullah] bahwa [Abdullah bin Az Zubair], telah menceritakan kepada mereka, ia berkata; telah menceritakan kepada kami [Faraj bin Sa'id], telah menceritakan kepadaku [pamanku yaitu Tsabit bin Sa'id] dari [ayahnya yaitu Sa'id bin Abyadh] dari [kakeknya yaitu Abyadh bin Jammal], bahwa ia telah berbicara kepada kepada Rasulullah shallallahu 'alaihi wasallam mengenai zakat ketika ia menjadi utusan kepadanya. Kemudian beliau berkata: \"Wahai saudara Saba`, harus ada zakat.\" Kemudian ia berkata; wahai Rasulullah, kami hanya menanam kapas. Saba` telah bercerai berai dan tidak tersisa dari mereka kecuali sedikit di Ma`rib (suatu negeri di Yaman). Kemudian Nabi shallallahu 'alaihi wasallam kemudian Nabi shallallahu 'alaihi wasallam berdamai agar mereka memberikan tujuh puluh Hullah (pakaian Yaman) dari nilai penunaian pakaian yang berasal dari Ma'afir setiap tahun untuk orang yang tersisa dari orang-orang Saba` di Ma'rib. Kemudian mereka terus menunaikannya hingga Rasulullah shallallahu 'alaihi wasallam wafat. Dan para pegawai membatalkan perjanjian tersebut setelah Rasulullah shallallahu 'alaihi wasallam meninggal dalam perjanjian yang dibuat Abyadh bersama Rasulullah shallallahu 'alaihi wasallam mengenai tujuh puluh pakaian tersebut. Kemudian Abu Bakr mengembalikan kembali kepada apa yang telah diterapkan Rasulullah shallallahu 'alaihi wasallam hingga Abu Bakr meninggal, kemudian tatkala Abu Bakr radliallahu 'anhu telah meninggal perjanjian tersebut dibatalkan dan menjadi zakat. "},"2561":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْصَى بِثَلَاثَةٍ فَقَالَ أَخْرِجُوا الْمُشْرِكِينَ مِنْ جَزِيرَةِ الْعَرَبِ وَأَجِيزُوا الْوَفْدَ بِنَحْوٍ مِمَّا كُنْتُ أُجِيزُهُمْقَالَ ابْنُ عَبَّاسٍ وَسَكَتَ عَنْ الثَّالِثَةِ أَوْ قَالَ فَأُنْسِيتُهَا و قَالَ الْحُمَيْدِيُّ عَنْ سُفْيَانَ قَالَ سُلَيْمَانُ لَا أَدْرِي أَذَكَرَ سَعِيدٌ الثَّالِثَةَ فَنَسِيتُهَا أَوْ سَكَتَ عَنْهَا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Sufyan bin 'Uyainah], dari [Sulaiman Al Ahwal], dari [Sa'id bin Jubair], dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam telah berwasiat dengan tiga perkara. Beliau berkata: \"Keluarkan orang-orang musyrik dari Jazirah Arab, berikanlah hadiah kepada para utusan sebagaimana dahulu aku memberikan hadiah kepada mereka.\" Ibnu Abbas berkata; -dan ia tidak menyebutkan yang ketiga, atau dia mengatakan; aku lupa yang ketiga. [Al Humaidi] berkata; dari [Sufyan]; [Sulaiman] berkata; aku tidak mengetahui apakah Sa'id mengatakan yang ketiga; aku lupa yang ketiga atau ia tidak menyebutkan yang ketiga. "},"2562":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ وَعَبْدُ الرَّزَّاقِ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ أَخْبَرَنِي عُمَرُ بْنُ الْخَطَّابِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَأُخْرِجَنَّ الْيَهُودَ وَالنَّصَارَى مِنْ جَزِيرَةِ الْعَرَبِ فَلَا أَتْرُكُ فِيهَا إِلَّا مُسْلِمًاحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو أَحْمَدَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ وَالْأَوَّلُ أَتَمُّ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abu 'Ashim], dan [Abdurrazzaq], mereka berkata; telah mengabarkan kepada kami [Ibnu Juraij], telah mengabarkan kepadaku [Abu Az Zubair], bahwa ia mendengar [Jabir bin Abdullah] berkata; telah mengabarkan kepadaku [Umar bin Al Khathab] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Sungguh aku akan mengeluarkan orang-orang yahudi dan nashrani dari Jazirah Arab. Dan tidak aku tinggalkan padanya kecuali orang muslim.\" Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abu Ahmad Muhammad bin Abdullah], telah menceritakan kepada kami [Sufyan], dari [Abu Az Zubair], dari [Jabir] dari [Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: ….. dengan makna yang sama dengannya, sedangkan hadits yang pertama lebih sempurna. "},"2563":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا جَرِيرٌ عَنْ قَابُوسَ بْنِ أَبِي ظَبْيَانَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكُونُ قِبْلَتَانِ فِي بَلَدٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki], telah menceritakan kepada kami [Jarir], dari [Qabus bin Abu Zhabyan] dari [ayahnya], dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada dua kiblat dalam satu negeri.\""},"2564":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا عُمَرُ يَعْنِي ابْنَ عَبْدِ الْوَاحِدِ قَالَ قَالَ سَعِيدٌ يَعْنِي ابْنَ عَبْدِ الْعَزِيزِجَزِيرَةُ الْعَرَبِ مَا بَيْنَ الْوَادِي إِلَى أَقْصَى الْيَمَنِ إِلَى تُخُومِ الْعِرَاقِ إِلَى الْبَحْرِ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Umar bin Abdul Wahid], ia berkata; [Sa'id bin Abdul Aziz] berkata; Jazirah Arab adalah antara bukit hingga ujung Yaman hingga batasan Irak hingga laut. "},"2565":{"ar":"قَالَ أَبُو دَاوُد قُرِئَ عَلَى الْحَارِثِ بْنِ مِسْكِينٍ وَأَنَا شَاهِدٌ أَخْبَرَكَ أَشْهَبُ بْنُ عَبْدِ الْعَزِيزِ قَالَ قَالَ مَالِكٌعُمَرُ أَجْلَى أَهْلَ نَجْرَانَ وَلَمْ يُجْلَوْا مِنْ تَيْمَاءَ لِأَنَّهَا لَيْسَتْ مِنْ بِلَادِ الْعَرَبِ فَأَمَّا الْوَادِي فَإِنِّي أَرَى أَنَّمَا لَمْ يُجْلَ مَنْ فِيهَا مِنْ الْيَهُودِ أَنَّهُمْ لَمْ يَرَوْهَا مِنْ أَرْضِ الْعَرَبِحَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ قَالَ مَالِكٌ وَقَدْ أَجْلَى عُمَرُ رَحِمَهُ اللَّهُ يَهُودَ نَجْرَانَ وَفَدَكَ","id":"Abu Daud berkata; telah dibacakan riwayat kepada [Al Harits bin Miskin], sementara aku menyaksikan, [Asyhab bin Abdul Aziz] telah mengabarkan kepadaku, ia berkata; [Malik] berkata; Umar telah mengusir penduduk Najran, dan mereka tidak diusir dari Taima` karena Taima` bukan termasuk negeri Arab. Adapun Bukit, maka aku berpendapat orang yahudi tidak diusir darinya karena mereka tidak memandangnya sebagai bagian dari tanah Arab. Telah menceritakan kepada kami [Ibnu As Sarh], telah menceritakan kepada kami [Ibnu Wahb], ia berkata; [Malik] berkata; Umar rahimahullah telah mengusir orang-orang Yahudi Najran dan Fadak. "},"2566":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنَعَتْ الْعِرَاقُ قَفِيزَهَا وَدِرْهَمَهَا وَمَنَعَتْ الشَّامُ مُدْيَهَا وَدِينَارَهَا وَمَنَعَتْ مِصْرُ إِرْدَبَّهَا وَدِينَارَهَا ثُمَّ عُدْتُمْ مِنْ حَيْثُ بَدَأْتُمْقَالَهَا زُهَيْرٌ ثَلَاثَ مَرَّاتٍ شَهِدَ عَلَى ذَلِكَ لَحْمُ أَبِي هُرَيْرَةَ وَدَمُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Irak menahan Qafiz dan Dirhamnya, dan orang-orang Syam menahan mudyunya dan orang-orang Mesir menahan Irdab serta dinarnya. Kemudian kalian kembali dari tempat kalian bermula.\" -Zuhair mengatakannya tiga kali- Daging dan darah Abu Hurairah bersaksi atas hal tersebut. "},"2567":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا بِهِ أَبُو هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا قَرْيَةٍ أَتَيْتُمُوهَا وَأَقَمْتُمْ فِيهَا فَسَهْمُكُمْ فِيهَا وَأَيُّمَا قَرْيَةٍ عَصَتْ اللَّهَ وَرَسُولَهُ فَإِنَّ خُمُسَهَا لِلَّهِ وَلِلرَّسُولِ ثُمَّ هِيَ لَكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrzzaq], telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih], ia berkata; ini adalah yang diceritakan [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau besabda: \"Kampung manapun yang kalian datangi dan kalian tinggali maka saham kalian ada padanya, dan kampung manapun yang berdurhaka kepada Allah dan rasulNya maka seperlimanya adalah untuk Allah dan Rasul, kemudian kampung tersebut milik kalian.\""},"2568":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنَا سَهْلُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَاصِمِ بْنِ عُمَرَ عَنْ أَنَسِ بْنِ مَالِكٍ وَعَنْ عُثْمَانَ بْنِ أَبِي سُلَيْمَانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ خَالِدَ بْنَ الْوَلِيدِ إِلَى أُكَيْدِرِ دُومَةَ فَأُخِذَ فَأَتَوْهُ بِهِ فَحَقَنَ لَهُ دَمَهُ وَصَالَحَهُ عَلَى الْجِزْيَةِ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul 'Azhim], telah menceritakan kepada kami [Sahl bin Muhammad], telah menceritakan kepada kami [Yahya bin Abu Zaidah], dari [Muhammad bin Ishaq] dari ['Ashim bin Umar], dari [Anas bin Malik], dan dari [Utsman bin Abu Sulaiman], bahwa Nabi shallallahu 'alaihi wasallam telah mengirimkan Khalid bin Al Walid ke Ukaidir Dumah, kemudian ia ditangkap, lalu mereka membawanya kepada beliau. Kemudian beliau memampatkan darahnya dan berdamai dengan syarat ia memberikan jizyah. "},"2569":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ مُعَاذٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا وَجَّهَهُ إِلَى الْيَمَنِ أَمَرَهُ أَنْ يَأْخُذَ مِنْ كُلِّ حَالِمٍ يَعْنِي مُحْتَلِمًا دِينَارًا أَوْ عَدْلَهُ مِنْ الْمُعَافِرِيِّ ثِيَابٌ تَكُونُ بِالْيَمَنِحَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ مُعَاذٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Abu Mu'awiyah], dari [Al A'masy], dari [Abu Wail], dari [Mu'adz], bahwa Nabi shallallahu 'alaihi wasallam tatkala mengutusnya ke Yaman beliau memerintahkannya agar ia mengambil dari dari setiap orang yang baligh zakat satu dinar atau yang setara dengannya dari mu'afiri, yaitu pakaian yang ada di Yaman. Telah menceritakan kepada kami [An Nufaili], telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Al A'masy], dari [Ibrahim], dari [Masruq], dari [Mu'adz], dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"2570":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ هَانِئٍ أَبُو نُعَيمٍ النَّخَعِيُّ أَخْبَرَنَا شَرِيكٌ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ زِيَادِ بْنِ حُدَيْرٍ قَالَ قَالَ عَلِيٌّلَئِنْ بَقِيتُ لِنَصَارَى بَنِي تَغْلِبَ لَأَقْتُلَنَّ الْمُقَاتِلَةَ وَلَأَسْبِيَنَّ الذُّرِّيَّةَ فَإِنِّي كَتَبْتُ الْكِتَابَ بَيْنَهُمْ وَبَيْنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنْ لَا يُنَصِّرُوا أَبْنَاءَهُمْقَالَ أَبُو دَاوُد هَذَا حَدِيثٌ مُنْكَرٌ بَلَغَنِي عَنْ أَحْمَدَ أَنَّه كَانَ يُنْكِرُ هَذَا الْحَدِيثَ إِنْكَارًا شَدِيدًا قَالَ أَبُو عَلِيٍّ وَلَمْ يَقْرَأْهُ أَبُو دَاوُدَ فِي الْعَرْضَةِ الثَّانِيَةِ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim], telah menceritakan kepada kami [Abdurrahman bin Hani` Abu Nu'aim An Nakha'i], telah mengabarkan kepada kami [Syarik] dari [Ibrahim bin Muhajir], dari [Ziyad bin Hudair], ia berkata; [Ali] berkata; seandainya aku masih hidup niscaya aku akan membunuh orang-orang nashrani Bani Taghlab yang berperang dan aku tawan anak keturunannya, sungguh aku telah menulis surat perjanjian antara mereka dengan Nabi shallallahu 'alaihi wasallam yaitu agar mereka tidak menjadikan anak-anak mereka beragama nashrani. Abu Daud berkata; hadits ini adalah hadits munkar. Telah sampai kepadaku dari Ahmad bahwa ia mengingkari hadits ini dengan keras. Abu Ali berkata; Abu Daud tidak membacanya pada pemaparan yang kedua. "},"2571":{"ar":"حَدَّثَنَا مُصَرِّفُ بْنُ عَمْرٍو الْيَامِيُّ حَدَّثَنَا يُونُسُ يَعْنِي ابْنَ بُكَيْرٍ حَدَّثَنَا أَسْبَاطُ بْنُ نَصْرٍ الْهَمْدَانِيُّ عَنْ إِسْمَعِيلَ بْنِ عَبْدِ الرَّحْمَنِ الْقُرَشِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَصَالَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلَ نَجْرَانَ عَلَى أَلْفَيْ حُلَّةٍ النِّصْفُ فِي صَفَرٍ وَالْبَقِيَّةُ فِي رَجَبٍ يُؤَدُّونَهَا إِلَى الْمُسْلِمِينَ وَعَوَرِ ثَلَاثِينَ دِرْعًا وَثَلَاثِينَ فَرَسًا وَثَلَاثِينَ بَعِيرًا وَثَلَاثِينَ مِنْ كُلِّ صِنْفٍ مِنْ أَصْنَافِ السِّلَاحِ يَغْزُونَ بِهَا وَالْمُسْلِمُونَ ضَامِنُونَ لَهَا حَتَّى يَرُدُّوهَا عَلَيْهِمْ إِنْ كَانَ بِالْيَمَنِ كَيْدٌ أَوْ غَدْرَةٌ عَلَى أَنْ لَا تُهْدَمَ لَهُمْ بَيْعَةٌ وَلَا يُخْرَجَ لَهُمْ قَسٌّ وَلَا يُفْتَنُوا عَنْ دِينِهِمْ مَا لَمْ يُحْدِثُوا حَدَثًا أَوْ يَأْكُلُوا الرِّبَاقَالَ إِسْمَعِيلُ فَقَدْ أَكَلُوا الرِّبَا قَالَ أَبُو دَاوُد إِذَا نَقَضُوا بَعْضَ مَا اشْتُرِطَ عَلَيْهِمْ فَقَدْ أَحْدَثُوا","id":"Telah menceritakan kepada kami [Musharrif bin 'Amr Al Yami], telah menceritakan kepada kami [Yunus bin Bukair], telah menceritakan kepada kami [Asbath bin Nashr Al Hamdani], dari [Isma'il bin Abdurrahman Al Qurasyi], dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah berdama dengan penduduk Najran dengan syarat mereka membayar dua ribu pakaian setengahnya pada Bulan Shafar dan sisanya pada Bulan Rajab, mereka memberikannya kepada orang-orang muslim. Serta 'Awar, mereka membayar tiga puluh baju zirah, tiga puluh unta, dan tiga puluh setiap jenis dari jenis senjata yang mereka gunakan untuk berperang. Dan orang-orang muslim memberikan jaminan -hingga mereka memberikannya kepada orang-orang muslim apabila di Yaman terdapat tipu muslihat serta pengkhianatan- bahwa tempat ibadah mereka tidak dihancurkan dan pendeta mereka tidak dikeluarkan serta mereka tidak difitnah dalam agama mereka selama tidak membuat suatu kejadian atau memakan barang riba. Isma'il berkata; sungguh mereka telah makan riba. Abu Daud berkata; apabila mereka membatalkan sebagian yang telah disyaratkan kepada mereka maka sungguh mereka telah membuat perkara. "},"2572":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ الْوَاسِطِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ بِلَالٍ عَنْ عِمْرَانَ الْقَطَّانِ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّ أَهْلَ فَارِسَ لَمَّا مَاتَ نَبِيُّهُمْ كَتَبَ لَهُمْ إِبْلِيسُ الْمَجُوسِيَّةَ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan Al Wasithi], telah menceritakan kepada kami [Muhammad bin Bilal], dari [Imran Al Qaththan] dari [Abu Jamrah], dari [Ibnu Abbas]; ia berkata; sesungguhnya penduduk Persia tatkala Nabi mereka meninggal maka Iblis menjadikan Al Majusiyyah sebagai pengganti agama nabi mereka. "},"2573":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ بَجَالَةَ يُحَدِّثُ عَمْرَو بْنَ أَوْسٍ وَأَبَا الشَّعْثَاءِ قَالَكُنْتُ كَاتِبًا لِجَزْءِ بْنِ مُعَاوِيَةَ عَمِّ الْأَحْنَفِ بْنِ قَيْسٍ إِذْ جَاءَنَا كِتَابُ عُمَرَ قَبْلَ مَوْتِهِ بِسَنَةٍ اقْتُلُوا كُلَّ سَاحِرٍ وَفَرِّقُوا بَيْنَ كُلِّ ذِي مَحْرَمٍ مِنْ الْمَجُوسِ وَانْهَوْهُمْ عَنْ الزَّمْزَمَةِ فَقَتَلْنَا فِي يَوْمٍ ثَلَاثَةَ سَوَاحِرَ وَفَرَّقْنَا بَيْنَ كُلِّ رَجُلٍ مِنْ الْمَجُوسِ وَحَرِيمِهِ فِي كِتَابِ اللَّهِ وَصَنَعَ طَعَامًا كَثِيرًا فَدَعَاهُمْ فَعَرَضَ السَّيْفَ عَلَى فَخْذِهِ فَأَكَلُوا وَلَمْ يُزَمْزِمُوا وَأَلْقَوْا وِقْرَ بَغْلٍ أَوْ بَغْلَيْنِ مِنْ الْوَرِقِ وَلَمْ يَكُنْ عُمَرُ أَخَذَ الْجِزْيَةَ مِنْ الْمَجُوسِ حَتَّى شَهِدَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَهَا مِنْ مَجُوسِ هَجَرَ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad], telah menceritakan kepada kami [Sufyan], dari ['Amr bin Dinar], ia mendengar [Bajalah], menceritakan kepada 'Amr bin Aus, serta Abu Asy Sya'tsa`, ia berkata; dahulu aku adalah seorang sekretaris Jaz` bin Mu'awiyah paman Al Ahnaf bin Qais, tiba-tiba terdapat surat [Umar] datang kepada kami satu tahun sebelum ia meninggal, ia berkata; bunuhlah seluruh tukang sihir, dan pisahkan antara setiap orang yang memiliki mahram dari kalangan orang-orang majusi, dan laranglah mereka dari bersuara rendah yang hampir tidak terdengar suaranya. Maka kami dalam sehari telah membunuh tiga orang tukang sihir, dan memisahkan antara setiap laki-laki majusi dan mahramnya dalam kitab Allah. Dan Umar membuat makanan yang banyak kemudian mengundang mereka kemudian ia memperlihatkan pedang di atas pahanya. Kemudian mereka makan tanpa mengeluarkan suara samar yang tidak jelas dan mereka menjatuhkan bawaan seekor atau dua ekor bighal dari perak, dan Umar tidak mengambil jizyah dari orang-orang majusi hingga [Abdurrahman bin 'Auf] bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam mengambilnya dari majusi Hajar."},"2574":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِسْكِينٍ الْيَمَامِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ قُشَيْرِ بْنِ عَمْرٍو عَنْ بَجَالَةَ بْنِ عَبْدَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ رَجُلٌ مِنْ الْأَسْبَذِيِّينَ مِنْ أَهْلِ الْبَحْرَيْنِ وَهُمْ مَجُوسُ أَهْلِ هَجَرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَكَثَ عِنْدَهُ ثُمَّ خَرَجَ فَسَأَلْتُهُ مَا قَضَى اللَّهُ وَرَسُولُهُ فِيكُمْ قَالَ شَرٌّ قُلْتُ مَهْ قَالَ الْإِسْلَامُ أَوْ الْقَتْلُ قَالَ وَقَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ قَبِلَ مِنْهُمْ الْجِزْيَةَقَالَ ابْنُ عَبَّاسٍ فَأَخَذَ النَّاسُ بِقَوْلِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَتَرَكُوا مَا سَمِعْتُ أَنَا مِنْ الْأَسْبَذِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Miskin Al Yamami], telah menceritakan kepada kami [Yahya bin Hassan], telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Daud bin Abu Hindun], dari [Qusyair bin 'Amr], dari [Bajalah bin 'Abdah] dari [Ibnu Abbas], ia berkata; telah datang seorang laki-laki asbdzi dari penduduk Bahrain, mereka adalah orang-orang majusi penduduk Hajar kepada Rasulullah shallallahu 'alaihi wasallam, kemudian ia tinggal di sisi beliau kemudian keluar. Lalu aku bertanya kepada beliau; apakah yang telah Allah dan rasulNya putuskan pada diri kalian? Ia berkata; keputusan yang buruk. Aku katakan; apakah itu? Ia berkata; masuk Islam atau dibunuh. Bajalah berkata; dan Abdurrahman bin 'Auf telah menerima jizyah dari mereka. Ibnu Abbas berkata; kemudian orang-orang mengambil pendapat Abdurrahman bin 'Auf, dan meninggalkan apa yang aku dengar dari orang asbadzi tersebut. "},"2575":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِأَنَّ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ وَجَدَ رَجُلًا وَهُوَ عَلَى حِمْصَ يُشَمِّسُ نَاسًا مِنْ الْقِبْطِ فِي أَدَاءِ الْجِزْيَةِ فَقَالَ مَا هَذَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يُعَذِّبُ الَّذِينَ يُعَذِّبُونَ النَّاسَ فِي الدُّنْيَا","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus bin Yazid?], dari [Ibnu Syihab], dari ['Urwah bin Az Zubair] bahwa [Hisyam bin Hakim bin Hizam] telah mendapati seorang laki-laki pemimpin Himsh menjemur beberapa orang dari Qibth (penduduk Mesir) di bawah terik matahari, dalam menunaikan jizyah. Kemudian Hisyam berkata; ada apa ini? Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata; sesungguhnya Allah akan menyiksa orang-orang yang menyiksa manusia di dunia. "},"2576":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ حَرْبِ بْنِ عُبَيْدِ اللَّهِ عَنْ جَدِّهِ أَبِي أُمِّهِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْعُشُورُ عَلَى الْيَهُودِ وَالنَّصَارَى وَلَيْسَ عَلَى الْمُسْلِمِينَ عُشُورٌحَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْمُحَارِبِيُّ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ حَرْبِ بْنِ عُبَيْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ خَرَاجٌ مَكَانَ الْعُشُورِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Al Ahwash], telah menceritakan kepada kami ['Atho` bin As Saib], dari [Harb bin 'Ubaidullah] dari [kakeknya yaitu Abu Ummuhu] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya membayar sepersepuluh harta adalah kewajiban atas orang-orang yahudi dan nashrani dan tidak ada kewajiban sepersepuluh atas orang-orang muslim.\" Telah menceritakan kepada kami [Muhammad bin 'Ubaid Al Muharibi], telah menceritakan kepada kami [Waki'] dari [Sufyan], dari ['Atho` bin As Saib] dari [Harb bin 'Ubaidullah] dari Nabi shallallahu 'alaihi wasallam dengan maknanya, beliau bersabda: \"Pajak bumi sebagai ganti sepersepuluh.\""},"2577":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ عَطَاءٍ عَنْ رَجُلٍ مِنْ بَكْرِ بْنِ وَائِلٍ عَنْ خَالِهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أُعَشِّرُ قَوْمِي قَالَ إِنَّمَا الْعُشُورُ عَلَى الْيَهُودِ وَالنَّصَارَى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abdurrahman], telah menceritakan kepada kami [Sufyan] dari ['Atho`], dari [seorang laki-laki dari Bakr bin Wail], dari [pamannya], ia berkata; aku katakan kepada Rasulullah shallallahu 'alaihi wasallam; wahai Rasulullah, apakah aku mewajibkan sepersepuluh atas kaumku? Beliau berkata; sesungguhnya sepersepuluh adalah kewajiban atas orang-orang yahudi dan nashrani. "},"2578":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الْبَزَّازُ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ السَّلَامِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ حَرْبِ بْنِ عُبَيْدِ اللَّهِ بْنِ عُمَيْرٍ الثَّقَفِيِّ عَنْ جَدِّهِ رَجُلٍ مِنْ بَنِي تَغْلِبَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمْتُ وَعَلَّمَنِي الْإِسْلَامَ وَعَلَّمَنِي كَيْفَ آخُذُ الصَّدَقَةَ مِنْ قَوْمِي مِمَّنْ أَسْلَمَ ثُمَّ رَجَعْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ كُلُّ مَا عَلَّمْتَنِي قَدْ حَفِظْتُهُ إِلَّا الصَّدَقَةَ أَفَأُعَشِّرُهُمْ قَالَ لَا إِنَّمَا الْعُشُورُ عَلَى النَّصَارَى وَالْيَهُودِ","id":"Telah menceritakan kepada kami [Muhammad bin Ibrahim Al Bazzaz], telah menceritakan kepada kami [Abu Nu'aim], telah menceritakan kepada kami [Abdussalam] dari ['Atho` bin As Saib] dari [Harb bin 'Ubaidullah bin 'Umair Ats Tsaqafi], dari [kakeknya], yaitu seorang laki-laki dari Bani Taghlib. Ia berkata; aku datang kepada Nabi shallallahu 'alaihi wasallam kemudian aku masuk Islam dan beliau mengajariku Islam, dan mengajariku bagaimana aku mengambil zakat dari kaumku diantara orang-orang yang masuk Islam. Kemudian aku kembali kepadanya dan aku katakan; wahai Rasulullah, seluruh apa yang anda ajarkan telah aku hafal, kecuali zakat. Apakah aku mengambil sepersepuluh dari mereka? Ia berkata; tidak, sesungguhnya sepersepuluh adalah kewajiban atas orang-orang nashrani dan yahudi. "},"2579":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَشْعَثُ بْنُ شُعْبَةَ حَدَّثَنَا أَرْطَاةُ بْنُ الْمُنْذِرِ قَالَ سَمِعْتُ حَكِيمَ بْنَ عُمَيْرٍ أَبَا الْأَحْوَصِ يُحَدِّثُ عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَ السُّلَمِيِّ قَالَنَزَلْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ وَمَعَهُ مَنْ مَعَهُ مِنْ أَصْحَابِهِ وَكَانَ صَاحِبُ خَيْبَرَ رَجُلًا مَارِدًا مُنْكَرًا فَأَقْبَلَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ أَلَكُمْ أَنْ تَذْبَحُوا حُمُرَنَا وَتَأْكُلُوا ثَمَرَنَا وَتَضْرِبُوا نِسَاءَنَا فَغَضِبَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ يَا ابْنَ عَوْفٍ ارْكَبْ فَرَسَكَ ثُمَّ نَادِ أَلَا إِنَّ الْجَنَّةَ لَا تَحِلُّ إِلَّا لِمُؤْمِنٍ وَأَنْ اجْتَمِعُوا لِلصَّلَاةِ قَالَ فَاجْتَمَعُوا ثُمَّ صَلَّى بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَامَ فَقَالَ أَيَحْسَبُ أَحَدُكُمْ مُتَّكِئًا عَلَى أَرِيكَتِهِ قَدْ يَظُنُّ أَنَّ اللَّهَ لَمْ يُحَرِّمْ شَيْئًا إِلَّا مَا فِي هَذَا الْقُرْآنِ أَلَا وَإِنِّي وَاللَّهِ قَدْ وَعَظْتُ وَأَمَرْتُ وَنَهَيْتُ عَنْ أَشْيَاءَ إِنَّهَا لَمِثْلُ الْقُرْآنِ أَوْ أَكْثَرُ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَمْ يُحِلَّ لَكُمْ أَنْ تَدْخُلُوا بُيُوتَ أَهْلِ الْكِتَابِ إِلَّا بِإِذْنٍ وَلَا ضَرْبَ نِسَائِهِمْ وَلَا أَكْلَ ثِمَارِهِمْ إِذَا أَعْطَوْكُمْ الَّذِي عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Asy'ats], telah menceritakan kepada kami [Arthoh bin Al Mundzir], ia berkata; saya mendengar [Hakim bin 'Umair Abu Al Ahwash] menceritakan dari [Al 'Irbadh bin Sariyah As Sulami], ia berkata; kami singgah bersama Nabi shallallahu 'alaihi wasallam di Khibar dan beliau bersama beberapa sahabatnya. Dan pemimpin Khaibar adalah seorang yang keras dan berlaku mungkar. Kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Muhammad, apakah kalian boleh menyembelih keledai kami, dan memakan buah kami serta memukul wanita kami? Maka Nabi shallallahu 'alaihi wasallam marah dan berkata; wahai Ibnu 'Auf naikilah kudamu kemudian serulah bahwa Surga tidak halal kecuali bagi orang mukmin dan hendaknya mereka berkumpul untuk melakukan shalat. Al 'Irbadh bin Sariyah berkata; kemudian mereka berkumpul kemudian Nabi shallallahu 'alaihi wasallam melakukan shalat bersama mereka. Kemudian beliau berdiri dan berkata; apakah salah seorang diantara kalian dalam keadaan bersandar kepada singgasanannya menyangka bahwa Allah tidak mengharamkan sesuatupun kecuali yang ada dalam Al Qur'an? Ketahuilah, demi Allah, sesungguhnya aku telah memberi nasehat, memerintahkan dan melarang dari berbagai sesuatu, sesungguhnya hal itu adalah seperti Al Qur'an atau lebih banyak. Sesungguhnya Allah 'azza wajalla tidak menghalalkan bagi kalian untuk memasuki rumah-rumah ahli kitab kecuali dengan izin, dan tidak halal memukul wanita mereka, serta makan buah mereka apabila mereka telah memberikan kepada kalian apa yang menjadi kewajiban atas mereka. "},"2580":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَسَعِيدُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ هِلَالٍ عَنْ رَجُلٍ مِنْ ثَقِيفٍ عَنْ رَجُلٍ مِنْ جُهَيْنَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكُمْ تُقَاتِلُونَ قَوْمًا فَتَظْهَرُونَ عَلَيْهِمْ فَيَتَّقُونَكُمْ بِأَمْوَالِهِمْ دُونَ أَنْفُسِهِمْ وَأَبْنَائِهِمْ قَالَ سَعِيدٌ فِي حَدِيثِهِ فَيُصَالِحُونَكُمْ عَلَى صُلْحٍ ثُمَّ اتَّفَقَا فَلَا تُصِيبُوا مِنْهُمْ شَيْئًا فَوْقَ ذَلِكَ فَإِنَّهُ لَا يَصْلُحُ لَكُمْ","id":"Telah menceritakan kepada kami [Musaddad] dan [Sa'id bin Manshur], mereka berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Hilal] dari [seorang laki-laki dari Tsaqif] dari [seseorang dari Juhainah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kemungkinan kalian akan memerangi sebuah kaum, dan mengalahkan mereka, kemudian mereka melindungi diri mereka dari kalian dengan harta mereka bukan dengan jiwa mereka dan anak-anak mereka.\" -Sa'id berkata dalam haditsnya; kemudian mereka berdamai dengan kalian-. Kemudian keduanya sama lafazh mereka; maka janganlah kalian mengambil sesuatupun di atas hal tersebut karena sesungguhnya hal tersebut tidak layak bagi kalian.\""},"2581":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي أَبُو صَخْرٍ الْمَدِينِيُّ أَنَّ صَفْوَانَ بْنَ سُلَيْمٍ أَخْبَرَهُ عَنْ عِدَّةٍ مِنْ أَبْنَاءِ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ آبَائِهِمْ دِنْيَةًعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا مَنْ ظَلَمَ مُعَاهِدًا أَوْ انْتَقَصَهُ أَوْ كَلَّفَهُ فَوْقَ طَاقَتِهِ أَوْ أَخَذَ مِنْهُ شَيْئًا بِغَيْرِ طِيبِ نَفْسٍ فَأَنَا حَجِيجُهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], telah menceritakan kepadaku [Abu Shakhr Al Madini] bahwa [Shafwan bin Sulaim] telah mengabarkan kepadanya dari [beberapa anak para sahabat Rasulullah shallallahu 'alaihi wasallam], dari [bapak-bapak mereka] dari Rasulullah shallallahu 'alaihi wasallam, beliau berkata: \"Ketahuilah bahwa orang yang menzhalimi orang kafir yang menjalin perjanjian dengan Islam atau mengurangi haknya atau membebaninya di atas kemampuannya atau mengambil darinya sesuatu yang ia relakan maka aku adalah orang yang akan membelanya pada Hari Kiamat.\""},"2582":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ عَنْ جَرِيرٍ عَنْ قَابُوسَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى الْمُسْلِمِ جِزْيَةٌحَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ سُئِلَ سُفْيَانُ عَنْ تَفْسِيرِ هَذَا فَقَالَ إِذَا أَسْلَمَ فَلَا جِزْيَةَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Al Jarrah], dari [Jarir] dari [Qabus] dari [ayahnya], dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang muslim tidak wajib membayar jizyah.\" Telah menceritakan kepada kami Muhammad bin Katsir, ia berkata; Sufyan ditanya mengenai tafsir hadits ini, kemudian ia berkata; apabila ia telah masuk Islam maka tidak wajib ia membayar jizyah."},"2583":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ زَيْدٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ الْهَوْزَنِيُّ قَالَلَقِيتُ بِلَالًا مُؤَذِّنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَلَبَ فَقُلْتُ يَا بِلَالُ حَدِّثْنِي كَيْفَ كَانَتْ نَفَقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا كَانَ لَهُ شَيْءٌ كُنْتُ أَنَا الَّذِي أَلِي ذَلِكَ مِنْهُ مُنْذُ بَعَثَهُ اللَّهُ إِلَى أَنْ تُوُفِّيَ وَكَانَ إِذَا أَتَاهُ الْإِنْسَانُ مُسْلِمًا فَرَآهُ عَارِيًا يَأْمُرُنِي فَأَنْطَلِقُ فَأَسْتَقْرِضُ فَأَشْتَرِي لَهُ الْبُرْدَةَ فَأَكْسُوهُ وَأُطْعِمُهُ حَتَّى اعْتَرَضَنِي رَجُلٌ مِنْ الْمُشْرِكِينَ فَقَالَ يَا بِلَالُ إِنَّ عِنْدِي سَعَةً فَلَا تَسْتَقْرِضْ مِنْ أَحَدٍ إِلَّا مِنِّي فَفَعَلْتُ فَلَمَّا أَنْ كَانَ ذَاتَ يَوْمٍ تَوَضَّأْتُ ثُمَّ قُمْتُ لِأُؤَذِّنَ بِالصَّلَاةِ فَإِذَا الْمُشْرِكُ قَدْ أَقْبَلَ فِي عِصَابَةٍ مِنْ التُّجَّارِ فَلَمَّا أَنْ رَآنِي قَالَ يَا حَبَشِيُّ قُلْتُ يَا لَبَّاهُ فَتَجَهَّمَنِي وَقَالَ لِي قَوْلًا غَلِيظًا وَقَالَ لِي أَتَدْرِي كَمْ بَيْنَكَ وَبَيْنَ الشَّهْرِ قَالَ قُلْتُ قَرِيبٌ قَالَ إِنَّمَا بَيْنَكَ وَبَيْنَهُ أَرْبَعٌ فَآخُذُكَ بِالَّذِي عَلَيْكَ فَأَرُدُّكَ تَرْعَى الْغَنَمَ كَمَا كُنْتَ قَبْلَ ذَلِكَ فَأَخَذَ فِي نَفْسِي مَا يَأْخُذُ فِي أَنْفُسِ النَّاسِ حَتَّى إِذَا صَلَّيْتُ الْعَتَمَةَ رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَهْلِهِ فَاسْتَأْذَنْتُ عَلَيْهِ فَأَذِنَ لِي فَقُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي إِنَّ الْمُشْرِكَ الَّذِي كُنْتُ أَتَدَيَّنُ مِنْهُ قَالَ لِي كَذَا وَكَذَا وَلَيْسَ عِنْدَكَ مَا تَقْضِي عَنِّي وَلَا عِنْدِي وَهُوَ فَاضِحِي فَأْذَنْ لِي أَنْ آبَقَ إِلَى بَعْضِ هَؤُلَاءِ الْأَحْيَاءِ الَّذِينَ قَدْ أَسْلَمُوا حَتَّى يَرْزُقَ اللَّهُ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَقْضِي عَنِّي فَخَرَجْتُ حَتَّى إِذَا أَتَيْتُ مَنْزِلِي فَجَعَلْتُ سَيْفِي وَجِرَابِي وَنَعْلِي وَمِجَنِّي عِنْدَ رَأْسِي حَتَّى إِذَا انْشَقَّ عَمُودُ الصُّبْحِ الْأَوَّلِ أَرَدْتُ أَنْ أَنْطَلِقَ فَإِذَا إِنْسَانٌ يَسْعَى يَدْعُو يَا بِلَالُ أَجِبْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ حَتَّى أَتَيْتُهُ فَإِذَا أَرْبَعُ رَكَائِبَ مُنَاخَاتٌ عَلَيْهِنَّ أَحْمَالُهُنَّ فَاسْتَأْذَنْتُ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْشِرْ فَقَدْ جَاءَكَ اللَّهُ بِقَضَائِكَ ثُمَّ قَالَ أَلَمْ تَرَ الرَّكَائِبَ الْمُنَاخَاتِ الْأَرْبَعَ فَقُلْتُ بَلَى فَقَالَ إِنَّ لَكَ رِقَابَهُنَّ وَمَا عَلَيْهِنَّ فَإِنَّ عَلَيْهِنَّ كِسْوَةً وَطَعَامًا أَهْدَاهُنَّ إِلَيَّ عَظِيمُ فَدَكَ فَاقْبِضْهُنَّ وَاقْضِ دَيْنَكَ فَفَعَلْتُ فَذَكَرَ الْحَدِيثَ ثُمَّ انْطَلَقْتُ إِلَى الْمَسْجِدِ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌ فِي الْمَسْجِدِ فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَا فَعَلَ مَا قِبَلَكَ قُلْتُ قَدْ قَضَى اللَّهُ كُلَّ شَيْءٍ كَانَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَبْقَ شَيْءٌ قَالَ أَفَضَلَ شَيْءٍ قُلْتُ نَعَمْ قَالَ انْظُرْ أَنْ تُرِيحَنِي مِنْهُ فَإِنِّي لَسْتُ بِدَاخِلٍ عَلَى أَحَدٍ مِنْ أَهْلِي حَتَّى تُرِيحَنِي مِنْهُ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَتَمَةَ دَعَانِي فَقَالَ مَا فَعَلَ الَّذِي قِبَلَكَ قَالَ قُلْتُ هُوَ مَعِي لَمْ يَأْتِنَا أَحَدٌ فَبَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ وَقَصَّ الْحَدِيثَ حَتَّى إِذَا صَلَّى الْعَتَمَةَ يَعْنِي مِنْ الْغَدِ دَعَانِي قَالَ مَا فَعَلَ الَّذِي قِبَلَكَ قَالَ قُلْتُ قَدْ أَرَاحَكَ اللَّهُ مِنْهُ يَا رَسُولَ اللَّهِ فَكَبَّرَ وَحَمِدَ اللَّهَ شَفَقًا مِنْ أَنْ يُدْرِكَهُ الْمَوْتُ وَعِنْدَهُ ذَلِكَ ثُمَّ اتَّبَعْتُهُ حَتَّى إِذَا جَاءَ أَزْوَاجَهُ فَسَلَّمَ عَلَى امْرَأَةٍ امْرَأَةٍ حَتَّى أَتَى مَبِيتَهُ فَهَذَا الَّذِي سَأَلْتَنِي عَنْهُحَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُعَاوِيَةُ بِمَعْنَى إِسْنَادِ أَبِي تَوْبَةَ وَحَدِيثِهِ قَالَ عِنْدَ قَوْلِهِ مَا يَقْضِي عَنِّي فَسَكَتَ عَنِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاغْتَمَزْتُهَا","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'], telah menceritakan kepada kami [Mu'awiyah bin Sallam], dari [Zaid] bahwa ia mendengar [Abu Sallam] berkata; telah menceritakan kepadaku [Abdullah Al Hauzani] ia berkata; aku bertemu [Bilal] tukang adzan Rasulullah shallallahu 'alaihi wasallam di Jalab, kemudian aku katakan; wahai Bilal, ceritakan kepadaku bagaimana nafkah Rasulullah shallallahu 'alaihi wasallam! Ia berkata; beliau tidak memiliki sesuatu maka aku yang mengurusi hal tersebut sejak Allah mengutusnya hingga beliau meninggal, apabila ada seorang muslim yang datang kepadanya dan beliau melihatnya dalam keadaan telanjang maka beliau memberiku perintah, maka aku pergi dan mencari hutangan, dan membelikan baju untuknya dan memberinya pakaian serta memberinya makan hingga seorang musyrik menemuiku dan berkata; wahai Bilal, sesungguhnya aku memiliki kelapangan, maka janganlah engkau berhutang kecuali kepadaku. Kemudian aku melakukannya, tatkala pada suatu hari aku berwudhu kemudian aku pergi untuk melakukan adzan shalat. Ternyata terdapat seorang musyrik datang diantara sekelompok pedagang. Kemudian tatkala ia melihatku, ia berkata; wahai orang habasyah! Aku katakan; ya, ada apa? Kemudian orang musyrik bermuka masam kepadaku, dan berkata kepadaku dengan perkataan yang kasar. Ia berkata; tahukah engkau berapa jarak antara dirimu dan antara bulan ini? Aku katakan; dekat. Ia berkata; sesungguhnya antaramu dan antara bulan ini ada empat malam. Aku akan menuntutmu dengan sesuatu yang menjadi tanggunganmu. Aku akan mengembalikanmu menggembala kambing sebagaimana engkau sebelum itu. Maka aku tidak menyukai sebagaima orang-orang tidak menyukai hingga tatkala aku melakukan shalat Isya`, Rasulullah shallallahu 'alaihi wasallam kembali kepada keluarganya. Lalu aku meminta izin kepada untuk menemui beliau. Kemudian beliau memberiku izin, lalu aku katakan; wahai Rasulullah, sesungguhnya orang musyrik yang aku hutangi berkata kepadaku demikian dan demikian. Sementara anda tidak memiliki sesuatu yang dapat menunaikan untukku, dan akupun tidak memiliki sesuatu. Hal tersebut mencemarkan diriku, maka izinkan saya untuk melarikan diri kepada beberapa kampung yang telah masuk Islam hingga Allah memberikan rizqi yang dapat membayar hutangku. Kemudian aku keluar hingga aku datang ke tempat tinggalku, dan aku letakkan pedang, geriba, sandal dan baju tamengku di atas kepala hingga fajar pertama menyingsing aku hendak pergi. Tiba-tiba terdapat seseorang yang berlari-lari kecil dan memanggil; wahai Bilal, sambutlah seruan Rasulullah shallallahu 'alaihi wasallam! Kemudian aku pergi hingga setelah aku datang kepadanya ternyata terdapat empat unta yang diderumkan, di atasnya terdapat barang bawaannya. Kemudian aku meminta izin. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Bergembiralah, Allah telah datang kepadamu dengan membawa pembayaran hutangmu.\" Kemudian beliau berkata: \"Bukankah engkau melihat empat unta yang diderumkan?\" aku katakan; benar. Beliau berkata; \"Sesungguhnya untukmu unta-unta tersebut dan apa yang ada di atasnya, sesungguhnya di atasnya terdapat pakaian, dan makanan yang telah dihadiahkan kepadaku oleh pemimpin Fadak. Ambillah dan bayarlah hutangmu!\" kemudian aku melakukannya. Lalu ia menyebutkan hadits tersebut kemudian aku pergi ke masjid, ternyata Rasulullah shallallahu 'alaihi wasallam sedang duduk di masjid. Lalu aku mengucapkan salam kepada beliau. Lalu beliau berkata: \"Bagaiamana keadaan yang ada padamu?\" Aku katakan; Allah telah membayarkan segala sesuatu yang menjadi tanggungan Rasulullah shallallahu 'alaihi wasallam, tidak ada sesuatupun yang tersisa. Beliau berkata: \"Apakah ada yang sebagian yang tersisa?\" aku katakan; ya. beliau berkata: \"Berusahalah untuk membuatku tenang dan lihatlah sebab-sebab untuk membuatku tenang! Sesungguhnya aku tidak akan menemui seorangpun dari keluargaku hingga engkau menenangkan diriku darinya.\" Kemudian tatkala Rasulullah shallallahu 'alaihi wasallam telah melakukan Shalat 'Isya`, beliau memanggilku dan berkata: \"Bagaimana keadaan yang ada padamu?\" Aku katakan; masih ada padaku, belum ada seorangpun yang datang kepada saya. kemudian Rasulullah shallallahu 'alaihi wasallam bermalam di masjid. -Dan ia menceritakan hadits tersebut- hingga ketika beliau telah melakukan Shalat 'Isya` keesokan harinya, beliau memanggilku dan berkata: \"\"Bagaimana keadaan yang ada padamu?\" Bilal berkata; sungguh Allah telah menenangkan anda darinya wahai Rasulullah! Beliau bertakbir dan memuji Allah, karena khawatir kematian menjemputnya sementara hal tersebut masih ada pada beliau. Kemudian aku mengikuti beliau hingga beliau datang kepada para isterinya, lalu beliau mengucapkan salam kepada isterinya satu persatu hingga beliau sampai di tempat beliau bermalam. Inilah yang engkau tanyakan kepadaku. Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Marwan bin Muhammad], telah menceritakan kepada kami [Mu'awiyah] dengan makna sanad Abu Taubah serta haditsnya. Setelah perkataan; (yang dapat membayar hutangku) ia berkata; kemudian Rasulullah shallallahu 'alaihi wasallam diam lalu aku. Maka aku tidak menyukai keadaan demikian itu. "},"2584":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا عِمْرَانُ عَنْ قَتَادَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ عِيَاضِ بْنِ حِمَارٍ قَالَأَهْدَيْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاقَةً فَقَالَ أَسْلَمْتَ فَقُلْتُ لَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي نُهِيتُ عَنْ زَبْدِ الْمُشْرِكِينَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Abu Daud], telah menceritakan kepada kami [Imran], dari [Qatadah], dari [Yazid? bin Abdullah bin Asy Syikhir], dari ['Iyadh bin Himar], ia berkata; aku telah memberi Nabi shallallahu 'alaihi wasallam hadiah seekor unta. Kemudian beliau berkata; apakah engkau telah masuk Islam? Aku katakan; tidak. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku telah dilarang dari menerima pertolongan orang-orang musyrikin.\""},"2585":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ سِمَاكٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْطَعَهُ أَرْضًا بِحَضْرَمُوتَحَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا جَامِعُ بْنُ مَطَرٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ بِإِسْنَادِهِ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Amr bin Marzuq], telah mengabarkan kepada kami [Syu'bah], dari [Simak] dari ['Alqamah bin Wail] dari [ayahnya], bahwa Nabi shallallahu 'alaihi wasallam telah mengalokasikan untuknya lahan di Hadhramaut. Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Jami' bin Mathar], dari ['Alqamah bin Wail] dengan sanadnya seperti itu. "},"2586":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ فِطْرٍ حَدَّثَنِي أَبِي عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَخَطَّ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَارًا بِالْمَدِينَةِ بِقَوْسٍ وَقَالَ أَزِيدُكَ أَزِيدُكَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdullah bin Daud] dari [Fithr], telah menceritakan kepadaku [ayahku] dari ['Amr bin Huraits], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah menggambarkan untukku sebuah rumah di Madina, dan beliau berkata; aku akan menambahkan untumu, aku akan menambahkan untukmu. "},"2587":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ مُحَمَّدِ بْنِ حَاتِمٍ وَغَيْرُهُ قَالَ الْعَبَّاسُ حَدَّثَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ أَخْبَرَنَا أَبُو أُوَيْسٍ حَدَّثَنَا كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ الْمُزَنِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْطَعَ بِلَالَ بْنَ الْحَارِثِ الْمُزَنِيَّ مَعَادِنَ الْقَبَلِيَّةِ جَلْسِيَّهَا وَغَوْرِيَّهَا وَقَالَ غَيْرُهُ جَلْسَهَا وَغَوْرَهَا وَحَيْثُ يَصْلُحُ الزَّرْعُ مِنْ قُدْسٍ وَلَمْ يُعْطِهِ حَقَّ مُسْلِمٍ وَكَتَبَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ هَذَا مَا أَعْطَى مُحَمَّدٌ رَسُولُ اللَّهِ بِلَالَ بْنَ الْحَارِثِ الْمُزَنِيَّ أَعْطَاهُ مَعَادِنَ الْقَبَلِيَّةِ جَلْسِيَّهَا وَغَوْرِيَّهَا وَقَالَ غَيْرُهُ جَلْسَهَا وَغَوْرَهَا وَحَيْثُ يَصْلُحُ الزَّرْعُ مِنْ قُدْسٍ وَلَمْ يُعْطِهِ حَقَّ مُسْلِمٍقَالَ أَبُو أُوَيْسٍ وَحَدَّثَنِي ثَوْرُ بْنُ زَيْدٍ مَوْلَى بَنِي الدِّيْلِ بْنِ بَكْرِ بْنِ كِنَانَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Al Abbas bin Muhammad bin Hatim], dan yang lainnya, Al Abbas berkata; telah menceritakan kepada kami [Al Husain bin Muhammad], telah mengabarkan kepada kami [Abu Uwais], telah menceritakan kepada kami [Katsir bin Abudullah bin 'Auf Al Muzni], dari [ayahnya] dari [kakeknya], bahwa Nabi shallallahu 'alaihi wasallam telah mengalokasikan untuk Bilal bin Al Harits Al Muzani tambang Al Qabiliyyah, dataran yang tinggi dan yang rendah. Dan tempat yang layak untuk ditanami dari lahan Quds dan beliau tidak memberikan kepadanya hak seorang muslim. Abu Uwais berkata; dan telah menceritakan kepadaku [Tsaur bin Zaid] mantan budak Bani Ad Dalil bin Bakr bin Kinanah, dari [Ikrimah] dari [Ibnu Abbas] seperti itu. "},"2588":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ النَّضْرِ قَالَ سَمِعْتُ الْحُنَيْنِيَّ قَالَ قَرَأْتُهُ غَيْرَ مَرَّةٍ يَعْنِي كِتَابَ قَطِيعَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد و حَدَّثَنَا غَيْرُ وَاحِدٍ عَنْ حُسَيْنِ بْنِ مُحَمَّدٍ أَخْبَرَنَا أَبُو أُوَيْسٍ حَدَّثَنِي كَثِيرُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْطَعَ بِلَالَ بْنَ الْحَارِثِ الْمُزَنِيَّ مَعَادِنَ الْقَبَلِيَّةِ جَلْسِيَّهَا وَغَوْرِيَّهَا قَالَ ابْنُ النَّضْرِ وَجَرْسَهَا وَذَاتَ النُّصُبِ ثُمَّ اتَّفَقَا وَحَيْثُ يَصْلُحُ الزَّرْعُ مِنْ قُدْسٍ وَلَمْ يُعْطِ بِلَالَ بْنَ الْحَارِثِ حَقَّ مُسْلِمٍ وَكَتَبَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا مَا أَعْطَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالَ بْنَ الْحَارِثِ الْمُزَنِيَّ أَعْطَاهُ مَعَادِنَ الْقَبَلِيَّةِ جَلْسَهَا وَغَوْرَهَا وَحَيْثُ يَصْلُحُ الزَّرْعُ مِنْ قُدْسٍ وَلَمْ يُعْطِهِ حَقَّ مُسْلِمٍقَالَ أَبُو أُوَيْسٍ وَحَدَّثَنِي ثَوْرُ بْنُ زَيْدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ زَادَ ابْنُ النَّضْرِ وَكَتَبَ أُبَيُّ بْنُ كَعْبٍ","id":"Telah menceritakan kepada kami [Muhammad bin An Nadhir], ia berkata; saya telah mendengar [Al Hunaini] berkata; aku telah membacakannya tidak hanya sekali yaitu surat pengalokasian Nabi shallallahu 'alaihi wasallam. Abu Daud berkata; dan telah menceritakan kepada kami [lebih dari satu orang], dari [Husain bin Muhammad], telah mengabarkan kepada kami [Abu Uwais], telah menceritakan kepadaku [Katsir bin Abdullah] dari [ayahnya], dari [kakeknya], bahwa Nabi shallallahu 'alaihi wasallam telah mengalokasikan untuk Bilal bin Al Harits Al Muzani tambang Al Qabiliyyah, Jarsh. -Ibnu An Nadhr berkata; dan dataran tingginya serta Dzatu An Nushub. Kemudian lafazh mereka berdua sama: Dan tempat yang layak untuk ditanami dari lahan Quds dan beliau tidak memberikan kepada Bilal bin Al Harits hak seorang muslim. Nabi shallallahu 'alaihi wasallam menuliskan surat; ini adalah apa yang Rasulullah shallallahu 'alaihi wasallam berikan kepada Bilal bin Al Harits Al Muzani. Beliau telah memberikan kepadanya tambang Al Qabiliyyah daerah yang tinggi dan yang rendah Dan tempat yang layak untuk ditanami dari lahan Quds dan beliau tidak memberikan kepadanya hak seorang muslim. Abu Uwais berkata; dan telah menceritakan kepadaku [Tsaur bin Zaid], dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti itu. Ibnu An Nadhr menambahkan, dan Ubai bin Ka'b telah menuliskan hal tersebut. "},"2589":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ الثَّقَفِيُّ وَمُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ الْمَعْنَى وَاحِدٌ أَنَّ مُحَمَّدَ بْنَ يَحْيَى بْنِ قَيْسٍ الْمَأْرِبِيَّ حَدَّثَهُمْ أَخْبَرَنِي أَبِي عَنْ ثُمَامَةَ بْنِ شَرَاحِيلَ عَنْ سُمَيِّ بْنِ قَيْسٍ عَنْ شُمَيْرٍ قَالَ ابْنُ الْمُتَوَكِّلِ ابْنِ عَبْدِ الْمَدَانِ عَنْ أَبْيَضَ بْنِ حَمَّالٍأَنَّهُ وَفَدَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَقْطَعَهُ الْمِلْحَ قَالَ ابْنُ الْمُتَوَكِّلِ الَّذِي بِمَأْرِبَ فَقَطَعَهُ لَهُ فَلَمَّا أَنْ وَلَّى قَالَ رَجُلٌ مِنْ الْمَجْلِسِ أَتَدْرِي مَا قَطَعْتَ لَهُ إِنَّمَا قَطَعْتَ لَهُ الْمَاءَ الْعِدَّ قَالَ فَانْتَزَعَ مِنْهُ قَالَ وَسَأَلَهُ عَمَّا يُحْمَى مِنْ الْأَرَاكِ قَالَ مَا لَمْ تَنَلْهُ خِفَافٌ وَقَالَ ابْنُ الْمُتَوَكِّلِ أَخْفَافُ الْإِبِلِحَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ قَالَ مُحَمَّدُ بْنُ الْحَسَنِ الْمَخْزُومِيُّ مَا لَمْ تَنَلْهُ أَخْفَافُ الْإِبِلِ يَعْنِي أَنَّ الْإِبِلَ تَأْكُلُ مُنْتَهَى رُءُوسِهَا وَيُحْمَى مَا فَوْقَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id Ats Tsaqafi] dan [Muhammad bin Al Mutawakkil Al 'Asqalani] dan maknanya satu, bahwa [Muhammad bin Yahya bin Qais Al Ma`ribi] telah menceritakan kepada mereka; telah mengabarkan kepadaku [ayahku] dari [Tsumamah bin Syarahil] dari [Sumai bin Qais] dari [Syumair], Ibnu Al Mutawakkilberkata; Ibnu Abdul Madan dari [Abyadh bin Hammal] bahwa ia menjadi utusan kepada Rasulullah shallallahu 'alaihi wasallam, kemudian ia meminta garam. Ibnu Al Mutawakkil berkata; yang ada di Ma`rib. Kemudian ia memotong untuknya. kemudian tatkala ia pergi, seseorang yang berasal dari majelis tersebut berkata; tahukah anda apa yang anda berikan kepadanya? sesungguhnya anda telah memberikan kepadanya air terus mengalir. Ibnu Al Mutawakkil berkata; kemudian beliau mengambil darinya. Kemudian ia bertanya kepada beliau mengenai apa yang dilindungi dari pohon Arok? Beliau berkata: \"Apa yang tidak mampu dicapai oleh kuku unta.\" Ibnu Al Mutawakkil berkata; kuku-kuku unta. Telah menceritakan kepadaku Harun bin Abdullah ia berkata; Muhammd bin Al Hasan Al Makhzumi berkata; apa yang tidak dicapai kuku unta, yaitu bahwa unta memakan sepanjang yang dapat dicapai kepalanya dan yang di atasnya terlindungi. "},"2590":{"ar":"حَدَّثَنَا عُمَرُ بْنُ الْخَطَّابِ أَبُو حَفْصٍ حَدَّثَنَا الْفِرْيَابِيُّ حَدَّثَنَا أَبَانُ قَالَ عُمَرُ وَهُوَ ابْنُ عَبْدِ اللَّهِ بْنِ أَبِي حَازِمٍ قَالَ حَدَّثَنِي عُثْمَانُ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ صَخْرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا ثَقِيفًا فَلَمَّا أَنْ سَمِعَ ذَلِكَ صَخْرٌ رَكِبَ فِي خَيْلٍ يُمِدُّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ انْصَرَفَ وَلَمْ يَفْتَحْ فَجَعَلَ صَخْرٌ يَوْمَئِذٍ عَهْدَ اللَّهِ وَذِمَّتَهُ أَنْ لَا يُفَارِقَ هَذَا الْقَصْرَ حَتَّى يَنْزِلُوا عَلَى حُكْمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُفَارِقْهُمْ حَتَّى نَزَلُوا عَلَى حُكْمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَتَبَ إِلَيْهِ صَخْرٌ أَمَّا بَعْدُ فَإِنَّ ثَقِيفًا قَدْ نَزَلَتْ عَلَى حُكْمِكَ يَا رَسُولَ اللَّهِ وَأَنَا مُقْبِلٌ إِلَيْهِمْ وَهُمْ فِي خَيْلٍ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّلَاةِ جَامِعَةً فَدَعَا لِأَحْمَسَ عَشْرَ دَعَوَاتٍ اللَّهُمَّ بَارِكْ لِأَحْمَسَ فِي خَيْلِهَا وَرِجَالِهَا وَأَتَاهُ الْقَوْمُ فَتَكَلَّمَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ صَخْرًا أَخَذَ عَمَّتِي وَدَخَلَتْ فِيمَا دَخَلَ فِيهِ الْمُسْلِمُونَ فَدَعَاهُ فَقَالَ يَا صَخْرُ إِنَّ الْقَوْمَ إِذَا أَسْلَمُوا أَحْرَزُوا دِمَاءَهُمْ وَأَمْوَالَهُمْ فَادْفَعْ إِلَى الْمُغِيرَةِ عَمَّتَهُ فَدَفَعَهَا إِلَيْهِ وَسَأَلَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لِبَنِي سُلَيْمٍ قَدْ هَرَبُوا عَنْ الْإِسْلَامِ وَتَرَكُوا ذَلِكَ الْمَاءَ فَقَالَ يَا نَبِيَّ اللَّهِ أَنْزِلْنِيهِ أَنَا وَقَوْمِي قَالَ نَعَمْ فَأَنْزَلَهُ وَأَسْلَمَ يَعْنِي السُّلَمِيِّينَ فَأَتَوْا صَخْرًا فَسَأَلُوهُ أَنْ يَدْفَعَ إِلَيْهِمْ الْمَاءَ فَأَبَى فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا نَبِيَّ اللَّهِ أَسْلَمْنَا وَأَتَيْنَا صَخْرًا لِيَدْفَعَ إِلَيْنَا مَاءَنَا فَأَبَى عَلَيْنَا فَأَتَاهُ فَقَالَ يَا صَخْرُ إِنَّ الْقَوْمَ إِذَا أَسْلَمُوا أَحْرَزُوا أَمْوَالَهُمْ وَدِمَاءَهُمْ فَادْفَعْ إِلَى الْقَوْمِ مَاءَهُمْ قَالَ نَعَمْ يَا نَبِيَّ اللَّهِ فَرَأَيْتُ وَجْهَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَغَيَّرُ عِنْدَ ذَلِكَ حُمْرَةً حَيَاءً مِنْ أَخْذِهِ الْجَارِيَةَ وَأَخْذِهِ الْمَاءَ","id":"Telah menceritakan kepada kami [Umar bin Al Khathab Abu Hafsh], telah menceritakan kepada kami [Al Firyabi] telah menceritakan kepada kami [Aban], Umar berkata; ia adalah Ibnu Abdullah bin Abu Hazin, ia berkata; telah menceritakan kepadaku, [Utsman bin Abu Hazin] dari [ayahnya] dari [kakeknya yaitu Shakhr] bahwa Rasulullah shallallahu 'alaihi wasallam memerangi Tsaqif, kemudian tatkala Shakh mendengar hal tersebut ia mengendarai kudanya menuju kepada Nabi shallallahu 'alaihi wasallam, kemudian ia mendapati Nabi shallallahu 'alaihi wasallam telah pergi, dan tidak menaklukkan Tsaqif. Kemudian pada saat itu ia menjadikan janji Allah untuk tidak meninggalkan benteng ini hingga mereka turun kepada hukum Rasulullah shallallahu 'alaihi wasallam. Kemudian Shakhr menulis surat kepadanya; sesungguhnya Tsaqif telah menyerahkan kepada hukummu wahai Rasulullah, dan aku datang kepada mereka, sementara mereka berada dalam pasukan berkuda. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahan agar melakukan shalat berjama'ah. Kemudian beliau berdoa untuk Ahmas sepuluh kali doa: \"Ya Allah, berkahilah untuk Ahmas pada kudanya dan para penunggangnya.\" Kemudian orang-orang tersebut datang kepada beliau, lalu Al Mughirah bin Syu'bah berbicara. Ia berkata; wahai nabi Allah, sesungguhnya Shakhr telah mengambil bibiku, sementara ia telah memasuki apa yang dimasuki orang-orang muslim. Kemudian beliau memanggil Shakhr dan berkata: \"Wahai Shakhr, sesungguhnya sebuah kaum, apabila telah masuk Islam maka mereka melindungi darah mereka dan harta mereka, maka serahkan bibi Al Mughirah kepadanya!\" kemudian ia menyerahkannya kepada Al Mughirah. Dan Nabi shallallahu 'alaihi wasallam bertanya mengapa orang-orang Bani Sulaim lari dari Islam dan meninggalkan air tersebut? Kemudian Al Mughirah berkata; wahai Nabi Allah, serahkan hal tesebut kepadaku dan kepada kaumku. Beliau bekata; ya. lalu beliau menyerahkn kepadanya, dn orang Bani Sulaim masuk Islam. Lalu mereka datang kepada Shakhr, dan meminta kepadanya agar menyerahkan kepada mereka mata air tersebut, namun ia menolak. Kemudian mereka datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Nabi Allah, kami telah masuk Islam, mereka telah melindungi harta mereka dan darah mereka. Maka serahkan kepada orang-orang tersebut mata air mereka! Beliau berkata: \"Ya.\" kemudian aku melihat wajah Rasulullah shallallahu 'alaihi wasallam berubah pada saat itu memerah karena rasa malu telah mengambil budak wanita dan mata air. "},"2591":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي سَبْرَةُ بْنُ عَبْدِ الْعَزِيزِ بْنِ الرَّبِيعِ الْجُهَنِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ فِي مَوْضِعِ الْمَسْجِدِ تَحْتَ دَوْمَةٍ فَأَقَامَ ثَلَاثًا ثُمَّ خَرَجَ إِلَى تَبُوكَ وَإِنَّ جُهَيْنَةَ لَحِقُوهُ بِالرَّحْبَةِ فَقَالَ لَهُمْ مَنْ أَهْلُ ذِي الْمَرْوَةِ فَقَالُوا بَنُو رِفَاعَةَ مِنْ جُهَيْنَةَ فَقَالَ قَدْ أَقْطَعْتُهَا لِبَنِي رِفَاعَةَ فَاقْتَسَمُوهَا فَمِنْهُمْ مَنْ بَاعَ وَمِنْهُمْ مَنْ أَمْسَكَ فَعَمِلَثُمَّ سَأَلْتُ أَبَاهُ عَبْدَ الْعَزِيزِ عَنْ هَذَا الْحَدِيثِ فَحَدَّثَنِي بِبَعْضِهِ وَلَمْ يُحَدِّثْنِي بِهِ كُلِّهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], telah menceritakan kepadaku [Sabrah bin Abdul Aziz bin Ar Rabi' Al Juhani], dari [ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam singgah di suatu tempat di masjid di bawah Daumah. Lalu beliau tinggal selama tiga hari kemudian keluar menuju Tabut. Dan orang-orang Juhainah menyusul beliau di Rahbah, kemudian beliau berkata kepada mereka; \"Siapakah yang merupakan penduduk Dzul Marwah?\" kemudian mereka berkata; Banu Rifa'ah dari Juhainah. Kemudian beliau berkata: \"Aku telah mengalokasikannya untuk Bani Rifa'ah, maka bagilah.\" Lalu diantara mereka ada yang menjual bagiannya dan diantara mereka ada yang menahannya dan mengerjakannya. Kemudian aku bertanya kepada ayahnya yaitu Abdul Aziz mengenai hadits ini. Kemudian ia menceritakan sebagiannya kepadaku, dan tidak menceritakan seluruhnya. "},"2592":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُوسَى بْنُ إِسْمَعِيلَ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ حَسَّانَ الْعَنْبَرِيُّ حَدَّثَتْنِي جَدَّتَايَ صَفِيَّةُ وَدُحَيْبَةُ ابْنَتَا عُلَيْبَةَ وَكَانَتَا رَبِيبَتَيْ قَيْلَةَ بِنْتِ مَخْرَمَةَ وَكَانَتْ جَدَّةَ أَبِيهِمَا أَنَّهَا أَخْبَرَتْهُمَا قَالَتْقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ تَقَدَّمَ صَاحِبِي تَعْنِي حُرَيْثَ بْنَ حَسَّانَ وَافِدَ بَكْرِ بْنِ وَائِلٍ فَبَايَعَهُ عَلَى الْإِسْلَامِ عَلَيْهِ وَعَلَى قَوْمِهِ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ اكْتُبْ بَيْنَنَا وَبَيْنَ بَنِي تَمِيمٍ بِالدَّهْنَاءِ أَنْ لَا يُجَاوِزَهَا إِلَيْنَا مِنْهُمْ أَحَدٌ إِلَّا مُسَافِرٌ أَوْ مُجَاوِرٌ فَقَالَ اكْتُبْ لَهُ يَا غُلَامُ بِالدَّهْنَاءِ فَلَمَّا رَأَيْتُهُ قَدْ أَمَرَ لَهُ بِهَا شُخِصَ بِي وَهِيَ وَطَنِي وَدَارِي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُ لَمْ يَسْأَلْكَ السَّوِيَّةَ مِنْ الْأَرْضِ إِذْ سَأَلَكَ إِنَّمَا هِيَ هَذِهِ الدَّهْنَاءُ عِنْدَكَ مُقَيَّدُ الْجَمَلِ وَمَرْعَى الْغَنَمِ وَنِسَاءُ بَنِي تَمِيمٍ وَأَبْنَاؤُهَا وَرَاءَ ذَلِكَ فَقَالَ أَمْسِكْ يَا غُلَامُ صَدَقَتْ الْمِسْكِينَةُ الْمُسْلِمُ أَخُو الْمُسْلِمِ يَسَعُهُمَا الْمَاءُ وَالشَّجَرُ وَيَتَعَاوَنَانِ عَلَى الْفَتَّانِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], dan [Musa bin Isma'il] secara makna adalah satu. Mereka berkata; telah menceritakan kepada kami [Abdullah bin Hassan Al 'Anbari] telah menceritakan kepadaku kedua nenekku yaitu [Shafiyyah] dan [Duhaibah] dua anak wanita 'Ulaibah. Dan mereka berdua adalah dua anak asuh [Qailah binti Makhramah], dan ia adalah nenek ayah mereka berdua, bahwa ia telah mengabarkan kepada mereka berdua, ia berkata; kami datang kepada Rasulullah shallallahu 'alaihi wasallam, kemudian sahabatku yaitu Huraits bin Hassan utusan Bakr bin Wail maju ke depan, kemudian beliau membai'atnya ia dan kaumnya harus berada di atas Islam. Kemudian ia berkata; wahai Rasulullah, tulislah antara kami dan Bani Tamim di Ad Dahna` di Ad Dahna` agar tidak ada seorangpun yang melampauinya kepada kami kecuali orang musafir atau orang yang bertetangga. Kemudian beliau berkata: \"Tuliskan untuknya wahai pembantu, di Ad Dahnah`, bahwa tidak ada menewatinya menuju kepada kami seorang pun diantara mereka kecuali orang y ang bersafar, atau orang yang bertetangga.\" Kemudian tatkala aku melihat beliau memerintahkan agar menuliskan hal tersebut maka aku merasa gelisah, Ad Dahna` adalah negeriku dan tempat tinggalku. Kemudian aku katakan; wahai Rasulullah, sesungguhnya ia tidak meminta kepadamu tanah datarketika ia meminta kepadamu. Sesungguhnya Ad Dahna` ini adalah tempat mengikat unta serta tempat menggembala kambing, sementara para wanita Bani Tamim dan anak-anak mereka di belakang perjanjian tersebut. Kemudian beliau berkata; tahan wahai pelayan. Wanita miskin (yaitu Qailah) itu benar, seorang muslim adalah saudara muslim yang lain, mereka berdua boleh mengambil air dan pohon serta mereka berdua saling tolang menolong melawan pembawa fitnah. "},"2593":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنِي عَبْدُ الْحَمِيدِ بْنُ عَبْدِ الْوَاحِدِ حَدَّثَتْنِي أُمُّ جَنُوبٍ بِنْتُ نُمَيْلَةَ عَنْ أُمِّهَا سُوَيْدَةَ بِنْتِ جَابِرٍ عَنْ أُمِّهَا عَقِيلَةَ بِنْتِ أَسْمَرَ بْنِ مُضَرِّسٍ عَنْ أَبِيهَا أَسْمَرَ بْنِ مُضَرِّسٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْتُهُ فَقَالَ مَنْ سَبَقَ إِلَى مَاءٍ لَمْ يَسْبِقْهُ إِلَيْهِ مُسْلِمٌ فَهُوَ لَهُ قَالَ فَخَرَجَ النَّاسُ يَتَعَادَوْنَ يَتَخَاطُّونَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepadaku [Abdul Hamid bin Abdul Wahid] telah menceritakan kepadaku [ummu Janub ninti Numailah] dari [Ibunya yaitu Suadah binti Jabir], dari [Ibunya yaitu 'Aqilah binti Asmar bin Mudharris] dari [ayahnya yaitu Asmar bin Mudharris] ia berkata; aku datang kepada Nabi shallallahu 'alaihi wasallam kemudian kami membai'atnya. Kemudian beliau berkata: \"Barang siapa mendahului menuju sebuah mata air yang belum di dahului seorang muslimpun, maka air tersebut adalah miliiknya.\" Ia berkata; kemudian orang-orang saling mendahului. "},"2594":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْطَعَ الزُّبَيْرَ حُضْرَ فَرَسِهِ فَأَجْرَى فَرَسَهُ حَتَّى قَامَ ثُمَّ رَمَى بِسَوْطِهِ فَقَالَ أَعْطُوهُ مِنْ حَيْثُ بَلَغَ السَّوْطُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Hammad bin Khalid] dari [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam telah mengalokasikan untuk Az Zubair Hudhru Farasih. Kemudian beliau menjalankan kudanya hingga berdiri kemudian memanah menggunakan busurnya dan berkata; berikan kepadanya sejauh jarak yang dicapai busur ini. "},"2595":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحْيَا أَرْضًا مَيْتَةً فَهِيَ لَهُ وَلَيْسَ لِعِرْقٍ ظَالِمٍ حَقٌّحَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ إِسْحَقَ عَنْ يَحْيَى بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحْيَا أَرْضًا مَيْتَةً فَهِيَ لَهُ وَذَكَرَ مِثْلَهُ قَالَ فَلَقَدْ خَبَّرَنِي الَّذِي حَدَّثَنِي هَذَا الْحَدِيثَ أَنَّ رَجُلَيْنِ اخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَرَسَ أَحَدُهُمَا نَخْلًا فِي أَرْضِ الْآخَرِ فَقَضَى لِصَاحِبِ الْأَرْضِ بِأَرْضِهِ وَأَمَرَ صَاحِبَ النَّخْلِ أَنْ يُخْرِجَ نَخْلَهُ مِنْهَا قَالَ فَلَقَدْ رَأَيْتُهَا وَإِنَّهَا لَتُضْرَبُ أُصُولُهَا بِالْفُؤُوسِ وَإِنَّهَا لَنَخْلٌ عُمٌّ حَتَّى أُخْرِجَتْ مِنْهَا حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا وَهْبٌ عَنْ أَبِيهِ عَنْ ابْنِ إِسْحَقَ بِإِسْنَادِهِ وَمَعْنَاهُ إِلَّا أَنَّهُ قَالَ عِنْدَ قَوْلِهِ مَكَانَ الَّذِي حَدَّثَنِي هَذَا فَقَالَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَكْثَرُ ظَنِّي أَنَّهُ أَبُو سَعِيدٍ الْخُدْرِيُّ فَأَنَا رَأَيْتُ الرَّجُلَ يَضْرِبُ فِي أُصُولِ النَّخْلِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang menghidupkan lahan yang mati maka lahan tesebut adalah miliknya, tidak ada hak bagi keringat yang zhalim.\" Telah menceritakan kepada kami [Hannad bin As Sari] telah menceritakan kepada kami ['Abdah] dari [Muhammad bin Ishaq] dari [Yahya bin 'Urwah] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Barang siapa yang menghidupkan lahan yang mati maka lahan tesebut adalah miliknya.\" Dan ia menyebutkan sesuatu yang sama dengannya. Ia berkata; sungguh telah telah mengabarkan kepadaku orang yang telah menceritakan kepadaku hadits ini, bahwa dua orang telah memperkarakan kepada Rasulullah shallallahu 'alaihi wasallam. Salah seorang diantara diantara mereka menanam pohon kurma di lahan orang lain. Kemudian beliau memutuskan bahwa orang yang memiliki lahan mendapatkan lahannya dan memerintahkan kepada pemilik pohon kurma agar mengeluarkan pohon kurma dari lahan tersebut. 'Urwah berkata; sungguh aku melihat pohon kurma tersebut akarnya telah ditebang menggunakan kapak. Sesungguhnya pohon kurma tersebut adalah pohon kurma yang sempurna tinggi dan lebatnya. Hingga pohon tersebut telah dikeluarkan darinya. Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi], telah menceritakan kepada kami [Wahb] dari [ayahnya], dari [Ibnu Ishaq] dengan sanad dan maknanya, hanya saja ia mengatakan pada perkataan (di tempat ia menceritakan kepadaku ini); kemudian seorang sahabat Nabi shallallahu 'alaihi wasallam berkata; dan perkiraan kuatku bahwa ia adalah [Abu Sa'id Al Khudri], dan aku melihat seorang laki-laki yang menebang akar pohon kurma. "},"2596":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الْآمُلِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُرْوَةَ قَالَأَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ الْأَرْضَ أَرْضُ اللَّهِ وَالْعِبَادَ عِبَادُ اللَّهِ وَمَنْ أَحْيَا مَوَاتًا فَهُوَ أَحَقُّ بِهِ جَاءَنَا بِهَذَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِينَ جَاءُوا بِالصَّلَوَاتِ عَنْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Al Amuli], telah menceritakan kepada kami [Abdullah bin Utsman], telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan kepada kami [Nafi' bin Umar], dari [Ibnu Abu Mulaikah] dari ['Urwah] ia berkata; aku bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam telah memutuskan bahwa bumi ini adalah bumi Allah, dan para hamba adalah hamba Allah, dan barang siapa yang menghidupkan lahan mati maka ia yang lebih berhak terhadapnya. Telah datang kepada kami dengan membawa hal ini dari Nabi shallallahu 'alaihi wasallam [orang-orang yang datang membawa shalat] darinya. "},"2597":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَاطَ حَائِطًا عَلَى أَرْضٍ فَهِيَ لَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Muhammad bin Bisyr], telah menceritakan kepada kami [Sa'id] dari [Qatadah], dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa yang memagari kebun di atas tanah, maka lahan tersebut adalah miliknya.\""},"2598":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكٌ قَالَ هِشَامٌالْعِرْقُ الظَّالِمُ أَنْ يَغْرِسَ الرَّجُلُ فِي أَرْضِ غَيْرِهِ فَيَسْتَحِقَّهَا بِذَلِكَقَالَ مَالِكٌ وَالْعِرْقُ الظَّالِمُ كُلُّ مَا أُخِذَ وَاحْتُفِرَ وَغُرِسَ بِغَيْرِ حَقٍّ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], telah mengabarkan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Malik], ia berkata; [Hisyam]; keringat yang zhalim adalah seorang laki-laki menanamdi lahan orang lain kemudian orang lain tersebut memilikinya karena sebab tersebut. Malik berkata; dan keringat zhalim adalah setiap apa yang diambil dan digali serta ditanam dengan tanpa hak. "},"2599":{"ar":"حَدَّثَنَا سَهْلُ بْنُ بَكَّارٍ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ الْعَبَّاسِ السَّاعِدِيِّ يَعْنِي ابْنَ سَهْلِ بْنِ سَعْدٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبُوكَ فَلَمَّا أَتَى وَادِي الْقُرَى إِذَا امْرَأَةٌ فِي حَدِيقَةٍ لَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ اخْرُصُوا فَخَرَصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَةَ أَوْسُقٍ فَقَالَ لِلْمَرْأَةِ أَحْصِي مَا يَخْرُجُ مِنْهَا فَأَتَيْنَا تَبُوكَ فَأَهْدَى مَلِكُ أَيْلَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَغْلَةً بَيْضَاءَ وَكَسَاهُ بُرْدَةً وَكَتَبَ لَهُ يَعْنِي بِبَحْرِهِ قَالَ فَلَمَّا أَتَيْنَا وَادِي الْقُرَى قَالَ لِلْمَرْأَةِ كَمْ كَانَ فِي حَدِيقَتِكِ قَالَتْ عَشْرَةَ أَوْسُقٍ خَرْصَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي مُتَعَجِّلٌ إِلَى الْمَدِينَةِ فَمَنْ أَرَادَ مِنْكُمْ أَنْ يَتَعَجَّلَ مَعِي فَلْيَتَعَجَّلْ","id":"Telah menceritakan kepada kami [Sahl bin Bakkar], telah menceritakan kepada kami [Wuhaib bin Khalid] dari ['Amr bin Yahya] dari [Al Abbas As Sa'idi bin Sahl bin Sa'id] dari [Abu Humaid As Sa'idi] ia berkata; aku berperang Tabuk bersama Rasulullah, kemudian tatkala beliau datang ke bukit Al Qura, ternyata terdapat seorang wanita yang berada di kebunnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Potonglah!\" kemudian Rasulullah shallallahu 'alaihi wasallam memotong sepuluh wasaq. Kemudian beliau berkata kepada wanita tersebut: \" Hitunglah apa yang keluar dari kebun tersebut.\" Kemudian kami datang ke Tabuk, lalu raja Ailah memberikan hadiah seekor baghal kepada Rasulullah shallallahu 'alaihi wasallam yang berwarna putih, dan memberinya pakaian, dan ia mengakui bahwa beliau berhak terhadap jizyah atas penduduk tepi laut. Abu Humaid berkata; kemudian tatkala kami sampai di bukit Al Qura, beliau berkata kepada wanita tersebut: \"Berapa yang ada di dalam kebunmu?\" Ia berkata; sepuluh Wasaq sesuai yang dipoton Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Sesungguhnya aku akan bersegera kembali ke Madinah, maka barang siapa diantara kalian yang hendak bersegara kembali bersamaku maka silahkan ia bersegera.\""},"2600":{"ar":"حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ غِيَاثٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْأَعْمَشُ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ كُلْثُومٍ عَنْ زَيْنَبَأَنَّهَا كَانَتْ تَفْلِي رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ امْرَأَةُ عُثْمَانَ بْنِ عَفَّانَ وَنِسَاءٌ مِنْ الْمُهَاجِرَاتِ وَهُنَّ يَشْتَكِينَ مَنَازِلَهُنَّ أَنَّهَا تَضِيقُ عَلَيْهِنَّ وَيُخْرَجْنَ مِنْهَا فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُوَرَّثَ دُورَ الْمُهَاجِرِينَ النِّسَاءُ فَمَاتَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ فَوُرِّثَتْهُ امْرَأَتُهُ دَارًا بِالْمَدِينَةِ","id":"Telah menceritakan kepada kami [Abdul Wahid bin Ghiyats], telah menceritakan kepada kami [Abdul Wahid bin Ziyad], telah menceritakan kepada kami [Al A'masy] dari [Jami' bin Syaddad] dari [Kultsum] dari [Zainab], bahwa ia mencari kutu dari kepala Rasulullah shallallahu 'alaihi wasallam sementara bersama beliau terdapat isteri Utsman bin Affan dan para wanita muhajirin, mereka mengadukan tempat tinggal mereka yang terasa sempit bagi mereka, dan mereka dikeluarkan darinya. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan agar rumah-rumah orang-orang muhajirin diwariskan kepada para isteri. Kemudian Abdullah bin Mas'ud meninggal dan isterinya mendapat warisan rumahnya yang berada di Madinah. "},"2601":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ أَخْبَرَنَا مُحَمَّدُ ابْنُ عِيسَى يَعْنِي ابْنَ سُمَيْعٍ حَدَّثَنَا زَيْدُ بْنُ وَاقِدٍ حَدَّثَنِي أَبُو عَبْدِ اللَّهِ عَنْ مُعَاذٍ أَنَّهُ قَالَمَنْ عَقَدَ الْجِزْيَةَ فِي عُنُقِهِ فَقَدْ بَرِئَ مِمَّا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Harun bin Muhammad bin Bakkar bin Bilal], telah mengabarkan kepada kami [Muhammad bin Isa bin Sumai'], telah menceritakan kepada kami [Zaid bin Waqid], telah menceritakan kepadaku [Abu Abdullah], dari [Mu'adz] bahwa ia berkata; barangsiapa yang mengikatkan jizyah pada lehernya maka ia telah berlepas diri dari jalan yang dilalui Rasulullah shallallahu 'alaihi wasallam. "},"2602":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ الْحَضْرَمِيُّ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا عُمَارَةُ ابْنُ أَبِي الشَّعْثَاءِ حَدَّثَنِي سِنَانُ بْنُ قَيْسٍ حَدَّثَنِي شَبِيبُ بْنُ نُعَيْمٍ حَدَّثَنِي يَزِيدُ بْنُ خُمَيْرٍ حَدَّثَنِي أَبُو الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَخَذَ أَرْضًا بِجِزْيَتِهَا فَقَدْ اسْتَقَالَ هِجْرَتَهُ وَمَنْ نَزَعَ صَغَارَ كَافِرٍ مِنْ عُنُقِهِ فَجَعَلَهُ فِي عُنُقِهِ فَقَدْ وَلَّى الْإِسْلَامَ ظَهْرَهُقَالَ فَسَمِعَ مِنِّي خَالِدُ بْنُ مَعْدَانَ هَذَا الْحَدِيثَ فَقَالَ لِي أَشُبَيْبٌ حَدَّثَكَ قُلْتُ نَعَمْ قَالَ فَإِذَا قَدِمْتَ فَسَلْهُ فَلْيَكْتُبْ إِلَيَّ بِالْحَدِيثِ قَالَ فَكَتَبَهُ لَهُ فَلَمَّا قَدِمْتُ سَأَلَنِي خَالِدُ بْنُ مَعْدَانَ الْقِرْطَاسَ فَأَعْطَيْتُهُ فَلَمَّا قَرَأَهُ تَرَكَ مَا فِي يَدِهِ مِنْ الْأَرْضِينَ حِينَ سَمِعَ ذَلِكَ قَالَ أَبُو دَاوُد هَذَا يَزِيدُ بْنُ خُمَيْرٍ الْيَزَنِيُّ لَيْسَ هُوَ صَاحِبَ شُعْبَةَ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih Al Hadhrami] telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepada kami ['Umarah bin Abu Asy sya'tsa`] telah menceritakan kepadaku [Sinan bin Qais], telah menceritakan kepadaku [Syabib bin Nu'aim] telah menceritakan kepadaku [Yazid bin Khumair] telah menceritakan kepadaku [Abu Ad Darda`] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mengambil tanah dengan jizyahnya maka sungguh ia telah melepas hijranya. Dan barang siapa yang melepas kehinaan orang kafir dan ia meletakkannya pada lehernya maka sungguh ia telah membuat Islam lari ke belakangnya.\" Ia berkata; kemudian Khalid bin Ma'dan mendengar hadits ini dariku, lalu Asyubaib berkata kepadaku; apakah ia menceritakan kepadamu? Aku katakan; ya. ia berkata; apabila engkau datang maka mintalah kepadanya agar menulis hadits tersebut kepadaku. ia berkata; kemudian ia menulis hadits tersebut untuk Asyubaib. Kemudian tatkala aku datang, Khalid bin Ma'dan meminta kertas kepadaku, kemudian aku berikan kepadanya. kemudian tatkala ia membacanya ia meninggalkan tanah yang ada di kekuasaannya, ketika ia mendengar hal tersebut. Abu Daud berkata; ini adalah Yazid bin Khumair Al yazini, ia bukan sahabat Syu'bah. "},"2603":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ الصَّعْبِ بْنِ جَثَّامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا حِمَى إِلَّا لِلَّهِ وَلِرَسُولِهِقَالَ ابْنُ شِهَابٍ وَبَلَغَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمَى النَّقِيعَ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Ash Sha'b bin Jatstsamah] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Tidak ada daerah larangan kecuali milik Allah dan RasulNya.\" Ibnu Syihab berkata; dan telah sampai kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam telah melindungi Naqi' (mata air dekat dengan Madinah). "},"2604":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ الصَّعْبِ بْنِ جَثَّامَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمَى النَّقِيعَ وَقَالَ لَا حِمَى إِلَّا لِلَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur?] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Abdurrahman bin Al Harits] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Abdullah bin Abbas] dari [Ash Sha'b bin Jatstsamah] bahwa Rasulullah shallallahu 'alaihi wasallam telah melindungi Naqi' (mata air dekat dengan Madinah) dan berkata: \"Tidak ada daerah larangan kecuali milik Allah dan RasulNya.\""},"2605":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ وَأَبِي سَلَمَةَ سَمِعَا أَبَا هُرَيْرَةَ يُحَدِّثُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الرِّكَازِ الْخُمُسُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri], dari [Sa'id b al Musayyab] dan [Abu Salamah], mereka mendengar [Abu Hurairah] menceritakan bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Dalam barang terpendam terdapat zamat seperlima.\""},"2606":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَالرِّكَازُ الْكَنْزُ الْعَادِيُّ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Abbad bin Al 'Awwam] dari [Hisyam] dari [Al Hasan] ia berkata; barang terpendam adalah barang simpanan biasa. "},"2607":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنَا الزَّمْعِيُّ عَنْ عَمَّتِهِ قُرَيْبَةَ بِنْتِ عَبْدِ اللَّهِ بْنِ وَهْبٍ عَنْ أُمِّهَا كَرِيمَةَ بِنْتِ الْمِقْدَادِ عَنْ ضُبَاعَةَ بِنْتِ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِ بْنِ هَاشِمٍ أَنَّهَا أَخْبَرَتْهَا قَالَتْذَهَبَ الْمِقْدَادُ لِحَاجَتِهِ بِبَقِيعِ الْخَبْخَبَةِ فَإِذَا جُرَذٌ يُخْرِجُ مِنْ جُحْرٍ دِينَارًا ثُمَّ لَمْ يَزَلْ يُخْرِجُ دِينَارًا دِينَارًا حَتَّى أَخْرَجَ سَبْعَةَ عَشَرَ دِينَارًا ثُمَّ أَخْرَجَ خِرْقَةً حَمْرَاءَ يَعْنِي فِيهَا دِينَارٌ فَكَانَتْ ثَمَانِيَةَ عَشَرَ دِينَارًا فَذَهَبَ بِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ وَقَالَ لَهُ خُذْ صَدَقَتَهَا فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ هَوَيْتَ إِلَى الْجُحْرِ قَالَ لَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَارَكَ اللَّهُ لَكَ فِيهَا","id":"Telah menceritakan kepada kami [Ja'far bin Musafir] telah menceritakan kepada kami [ibnu Abu Fudaik], telah menceritakan kepada kami [Az Zam'i], dari [bibinya yaitu Quraibah binti Abdullah bin Wahb] dari [ibunya yaitu karimah binti Al Miqdad] dari [Dhuba'ah binti Az Zubair bin Abdul Muththalib bin Hasyim] bahwa ia telah mengabarkan kepadanya, ia berkata; Al Miqdad pergi untuk suatu keperluannya di Baqi' Al Khabkhabah, tiba-tiba terdapat tikus yang mengeluarkan dari lubangnya uang satu dinar, kemudian terus mengeluarkan satu dinar-satu dinar hingga ia mengeluarkan tujuh belas dinar. Kemudian tikus tersebut mengeluarkan secarik kain berwarna merah yang berisi dinar. Sehingga dinar tersebut berjumlah tujuh belas. Kemudian Al Miqdad membawanya kepada Nabi shallallahu 'alaihi wasallam dan mengabarkan hal tersebut kepadanya. dan beliau berkata: \"Ambillah sedekahnya.\" Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Apakah engkau engkau memasukkan tanganmu ke lubang?\" ia berkata; tidak. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Semoga Allah memberimu berkah padanya.\""},"2608":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي سَمِعْتُ مُحَمَّدَ بْنَ إِسْحَقَ يُحَدِّثُ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ بُجَيْرِ بْنِ أَبِي بُجَيْرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حِينَ خَرَجْنَا مَعَهُ إِلَى الطَّائِفِ فَمَرَرْنَا بِقَبْرٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا قَبْرُ أَبِي رِغَالٍ وَكَانَ بِهَذَا الْحَرَمِ يَدْفَعُ عَنْهُ فَلَمَّا خَرَجَ أَصَابَتْهُ النِّقْمَةُ الَّتِي أَصَابَتْ قَوْمَهُ بِهَذَا الْمَكَانِ فَدُفِنَ فِيهِ وَآيَةُ ذَلِكَ أَنَّهُ دُفِنَ مَعَهُ غُصْنٌ مِنْ ذَهَبٍ إِنْ أَنْتُمْ نَبَشْتُمْ عَنْهُ أَصَبْتُمُوهُ مَعَهُ فَابْتَدَرَهُ النَّاسُ فَاسْتَخْرَجُوا الْغُصْنَ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in] telah menceritakan kepada kami [Wahb bin Jarir], telah menceritakan kepada kami [ayahku], aku mendengar [Muhammad bin Ishaq] menceritatakan dari [Isma'il bin Umayyyah] dari [Bujair bin Abu Bujair], ia berkata; aku mendengar [Abdullah bin Amr] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam ketika kami keluar bersamanya menuju Thaif, lalu kami melewati sebuah kuburan, beliau berkata: \"Ini adalah kuburan Abu Righal, dahulu ketika ia berada di tanah Haram ini ia membelanya. Kemudian tatkala ia keluar ia mendapatkan balas dendam yang pernah menimpa kaumny di tempat ini. Kemudian ia dikubur di tempat tersebut. Ia dikubur bersama dengan ranting dari emas. Apabila kalian mengambilnya maka kalian mendapatkannya bersamanya.\" Kemudaian orang-orang bersegera untuk mengeluarkan ranting tersebut."},"2609":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنِي رَجُلٌ مِنْ أَهْلِ الشَّامِ يُقَالُ لَهُ أَبُو مَنْظُورٍ عَنْ عَمِّهِ قَالَ حَدَّثَنِي عَمِّي عَنْ عَامِرٍ الرَّامِ أَخِي الْخَضِرِ قَالَ أَبُو دَاوُد قَالَ النُّفَيْلِيُّ هُوَ الْخُضْرُ وَلَكِنْ كَذَا قَالَ قَالَإِنِّي لَبِبِلَادِنَا إِذْ رُفِعَتْ لَنَا رَايَاتٌ وَأَلْوِيَةٌ فَقُلْتُ مَا هَذَا قَالُوا هَذَا لِوَاءُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ وَهُوَ تَحْتَ شَجَرَةٍ قَدْ بُسِطَ لَهُ كِسَاءٌ وَهُوَ جَالِسٌ عَلَيْهِ وَقَدْ اجْتَمَعَ إِلَيْهِ أَصْحَابُهُ فَجَلَسْتُ إِلَيْهِمْ فَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَسْقَامَ فَقَالَ إِنَّ الْمُؤْمِنَ إِذَا أَصَابَهُ السَّقَمُ ثُمَّ أَعْفَاهُ اللَّهُ مِنْهُ كَانَ كَفَّارَةً لِمَا مَضَى مِنْ ذُنُوبِهِ وَمَوْعِظَةً لَهُ فِيمَا يَسْتَقْبِلُ وَإِنَّ الْمُنَافِقَ إِذَا مَرِضَ ثُمَّ أُعْفِيَ كَانَ كَالْبَعِيرِ عَقَلَهُ أَهْلُهُ ثُمَّ أَرْسَلُوهُ فَلَمْ يَدْرِ لِمَ عَقَلُوهُ وَلَمْ يَدْرِ لِمَ أَرْسَلُوهُ فَقَالَ رَجُلٌ مِمَّنْ حَوْلَهُ يَا رَسُولَ اللَّهِ وَمَا الْأَسْقَامُ وَاللَّهِ مَا مَرِضْتُ قَطُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُمْ عَنَّا فَلَسْتَ مِنَّا فَبَيْنَا نَحْنُ عِنْدَهُ إِذْ أَقْبَلَ رَجُلٌ عَلَيْهِ كِسَاءٌ وَفِي يَدِهِ شَيْءٌ قَدْ الْتَفَّ عَلَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَمَّا رَأَيْتُكَ أَقْبَلْتُ إِلَيْكَ فَمَرَرْتُ بِغَيْضَةِ شَجَرٍ فَسَمِعْتُ فِيهَا أَصْوَاتَ فِرَاخِ طَائِرٍ فَأَخَذْتُهُنَّ فَوَضَعْتُهُنَّ فِي كِسَائِي فَجَاءَتْ أُمُّهُنَّ فَاسْتَدَارَتْ عَلَى رَأْسِي فَكَشَفْتُ لَهَا عَنْهُنَّ فَوَقَعَتْ عَلَيْهِنَّ مَعَهُنَّ فَلَفَفْتُهُنَّ بِكِسَائِي فَهُنَّ أُولَاءِ مَعِي قَالَ ضَعْهُنَّ عَنْكَ فَوَضَعْتُهُنَّ وَأَبَتْ أُمُّهُنَّ إِلَّا لُزُومَهُنَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ أَتَعْجَبُونَ لِرُحْمِ أُمِّ الْأَفْرَاخِ فِرَاخَهَا قَالُوا نَعَمْ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَوَالَّذِي بَعَثَنِي بِالْحَقِّ لَلَّهُ أَرْحَمُ بِعِبَادِهِ مِنْ أُمِّ الْأَفْرَاخِ بِفِرَاخِهَا ارْجِعْ بِهِنَّ حَتَّى تَضَعَهُنَّ مِنْ حَيْثُ أَخَذْتَهُنَّ وَأُمُّهُنَّ مَعَهُنَّ فَرَجَعَ بِهِنَّ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq], ia berkata; telah menceritakan kepadaku [seorang laki-laki] dari Syam yang dipanggil Abu Manzhur, dari [pamannya] ia berkata; telah menceritakan kepadaku [pamanku] dari ['Amir Ar Ram] saudara Al Khadhir, Abu Daud berkata; An Nufaili adalah Al Khudhr, akan tetapi dekianlah ia berkata. ia berkata; sungguh aku berada di suatu negeri, tiba-tiba diangkat kepada kami beberapa bendera, kemudian aku katakan; apa ini? Mereka berkata; ini adalah bendera Rasulullah shallallahu 'alaihi wasallam. Kemudian aku datang kepadanya, dan beliau sedang berada di bawah pohon, telah dihamparkan untuknya kain, dan beliau dalam keadaan duduk di atasnya, dan para sahabatnya mengrumuninya. Lalu aku duduk di samping mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam menyebutkan bebeapa penyakit. Kemudian berkata; sesungguhnya seorang mukmin apabila terkena sakit kemudian Allah menyembuhkanya maka sakit adalah penghapus dosanya yang telah lalu dan sebagai nasehat baginya untuk waktu yang akan datang. Dan sesungguhnya orang munafik apabila sakit kemudian disembuhkan maka ia seperti unta yang diikat pemiliknya, kemudian mereka melepaskannya, dan ia tidak mengeatui kenapa mereka mengikatnya, dan tidak mengerti kenapa mereka melepaskannya. Kemudian terdapat seorang laki-laki diantara orang-orang yang ada di sekitarnya berkata; wahai Rasulullah, apakah penyakit tersebut. Demi Allah aku belum pernah sakit sama sekali. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Bangkit dan tinggalkan kami, engkau bukan golongan kami!\" kemudian tatkala kami berada di sisi beliau tiba-tiba terdapat seorang laki-laki yang memakai kisa`, dan di tangannya terdapat sesuatu yang melilit padanya. Kemudian ia berkata; wahai Rasulullah sesungguhnya aku tatkala melihat anda aku menhadap kepada anda. Lalu aku mendapatkan di rerimbunan pohon, lalu aku mendengar padanya terdapat beberapa suara anak-anak burung, lalu aku mengambilnya di dalam bajuku, kemudian ibu mereka datang dan mengitari bahayanya. Apakah kalian kagum terhadap kasih sayang induk burung tersebut kepada anak-anaknya? Mereka berkata; ya, wahai Rasulullah. Kemudian beliau berkata; demi Dzat yang jiwaku ada di tanganNya. Sungguh Allah lebih sayang kepada para hambaNya daripada induk burung kepada anak-anaknya. Kembalikan mereka hingga engkau meletakkahnya pada tempat dimana engkau dahulu mengambilnya. Sementara induknya bersama mereka!\" kemudian ia mengembalikannya. "},"2610":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ وَإِبْرَاهِيمُ بْنُ مَهْدِيٍّ الْمِصِّيصِيُّ الْمَعْنَى قَالَا حَدَّثَنَا أَبُو الْمَلِيحِ عَنْ مُحَمَّدِ بْنِ خَالِدٍ قَالَ أَبُو دَاوُد قَالَ إِبْرَاهِيمُ بْنُ مَهْدِيٍّ السَّلَمِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ وَكَانَتْ لَهُ صُحْبَةٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْعَبْدَ إِذَا سَبَقَتْ لَهُ مِنْ اللَّهِ مَنْزِلَةٌ لَمْ يَبْلُغْهَا بِعَمَلِهِ ابْتَلَاهُ اللَّهُ فِي جَسَدِهِ أَوْ فِي مَالِهِ أَوْ فِي وَلَدِهِ قَالَ أَبُو دَاوُد زَادَ ابْنُ نُفَيْلٍ ثُمَّ صَبَّرَهُ عَلَى ذَلِكَ ثُمَّ اتَّفَقَا حَتَّى يُبْلِغَهُ الْمَنْزِلَةَ الَّتِي سَبَقَتْ لَهُ مِنْ اللَّهِ تَعَالَى","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], dan [Ibrahim bin Mahdi As Salami] secara makna, keduanya berkata; telah menceritakan kepada kami [Abu Al Malih] dari [Muhammad bin Kholid]. Abu Daud berkata; telah berkata [Ibrohim bin Mahdi As Salami]; dari [ayahnya] dari [kakeknya] dan ia pernah menyertai Rasulullah shallallahu 'alaihi wasallam. ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang hamba, apabila pernah memiliki kedudukan dari Allah, yang tidak ia peroleh dengan amalannya maka Allah mengujinya pada jasadnya, harta, atau pada anaknya.\" Abu Daud berkata; kemudian Ibnu Nufail menambahkan; kemudian Allah memberikan kesabaran atas hal tersebut. -kemudian keduanya lafazhnya sama-: \"Hingga Allah menyampaikannya kepada kedudukan yang dahulu ia peroleh dari Allah ta'ala.\""},"2611":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَمُسَدَّدٌ الْمَعْنَى قَالَا حَدَّثَنَا هُشَيْمٌ عَنْ الْعَوَّامِ بْنِ حَوْشَبٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ السَّكْسَكِيِّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ مَرَّةٍ وَلَا مَرَّتَيْنِ يَقُولُ إِذَا كَانَ الْعَبْدُ يَعْمَلُ عَمَلًا صَالِحًا فَشَغَلَهُ عَنْهُ مَرَضٌ أَوْ سَفَرٌ كُتِبَ لَهُ كَصَالِحِ مَا كَانَ يَعْمَلُ وَهُوَ صَحِيحٌ مُقِيمٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] dan [Musaddad] secara makna, mereka berkata; telah menceritakan kepada kami [Husyaim], dari [Al 'Awwam bin Hausyab] dari [Ibrahim bin Abdurrahman As Saksaki], dari [Abu Burdah] dari [Abu Musa], ia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam tidak hanya sekali atau dua kali, beliau bersabda: \"Apabila seorang hamba melakukan amal shalih, kemudian ia terhalang oleh suatu penyakit atau suatu perjalanan maka tercatat baginya seperti amalan shalih yang pernah ia lakukan dalam keadaan sehat.\""},"2612":{"ar":"حَدَّثَنَا سَهْلُ بْنُ بَكَّارٍ عَنْ أَبِي عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أُمِّ الْعَلَاءِ قَالَتْعَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَرِيضَةٌ فَقَالَ أَبْشِرِي يَا أُمَّ الْعَلَاءِ فَإِنَّ مَرَضَ الْمُسْلِمِ يُذْهِبُ اللَّهُ بِهِ خَطَايَاهُ كَمَا تُذْهِبُ النَّارُ خَبَثَ الذَّهَبِ وَالْفِضَّةِ","id":"Telah menceritakan kepada kami [Sahl bin Bakkar], dari [Abu 'Awanah] dari [Abdul Malik bin 'Umair] dari [Ummu Al 'Ala`] ia berkata; Rasulullah shallallahu 'alaihi wasallam menjengukku sementara aku sedang sakit. Kemudian beliau berkata: \"Bergembiralah wahai Ummu Al 'Ala`, karena sesungguhnya sakit seorang mukmin karena Allah menghilangkan dosa-dosanya sebagaimana api menghilangkan kotoran emas dan perak.\""},"2613":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَبُو دَاوُد وَهَذَا لَفْظُ ابْنِ بَشَّارٍ عَنْ أَبِي عَامِرٍ الْخَزَّازِ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي لَأَعْلَمُ أَشَدَّ آيَةٍ فِي الْقُرْآنِ قَالَ أَيَّةُ آيَةٍ يَا عَائِشَةُ قَالَتْ قَوْلُ اللَّهِ تَعَالَى{ مَنْ يَعْمَلْ سُوءًا يُجْزَ بِهِ }قَالَ أَمَا عَلِمْتِ يَا عَائِشَةُ أَنَّ الْمُؤْمِنَ تُصِيبُهُ النَّكْبَةُ أَوْ الشَّوْكَةُ فَيُكَافَأُ بِأَسْوَإِ عَمَلِهِ وَمَنْ حُوسِبَ عُذِّبَ قَالَتْ أَلَيْسَ اللَّهُ يَقُولُ{ فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا }قَالَ ذَاكُمْ الْعَرْضُ يَا عَائِشَةُ مَنْ نُوقِشَ الْحِسَابَ عُذِّبَقَالَ أَبُو دَاوُد وَهَذَا لَفْظُ ابْنِ بَشَّارٍ قَالَ حَدَّثَنَا ابْنُ أَبِي مُلَيْكَةَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya], dan telah diriwayatkan dari jalur yang lain: telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Utsman bin Umar]. Abu Daud berkata; ini adalah lafazh Ibnu Basysyar, dari [Abu 'Amir Al Khazzaz], dari [Ibnu Abu Mulaikah] dari [Aisyah], ia berkata; aku katakan; wahai Rasulullah, wahai Rasulullah, sesungguhnya aku mengetahui ayat Al Qur'an yang paling keras. Beliau bertanya: \"Ayat apakah itu wahai Aisyah?\" Aisyah berkata; firman Allah ta'ala: \"Barang siapa yang berbuat keburukan maka ia akan dibalas dengannya.\" Beliau bersabda: \"Tahukah bahwa seorang mukmin yang tertimpa musibah atau duri hingga ia dibalas dengan amalah terburuknya. Barang siapa yang dihisab maka ia akan diadzab.\" Aisyah berkata; bukankah Allah telah berfirman: \"Maka dia akan diperiksa dengan pemeriksaan yang mudah.\" Beliau bersabda: \"Itu hanyalah memperlihatkan amalan wahai Aisyah. barang siapa yang dihisab maka ia akan diadzab.\" Abu Daud berkata; ini adalah lafazh Ibnu Basysyar, ia berkata; telah menceritakan kepadaku Ibnu Mulaikah. "},"2614":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ فَلَمَّا دَخَلَ عَلَيْهِ عَرَفَ فِيهِ الْمَوْتَ قَالَ قَدْ كُنْتُ أَنْهَاكَ عَنْ حُبِّ يَهُودَ قَالَ فَقَدْ أَبْغَضَهُمْ سَعْدُ بْنُ زُرَارَةَ فَمَهْ فَلَمَّا مَاتَ أَتَاهُ ابْنُهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَدْ مَاتَ فَأَعْطِنِي قَمِيصَكَ أُكَفِّنْهُ فِيهِ فَنَزَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَهُ فَأَعْطَاهُ إِيَّاهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya], telah menceritakan kepada kami [Muhammad bin Salamah], dari [Muhammad bin Ishaq], dari [Az Zuhri] dari ['Urwah] dari [Usamah bin Zaid], ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar mengunjungi Abdullah bin Ubai ketika ia sedang sakit, yang karenanya ia meninggal. Kemudian tatkala beliau menemuinya maka beliau mengetahui kematian padanya, beliau bersabda: \"Sungguh aku telah melarangmu dari mencintai orang-orang yahudi.\" Ia berkata; Sa'd bin Zurarah telah membenci mereka. Maka apa yang terjadi baginya dengan membenci mereka? Kemudian tatkala ia meninggal anaknya, kemudian berkata; wahai Rasulullah, sesungguhnya Abdullah bin Ubai telah meninggal, maka berikanlah jubahmu agar aku mengkafaninya dalam jubah tersebut. Kemudian Rasulullah shallallahu 'alaihi wasallam melepas jubahnya dan memberikan jubah tersebut kepadanya. "},"2615":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ غُلَامًا مِنْ الْيَهُودِ كَانَ مَرِضَ فَأَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَقَعَدَ عِنْدَ رَأْسِهِ فَقَالَ لَهُ أَسْلِمْ فَنَظَرَ إِلَى أَبِيهِ وَهُوَ عِنْدَ رَأْسِهِ فَقَالَ لَهُ أَبُوهُ أَطِعْ أَبَا الْقَاسِمِ فَأَسْلَمَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ الْحَمْدُ لِلَّهِ الَّذِي أَنْقَذَهُ بِي مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] bahwa anak seorang yahudi mengalami sakit, kemudian Nabi shallallahu 'alaihi wasallam datang menjenguknya, kemudian beliau duduk di sebelah kepalanya dan berkata kepadanya: \"Masuklah Islam!\" kemudian anak tersebut melihat kepada ayahnya sementara ayahnya berada di sebelah kepalanya. Kemudian ayahnya berkata; taatilah Abu Al Qasim. Kemudian anak tersebut masuk Islam. Kemudian Nabi shallallahu 'alaihi wasallam mengucapkan: \"Segala puji bagi Allah yang telah menyelamatkannya dari neraka.\""},"2616":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي لَيْسَ بِرَاكِبِ بَغْلٍ وَلَا بِرْذَوْنٍ","id":"Telah menceritakan kepada kami [Ahmad bin Hambal] telah menceritakan kepada kami [Abdurrahman bin Mahdi], dari [Sufyan] dari [Muhammad bin Al Munkadir], dari [Jabir], ia berkata; Nabi shallallahu 'alaihi wasallam menjengukku, beliau tidak naik bighal dan tidak pula kuda. "},"2617":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا الرَّبِيعُ بْنُ رَوْحِ بْنِ خُلَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ حَدَّثَنَا الْفَضْلُ بْنُ دَلْهَمٍ الْوَاسِطِيُّ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ وَعَادَ أَخَاهُ الْمُسْلِمَ مُحْتَسِبًا بُوعِدَ مِنْ جَهَنَّمَ مَسِيرَةَ سَبْعِينَ خَرِيفًاقُلْتُ يَا أَبَا حَمْزَةَ وَمَا الْخَرِيفُ قَالَ الْعَامُ قَالَ أَبُو دَاوُد وَالَّذِي تَفَرَّدَ بِهِ الْبَصْرِيُّونَ مِنْهُ الْعِيَادَةُ وَهُوَ مُتَوَضِّئٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Auf Ath Thai], telah menceritakan kepada kami [Ar Rabi' bin Rauh bin Khulaid], telah menceritakan kepada kami [Muhammad bin Khalid], telah menceritakan kepada kami [Al Fadhl bin Dalham Al Wasithi], dari [Tsabit Al Bunani] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berwudhu kemudian memperbaiki wudhunya dan menjenguk saudaranya yang muslim dengan mengharapkan pahala maka ia akan dijauhkan dari Jahannam sejauh perjalanan tujuh puluh kharif.\" Aku katakan; wahai Abu Hamzah, apakah kharif itu? Ia berkata; tahun. Abu Daud berkata; yang hanya diriwayatkan oleh orang-orang Bashrah adalah kata; menjenguk dalam keadaan berwudhu. "},"2618":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَبْدِ اللَّهِ بْنِ نَافِعٍ عَنْ عَلِيٍّ قَالَمَا مِنْ رَجُلٍ يَعُودُ مَرِيضًا مُمْسِيًا إِلَّا خَرَجَ مَعَهُ سَبْعُونَ أَلْفَ مَلَكٍ يَسْتَغْفِرُونَ لَهُ حَتَّى يُصْبِحَ وَكَانَ لَهُ خَرِيفٌ فِي الْجَنَّةِ وَمَنْ أَتَاهُ مُصْبِحًا خَرَجَ مَعَهُ سَبْعُونَ أَلْفَ مَلَكٍ يَسْتَغْفِرُونَ لَهُ حَتَّى يُمْسِيَ وَكَانَ لَهُ خَرِيفٌ فِي الْجَنَّةِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ لَ��ْ يَذْكُرْ الْخَرِيفَ قَالَ أَبُو دَاوُد رَوَاهُ مَنْصُورٌ عَنْ الْحَكَمِ كَمَا رَوَاهُ شُعْبَةُ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ أَبِي جَعْفَرٍ عَبْدِ اللَّهِ بْنِ نَافِعٍ قَالَ وَكَانَ نَافِعٌ غُلَامُ الْحَسَنِ بْنِ عَلِيٍّ قَالَ جَاءَ أَبُو مُوسَى إِلَى الْحَسَنِ بْنِ عَلِيٍّ يَعُودُهُ قَالَ أَبُو دَاوُد وَسَاقَ مَعْنَى حَدِيثِ شُعْبَةَ قَالَ أَبُو دَاوُد أُسْنِدَ هَذَا عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ وَجْهٍ صَحِيحٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Syu'bah] dari [Al Hakam] dari [Abdullah bin Nafi'] dari [Ali], ia berkata; tidaklah seorang laki-laki menjenguk orang yang saki pada sore hari melainkan akan keluar tujuh puluh ribu malaikat yang memintakan ampunan untuknya hingga pagi hari, dan baginya kebun di Surga. Dan barang siapa yang mendatanginya pada pagi hari, maka keluarg bersamanya tujuh puluh ribu malaikat yang memohonkan ampunan baginya hingga sore hari, dan baginya kebun di Surga. Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Abu Mu'awiyah], ia berkata; telah menceritakan kepada kami [Al A'masy], dari [Al Hakam] dari [Abdurrahman bin Abu Laila], dari [Ali] dari Nabi shallallahu 'alaihi wasallam dengan maknanya, ia tidak menyebutkan kebun. Abu Daud berkata; hadits tersebut diriwayatkan oleh Manshur dari Al Hakam, sebagaimana diriwayatkan oleh syu'bah. Telah menceritakan kepada kami [Ustman bin Abi Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Al Hakam] dari [Abu Ja'far Abdullah bin Nafi'], ia berkata; dan Nafi' adalah budak Al Hasan bin Ali. Ia berkata; Abu Musa telah datang kepada Al Hasan bin Ali untuk mengunjunginya. Abu Daud berkata; dan ia menyebutkan makna hadits Syu'bah. Abu Daud berkata; hadits ini disandarkan dari Ali dari Nabi shallallahu 'alaihi wasallam tidak hanya dari sisi yang benar. "},"2619":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَمَّا أُصِيبَ سَعْدُ بْنُ مُعَاذٍ يَوْمَ الْخَنْدَقِ رَمَاهُ رَجُلٌ فِي الْأَكْحَلِ فَضَرَبَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْمَةً فِي الْمَسْجِدِ لِيَعُودَهُ مِنْ قَرِيبٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?] telah menceritakan kepada kami [Abdullah bin Numair], dari [Hisyam bin 'Urwah] dari [ayahnya], dari [Aisyah] ia berkata; tatkala Sa'd bin Mu'adz terkena musibah pada saat perang Khandaq karena ia dipanah oleh seorang laki-laki pada otot tengah lengan, maka Rasulullah shallallahu 'alaihi wasallam mendirikan tenda di Masjid agar beliau dapat mengunjunginya dari jarak yang dekat. "},"2620":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ أَبِيهِ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَعَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ وَجَعٍ كَانَ بِعَيْنِي","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Yunus bin Abu Ishaq] dari [ayahnya], dari [Zaid bin Arqam], ia berkata; Rasulullah shallallahu 'alaihi wasallam menjengukku ketika mataku sakit. "},"2621":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ زَيْدِ بْنِ الْخَطَّابِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَ قَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَمِعْتُمْ بِهِ بِأَرْضٍ فَلَا تُقْدِمُوا عَلَيْهِ وَإِذَا وَقَعَ بِأَرْضٍ وَأَنْتُمْ بِهَا فَلَا تَخْرُجُوا فِرَارًا مِنْهُ يَعْنِي الطَّاعُونَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab], dari [Abdul Hamid bin Abdurrahman bin Zaid bin Al Khathab], dari [Abdullah bin Abdullah bin Al Harits bin Naufal] dari [Abdullah bin Abbas], ia berkata; [Abdurrahman bin 'Auf] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian mendengarnya ada di suatu negeri maka janganlah kalian memasukinya dan apabila telah terjadi di dalamnya dan kalian ada padanya maka jangalah kalian lari keluar darinya!\" yaitu penyakit pes. "},"2622":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْجُعَيْدُ عَنْ عَائِشَةَ بِنْتِ سَعْدٍ أَنَّ أَبَاهَا قَالَاشْتَكَيْتُ بِمَكَّةَ فَجَاءَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَوَضَعَ يَدَهُ عَلَى جَبْهَتِي ثُمَّ مَسَحَ صَدْرِي وَبَطْنِي ثُمَّ قَالَ اللَّهُمَّ اشْفِ سَعْدًا وَأَتْمِمْ لَهُ هِجْرَتَهُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Makki bin Ibrahim] telah menceritakan kepada kami [Al Ju'aid] dari [Aisyah binti Sa'd], bahwa [ayahnya] berkata; aku mengalami sakit di Mekkah, kemudian Nabi shallallahu 'alaihi wasallam datang mengunjungiku dan meletakkan tangannya di atas keningku, kemudian beliau mengusap dada dan perutku kemudian berdoa: \"Ya Allah sembuhkanlah Sa'd dan sempurnakanlah hijrahnya.\""},"2623":{"ar":"حَدَّثَنَا ابْنُ كَثِيرٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْعِمُوا الْجَائِعَ وَعُودُوا الْمَرِيضَ وَفُكُّوا الْعَانِيَقَالَ سُفْيَانُ وَالْعَانِي الْأَسِيرُ","id":"Telah menceritakan kepada kami [Ibnu Katsir] ia berkata; [Sufyan] dari [Manshur?], dari [Abu Wail] dari [Abu Musa Al Asy'ari], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah makan orang yang lapar dan jenguklah orang yang sakit serta bebaskanlah budak!\""},"2624":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ يَحْيَى حَدَّثَنَا شُعْبَةُ حَدَّثَنَا يَزِيدُ أَبُو خَالِدٍ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ عَادَ مَرِيضًا لَمْ يَحْضُرْ أَجَلُهُ فَقَالَ عِنْدَهُ سَبْعَ مِرَارٍ أَسْأَلُ اللَّهَ الْعَظِيمَ رَبَّ الْعَرْشِ الْعَظِيمِ أَنْ يَشْفِيَكَ إِلَّا عَافَاهُ اللَّهُ مِنْ ذَلِكَ الْمَرَضِ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Yahya], telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Yazid? Abu Khalid] dari [Al Minhal bin 'Amr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa yang mengunjungi orang sakit yang belum datang ajalnya kemudian ia mengucapkan (doa) di sebelahnya sebanyak tujuh kali: AS ALULLAAHAL 'AZHIIM RABBAL 'ARSYIL 'AZHIIM AN YASYFIYAKA (aku mohon kepada Allah yang Maha Agung, Tuhan Arsy yang Agung semoga Dia menyembuhkanmu), maka Allah akan menyembuhkannya dari penyakit tersebut. "},"2625":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدٍ الرَّمْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ حُيَيِّ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ ابْنِ عَمْرٍو قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ الرَّجُلُ يَعُودُ مَرِيضًا فَلْيَقُلْ اللَّهُمَّ اشْفِ عَبْدَكَ يَنْكَأُ لَكَ عَدُوًّا أَوْ يَمْشِي لَكَ إِلَى جَنَازَةٍ قَالَ أَبُو دَاوُد وَقَالَ ابْنُ السَّرْحِ إِلَى صَلَاةٍ","id":"Telah menceritakan kepada kami [Yazid? bin Khalid Ar Ramli], telah menceritakan kepada kami [Ibnu Wahb] dari [Huyai bin Abdullah] dari [Abu Abdurrahman Al Hubuli], dari [Ibnu Amru], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila ada seseorang datang menjenguk orang yang sakit, hendaknya ia mengucapkan (doa); ALLAAHUMMASYFI 'ABDAKA YANKA`U LAKA 'ADUWWAN AU YAMSYII LAKA ILAA JANAZATIN (ya Allah, sembuhkanlah hambaMu yang akan mengalahkan musuhMu, atau berjalan karenaMu mengantarkan jenazah). Abu Dawud berkata, Ibnu Sarj berkata, Menuju shalat. "},"2626":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْعُوَنَّ أَحَدُكُمْ بِالْمَوْتِ لِضُرٍّ نَزَلَ بِهِ وَلَكِنْ لِيَقُلْ اللَّهُمَّ أَحْيِنِي مَا كَانَتْ الْحَيَاةُ خَيْرًا لِي وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِيحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ يَعْنِي الطَّيَالِسِيَّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَمَنَّيَنَّ أَحَدُكُمْ الْمَوْتَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal], telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang diantara kalian berdoa agar diberi kematian karena musibah yang menimpanya, akan tetapi hendaknya ia mengucapkan; ALLAHUMMA AHYINI MA KAANATIL HAYATU KHAIRAN LI WA TAWAFFANI IDZA KANATIL WAFATU KHAIRAN LI (ya Allah hidupkanlah aku selama hidup adalah lebih baik bagiku dan wafatkanlah aku apabila kematian adalah lebih baik bagiku.\" Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abu Daud Ath Thayalisi], telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang diantara kalian mengharapkan kematian…!\" kemudian ia menyebutkan hadits seperti itu. "},"2627":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ تَمِيمِ بْنِ سَلَمَةَ أَوْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ عُبَيْدِ بْنِ خَالِدٍ السُّلَمِيِّ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَرَّةً عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ مَرَّةً عَنْ عُبَيْدٍقَالَ مَوْتُ الْفَجْأَةِ أَخْذَةُ أَسِفٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Manshur?] dari [Tamim bin Salamah] atau [Sa'd bin 'Ubaidah] dari [Ubaid bin Khalid As Sulami] seorang sahabat Nabi shallallahu 'alaihi wasallam, sesekali ia berkata dari Nabi shallallahu 'alaihi wasallam, dan sesekali ia berkata; dari 'Ubaid ia berkata: \"Mati tiba-tiba adalah siksaan karena kemarahan.\""},"2628":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ جَابِرِ بْنِ عَتِيكٍ عَنْ عَتِيكِ بْنِ الْحَارِثِ بْنِ عَتِيكٍ وَهُوَ جَدُّ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَبُو أُمِّهِ أَنَّهُ أَخْبَرَهُ أَنَّ عَمَّهُ جَابِرَ بْنَ عَتِيكٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ يَعُودُ عَبْدَ اللَّهِ بْنَ ثَابِتٍ فَوَجَدَهُ قَدْ غُلِبَ فَصَاحَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُجِبْهُ فَاسْتَرْجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ غُلِبْنَا عَلَيْكَ يَا أَبَا الرَّبِيعِ فَصَاحَ النِّسْوَةُ وَبَكَيْنَ فَجَعَلَ ابْنُ عَتِيكٍ يُسَكِّتُهُنَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُنَّ فَإِذَا وَجَبَ فَلَا تَبْكِيَنَّ بَاكِيَةٌ قَالُوا وَمَا الْوُجُوبُ يَا رَسُولَ اللَّهِ قَالَ الْمَوْتُ قَالَتْ ابْنَتُهُ وَاللَّهِ إِنْ كُنْتُ لَأَرْجُو أَنْ تَكُونَ شَهِيدًا فَإِنَّكَ كُنْتَ قَدْ قَضَيْتَ جِهَازَكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ أَوْقَعَ أَجْرَهُ عَلَى قَدْرِ نِيَّتِهِ وَمَا تَعُدُّونَ الشَّهَادَةَ قَالُوا الْقَتْلُ فِي سَبِيلِ اللَّهِ تَعَالَى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهَادَةُ سَبْعٌ سِوَى الْقَتْلِ فِي سَبِيلِ اللَّهِ الْمَطْعُونُ شَهِيدٌ وَالْغَرِقُ شَهِيدٌ وَصَاحِبُ ��َاتِ الْجَنْبِ شَهِيدٌ وَالْمَبْطُونُ شَهِيدٌ وَصَاحِبُ الْحَرِيقِ شَهِيدٌ وَالَّذِي يَمُوتُ تَحْتَ الْهَدْمِ شَهِيدٌ وَالْمَرْأَةُ تَمُوتُ بِجُمْعٍ شَهِيدٌ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Abdullah bin Abdullah bin Jabir bin 'Atik] dari ['Atik bin Al Harits bin 'Atik] ia adalah kakek Abdullah bin Abdullah ayah ibunya, bahwa ia telah mengabarkan kepadanya bahwa pamannya yaitu [Jabir bin 'Atik] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam datang mengunjungi Abdullah bin Tsabit, lalu beliau mendapatinya telah parah sakitnya, kemudian Rasulullah shallallahu 'alaihi wasallam memanggilnya dan Abdullah tidak menjawab panggilan beliau. Lalu mengucapkan istirja' (INNAALILLAAHI WA INNAA ILAIHI RAAJI'UUN), beliau berkata: \"Taqdirmu telah mendahului kami wahai Abu Ar Rabi'! kemudian para wanita berteriak dan menangis, lalu Ibnu 'Atik mendiamkan mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkan mereka, seandainya ia telah 'wajab' maka janganlah ada seorang wanita yang menangis!\" Mereka bertanya; apakah 'wajab' itu wahai Rasulullah? Beliau bersabda: \"Meninggal dunia.\" Anak wanitanya berkata; demi Allah, sungguh aku berharap kamu (doa untuk sang ayah) menjadi orang yang syahid. Sungguh engkau telah menyelesaikan persiapan (perang) mu. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla telah memberikannya pahala sesuai dengan niatnya. Apakah yang kalian anggap sebagai mati syahid?\" Mereka berkata; terbunuh di jalan Allah ta'ala. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mati syahid selain terbunuh di jalan Allah ada tujuh, yaitu: orang yang meninggal karena terkena penyakit tha'un (sampar, pes) adalah syahid, orang yang mati tenggelam adalah syahid, orang yang meninggal karena sakit radang selaput dada adalah syahid, orang meninggal karena sakit perut adalah syahid, orang yang terbakar adalah syahid, dan orang yang meninggal terkena reruntuhan adalah syahid, serta seorang wanita yang meninggal dalam keadaan hamil adalah syahid.\""},"2629":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ أَخْبَرَنَا ابْنُ شِهَابٍ أَخْبَرَنِي عَمْرُو بْنُ جَارِيَةَ الثَّقَفِيُّ حَلِيفُ بَنِي زُهْرَةَ وَكَانَ مِنْ أَصْحَابِ أَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَ قَالَابْتَاعَ بَنُو الْحَارِثِ بْنِ عَامِرِ بْنِ نَوْفَلٍ خُبَيْبًا وَكَانَ خُبَيْبٌ هُوَ قَتَلَ الْحَارِثَ بْنَ عَامِرٍ يَوْمَ بَدْرٍ فَلَبِثَ خُبَيْبٌ عِنْدَهُمْ أَسِيرًا حَتَّى أَجْمَعُوا لِقَتْلِهِ فَاسْتَعَارَ مِنْ ابْنَةِ الْحَارِثِ مُوسًى يَسْتَحِدُّ بِهَا فَأَعَارَتْهُ فَدَرَجَ بُنَيٌّ لَهَا وَهِيَ غَافِلَةٌ حَتَّى أَتَتْهُ فَوَجَدَتْهُ مُخْلِيًا وَهُوَ عَلَى فَخْذِهِ وَالْمُوسَى بِيَدِهِ فَفَزِعَتْ فَزْعَةً عَرَفَهَا فِيهَا فَقَالَ أَتَخْشَيْنَ أَنْ أَقْتُلَهُ مَا كُنْتُ لِأَفْعَلَ ذَلِكَقَالَ أَبُو دَاوُد رَوَى هَذِهِ الْقِصَّةَ شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عِيَاضٍ أَنَّ ابْنَةَ الْحَارِثِ أَخْبَرَتْهُ أَنَّهُمْ حِينَ اجْتَمَعُوا يَعْنِي لِقَتْلِهِ اسْتَعَارَ مِنْهَا مُوسًى يَسْتَحِدُّ بِهَا فَأَعَارَتْهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Ibrahim bin Sa'd] telah mengabarkan kepada kami [Ibnu Syihab], telah mengabarkan kepadaku ['Amr bin Jariyah Ats Tsaqafi] sekutu Bani Zuhrah, dan ia termasuk diantara sahabat Abu Hurairah, dari [Abu Hurairah], ia berkata; anak-anak Al Harits bin 'Amir bin Naufal telah membeli Khubaib, dan Khubai telah membunuh Al Harits bin 'Amir pada saat perang Badr, dan Khubaib tinggal bersama mereka sebagai tawanan hingga mereka bertekad untuk membunuhnya, kemudian ia meminjam pisau cukur dari anak wanita Al Harits yang akan ia gunakan untuk mencukur bulu kemaluan. Lalu wanita tersebut meminjamkannya kepadanya, kemudian anak wanita tersebut merangkak sementara ia lalai hingga sampai kepada Khubaib. Lalu wanita tersebut mendapati anaknya sendirian berada di atas pangkuan Khubaib sementara pisau cukur ada di tangannya. Maka wanita tersebut sangat terkejut, dan Khubaib mengetahui hal tersebut padanya. Kemudian ia berkata; apakah engkau khawatir aku akan membunuhnya? Aku tidak akan melakukan hal tersebut. Abu Daud berkata; kisah ini diriwayatkan oleh [Syu'aib bin Abu Hamzah], dari [Az Zuhri], ia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Iyadh] bahwa [anak wanita Al Harits] telah mengabarkan kepadanya bahwa mereka berkumpul untuk membunuhnya, Khubaib meminjam pisau cukur darinya yang akan ia gunakan untuk mencukur bulu kemaluannya. Lalu wanita tersebut meminjamkannya. "},"2630":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَبْلَ مَوْتِهِ بِثَلَاثٍ قَالَ لَا يَمُوتُ أَحَدُكُمْ إِلَّا وَهُوَ يُحْسِنُ الظَّنَّ بِاللَّهِ","id":"Telah menceritakan kepada kami [Musaddad], Telah menceritakan kepada kami [Isa bin Yunus], Telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir bin Abdullah], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam tiga hari sebelum meninggal bersabda: \"Janganlah salah seorang diantara kalian meninggal kecuali ia berprasangka baik kepada Allah.\""},"2631":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ لَمَّا حَضَرَهُ الْمَوْتُ دَعَا بِثِيَابٍ جُدُدٍ فَلَبِسَهَا ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْمَيِّتَ يُبْعَثُ فِي ثِيَابِهِ الَّتِي يَمُوتُ فِيهَا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Ibnu Abu Maryam], telah mengabarkan kepada kami [Yahya bin Ayyub], dari [Ibnu Al Had] dari [Muhammad bin Ibrahim], dari [Abu Salamah], dari [Abu Sa'id Al Khudri] bahwa tatkala ia mendekati kematian ia meminta pakaian baru lalu ia memakainya, kemudian berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang meninggal akan dibangkitkan dengan memakai pakaiannya yang ia pakai tatkala meninggal.\""},"2632":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرْتُمْ الْمَيِّتَ فَقُولُوا خَيْرًا فَإِنَّ الْمَلَائِكَةَ يُؤَمِّنُونَ عَلَى مَا تَقُولُونَ فَلَمَّا مَاتَ أَبُو سَلَمَةَ قُلْتُ يَا رَسُولَ اللَّهِ مَا أَقُولُ قَالَ قُولِي اللَّهُمَّ اغْفِرْ لَهُ وَأَعْقِبْنَا عُقْبَى صَالِحَةً قَالَتْ فَأَعْقَبَنِي اللَّهُ تَعَالَى بِهِ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Wail], dari [Ummu Salamah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian menghadiri jenazah maka ucapkanlah kebaikan, karena sesungguhnya malaikat mengamini apa yang ia ucapkan.\" Kemudian tatkala Abu Salamah meninggal, aku katakan; wahai Rasulullah, apa yang harus aku ucapkan? Beliau berkata: \"Ucapkanlah; ALLAAHUMMAGHRIR LAHU WA A'QIBNAA 'UQBAA SHAALIHAH (ya Allah ampunila dia dan gantilah untuk kami pengganti yang baik) \" Ia berkata; kemudian Allah ta'ala menggantikan Muhammad shallallahu 'alaihi wasallam untukku. "},"2633":{"ar":"حَدَّثَنَا مَالِكُ بْنُ عَبْدِ الْوَاحِدِ الْمِسْمَعِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنِي صَالِحُ بْنُ أَبِي عَرِيبٍ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ آخِرُ كَلَامِهِ لَا إِلَهَ إِلَّا اللَّهُ دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Malik bin Abdul Wahid Al Misma'i], telah menceritakan kepada kami [Adh Dhahhak bin Makhlad], telah menceritakan kepada kami [Abdul Hamid bin Ja'far], telah menceritakan kepadaku [Shalih bin Abu 'Arib] dari [Katsir bin Murrah] dari [Mu'adz bin Jabal], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang akhir perkataannya (sebelum meninggal dunia) 'LAA ILAAHA ILLALLAAH\" maka ia akan masuk surga.\""},"2634":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ حَدَّثَنَا عُمَارَةُ بْنُ غَزِيَّةَ حَدَّثَنَا يَحْيَى بْنُ عُمَارَةَ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِّنُوا مَوْتَاكُمْ قَوْلَ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Bisyr], Telah menceritakan kepada kami ['Umarah bin Gahziyyah], telah menceritakan kepada kami [Yahya bin 'Umarah], ia berkata; saya mendengar [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Talqinlah (ajarilah) orang yang (akan) meninggal diantara kalian dengan ucapan 'LAA ILAAHA ILLALLAAH'.\""},"2635":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ حَبِيبٍ أَبُو مَرْوَانَ حَدَّثَنَا أَبُو إِسْحَقَ يَعْنِي الْفَزَارِيَّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ عَنْ أُمِّ سَلَمَةَ قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَبِي سَلَمَةَ وَقَدْ شَقَّ بَصَرَهُ فَأَغْمَضَهُ فَصَيَّحَ نَاسٌ مِنْ أَهْلِهِ فَقَالَ لَا تَدْعُوا عَلَى أَنْفُسِكُمْ إِلَّا بِخَيْرٍ فَإِنَّ الْمَلَائِكَةَ يُؤَمِّنُونَ عَلَى مَا تَقُولُونَ ثُمَّ قَالَ اللَّهُمَّ اغْفِرْ لِأَبِي سَلَمَةَ وَارْفَعْ دَرَجَتَهُ فِي الْمَهْدِيِّينَ وَاخْلُفْهُ فِي عَقِبِهِ فِي الْغَابِرِينَ وَاغْفِرْ لَنَا وَلَهُ رَبَّ الْعَالَمِينَ اللَّهُمَّ افْسَحْ لَهُ فِي قَبْرِهِ وَنَوِّرْ لَهُ فِيهِقَالَ أَبُو دَاوُد وَتَغْمِيضُ الْمَيِّتِ بَعْدَ خُرُوجِ الرُّوحِ سَمِعْتُ مُحَمَّدَ بْنَ مُحَمَّدِ بْنِ النُّعْمَانِ الْمُقْرِيَّ قَالَ سَمِعْتُ أَبَا مَيْسَرَةَ رَجُلًا عَابِدًا يَقُولُ غَمَّضْتُ جَعْفَرًا الْمُعَلِّمَ وَكَانَ رَجُلًا عَابِدًا فِي حَالَةِ الْمَوْتِ فَرَأَيْتُهُ فِي مَنَامِي لَيْلَةَ مَاتَ يَقُولُ أَعْظَمُ مَا كَانَ عَلَيَّ تَغْمِيضُكَ لِي قَبْلَ أَنْ أَمُوتَ","id":"Telah menceritakan kepada kami [Abdul Malik bin Habib Abu Marwan], telah menceritakan kepada kami [Abu Ishaq Al Al Fazari], dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Qabishah bin Dzuaib] dari [Ummu Salamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam menemui Abu Salamah sementara ia telah mengangkat matanya, kemudian memejamkannya, dan orang-orang dari keluarganya meneriakinya (menjerit atas kematiannya). Kemudian beliau berkata: \"Janganlah kalian mendoakan atas diri kalian kecuali dengan kebaikan. Sesungguhnya para malaikat mengamini apa yang kalian ucapkan.\" Kemudian beliau berkata: \"Ya Allah, ampunilah Abu Salamah, dan angkatlah derajatnya diantara orang-orang yang mendapatkan petunjuk, dan berilah ganti pada keluarganya diantara yang tersisa, dan ampunilah kami dan dirinya wahai Tuhan semesta alam. Ya Allah, lapangkanlah kuburnya dan terangilah dia di dalamnya.\" Abu Daud berkata; memejamkan mata orang yang meninggal adalah setelah nyawanya keluar. Aku mendengar Muhammad bin Muhammad bin An Nu'man Al Muqri berkata; aku mendengar Abu Maisarah yaitu orang yang ahli ibadah berkata; aku pejamkan mata Ja'far Al Mu'allim, dan ia adalah orang yang ahli ibadah tatkala ia meninggal, lalu aku melihatnya dalam tidurku pada malam ketika meninggal, ia berkata; sesungguhnya sesuatu yang paling berat bagiku adalah engkau memejamkan mataku sebelum aku meninggal. "},"2636":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ ابْنِ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصَابَتْ أَحَدَكُمْ مُصِيبَةٌ فَلْيَقُلْ إِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ اللَّهُمَّ عِنْدَكَ أَحْتَسِبُ مُصِيبَتِي فَآجِرْنِي فِيهَا وَأَبْدِلْ لِي بِهَا خَيْرًا مِنْهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Tsabit], dari [Ibnu Umar bin Abu Salamah], dari [ayahnya] dari [Ummu Salamah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian tertimpa musibah maka hendaknya ia mengucapkan; INNAA LILLAAHI WA INNAA ILAIHI RAAJI'UUN ALLAAHUMMA 'INDAKA AHTASIBU MUSHIIBATII FA-AAJIRNII FIIHAA WA ABDIL LII BIHAA KHAIRAN MINHAA (sesungguhnya kami milik Allah dan sesungguhnya kepadaNya kami akan kembali. Ya Allah aku mengharapkan pahala pada musibahku dan berilah aku pahala padanya dan gantikanlah untukku yang lebih baik darinya!) "},"2637":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُجِّيَ فِي ثَوْبِ حِبَرَةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri], dari [Abu Salamah], dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam ditutup dengan baju hibarah (baju yang terbuat dari kapas di Yaman). "},"2638":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَمُحَمَّدُ بْنُ مَكِّيٍّ الْمَرْوَزِيُّ الْمَعْنَى قَالَا حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ وَلَيْسَ بِالنَّهْدِيِّ عَنْ أَبِيهِ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا يس عَلَى مَوْتَاكُمْوَهَذَا لَفْظُ ابْنِ الْعَلَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], dan [Muhammad bin Makki Al Marwazi], secara makna, mereka berkata; telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Sulaiman At Taimi] dari [Abu Utsman] bukan An Nahdi, dari [ayahnya], dari [Ma'qil bin Yasar], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Bacakanlah Surat Yaasiin kepada orang yang akan meninggal diantara kalian.\" Dan ini adalah lafazh Ibnu Al 'Ala`. "},"2639":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا قُتِلَ زَيْدُ بْنُ حَارِثَةَ وَجَعْفَرٌ وَعَبْدُ اللَّهِ بْنُ رَوَاحَةَ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ يُعْرَفُ فِي وَجْهِهِ الْحُزْنُ وَذَكَرَ الْقِصَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sulaiman bin Katsir] dari [Yahya bin Sa'id] dari ['Amrah] dari [Aisyah], ia berkata; tatkala Zaid bin Haritsah, Ja'far, dan Abdullah bin Rawahah terbunuh Rasulullah shallallahu 'alaihi wasallam duduk di masjid dan terlihat pada diri beliau terdapat perasaan sedih. Dan Muhammad menyebutkan kisah tersebut. "},"2640":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ الْهَمْدَانِيُّ حَدَّثَنَا الْمُفَضَّلُ عَنْ رَبِيعَةَ بْنِ سَيْفٍ الْمَعَافِرِيِّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِىِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَقَبَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي مَيِّتًا فَلَمَّا فَرَغْنَا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْصَرَفْنَا مَعَهُ فَلَمَّا حَاذَى بَابَهُ وَقَفَ فَإِذَا نَحْنُ بِامْرَأَةٍ مُقْبِلَةٍ قَالَ أَظُنُّهُ عَرَفَهَا فَلَمَّا ذَهَبَتْ إِذَا هِيَ فَاطِمَةُ عَلَيْهَا السَّلَام فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَخْرَجَكِ يَا فَاطِمَةُ مِنْ بَيْتِكِ فَقَالَتْ أَتَيْتُ يَا رَسُولَ اللَّهِ أَهْلَ هَذَا الْبَيْتِ فَرَحَّمْتُ إِلَيْهِمْ مَيِّتَهُمْ أَوْ عَزَّيْتُهُمْ بِهِ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَعَلَّكِ بَلَغْتِ مَعَهُمْ الْكُدَى قَالَتْ مَعَاذَ اللَّهِ وَقَدْ سَمِعْتُكَ تَذْكُرُ فِيهَا مَا تَذْكُرُ قَالَ لَوْ بَلَغْتِ مَعَهُمْ الْكُدَى فَذَكَرَ تَشْدِيدًا فِي ذَلِكَفَسَأَلْتُ رَبِيعَةَ عَنْ الْكُدَى فَقَالَ الْقُبُورُ فِيمَا أَحْسَبُ","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Abdullah bin Mauhib Al Hamdani], telah menceritakan kepada kami [Al Mufadhdhal] dari [Rabi'ah bin Saif Al Ma'afiri], dari [Abu Abdurrahman Al Hubuli], dari [Abdullah bin 'Amr Al 'Ash], ia berkata; kami menguburkan jenazah bersama Rasulullah shallallahu 'alaihi wasallam, kemudian tatkala kami telah selesai Rasulullah shallallahu 'alaihi wasallam pergi dan kami pergi bersamanya. Kemudian tatkala beliau telah menghadap pintu, beliau berdiri. Ternyata kami di hadapan seorang wanita yang datang menghadap. Abdullah bin 'Amr bin Al 'Ash berkata; aku mengira beliau mengenalnya, kemudian tatkala wanita tersebut pergi ternyata ia adalah Fathimah 'alaihassalam. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Apa yang menyebabkanmu keluar dari rumahmu wahai Fathimah?\" Ia berkata; wahai Rasulullah, aku mendatangi penghuni rumah ini, dan menghibur mereka karena salah seorang diantara mereka meninggal. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kemungkinan engkau telah sampai ke Al Kuda (kuburan) bersama mereka.\" Ia berkata; aku berlindung kepada Allah, sungguh aku telah mendengar engkau mengatakan apa yang telah engkau katakan. Abdullah bin 'Amr bin Al 'Ash berkata; aku kira hal tersebut adalah kuburan. "},"2641":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَأَتَى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى امْرَأَةٍ تَبْكِي عَلَى صَبِيٍّ لَهَا فَقَالَ لَهَا اتَّقِي اللَّهَ وَاصْبِرِي فَقَالَتْ وَمَا تُبَالِي أَنْتَ بِمُصِيبَتِي فَقِيلَ لَهَا هَذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَتْهُ فَلَمْ تَجِدْ عَلَى بَابِهِ بَوَّابِينَ فَقَالَتْ يَا رَسُولَ اللَّهِ لَمْ أَعْرِفْكَ فَقَالَ إِنَّمَا الصَّبْرُ عِنْدَ الصَّدْمَةِ الْأُولَى أَوْ عِنْدَ أَوَّلِ صَدْمَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Utsman bin Umar], telah menceritakan kepada kami [Syu'bah] dari [Tsabit] dari [Anas] ia berkata; Nabi shallallahu 'alaihi wasallam datang kepada seorang wanita yang sedang menangisi kematian anaknya, kemudian beliau berkata kepadanya: \"Bertakwalah kepada Allah, dan bersabarlah!\" kemudian wanita tersebut berkata; engkau tidak mengalami musibahku. Kemudian dikatakan kepadanya; ia adalah Nabi shallallahu 'alaihi wasallam. Maka wanita tersebut datang kepada beliau dan ia tidak mendapati di depan pintu beliau terdapat para penjaga. Lalu wanita tersebut berkata; wahai Rasulullah, aku tidak mengenal engkau. Kemudian beliau bersabda: \"Sesungguhnya kesabaran itu disaat terkena musibah yang pertama.\""},"2642":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَ سَمِعْتُ أَبَا عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍأَنَّ ابْنَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَتْ إِلَيْهِ وَأَنَا مَعَهُ وَسَعْدٌ وَأَحْسَبُ أُبَيًّا أَنَّ ابْنِي أَوْ بِنْتِي قَدْ حُضِرَ فَاشْهَدْنَا فَأَرْسَلَ يُقْرِئُ السَّلَامَ فَقَالَ قُلْ لِلَّهِ مَا أَخَذَ وَمَا أَعْطَى وَكُلُّ شَيْءٍ عِنْدَهُ إِلَى أَجَلٍ فَأَرْسَلَتْ تُقْسِمُ عَلَيْهِ فَأَتَاهَا فَوُضِعَ الصَّبِيُّ فِي حِجْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَفْسُهُ تَقَعْقَعُ فَفَاضَتْ عَيْنَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ سَعْدٌ مَا هَذَا قَالَ إِنَّهَا رَحْمَةٌ وَضَعَهَا اللَّهُ فِي قُلُوبِ مَنْ يَشَاءُ وَإِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada kami [Syu'bah] dari ['Ashim Al Ahwal], ia berkata; saya mendengar [Abu Utsman] dari [Usamah bin Zaid] bahwa anak wanita Rasulullah shallallahu 'alaihi wasallam telah mengirimkan utusan kepada beliau sementara saya dan Sa'd bersama dengan beliau, aku mengira Ubai juga bersama beliau. Ia berkata; sesungguhnya anakku telah mendekati kematian maka saksikanlah kami! Kemudian beliau mengirimkan utusan dan membacakan salam. Kemudian beliau berkata; ucapkan; milik Allah apa yang Dia ambil dan apa yang Dia berikan, segala sesuatu disisiNya hingga waktu yang telah ditentukan. Kemudian ia mengirimkan utusan dan bersumpah atas beliau. Kemudian beliau datang kepadanya, lalu anak tersebut diletakkan dalam pangkuan Rasulullah shallallahu 'alaihi wasallam sementara nafasnya tersengal-sengal, kemudian kedua mata Rasulullah shallallahu 'alaihi wasallam bercucuran air mata. Kemudian Sa'd berkata kepada beliau; Mengapa engkau menangis? Beliau berkata: \"Sesungguhnya itu adalah kasih sayang yang Allah letakkan pada hati orang yang Dia kehendaki, sesungguhnya Allah merahmati hamba-hambaNya yang penyayang.\""},"2643":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وُلِدَ لِي اللَّيْلَةَ غُلَامٌ فَسَمَّيْتُهُ بِاسْمِ أَبِي إِبْرَاهِيمَ فَذَكَرَ الْحَدِيثَ قَالَ أَنَسٌ لَقَدْ رَأَيْتُهُ يَكِيدُ بِنَفْسِهِ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَمَعَتْ عَيْنَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تَدْمَعُ الْعَيْنُ وَيَحْزَنُ الْقَلْبُ وَلَا نَقُولُ إِلَّا مَا يُرْضِي رَبَّنَا إِنَّا بِكَ يَا إِبْرَاهِيمُ لَمَحْزُونُونَ","id":"Telah menceritakan kepada kami [Syaiban bin Farrukh], Telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit Al Bunani] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya tadi malam anakku lahir, kemudian aku menamainya dengan nama ayahku yaitu Ibrahim…\" kemudian ia menyebutkan hadits tersebut. Anas berkata; sungguh aku melihat anak tersebut mengalami sakarat di hadapan Rasulullah shallallahu 'alaihi wasallam kemudian kedua mata beliau mencucurkan air mata. Kemudian beliau berkata: \"Mata menangis dan hati bersedih, dan kami tidak mengucapkan kecuali apa yang membuat Tuhan kami ridha. Sesungguhnya kami sangat bersedih terhadapmu wahai Ibrahim.\""},"2644":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا عَنْ النِّيَاحَةِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdul Warits] dari [Ayyub] dari [Hafshah] dari [Ummu 'Athiyyah] ia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kami dari meratapi kematian. "},"2645":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا مُحَمَّدُ بْنُ رَبِيعَةَ عَنْ مُحَمَّدِ بْنِ الْحَسَنِ بْنِ عَطِيَّةَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّائِحَةَ وَالْمُسْتَمِعَةَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa], telah mengabarkan kepada kami [Muhammad bin Rabi'ah] dari [Muhammad bin Al Hasan bin 'Athiyyah], dari [ayahnya] dari [kakeknya] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang meratap dan wanita yang sengaja mendengarnya. "},"2646":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ عَبْدَةَ وَأَبِي مُعَاوِيَةَ الْمَعْنَى عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِ فَذُكِرَ ذَلِكَ لِعَائِشَةَ فَقَالَتْ وَهِلَ تَعْنِي ابْنَ عُمَرَ إِنَّمَا مَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرٍ فَقَالَ إِنَّ صَاحِبَ هَذَا لَيُعَذَّبُ وَأَهْلُهُ يَبْكُونَ عَلَيْهِ ثُمَّ قَرَأَتْ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }قَالَ عَنْ أَبِي مُعَاوِيَةَ عَلَى قَبْرِ يَهُودِيٍّ","id":"Telah menceritakan kepada kami [Hannad bin As Sari], dari ['Abdah] dan [Abu Mu'awiyah] secara makna, dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang mati disiksa karena tangisan keluarganya.\" Kemudian hal tersebut disebutkan kepada [Aisyah], kemudian ia berkata; sesungguhnya Ibnu Umar telah salah. Sesungguhnya Nabi shallallahu 'alaihi wasallam pernah melewati sebuah kuburan kemudian berkata; \"Sesungguhnya penghuni kuburan ini diadzab sementara keluarganya menangisinya.\" Kemudian Aisyah membaca ayat: \"Dan seorang yang berdosa tidak akan memikul dosa orang lain.\" Ia berkata; dari Abu Mu'awiyah; melewati kuburan orang yahudi. "},"2647":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ يَزِيدَ بْنِ أَوْسٍ قَالَدَخَلْتُ عَلَى أَبِي مُوسَى وَهُوَ ثَقِيلٌ فَذَهَبَتْ امْرَأَتُهُ لِتَبْكِيَ أَوْ تَهُمَّ بِهِ فَقَالَ لَهَا أَبُو مُوسَى أَمَا سَمِعْتِ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ بَلَى قَالَ فَسَكَتَتْ فَلَمَّا مَاتَ أَبُو مُوسَى قَالَ يَزِيدُ لَقِيتُ الْمَرْأَةَ فَقُلْتُ لَهَا مَا قَوْلُ أَبِي مُوسَى لَكِ أَمَا سَمِعْتِ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ سَكَتِّ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ حَلَقَ وَمَنْ سَلَقَ وَمَنْ خَرَقَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Jarir], dari [Manshur?] dari [Ibrahim] dari [Yazid? bin Aus], ia berkata; aku menemui Abu Musa sementara ia sedang sakit, kemudian isterinya menangis atau bersedih. Lalu Abu Musa berkata kepadanya; tidakkah engkau mendengar apa yang telah dikatakan Rasulullah shallallahu 'alaihi wasallam? Ia berkata; Iya. Kemudian wanita tersebut diam. Tatkala Abu Musa telah meninggal -Yazid? berkata; aku bertemu dengan wanita tersebut kemudian aku katakan kepadanya; apa maksud perkataan Abu Musa kepadamu; tidakkah engkau mendengar apa yang telah dikatakan Rasulullah shallallahu 'alaihi wasallam? [wanita] tersebut berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah dari golonganku orang yang mencukur rambutnya, menyobek bajunya, dan menjerit.\""},"2648":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حُمَيْدُ بْنُ الْأَسْوَدِ حَدَّثَنَا الْحَجَّاجُ عَامِلٌ لِعُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَلَى الرَّبَذَةِ حَدَّثَنِي أَسِيدُ بْنُ أَبِي أَسِيدٍ عَنْ امْرَأَةٍ مِنَ الْمُبَايِعَاتِ قَالَتْكَانَ فِيمَا أَخَذَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَعْرُوفِ الَّذِي أَخَذَ عَلَيْنَا أَنْ لَا نَعْصِيَهُ فِيهِ أَنْ لَا نَخْمُشَ وَجْهًا وَلَا نَدْعُوَ وَيْلًا وَلَا نَشُقَّ جَيْبًا وَأَنْ لَا نَنْشُرَ شَعَرًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Humaid bin Al Aswad] telah menceritakan kepada kami [Al Hajjaj] pekerja Umar bin Abdul Aziz yang memimpin Rabadzah, telah menceritakan kepadaku [Asid bin Abu Asid] dari [seorang wanita dari wanita-wanita yang berbaiat]. Ia berkata; diantara yang Rasulullah shallallahu 'alaihi wasallam wajibkan atas kami diantara perkara yang ma'ruf adalah kami tidak bermaksiat kepadanya, dan tidak mencakar wajah, tidak menyerukan kebinasaan, dan tidak merobek saku, serta tidak mengacak-acak rambut. "},"2649":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي جَعْفَرُ بْنُ خَالِدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اصْنَعُوا لِآلِ جَعْفَرٍ طَعَامًا فَإِنَّهُ قَدْ أَتَاهُمْ أَمْرٌ شَغَلَهُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Ja'far bin Khalid] dan [ayahnya], dari [Abdullah bin Ja'far], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Buatkan makanan untuk keluarga Ja'far, sesungguhnya telah datang kepada mereka perkara yang menyibukkan mereka.\""},"2650":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا مَعْنُ بْنُ عِيسَى ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْجُشَمِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَرُمِيَ رَجُلٌ بِسَهْمٍ فِي صَدْرِهِ أَوْ فِي حَلْقِهِ فَمَاتَ فَأُدْرِجَ فِي ثِيَابِهِ كَمَا هُوَ قَالَ وَنَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ma'n bin Isa] dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami ['Ubaidullah bin Umar Al Jusyami], telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Ibrahim bin Thahman], dan [Abu Az Zubair] dari [Jabir] ia berkata; seorang laki-laki dipanah menggunakan anak panah pada dadanya atau pada tenggorokannya, kemudian ia meninggal. Lalu ia dibiarkan memakai pakainnya sebagaimana apa adanya. Ia berkata sementara kami bersama Rasulullah shallallahu 'alaihi wasallam. "},"2651":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ وَعِيسَى بْنُ يُونُسَ قَالَا حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلَى أُحُدٍ أَنْ يُنْزَعَ عَنْهُمْ الْحَدِيدُ وَالْجُلُودُ وَأَنْ يُدْفَنُوا بِدِمَائِهِمْ وَثِيَابِهِمْ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] dan [Isa bin Yunus], mereka berkata; Telah menceritakan kepada kami [Ali bin 'Ashim] dari ['Atha` bin As Saib], dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan agar dicabut besi dan kulit dari para kurban perang Uhud dan agar mereka di kubur dengan darah dan pakaian mereka. "},"2652":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ ح و حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ وَهَذَا لَفْظُهُ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ اللَّيْثِيُّ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْأَنَّ شُهَدَاءَ أُحُدٍ لَمْ يُغَسَّلُوا وَدُفِنُوا بِدِمَائِهِمْ وَلَمْ يُصَلَّ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], dan ini adalah lafazhnya, telah mengabarkan kepadaku [Usamah bin Zaid Al Laitsi] bahwa [Ibnu Syihab] telah mengabarkan kepadanya bahwa [Anas bin Malik] telah menceritakan kepada mereka bahwa para syuhada` Uhud tidak dimandikan, dan mereka dikubur dengan darah mereka (lumuran darah yang pada jenazah mereka), serta tidak dishalatkan. "},"2653":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدٌ يَعْنِي ابْنَ الْحُبَابِ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو صَفْوَانَ يَعْنِي الْمَرْوَانِيَّ عَنْ أُسَامَةَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ الْمَعْنَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى حَمْزَةَ وَقَدْ مُثِّلَ بِهِ فَقَالَ لَوْلَا أَنْ تَجِدَ صَفِيَّةُ فِي نَفْسِهَا لَتَرَكْتُهُ حَتَّى تَأْكُلَهُ الْعَافِيَةُ حَتَّى يُحْشَرَ مِنْ بُطُونِهَا وَقَلَّتْ الثِّيَابُ وَكَثُرَتْ الْقَتْلَى فَكَانَ الرَّجُلُ وَالرَّجُلَانِ وَالثَّلَاثَةُ يُكَفَّنُونَ فِي الثَّوْبِ الْوَاحِدِ زَادَ قُتَيْبَةُ ثُمَّ يُدْفَنُونَ فِي قَبْرٍ وَاحِدٍ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُ أَيُّهُمْ أَكْثَرُ قُرْآنًا فَيُقَدِّمُهُ إِلَى الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?] telah menceritakan kepada kami [Zaid bin Al Hubab], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Abu Shafwan Al Marwazi], dari [Usamah] dari [Az Zuhri] dari [Anas bin Malik] secara makna bahwa Rasulullah shallallahu 'alaihi wasallam pernah melewati Hamzah dalam keadaan telah tercincang. Kemudian beliau berkata: \"Seandainya Shafiyyah tidak mencintainya, niscaya aku biarkan dia hingga dimakan binatang yang sedang mencari makanan, sampai ia dikumpulkan pada Hari Kiamat dari perut binatang tersebut.\" Pada saat itu jumlah kain sedikit, dan orang yang terbunuh banyak, sehingga satu orang, dua orang dan tiga orang dikafani dalam satu kain. Qutaibah berkata; kemudian mereka dikuburkan dalam satu kuburan. Rasululullah bertanya: \"Siapakah yang paling banyak hafalan Al Qur'annya?\" Kemudian beliau mendahulukannya menghadap ke Kiblat. "},"2654":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا أُسَامَةُ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِحَمْزَةَ وَقَدْ مُثِّلَ بِهِ وَلَمْ يُصَلِّ عَلَى أَحَدٍ مِنْ الشُّهَدَاءِ غَيْرِهِ","id":"Telah menceritakan kepada kami [Abbas Al 'Anbari], telah menceritakan kepada kami [Utsman bin Umar], telah menceritakan kepada kami [Usamah] dari [Az Zuhri], dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam melewati Hamzah dan ia telah dicincang dan beliau tidak menshalatkan seorang pun dari para syuhada` selainnya. "},"2655":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَيَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ أَنَّ اللَّيْثَ حَدَّثَهُمْ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ الرَّجُلَيْنِ مِنْ قَتْلَى أُحُدٍ وَيَقُولُ أَيُّهُمَا أَكْثَرُ أَخْذًا لِلْقُرْآنِ فَإِذَا أُشِيرَ لَهُ إِلَى أَحَدِهِمَا قَدَّمَهُ فِي اللَّحْدِ وَقَالَ أَنَا شَهِيدٌ عَلَى هَؤُلَاءِ يَوْمَ الْقِيَامَةِ وَأَمَرَ بِدَفْنِهِمْ بِدِمَائِهِمْ وَلَمْ يُغَسَّلُواحَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ اللَّيْثِ بِهَذَا الْحَدِيثِ بِمَعْنَاهُ قَالَ يَجْمَعُ بَيْنَ الرَّجُلَيْنِ مِنْ قَتْلَى أُحُدٍ فِي ثَوْبٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Yazid bin Khalid bin Mauhib], bahwa [Al Laits] telah menceritakan kepada mereka dari [Ibnu Syihab] dari [Abdurrahman bin Ka'b] bahwa [Jabir bin Abdullah] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam menggabungkan antara dua orang diantara orang-orang yang terbunuh dalam perang Uhud. Dan beliau berkata: \"Siapakah diantara mereka berdua yang lebih banyak menghafal Al Qur'an?\" apabila telah ditunjukkan kepada salah seorang diantara mereka berdua (banyaknya hafalan di antara keduanya), maka beliau mendahulukannya memasukkan ke dalam lahad dan berkata: \"Aku menjadi saksi bagi mereka pada Hari Kiamat.\" Beliau memerintahkan untuk mengubur mereka bersama darah mereka dan mereka tidak dimandikan. Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah menceritakan kepada kami [Ibnu Wahb], dari [Al Laits] dengan hadits ini dengan maknanya. Ia berkata; beliau menggabungkan dua orang diantara korban perang Uhud dalam satu kain. "},"2656":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَهْلٍ الرَّمْلِيُّ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أُخْبِرْتُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُبْرِزْ فَخِذَكَ وَلَا تَنْظُرَنَّ إِلَى فَخِذِ حَيٍّ وَلَا مَيِّتٍ","id":"Telah menceritakan kepada kami [Ali bin Sahl Ar Ramli], telah menceritakan kepada kami [Hajjaj] dari [Juraij], ia berkata; aku diberitahu dari [Habib bin Abu Tsabit], dari ['Ashim bin Dhamrah] dari [Ali] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Jangan engkau nampakkan pahamu, dan jangan engkau memandang kepada paha orang hidup maupun mati.\""},"2657":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي يَحْيَى بْنُ عَبَّادٍ عَنْ أَبِيهِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَ سَمِعْتُ عَائِشَةَ تَقُولُلَمَّا أَرَادُوا غَسْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَاللَّهِ مَا نَدْرِي أَنُجَرِّدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ثِيَابِهِ كَمَا نُجَرِّدُ مَوْتَانَا أَمْ نَغْسِلُهُ وَعَلَيْهِ ثِيَابُهُ فَلَمَّا اخْتَلَفُوا أَلْقَى اللَّهُ عَلَيْهِمْ النَّوْمَ حَتَّى مَا مِنْهُمْ رَجُلٌ إِلَّا وَذَقْنُهُ فِي صَدْرِهِ ثُمَّ كَلَّمَهُمْ مُكَلِّمٌ مِنْ نَاحِيَةِ الْبَيْتِ لَا يَدْرُونَ مَنْ هُوَ أَنْ اغْسِلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ ثِيَابُهُ فَقَامُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغَسَلُوهُ وَعَلَيْهِ قَمِيصُهُ يَصُبُّونَ الْمَاءَ فَوْقَ الْقَمِيصِ وَيُدَلِّكُونَهُ بِالْقَمِيصِ دُونَ أَيْدِيهِمْ وَكَانَتْ عَائِشَةُ تَقُولُ لَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا غَسَلَهُ إِلَّا نِسَاؤُهُ","id":"Telah menceritakan kepada kami [An Nufaili], telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq], telah menceritakan kepadaku [Yahya bin 'Abbad] dari [ayahnya yaitu 'Abbad bin Abdullah bin Az Zubair], ia berkata; aku mendengar [Aisyah] berkata; tatkala mereka hendak memandikan Rasulullah shallallahu 'alaihi wasallam mereka mengatakan; demi Allah, kami tidak tahu apakah kita akan menelanjangi Rasulullah shallallahu 'alaihi wasallam dari pakaiannya sebagaimana kita menelanjangi orang-orang yang meninggal diantara kita atau kita memandikannya dalam keadaan beliau memakai pakaiannya? Tatkala mereka berselisih, Allah menidurkan mereka hingga tidak ada seorangpun melainkan dagunya menempel pada dadanya. Kemudian mereka diajak bicara seseorang yang berbicara dari sisi rumah, mereka tidak mengetahui siapakah dia. Orang tersebut berkata; mandikan Nabi shallallahu 'alaihi wasallam dalam keadaan memakai pakaiannya. Kemudian mereka bangkit menuju kepada Rasulullah shallallahu 'alaihi wasallam dan memandikan beliau dalam keadaan beliau memakai jubahnya. Mereka menuangkan air dari atas jubah dan memijat-mijatnya dengan jubah bukan dengan tangan mereka. Aisyah berkata; seandainya nampak bagiku dahulu seperti apa yang nampak sekarang ini maka tidak ada yang memandikan beliau kecuali para isterinya. "},"2658":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ الْمَعْنَى عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَتْ ابْنَتُهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَعْطَانَا حَقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُ قَالَ عَنْ مَالِكٍ يَعْنِي إِزَارَهُ وَلَمْ يَقُلْ مُسَدَّدٌ دَخَلَ عَلَيْنَاحَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ وَأَبُو كَامِلٍ بِمَعْنَى الْإِسْنَادِ أَنَّ يَزِيدَ بْنَ زُرَيْعٍ حَدَّثَهُمْ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ حَفْصَةَ أُخْتِهِ عَنْ أُمِّ عَطِيَّةَ قَالَتْ مَشَطْنَاهَا ثَلَاثَةَ قُرُونٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا هِشَامٌ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْ وَضَفَّرْنَا رَأْسَهَا ثَلَاثَةَ قُرُونٍ ثُمَّ أَلْقَيْنَاهَا خَلْفَهَا مُقَدَّمَ رَأْسِهَا وَقَرْنَيْهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] secara makna, dari [Ayyub] dari [Muhammad bin Sirin] dari [Ummu 'Athiyyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menemui kami ketika anak wanitanya meninggal. Kemudian beliau bersabda: \"Mandikan dia tiga kali, atau lima kali atau lebih dari itu apabila kalian pandang hal itu perlu, dengan air bidara, dan jadikan pada terakhir kalinya kapur barus atau sedikit kapur barus. Apabila kalian telah selesai maka beritahukan kepadaku!\" Maka tatkala kami telah selesai, kami memberitahukan kepada beliau. Kemudian beliau memberikan sarung beliau dan berkata: \"Jadikanlah kain tersebut sebagai pakaiannya.\" Al Qa'nabi berkata dari Malik; yaitu sarungnya, sedangkan Musaddad tidak mengatakan; menemui kami. Telah menceritakan kepada kami [Ahmad bin 'Abdah] dan [Abu Kamil], dengan makna sanad tersebut bahwa [Yazid? bin Zurai'] telah menceritakan kepada mereka, telah menceritakan kepada kami [Ayyub] dari [Muhammad bin Sirin], dari [Hafshah] yaitu saudarinya, dari [Ummu 'Athiyyah], ia berkata; kami menyisir rambutnya dalam tiga kepang. Telah menceritakan kepada kami [Muhammad Al Mutsanna], telah menceritakan kepada kami [Abdul A'la], telah menceritakan kepada kami [Hisyam], telah menceritakan kepada kami [Hafshah binti Sirin], dari [Ummu 'Athiyyah], ia berkata; dan kami mengepang kepalanya menjadi tiga kepang, kemudian meletakkannya di belakangnya, di bagian depan dan kedua sampingnya. "},"2659":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا خَالِدٌ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُنَّ فِي غُسْلِ ابْنَتِهِ ابْدَأْنَ بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَاحَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ بِمَعْنَى حَدِيثِ مَالِكٍ زَادَ فِي حَدِيثِ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ بِنَحْوِ هَذَا وَزَادَتْ فِيهِ أَوْ سَبْعًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّهُ","id":"Telah menceritakan kepada kami [Abu Kamil], telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Khalid] dari [Hafshah binti Sirin], dari [Ummu 'Athiyyah] bahwa Rasulullah shallallahu 'alaihi wasallam berkata kepada mereka ketika memandikan anak wanitanya: \"Mulailah dari sisi kanannya dan tempat-tempat wudhunya.\" Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] sama dengan makna hadits Malik, ia tambahkan dalam hadits Hafshah dari Ummu 'Athiyyah sama dengan hadits ini, dan ia menambahkan padanya; atau tujuh kali, atau lebih dari hal itu apabila kalian memandang perlu.\""},"2660":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ مُحَمَّدِ بْنِ سِيرِينَأَنَّهُ كَانَ يَأْخُذُ الْغُسْلَ عَنْ أُمِّ عَطِيَّةَ يَغْسِلُ بِالسِّدْرِ مَرَّتَيْنِ وَالثَّالِثَةَ بِالْمَاءِ وَالْكَافُورِ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] dari [Muhammad bin Sirin] bahwa ia mengambil (cara) memandikan (mayat) dari [Ummu 'Athiyyah] dengan daun bidara dua kali dan ketiganya dengan air dan kapur barus. "},"2661":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ خَطَبَ يَوْمًا فَذَكَرَ رَجُلًا مِنْ أَصْحَابِهِ قُبِضَ فَكُفِّنَ فِي كَفَنٍ غَيْرِ طَائِلٍ وَقُبِرَ لَيْلًا فَزَجَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْبَرَ الرَّجُلُ بِاللَّيْلِ حَتَّى يُصَلَّى عَلَيْهِ إِلَّا أَنْ يَضْطَرَّ إِنْسَانٌ إِلَى ذَلِكَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَفَّنَ أَحَدُكُمْ أَخَاهُ فَلْيُحْسِنْ كَفَنَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], Telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] bahwa ia mendengar [Jabir bin Abdullah], menceritakan dari Nabi shallallahu 'alaihi wasallam bahwa beliau berkhutbah pada suatu hari. Kemudian beliau ingat kepada salah seorang sahabatnya yang meninggal dan dikafani pada kafan yang tidak sempurna dan dikuburkan pada malam hari. Dan Nabi shallallahu 'alaihi wasallam melarang seseorang dikubur pada malam hari hingga ia dishalatkan kecuali seseorang terpaksa melakukan hal tersebut. Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian mengkafani saudaranya, hendaknya ia mengkafani dengan baik.\""},"2662":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الزُّهْرِيُّ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْأُدْرِجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَوْبٍ حِبَرَةٍ ثُمَّ أُخِّرَ عَنْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Al Walid bin Muslim], telah menceritakan kepada kami [Al Auza'i], telah menceritakan kepada kami [Az Zuhri] dari [Al Qasim bin Muhammad], dari [Aisyah], ia berkata; Nabi shallallahu 'alaihi wasallam dikafani dengan hibarah (baju yang terbuat dari kapas di Yaman) kemudian ditunda dari penguburan beliau. "},"2663":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا إِسْمَعيِلُ يَعْنِي ابْنَ عَبْدِ الْكَرِيمِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ عَقِيلِ بْنِ مَعْقِلٍ عَنْ أَبِيهِ عَنْ وَهْبٍ يَعْنِي ابْنَ مُنَبِّهٍ عَنْ جَابِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا تُوُفِّيَ أَحَدُكُمْ فَوَجَدَ شَيْئًا فَلْيُكَفَّنْ فِي ثَوْبٍ حِبَرَةٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabah Al Bazzaz], telah menceritakan kepada kami [Isma'il bin Abdul Karim], telah menceritakan kepadaku [Ibrahim bin 'Aqil bin Ma'qil] dari [ayahnya] dari [Wahb bin Munabbih] dari [Jabir] ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian meninggal dalam keadaan mempunyai sesuatu (harta) maka hendaknya ia dikafani dengan hibarah.\""},"2664":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي أَخْبَرَتْنِي عَائِشَةُ قَالَتْكُفِّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثَةِ أَثْوَابٍ يَمَانِيَةٍ بِيضٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ مِثْلَهُ زَادَ مِنْ كُرْسُفٍ قَالَ فَذُكِرَ لِعَائِشَةَ قَوْلُهُمْ فِي ثَوْبَيْنِ وَبُرْدٍ حِبَرَةٍ فَقَالَتْ قَدْ أُتِيَ بِالْبُرْدِ وَلَكِنَّهُمْ رَدُّوهُ وَلَمْ يُكَفِّنُوهُ فِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Yahya bin Sa'id], dari [Hisyam] ia berkata; telah mengabarkan kepadaku [ayahku] telah menceritakan kepadanya [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam dikafani dalam tiga kain dari Yaman yang berwarna putih, tidak ada padanya jubah dan sorban. Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hafsh] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] seperti itu, ia menambahkan; dari Kursuf (kapas). Ia berkata; kemudian diceritkan kepada Aisyah ucapan mereka mengenai dua kain dan burdah hibarah (pakaian Yaman yang bergaris-garis dari kapas). Kemudian Aisyah berkata; telah didatangkan pakaian burdah akan tetapi mereka menolaknya dan tidak mengkafani beliau padanya. "},"2665":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ يَزِيدَ يَعْنِي ابْنَ أَبِي زِيَادٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَكُفِّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثَةِ أَثْوَابٍ نَجْرَانِيَّةٍ الْحُلَّةُ ثَوْبَانِ وَقَمِيصُهُ الَّذِي مَاتَ فِيهِ قَالَ أَبُو دَاوُد قَالَ عُثْمَانُ فِي ثَلَاثَةِ أَثْوَابٍ حُلَّةٍ حَمْرَاءَ وَقَمِيصِهِ الَّذِي مَاتَ فِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Utsman bin Abu Syaibah?], mereka berkata; telah menceritakan kepada kami [Ibnu Idris] dari [Yazid? bin Abu Ziyad] dari [Miqsam] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam dikafani dalam tiga kain dari Najran dua kain dan satu jubah yang beliau pakai tatkala meninggal. Abu Daud berkata; Utsman berkata; dalam tiga kain, dua pakaian dan jubahnya yang beliau pakai ketika meninggal. Abu Daud berkata; Utsman berkata; dalam tiga kain, pakaian merah, dan jubah yang beliau pakai ketiaka meninggal. "},"2666":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْمُحَارِبِيُّ حَدَّثَنَا عَمْرُو بْنُ هَاشِمٍ أَبُو مَالِكٍ الْجَنْبِيُّ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ عَامِرٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَلَا تُغَالِ لِي فِي كَفَنٍ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَغَالَوْا فِي ا��ْكَفَنِ فَإِنَّهُ يُسْلَبُهُ سَلْبًا سَرِيعًا","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid Al Muharibi], telah menceritakan kepada kami ['Amr bin Hasyim Abu Malik Al Janbi] dari [Isma'il bin Abu Khalid] dari [Amir] dari [Ali bin Abu Thalib], ia berkata; janganlah kalian bermewah-mewah dalam mengkafaniku. Karena sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian bermewah-mewah dalam mengkafani, karena sesungguhnya kain tersebut akan cepat rusak.\""},"2667":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ خَبَّابٍ قَالَإِنَّ مُصْعَبَ بْنَ عُمَيْرٍ قُتِلَ يَوْمَ أُحُدٍ وَلَمْ يَكُنْ لَهُ إِلَّا نَمِرَةٌ كُنَّا إِذَا غَطَّيْنَا بِهَا رَأْسَهُ خَرَجَ رِجْلَاهُ وَإِذَا غَطَّيْنَا رِجْلَيْهِ خَرَجَ رَأْسُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَطُّوا بِهَا رَأْسَهُ وَاجْعَلُوا عَلَى رِجْلَيْهِ شَيْئًا مِنْ الْإِذْخِرِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Al A'masy], dari [Abu Wail] dari [Khabbab] ia berkata; sesungguhnya Mush'ab bin 'Umair terbunuh pada saat perang Uhud dan ia hanya memiliki selembar kain yang apabila kami menutupi kepalanya maka kedua kakinya keluar dan apabila kami menutup kedua kakinya maka kepalanya keluar. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Tutupilah kepalanya dan letakkan di atas kakinya sebagian dari idzkhir.\""},"2668":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنِي ابْنُ وَهْبٍ حَدَّثَنِي هِشَامُ بْنُ سَعْدٍ عَنْ حَاتِمِ بْنِ أَبِي نَصْرٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ أَبِيهِ عَنْ عُبَادَةَ بْنِ الصَّامِتِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الْكَفَنِ الْحُلَّةُ وَخَيْرُ الْأُضْحِيَّةِ الْكَبْشُ الْأَقْرَنُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepadaku [Ibnu Wahb], telah menceritakan kepadaku [Hisyam bin Sa'dan] dari [Hatim bin Abu Nashr] dari ['Ubadah bin Nusai] dari [ayahnya] dari ['Ubadah bin Ash Shamit] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Sebaik-baik kafan adalah hullah (pakaian yang terdiri dari jubah, sarung dan serempang), dan sebaik-baik kurban adalah domba yang bertanduk.\""},"2669":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي نُوحُ بْنُ حَكِيمٍ الثَّقَفِيُّ وَكَانَ قَارِئًا لِلْقُرْآنِ عَنْ رَجُلٍ مِنْ بَنِي عُرْوَةَ بْنِ مَسْعُودٍ يُقَالُ لَهُ دَاوُدُ قَدْ وَلَّدَتْهُ أُمُّ حَبِيبَةَ بِنْتُ أَبِي سُفْيَانَ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ لَيْلَى بِنْتَ قَانِفٍ الثَّقَفِيَّةَ قَالَتْكُنْتُ فِيمَنْ غَسَّلَ أُمَّ كُلْثُومٍ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ وَفَاتِهَا فَكَانَ أَوَّلُ مَا أَعْطَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحِقَاءَ ثُمَّ الدِّرْعَ ثُمَّ الْخِمَارَ ثُمَّ الْمِلْحَفَةَ ثُمَّ أُدْرِجَتْ بَعْدُ فِي الثَّوْبِ الْآخَرِ قَالَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ عِنْدَ الْبَابِ مَعَهُ كَفَنُهَا يُنَاوِلُنَاهَا ثَوْبًا ثَوْبًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Ya'qub bin Ibrahim], telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq], telah menceritakan kepadaku [Nuh bin Hakim Ats Tsaqafi], dan ia adalah orang yang pandai membaca Al Qur'an, dari [seorang laki-laki] dari Bani 'Urwah bin Mas'ud yang dipanggil Daud, ia dilahirkan oleh Ummu Habibah binti Sufyan isteri Nabi shallallahu 'alaihi wasallam, bahwa [Laila binti Qanif Ats Tsaqafi] berkata; aku termasuk diantara orang yang memandikan Ummu Kultsum anak Rasulullah shallallahu 'alaihi wasallam ketika ia meninggal. Pertama yang beliau berikan kepada kami adalah sarung, kemudian baju kurung, kemudian penutup kepala, kemudian kain selimut kemudian setelah itu dimasukkan pada kain yang lain. Ia berkata; sementara Rasulullah shallallahu 'alaihi wasallam dalam keadaan duduk di depan pintu membawa kain kafannya, beliau memberikannya satu demi satu. "},"2670":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْمُسْتَمِرُ بْنُ الرَّيَّانِ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْيَبُ طِيبِكُمْ الْمِسْكُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Al Mustamir bin Ar Rayyan], dari [Abu Nadhrah], dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik minyak wangi yang kalian miliki adalah misik (kasturi) \""},"2671":{"ar":"حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ مُطَرِّفٍ الرُّؤَاسِيُّ أَبُو سُفْيَانَ وَأَحْمَدُ بْنُ جَنَابٍ قَالَا حَدَّثَنَا عِيسَى قَالَ أَبُو دَاوُد هُوَ ابْنُ يُونُسَ عَنْ سَعِيدِ بْنِ عُثْمَانَ الْبَلَوِيِّ عَنْ عُرْوَةَ بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ أَبِيهِ عَنْ الْحُصَيْنِ بْنِ وَحْوَحٍأَنَّ طَلْحَةَ بْنَ الْبَرَاءِ مَرِضَ فَأَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَقَالَ إِنِّي لَا أَرَى طَلْحَةَ إِلَّا قَدْ حَدَثَ فِيهِ الْمَوْتُ فَآذِنُونِي بِهِ وَعَجِّلُوا فَإِنَّهُ لَا يَنْبَغِي لِجِيفَةِ مُسْلِمٍ أَنْ تُحْبَسَ بَيْنَ ظَهْرَانَيْ أَهْلِهِ","id":"Telah menceritakan kepada kami [Abdurrahim bin Mutharrif Ar Ruasi Abu Sufyan] dan [Ahmad bin Janab], mereka berkata; telah menceritakan kepada kami [Isa]. Abu Daud berkata; ia adalah Ibnu Yunus dari [Sa'id bin Utsman Al Balwi], dari ['Urwah bin Sa'id Al Anshari], dari [ayahnya] dari [Al Hushain bin Wahwah] bahwa Thalhah bin Al Bara` sakit, kemudian Nabi shallallahu 'alaihi wasallam mengunjunginya. Lalu beliau berkata: \"Sesungguhnya aku melihat Thalhah telah mendekati kematiannya, maka beritahukan kematiannya dan bersegeralah untuk mengurus jenazahnya, karena sesungguhnya tidak layak jasad seorang muslim ditahan diantara keluarganya.\""},"2672":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا زَكَرِيَّا حَدَّثَنَا مُصْعَبُ بْنُ شَيْبَةَ عَنْ طَلْقِ بْنِ حَبِيبٍ الْعَنَزِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أَنَّهَا حَدَّثَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْتَسِلُ مِنْ أَرْبَعٍ مِنْ الْجَنَابَةِ وَيَوْمَ الْجُمُعَةِ وَمِنْ الْحِجَامَةِ وَغُسْلِ الْمَيِّتِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Muhammad bin Bisyr], telah menceritakan kepada kami [Zakariya], telah menceritakan kepada kami [Mush'ab bin Syaibah?], dari [Thalq bin Habib Al 'Anazi] dari [Abdullah bin Az Zubair] dari [Aisyah] bahwa ia telah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam mandi karena empat perkara yaitu, dari junub, pada hari Jum'at, dari berbekam dan memandikan mayit. "},"2673":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي ابْنُ أَبِي ذِئْبٍ عَنْ الْقَاسِمِ بْنِ عَبَّاسٍ عَنْ عَمْرِو بْنِ عُمَيْرٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ غَسَّلَ الْمَيِّتَ فَلْيَغْتَسِلْ وَمَنْ حَمَلَهُ فَلْيَتَوَضَّأْحَدَّثَنَا حَامِدُ بْنُ يَحْيَى عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ إِسْحَقَ مَوْلَى زَائِدَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ أَبُو دَاوُد هَذَا مَنْسُوخٌ و سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ وَسُئِلَ عَنْ الْغُسْلِ مِنْ غَسْلِ الْمَيِّتِ فَقَالَ يُجْزِيهِ الْوُضُوءُ قَالَ أَبُو دَاوُد أَدْخَلَ أَبُو صَالِحٍ بَيْنَهُ وَبَيْنَ أَبِي هُرَيْرَةَ فِي هَذَا الْحَدِيثِ يَعْنِي إِسْحَقَ مَوْلَى زَائِدَةَ قَالَ وَحَدِيثُ مُصْعَبٍ ضَعِيفٌ فِيهِ خِصَالٌ لَيْسَ الْعَمَلُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Abu Fudaik], telah menceritakan kepadaku [Ibnu Abu Dzi`b] dari [Al Qasim bin Abbas] dari ['Amr bin 'Umair] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memandikan mayit, maka hendaknya ia mandi, dan barangsiapa yang membawanya maka hendaknya ia berwudhu.\" Telah menceritakan kepada kami [Hamid bin Yahya], dari [Sufyan] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Ishaq] mantan budak Zaidah, dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam semakna dengan hadits tersebut. Abu Daud berkata; hadits ini adalah hadits yang mansukh (yang terhapus), dan aku telah mendengar Ahmad bin Hanbal ditanya mengenai memandikan mayit. Kemudian ia berkata; cukup baginya untuk berwudhu. Abu Daud berkata; Abu Shalih telah memasukkan Ishaq mantan budak Zaidah di antara dirinya dan Abu Hurairah. Abu Daud berkata; hadits Mush'ab adalah lemah padanya terdapat sifat yang tidak menjadi sandaran untuk beramal. "},"2674":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُ عُثْمَانَ بْنَ مَظْعُونٍ وَهُوَ مَيِّتٌ حَتَّى رَأَيْتُ الدُّمُوعَ تَسِيلُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari ['Ashim bin 'Ubaidullah] dari [Al Qasim] dari [Aisyah] ia berkata; aku melihat Rasulullah shallallahu 'alaihi wasallam mencium Utsman bin Mazh'un sementara ia telah meninggal hingga aku melihat air mata beliau mengalir. "},"2675":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ بَزِيعٍ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ أَوْ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَرَأَى نَاسٌ نَارًا فِي الْمَقْبَرَةِ فَأَتَوْهَا فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْقَبْرِ وَإِذَا هُوَ يَقُولُ نَاوِلُونِي صَاحِبَكُمْ فَإِذَا هُوَ الرَّجُلُ الَّذِي كَانَ يَرْفَعُ صَوْتَهُ بِالذِّكْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Bazi'], telah menceritakan kepada kami [Abu Nu'aim] dari [Muhammad bin Muslim] dari ['Amr bin Dinar] telah mengabarkan kepadaku [Jabir bin Abdullah] atau aku telah mendengar Jabir bin Abdullah berkata; orang-orang melihat api di sebuah kuburan, kemudian mereka mendatanginya, ternyata Rasulullah shallallahu 'alaihi wasallam berada dalam kuburan dan beliau berkata: \"Serahkan kepadaku sahabat kalian!\" Ternyata ia adalah seorang laki-laki yang mengeraskan suara ketika berdzikir."},"2676":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ نُبَيْحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا حَمَلْنَا الْقَتْلَى يَوْمَ أُحُدٍ لِنَدْفِنَهُمْ فَجَاءَ مُنَادِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكُمْ أَنْ تَدْفِنُوا الْقَتْلَى فِي مَضَاجِعِهِمْ فَرَدَدْنَاهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Al Aswad bin Qais] dari [Nubaih] dari [Jabir bin Abdullah], ia berkata; dahulu kami membawa orang-orang yang terbunuh pada saat perang Uhud untuk menguburkan mereka. Kemudian penyeru Rasulullah shallallahu 'alaihi wasallam datang dan berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkan kalian agar menguburkan orang-orang yang terbunuh di tempat-tempat mereka terbunuh. Maka kami mengembalikan mereka. "},"2677":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدٍ الْيَزَنِيِّ عَنْ مَالِكِ بْنِ هُبَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمٍ يَمُوتُ فَيُصَلِّي عَلَيْهِ ثَلَاثَةُ صُفُوفٍ مِنْ الْمُسْلِمِينَ إِلَّا أَوْجَبَقَالَ فَكَانَ مَالِكٌ إِذَا اسْتَقَلَّ أَهْلَ الْجَنَازَةِ جَزَّأَهُمْ ثَلَاثَةَ صُفُوفٍ لِلْحَدِيثِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepada kami [Hammad] dari [Muhammad bin Ishaq], dari [Yazid? bin Abu Habib] dari [Martsad Al Bazini], dari [Malik bin Hubairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim meninggal kemudian terdapat tiga shaf orang-orang muslim yang menshalatkannya kecuali Allah mewajibkan ia masuk surga.\" Martsad berkata; Malik apabila menganggap orang-orang yang akan menshalatkan jenazah sedikit, maka ia membaginya menjadi tiga barisan berdasarkan hadits. "},"2678":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْنُهِينَا أَنْ نَتَّبِعَ الْجَنَائِزَ وَلَمْ يُعْزَمْ عَلَيْنَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Hafshah] dari [Ummu 'Athiyyah] ia berkata; kami dilarang mengikuti (mengiringi) jenazah, akan tetapi tidak haramkan atas kami. "},"2679":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ يَرْوِيهِ قَالَمَنْ تَبِعَ جَنَازَةً فَصَلَّى عَلَيْهَا فَلَهُ قِيرَاطٌ وَمَنْ تَبِعَهَا حَتَّى يُفْرَغَ مِنْهَا فَلَهُ قِيرَاطَانِ أَصْغَرُهُمَا مِثْلُ أُحُدٍ أَوْ أَحَدُهُمَا مِثْلُ أُحُدٍحَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ وَعَبْدُ الرَّحْمَنِ بْنُ حُسَيْنٍ الْهَرَوِيُّ قَالَا حَدَّثَنَا الْمُقْرِئُ حَدَّثَنَا حَيْوَةُ حَدَّثَنِي أَبُو صَخْرٍ وَهُوَ حُمَيْدُ بْنُ زِيَادٍ أَنَّ يَزِيدَ بْنَ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ حَدَّثَهُ أَنَّ دَاوُدَ بْنَ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ حَدَّثَهُ عَنْ أَبِيهِ أَنَّهُ كَانَ عِنْدَ ابْنِ عُمَرَ بْنِ الْخَطَّابِ إِذْ طَلَعَ خَبَّابٌ صَاحِبِ الْمَقْصُورَةِ فَقَالَ يَا عَبْدَ اللَّهِ بْنَ عُمَرَ أَلَا تَسْمَعُ مَا يَقُولُ أَبُو هُرَيْرَةَ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ خَرَجَ مَعَ جَنَازَةٍ مِنْ بَيْتِهَا وَصَلَّى عَلَيْهَا فَذَكَرَ مَعْنَى حَدِيثِ سُفْيَانَ فَأَرْسَلَ ابْنُ عُمَرَ إِلَى عَائِشَةَ فَقَالَتْ صَدَقَ أَبُو هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Sumai] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; barangsiapa yang mengikuti jenazah dan menshalatinya maka baginya pahala satu qirath, dan barangsiapa yang mengikutinya hingga selesai darinya maka baginya pahala dua qirath, paling kecilnya adalah seperti Gunung Uhud atau salah satunya seperti Uhud. Telah menceritakan kepada kami [Harun bin Abdullah] dan [Abdurrahman bin Husain Al Marawi], mereka berkata; telah menceritakan kepada kami [Al Muqri`], telah menceritakan kepada kami [Haiwah], telah menceritakan kepadaku [Abu Shakhr yaitu Humaid bin Ziyad] bahwa [Yazid? bin Abdullah bin Qusaith] telah menceritakan kepadanya bahwa [Daud bin Amir bin Sa'd bin Abu Waqqash] telah menceritakan kepadanya dari [ayahnya] bahwa ia pernah berada di sisi Ibnu Umar bin Al Khathab tiba-tiba [Khabbab] pemilik maqshurah (rumah yang dibentengi dengan pagar) muncul dan berkata; wahai Abdullah bin Umar, tidakkah engkau mendengar apa yang dikatakan [Abu Hurairah]? Bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang keluar bersama jenazah dari rumahnya dan menshalatkannya…..\" kemudian ia menyebutkan makna hadits Sufyan. Kemudian Ibnu Umar mengirimkan utusan kepada Aisyah kemudian, kemudian [Aisyah] berkata; Abu Hurairah benar. "},"2680":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ شُجَاعٍ السَّكُونِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أَبُو صَخْرٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ مُسْلِمٍ يَمُوتُ فَيَقُومُ عَلَى جَنَازَتِهِ أَرْبَعُونَ رَجُلًا لَا يُشْرِكُونَ بِاللَّهِ شَيْئًا إِلَّا شُفِّعُوا فِيهِ","id":"Telah menceritakan kepada kami [Al Walid bin Syuja'As Sakuni], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Abu Shakhr] dari [Syarik bin Abdullah bin Abu Namir] dari [Kuraib] dari [Ibnu Abbas], ia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim meninggal dunia, kemudian terdapat empat puluh orang yang tidak mensekutukan Allah dengan sesuatupun berdiri untuk menshalatkan jenazahnya melainkan diterima syafa'at mereka untuknya.\""},"2681":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الصَّمَدِ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ قَالَا حَدَّثَنَا حَرْبٌ يَعْنِي ابْنَ شَدَّادٍ حَدَّثَنَا يَحْيَى حَدَّثَنِي بَابُ بْنُ عُمَيْرٍ حَدَّثَنِي رَجُلٌ مِنْ أَهْلِ الْمَدِينَةِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُتْبَعُ الْجَنَازَةُ بِصَوْتٍ وَلَا نَارٍ زَادَ هَارُونُ وَلَا يُمْشَى بَيْنَ يَدَيْهَا","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Abdushshamad], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibnu Al Mutsanna] Telah menceritakan kepada kami [Abu Daud] mereka berkata; telah menceritakan kepada kami [Harb bin Syaddad], telah menceritakan kepada kami [Yahya] telah menceritakan kepadaku [Bab bin 'Umair], telah menceritakan kepadaku [seorang laki-laki dari penduduk Madinah], dari [ayahnya], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak boleh jenazah diiringi dengan suara dan api.\" Harun menambahkan; dan tidak boleh ada yang berjalan di depannya. "},"2682":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ عَنْ عَامِرِ بْنِ رَبِيعَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الْجَنَازَةَ فَقُومُوا لَهَا حَتَّى تُخَلِّفَكُمْ أَوْ تُوضَعَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim], dari [ayahnya], dari [Amir bin Rabi'ah] hingga sampai kepada Nabi shallallahu 'alaihi wasallam: \"Apabila kalian melihat jenazah, maka berdirilah kalian untuk (menghormati) nya hingga jenazah telah melewati kalian atau diletakkan.\""},"2683":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ ابْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَبِعْتُمْ الْجَنَازَةَ فَلَا تَجْلِسُوا حَتَّى تُوضَعَقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ الثَّوْرِيُّ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ فِيهِ حَتَّى تُوضَعَ بِالْأَرْضِ وَرَوَاهُ أَبُو مُعَاوِيَةَ عَنْ سُهَيْلٍ قَالَ حَتَّى تُوضَعَ فِي اللَّحْدِ قَالَ أَبُو دَاوُد وَسُفْيَانُ أَحْفَظُ مِنْ أَبِي مُعَاوِيَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Suhail bin Abu Shalih], dari [Ibnu Abu Sa'id Al Khudri] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian mengiringi jenazah, maka janganlah kalian duduk hingga jenazah tersebut diletakkan.\" Abu Daud berkata; hadits ini diriwayatkan oleh [Ats Tsauri] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] ia berkata dalam hadits tersebut; hingga diletakkan di bumi. Dan telah diriwayatkan [Abu Mu'awiyah] dari [Suhail] ia berkata; hingga diletakkan dalam lahad. Abu Daud berkata; dan Sufyan lebih hafal daripada Abu Mu'awiyah. "},"2684":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا أَبُو عَمْرٍو عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ حَدَّثَنِي جَابِرٌ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ مَرَّتْ بِنَا جَنَازَةٌ فَقَامَ لَهَا فَلَمَّا ذَهَبْنَا لِنَحْمِلَ إِذَا هِيَ جَنَازَةُ يَهُودِيٍّ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّمَا هِيَ جَنَازَةُ يَهُودِيٍّ فَقَالَ إِنَّ الْمَوْتَ فَزَعٌ فَإِذَا رَأَيْتُمْ جَنَازَةً فَقُومُوا","id":"Telah menceritakan kepada kami [Mu'ammal bin Al Fadhl Al Harrani], telah menceritakan kepada kami [Al Walid], telah menceritakan kepada kami [Abu 'Amr], dari [Yahya bin Abu Katsir] dari ['Ubaidullah bin Miqsam], telah menceritakan kepadaku [Jabir], ia berkata; kami pernah bersama Nabi shallallahu 'alaihi wasallam, tiba-tiba terdapat jenazah yang meleawati kami. Kemudian beliau berdiri untuknya, kemudian tatkala kami pergi untuk membawanya ternyata jenazah tersebut adalah jenazah orang yahudi. Kemudian kami katakan; wahai Rasulullah, sesungguhnya jenazah tersebut adalah jenazah orang yahudi. Kemudian beliau berkata: \"Sesungguhnya kematian adalah sesuatu yang menakutkan, apabila kalian melihat jenazah maka berdirilah.\""},"2685":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ وَاقِدِ بْنِ عَمْرِو بْنِ سَعْدِ بْنِ مُعَاذٍ الْأَنْصَارِيِّ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ مَسْعُودِ بْنِ الْحَكَمِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِي الْجَنَائِزِ ثُمَّ قَعَدَ بَعْدُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik], dari [Yahya bin Sa'id] dari [Waqid bin 'Amr bin Sa'd bin Mu'adz Al Anshari], dari [Nafi bin Jubair bin Muth'im], dari [Mas'ud Al Hakam] dari [Ali bin Abu Thalib] bahwa Nabi shallallahu 'alaihi wasallam berdiri untuk menghormati jenazah kemudian duduk setelah itu. "},"2686":{"ar":"حَدَّثَنَا هِشَامُ بْنُ بَهْرَامَ الْمَدَائِنِيُّ أَخْبَرَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبُو الْأَسْبَاطِ الْحَارِثِيُّ عَنْ عَبْدِ اللَّهِ بْنِ سُلَيْمَانَ بْنِ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُومُ ف��ي الْجَنَازَةِ حَتَّى تُوضَعَ فِي اللَّحْدِ فَمَرَّ بِهِ حَبْرٌ مِنْ الْيَهُودِ فَقَالَ هَكَذَا نَفْعَلُ فَجَلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ اجْلِسُوا خَالِفُوهُمْ","id":"Telah menceritakan kepada kami [Hisyam bin Bahram Al Madaini], telah mengabarkan kepada kami [Hatim bin Isma'il], telah menceritakan kepada kami [Abu Al Asbath Al Haritsi] dari [Abdullah bin Sulaiman bin Junadah bin Abu Umayyah] dari [ayahnya] dari [kakeknya] dari ['Ubadah bin Ash Shamit] ia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri untuk menghormati jenazah hingga diletakkan dalam lahad. Kemudian terdapat seorang pendeta yahudi melewatinya dan berkata; demikianlah kami melakukan. Kemudian Nabi shallallahu 'alaihi wasallam duduk dan berkata: \"Duduklah, selisihilah (bersikap berbeda terhadap) mereka.\""},"2687":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ ثَوْبَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِدَابَّةٍ وَهُوَ مَعَ الْجَنَازَةِ فَأَبَى أَنْ يَرْكَبَهَا فَلَمَّا انْصَرَفَ أُتِيَ بِدَابَّةٍ فَرَكِبَ فَقِيلَ لَهُ فَقَالَ إِنَّ الْمَلَائِكَةَ كَانَتْ تَمْشِي فَلَمْ أَكُنْ لِأَرْكَبَ وَهُمْ يَمْشُونَ فَلَمَّا ذَهَبُوا رَكِبْتُ","id":"Telah menceritakan kepada kami [Yahya bin Musa Al Balkhi], telah mengabarkan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman bin 'Auf] dari [Tsauban], bahwa Rasulullah shallallahu 'alaihi wasallam telah diberi seekor unta sementara beliau sedang berada bersama jenazah, kemudian beliau menolak untuk menaikinya. Kemudian tatkala beliau telah pergi, beliau diberi unta lalu menaikinya. Kemudian beliau ditanya; lalu beliau berkata; sesungguhnya malaikat berjalan maka aku tidak akan naik kendaraan sementara mereka berjalan kaki. Kemudian tatkala mereka pergi, maka aku naik. "},"2688":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ سَمِعَ جَابِرَ بْنَ سَمُرَةَ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ابْنِ الدَّحْدَاحِ وَنَحْنُ شُهُودٌ ثُمَّ أُتِيَ بِفَرَسٍ فَعُقِلَ حَتَّى رَكِبَهُ فَجَعَلَ يَتَوَقَّصُ بِهِ وَنَحْنُ نَسْعَى حَوْلَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Syu'bah] dari [Simak], saya mendengar [Jabir bin Samurah] ia berkata; Nabi shallallahu 'alaihi wasallam menshalati Ibnu Ad Dahdah, dan kami menyaksikan, kemudian beliau diberi kuda lalu kuda tersebut diikat hingga beliau menaikinya dan berjalan pelan, sementara kami berjalan di sekitarnya. "},"2689":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ يَمْشُونَ أَمَامَ الْجَنَازَةِ","id":"Telah menceritakan kepada kami [Al Qa'nabi], telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Salim] dari [ayahnya], ia berkata; aku melihat Nabi shallallahu 'alaihi wasallam, Abu Bakr, dan Umar berjalan kaki di depan jenazah. "},"2690":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ يُونُسَ عَنْ زِيَادِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَوَأَحْسَبُ أَنَّ أَهْلَ زِيَادٍ أَخْبَرُونِي أَنَّهُ رَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرَّاكِبُ يَسِيرُ خَلْفَ الْجَنَازَةِ وَالْمَاشِي يَمْشِي خَلْفَهَا وَأَمَامَهَا وَعَنْ يَمِينِهَا وَعَنْ يَسَارِهَا قَرِيبًا مِنْهَا وَالسِّقْطُ يُصَلَّى عَلَيْهِ وَيُدْعَى لِوَالِدَيْهِ بِالْمَغْفِرَةِ وَالرَّحْمَةِ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah], dari [Khalid] dari [Yunus] dari [Ziyad bin Jubair] dari [ayahnya] dari [Al Mughirah bin Syu'bah] dan aku mengira bahwa keluarga Ziyad telah mengabarkan kepadaku bahwa ia mengangkatnya hingga Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang berkendaraan berjalan di belakang jenazah, orang yang berjalan kaki berjalan di belakangnya, dan di depannya, serta di samping kanan dan kirinya dekat dengannya. Dan janin yang keguguran dishalatkan dan didoakan untuk kedua orang tuanya agar diberi ampunan serta rahmat (kasih sayang) Allah.\""},"2691":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَسْرِعُوا بِالْجَنَازَةِ فَإِنْ تَكُ صَالِحَةً فَخَيْرٌ تُقَدِّمُونَهَا إِلَيْهِ وَإِنْ تَكُ سِوَى ذَلِكَ فَشَرٌّ تَضَعُونَهُ عَنْ رِقَابِكُمْ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id b al Musayyab] dari [Abu Hurairah] yang sampai kepada Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Percepatlah menguburkan jenazah, apabilla jenazah tersebut adalah jenazah yang baik maka kalian telah menyegerakannya kepada kebaikan (kenikmatan), dan apabila jenazah tersebut tidak seperti itu (jenazah yang buruk) maka kalian (segera) meletakkan keburukan tersebut dari pundak kalian.\""},"2692":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ عُيَيْنَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِأَنَّهُ كَانَ فِي جَنَازَةِ عُثْمَانَ بْنِ أَبِي الْعَاصِ وَكُنَّا نَمْشِي مَشْيًا خَفِيفًا فَلَحِقَنَا أَبُو بَكْرَةَ فَرَفَعَ سَوْطَهُ فَقَالَ لَقَدْ رَأَيْتُنَا وَنَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَرْمُلُ رَمَلًاحَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ ح و حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا عِيسَى يَعْنِي ابْنَ يُونُسَ عَنْ عُيَيْنَةَ بِهَذَا الْحَدِيثِ قَالَا فِي جَنَازَةِ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ وَقَالَ فَحَمَلَ عَلَيْهِمْ بَغْلَتَهُ وَأَهْوَى بِالسَّوْطِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Syu'bah] dari ['Uyainah bin Abdurrahman] dari [ayahnya] bahwa ia berada pada jenazah Utsman bin Abu Al 'Ash. Dan kami berjalan pelan, kemudian kami berjumpa dengan [Abu Bakrah], lalu ia mengangkat cemetinya dan berkata; sungguh aku telah melihat kami bersama Rasulullah shallallahu 'alaihi wasallam dan kami berjalan cepat. Telah menceritakan kepada kami [Humaid bin Mas'adah], telah menceritakan kepada kami [Khalid bin Al Harits], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibrahim bin Musa], telah menceritakan kepada kami [Isa bin Yunus] dari ['Uyainah] dengan hadits ini. Mereka berdua mengatakan; pada jenazah Abdurrahman bin Samurah. Dan ia berkata; kemudian beliau membawa bighalnya kepada mereka, dan menggiring menggunakan cemeti. "},"2693":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ يَحْيَى الْمُجَبِّرِ قَالَ أَبُو دَاوُد وَهُوَ يَحْيَى بْنُ عَبْدِ اللَّهِ التَّيْمِيُّ عَنْ أَبِي مَاجِدَةَ عَنْ ابْنِ مَسْعُودٍ قَالَسَأَلْنَا نَبِيَّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَشْيِ مَعَ الْجَنَازَةِ فَقَالَ مَا دُونَ الْخَبَبِ إِنْ يَكُنْ خَيْرًا تَعَجَّلَ إِلَيْهِ وَإِنْ يَكُنْ غَيْرَ ذَلِكَ فَبُعْدًا لِأَهْلِ النَّارِ وَالْجَنَازَةُ مَتْبُوعَةٌ وَلَا تُتْبَعُ لَيْسَ مَعَهَا مَنْ تَقَدَّمَهَاقَالَ أَبُو دَاوُد وَهُوَ ضَعِيفٌ هُوَ يَحْيَى بْنُ عَبْدِ اللَّهِ وَهُوَ يَحْيَى الْجَابِرُ قَالَ أَبُو دَاوُد وَهَذَا كُوفِيٌّ وَأَبُو مَاجِدَةَ بَصْرِيٌّ قَالَ أَبُو دَاوُد أَبُو مَاجِدَةَ هَذَا لَا يُعْرَفُ","id":"Telah menceritakan kepada kami [Musaddad], Telah menceritakan kepada kami [Abu 'Awanah], dan [Yahya Al Mujabbir], ia berkata; ia adalah Yahya bin Abdullah At Taimi, dari [Abu Majidah] dari [Ibnu Mas'ud] ia berkata; kami bertanya kepada Nabi kami shallallahu 'alaihi wasallam mengenai berjalan ketika menghantarkan jenazah. Kemudian beliau bersabda: \"Tidak sampai berlari, apabila jenazah itu baik maka ia segera mendapatkan kebaikan (kenikmatan), dan apabila tidak demikian (jenazahnya buruk) maka jauhilah penghuni neraka. Jenazah itu diikuti dan bukan engkau yang diikuti, tidak boleh ada yang mendahuluinya.\" Abu Daud berkata; hadits tersebut adalah dha'if, ia adalah Yahya bin Abdullah, dan ia adalah Yahya Al Jabir. Abu Daud berkata; dan ini adalah orang Kufah, dan Abu Majidah adalah orang Bashrah. Abu Daud berkata; Abu Majidah ini tidak dikenal. "},"2694":{"ar":"حَدَّثَنَا ابْنُ نُفَيْلٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سِمَاكٌ حَدَّثَنِي جَابِرُ بْنُ سَمُرَةَ قَالَمَرِضَ رَجُلٌ فَصِيحَ عَلَيْهِ فَجَاءَ جَارُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ إِنَّهُ قَدْ مَاتَ قَالَ وَمَا يُدْرِيكَ قَالَ أَنَا رَأَيْتُهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَمْ يَمُتْ قَالَ فَرَجَعَ فَصِيحَ عَلَيْهِ فَجَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ قَدْ مَاتَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَمْ يَمُتْ فَرَجَعَ فَصِيحَ عَلَيْهِ فَقَالَتْ امْرَأَتُهُ انْطَلِقْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبِرْهُ فَقَالَ الرَّجُلُ اللَّهُمَّ الْعَنْهُ قَالَ ثُمَّ انْطَلَقَ الرَّجُلُ فَرَآهُ قَدْ نَحَرَ نَفْسَهُ بِمِشْقَصٍ مَعَهُ فَانْطَلَقَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ أَنَّهُ قَدْ مَاتَ فَقَالَ وَمَا يُدْرِيكَ قَالَ رَأَيْتُهُ يَنْحَرُ نَفْسَهُ بِمَشَاقِصَ مَعَهُ قَالَ أَنْتَ رَأَيْتَهُ قَالَ نَعَمْ قَالَ إِذًا لَا أُصَلِّيَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ibnu Nufail], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Simak] telah menceritakan kepadaku [Jabir bin Samurah], ia berkata; ada seseorang yang mengalami sakit kemudian ia diteriaki (keluarganya menjerit karenanya). Lalu tetangganya datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata kepadanya; sesungguhnya ia telah meninggal. Beliau berkata: \"Bagaimana engkau mengetahui?\" ia berkata; saya melihatnya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia belum mati.\" Jabir berkata; kemudian orang itu kembali dan orang yang sakit tersebut diteriaki, lalu ia datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; sesungguhnya ia telah meninggal. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia belum mati.\" Kemudian orang itu kembali dan orang yang sakit tersebut diteriaki. Kemudian isterinya berkata; pergilah kepada Rasulullah shallallahu 'alaihi wasallam dan beritahukan kepada beliau! Lalu orang itu berkata; ya Allah laknatlah dia! Jabir bin Samurah berkata; kemudian orang itu pergi dan ia melihat orang yang sakit tersebut telah menyembelih dirinya menggunakan anak panah bermata lebar yang ia bawa. Orang itu pergi kepada Nabi shallallahu 'alaihi wasallam dan mengabarkan kepada beliau bahwa ia telah meninggal. Lalu beliau bersabda: \"Bagaimana engkau mengetahui?\" Ia berkata; saya melihatnya telah menyembelih dirinya menggunakan anak panah bermata lebar yang ia bawa. Beliau bertanya: \"Apakah engkau melihatnya?\" Ia berkata; Iya. Beliau bersabda: \"Jika demikian maka aku tidak akan menshalatinya.\""},"2695":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ حَدَّثَنِي نَفَرٌ مِنْ أَهْلِ الْبَصْرَةِ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُصَلِّ عَلَى مَاعِزِ بْنِ مَالِكٍ وَلَمْ يَنْهَ عَنْ الصَّلَاةِ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] telah menceritakan kepadaku [beberapa orang Bashrah], dari [Abu Barzah Al Aslami] bahwa Rasulullah shallallahu 'alaihi wasallam tidak menshalati Ma'iz bin Malik dan tidak melarang untuk menshalatkanya. "},"2696":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْمَاتَ إِبْرَاهِيمُ بْنُ النَّبِيِّ صَلّ��ى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ ابْنُ ثَمَانِيَةَ عَشَرَ شَهْرًا فَلَمْ يُصَلِّ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq], telah menceritakan kepadaku [Abdullah bin Abu Bakr] dari ['Amrah binti Abdurrahman] dari [Aisyah] ia berkata; Ibrahim anak Nabi shallallahu 'alaihi wasallam telah meninggal pada saat berumur delapan belas bulan, dan Rasulullah shallallahu 'alaihi wasallam tidak menshalatinya. "},"2697":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ وَائِلِ بْنِ دَاوُدَ قَالَ سَمِعْتُ الْبَهِيَّ قَالَلَمَّا مَاتَ إِبْرَاهِيمُ بْنُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَقَاعِدِقَالَ أَبُو دَاوُد قَ��َأْتُ عَلَى سَعِيدِ بْنِ يَعْقُوبَ الطَّالْقَانِيِّ قِيلَ لَهُ حَدَّثَكُمْ ابْنُ الْمُبَارَكِ عَنْ يَعْقُوبَ بْنِ الْقَعْقَاعِ عَنْ عَطَاءٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى ابْنِهِ إِبْرَاهِيمَ وَهُوَ ابْنُ سَبْعِينَ لَيْلَةً","id":"Telah menceritakan kepada kami [Hannad bin As Sari], telah menceritakan kepada kami [Muhammad bin 'Ubaid] dari [Wail bin Daud] ia berkata; saya mendengar [Al Bahi] berkata; tatkakala Ibrahim anak Nabi shallallahu 'alaihi wasallam meninggal, Rasulullah shallallahu 'alaihi wasallam menshalatinya di tempat yang dijadikan untuk duduk-duduk. Abu Daud berkata; aku membaca riwayat kepada [Sa'id bin Ya'qub Ath Thalqani], dikatakan kepadanya [Ibnu Al Mubarak] telah menceritakan kepada anda dari [Ya'qub Al Qa'qa'] dari ['Atha`] bahwa Nabi shallallahu 'alaihi wasallam menshalatkan anaknya yang bernama Ibrahim yang berumur tujuh puluh malam. "},"2698":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ صَالِحِ بْنِ عَجْلَانَ وَمُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّادٍ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْوَاللَّهِ مَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سُهَيْلِ ابْنِ الْبَيْضَاءِ إِلَّا فِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Shalih bin 'Ajlan] dan [Muhammad bin Abdullah bin 'Abbad] dari ['Abbad bin Abdullah bin Az Zubair] dari [Aisyah], ia berkata; Demi Allah, Rasulullah shallallahu 'alaihi wasallam tidak menshalati Suhail anak Al Baidha` kecuali di Mesjid. "},"2699":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ يَعْنِي ابْنَ عُثْمَانَ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْوَاللَّهِ لَقَدْ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ابْنَيْ بَيْضَاءَ فِي الْمَسْجِدِ سُهَيْلٍ وَأَخِيهِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Ibnu Abu Fudaik], dari [Adh Dhahhak bin Utsman] dari [Abu An Nadhr] dari [Abu Salamah] dari [Aisyah] ia berkata; demi Allah sungguh Rasulullah shallallahu 'alaihi wasallam telah menshalatkan dua anak Baidha` yaitu Suhail dan saudaranya di masjid."},"2700":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ أَبِي ذِئْبٍ حَدَّثَنِي صَالِحٌ مَوْلَى التَّوْأَمَةِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى عَلَى جَنَازَةٍ فِي الْمَسْجِدِ فَلَا شَيْءَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Abu Dzi`b] telah menceritakan kepadaku [Shalih] mantan budak At Tauma ah, dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menshalatkan jenazah di masjid, maka tidak mengapa.\""},"2701":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُوسَى بْنُ عَلِيِّ بْنِ رَبَاحٍ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ قَالَثَلَاثُ سَاعَاتٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا أَنْ نُصَلِّيَ فِيهِنَّ أَوْ نَقْبُرَ فِيهِنَّ مَوْتَانَا حِينَ تَطْلُعُ الشَّمْسُ بَازِغَةً حَتَّى تَرْتَفِعَ وَحِينَ يَقُومُ قَائِمُ الظَّهِيرَةِ حَتَّى تَمِيلَ وَحِينَ تَضَيَّفُ الشَّمْسُ لِلْغُرُوبِ حَتَّى تَغْرُبَ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Musa bin Ali bin Rabah], ia berkata; saya mendengar [ayahku] menceritakan bahwa ia mendengar ['Uqbah bin 'Amir] berkata; ada tiga waktu dimana Rasulullah shallallahu 'alaihi wasallam melarang kami untuk melakukan shalat atau mengkuburkan jenazah, yaitu; ketika matahari terbit hingga meninggi, ketika matahari tepat di atas kepala hingga bergeser (bergelincir), dan ketika matahari condong untuk tenggelam hingga matahari tenggelam. Atau sebagaimana yang beliau sabdakan. "},"2702":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ الرَّمْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ ابْنِ جُرَيْجٍ عَنْ يَحْيَى بْنِ صَبِيحٍ قَالَ حَدَّثَنِي عَمَّارٌ مَوْلَى الْحَارِثِ بْنِ نَوْفَلٍأَنَّهُ شَهِدَ جَنَازَةَ أُمِّ كُلْثُومٍ وَابْنِهَا فَجُعِلَ الْغُلَامُ مِمَّا يَلِي الْإِمَامَ فَأَنْكَرْتُ ذَلِكَ وَفِي الْقَوْمِ ابْنُ عَبَّاسٍ وَأَبُو سَعِيدٍ الْخُدْرِيُّ وَأَبُو قَتَادَةَ وَأَبُو هُرَيْرَةَ فَقَالُوا هَذِهِ السُّنَّةُ","id":"Telah menceritakan kepada kami [Yazid? bin Khalid bin Mauhab Ar Ramli], telah menceritakan kepada kami [Ibnu Wahb] dari [Ibnu Juraij], dari [Yahya bin Shabih], ia berkata; telah menceritakan kepadaku ['Ammar] mantan budak Al Harits bin Naufal, bahwa ia menyaksikan jenazah Ummu Kultsum dan anaknya. Anak diletakkan setelah (di belakang posisi) imam, kemudian aku mengingkari hal tersebut dan diantara mereka terdapat [Ibnu Abbas] dan [Abu Sa'id Al Khudri], [Abu Qatadah] serta [Abu Hurairah], dan mereka mengatakan hal ini adalah sunnah. "},"2703":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ مُعَاذٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ نَافِعٍ أَبِي غَالِبٍ قَالَكُنْتُ فِي سِكَّةِ الْمِرْبَدِ فَمَرَّتْ جَنَازَةٌ مَعَهَا نَاسٌ كَثِيرٌ قَالُوا جَنَازَةُ عَبْدِ اللَّهِ بْنِ عُمَيْرٍ فَتَبِعْتُهَا فَإِذَا أَنَا بِرَجُلٍ عَلَيْهِ كِسَاءٌ رَقِيقٌ عَلَى بُرَيْذِينَتِهِ وَعَلَى رَأْسِهِ خِرْقَةٌ تَقِيهِ مِنْ الشَّمْسِ فَقُلْتُ مَنْ هَذَا الدِّهْقَانُ قَالُوا هَذَا أَنَسُ بْنُ مَالِكٍ فَلَمَّا وُضِعَتْ الْجَنَازَةُ قَامَ أَنَسٌ فَصَلَّى عَلَيْهَا وَأَنَا خَلْفَهُ لَا يَحُولُ بَيْنِي وَبَيْنَهُ شَيْءٌ فَقَامَ عِنْدَ رَأْسِهِ فَكَبَّرَ أَرْبَعَ تَكْبِيرَاتٍ لَمْ يُطِلْ وَلَمْ يُسْرِعْ ثُمَّ ذَهَبَ يَقْعُدُ فَقَالُوا يَا أَبَا حَمْزَةَ الْمَرْأَةُ الْأَنْصَارِيَّةُ فَقَرَّبُوهَا وَعَلَيْهَا نَعْشٌ أَخْضَرُ فَقَامَ عِنْدَ عَجِيزَتِهَا فَصَلَّى عَلَيْهَا نَحْوَ صَلَاتِهِ عَلَى الرَّجُلِ ثُمَّ جَلَسَ فَقَالَ الْعَلَاءُ بْنُ زِيَادٍ يَا أَبَا حَمْزَةَ هَكَذَا كَانَ يَفْعَلُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الْجَنَازَةِ كَصَلَاتِكَ يُكَبِّرُ عَلَيْهَا أَرْبَعًا وَيَقُومُ عِنْدَ رَأْسِ الرَّجُلِ وَعَجِيزَةِ الْمَرْأَةِ قَالَ نَعَمْ قَالَ يَا أَبَا حَمْزَةَ غَزَوْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ غَزَوْتُ مَعَهُ حُنَيْنًا فَخَرَجَ الْمُشْرِكُونَ فَحَمَلُوا عَلَيْنَا حَتَّى رَأَيْنَا خَيْلَنَا وَرَاءَ ظُهُورِنَا وَفِي الْقَوْمِ رَجُلٌ يَحْمِلُ عَلَيْنَا فَيَدُقُّنَا وَيَحْطِمُنَا فَهَزَمَهُمْ اللَّهُ وَجَعَلَ يُجَاءُ بِهِمْ فَيُبَايِعُونَهُ عَلَى الْإِسْلَامِ فَقَالَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ عَلَيَّ نَذْرًا إِنْ جَاءَ اللَّهُ بِالرَّجُلِ الَّذِي كَانَ مُنْذُ الْيَوْمَ يَحْطِمُنَا لَأَضْرِبَنَّ عُنُقَهُ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجِيءَ بِالرَّجُلِ فَلَمَّا رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا رَسُولَ اللَّهِ تُبْتُ إِلَى اللَّهِ فَأَمْسَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُبَايِعُهُ لِيَفِيَ الْآخَرُ بِنَذْرِهِ قَالَ فَجَعَلَ الرَّجُلُ يَتَصَدَّى لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَأْمُرَهُ بِقَتْلِهِ وَجَعَلَ يَهَابُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقْتُلَهُ فَلَمَّا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَا يَصْنَعُ شَيْئًا بَايَعَهُ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ نَذْرِي فَقَالَ إِنِّي لَمْ أُمْسِكْ عَنْهُ مُنْذُ الْيَوْمَ إِلَّا لِتُوفِيَ بِنَذْرِكَ فَقَالَ يَا رَسُولَ اللَّهِ أَلَا أَوْمَضْتَ إِلَيَّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيْسَ لِنَبِيٍّ أَنْ يُومِضَقَالَ أَبُو غَالِبٍ فَسَأَلْتُ عَنْ صَنِيعِ أَنَسٍ فِي قِيَامِهِ عَلَى الْمَرْأَةِ عِنْدَ عَجِيزَتِهَا فَحَدَّثُونِي أَنَّهُ إِنَّمَا كَانَ لِأَنَّهُ لَمْ تَكُنْ النُّعُوشُ فَكَانَ الْإِمَامُ يَقُومُ حِيَالَ عَجِيزَتِهَا يَسْتُرُهَا مِنْ الْقَوْمِ قَالَ أَبُو دَاوُد قَوْلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ نُسِخَ مِنْ هَذَا الْحَدِيثِ الْوَفَاءُ بِالنَّذْرِ فِي قَتْلِهِ بِقَوْلِهِ إِنِّي قَدْ تُبْتُ","id":"Telah menceritakan kepada kami [Daud bin Mu'adz], telah menceritakan kepada kami [Abdul Warits] dari [Nafi' Abu Ghalib], ia berkata; aku berada di deretan pohon di tempat penambatan unta, kemudian ada (rombongan pengiring) jenazah yang lewat yang diiringi banyak orang. Mereka berkata; ini adalah jenazah Abdullah bin 'Umair, lalu aku mengikutinya. Tiba-tiba aku berada di dekat orang yang memakai baju tipis berada di atas kuda tariknya, dan di atas kepalanya terdapat secarik kain yang melindunginya dari panas matahari. Aku katakan; siapakah orang ini? Mereka berkata; ini adalah Anas bin Malik. Kemudian tatkala jenazah tersebut diletakkan [Anas] berdiri lalu menshalatkannya, sementara aku di belakangnya, tidak ada sesuatu pun yang menghalangi antara diriku dan dirinya. Ia berdiri di samping kepalanya lalu bertakbir empat kali, tidak lama dan tidak cepat-cepat. Kemudian ia pergi dan duduk. Orang-orang tersebut berkata; wahai Abu Hamzah, ini adalah jenazah seorang wanita anshar. Lalu mereka mendekatkan jenazah wanita tersebut kepadanya, jenazah tersebut di tutupi peti yang berwarna hijau. Lalu Anas berdiri di sisi pantat jenazah tersebut, lalu ia menshalatkannya seperti shalatnya kepada jenazah laki-laki tersebut, dan kemudian ia duduk. Al 'Ala` bin Ziyad berkata; wahai Abu Hamzah, apakah demikian Rasulullah shallallahu 'alaihi wasallam menshalatkan jenazah seperti shalatmu, bertakbir empat kali, dan berdiri di sisi kepala jenazah laki-laki dan di sisi pantat jenazah wanita? Ia berkata; ya. Ia berkata; wahai Abu Hamzah, apakah engkau pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam? ia berkata; Iya. Aku pernah melakukan perang Hunain bersama beliau. Orang-orang musyrik keluar dan menyerang kami hingga kami lihat kuda kami berada di belakang punggung kami. Dan diantara orang-orang tersebut terdapat seorang laki-laki yang menyerang kami, ia memukul kami dan meluap kemarahannya kepada kami. Lalu Allah, dan mereka dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam dan berbai'at kepada beliau untuk masuk Islam. Kemudian terdapat seorang sahabat Nabi yang berkata; sesungguhnya aku bernadzar, apabila Allah mendatangkan orang yang sejak hari tersebut meluapkan kemarahan kepada kami, niscaya aku akan memenggal lehernya sementara Rasulullah shallallahu 'alaihi wasallam terdiam. Lalu orang tersebut didatangkan, kemudian tatkala ia melihat Rasulullah shallallahu 'alaihi wasallam ia berkata; wahai Rasulullah, aku telah bertaubat kepada Allah. Rasulullah shallallahu 'alaihi wasallam menahan diri dan tidak membai'atnya agar orang lain dapat menunaikan nadzarnya. Lalu sahabat tersebut melayani Rasulullah shallallahu 'alaihi wasallam agar beliau memerintahkannya untuk membunuhnya, dan sahabat tersebut segan kepada Rasulullah shallallahu 'alaihi wasallam untuk membunuh orang tersebut. Kemudian tatkala Rasulullah shallallahu 'alaihi wasallam melihat bahwa ia tidak melakukan apapun, maka beliau membai'atnya. Lalu sahabat tersebut berkata; wahai Rasulullah, bagaimana dengan nadzarku? Beliau berkata: \"Sesungguhnya tidaklah aku menahan diri dari membai'atnya semenjak hari itu melainkan agar engkau menunaikan nadzarmu.\" Sahabat tersebut berkata; tidakkah engkau memberikan isyarat dengan mata kepadaku wahai Rasulullah? Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Sesungguhnya tidak layak bagi seorang nabi untuk memberi isyarat menggunakan mata.\" Abu Ghalib berkata; kemudian aku bertanya mengenai perbuatan Anas ketika menshalatkan jenazah wanita di sisi pantatnya. Kemudian mereka menceritakan kepadaku bahwa tidak ada peti jenazah sehingga imam berdiri berhadapan dengan pantatnya sehingga ia menutupinya dari orang-orang. Abu Daud berkata; sabda Nabi shallallahu 'alaihi wasallam \"Aku diperintahkan untuk memerangi manusia hingga mereka mengucapkan: LAA ILAAHA ILLALLAAH\", penunaian nadzar untuk membunuh dihapus dari hadits ini dengan ucapan orang yang hendak dibunuh; aku telah bertaubat. "},"2704":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَصَلَّيْتُ وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى امْرَأَةٍ مَاتَتْ فِي نِفَاسِهَا فَقَامَ عَلَيْهَا لِلصَّلَاةِ وَسَطَهَا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yazid? bin Zurai'] telah menceritakan kepada kami [Husain Al Mu'allim], telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Samurah bin Jundub] ia berkata; aku menshalatkan seorang wanita yang meninggal karena nifas di belakang Nabi shallallahu 'alaihi wasallam, dan beliau berdiri di tengah-tengahnya. "},"2705":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ أَخْبَرَنَا ابْنُ إِدْرِيسَ قَالَ سَمِعْتُ أَبَا إِسْحَقَ عَنْ الشَّعْبِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِقَبْرٍ رَطْبٍ فَصَفُّوا عَلَيْهِ وَكَبَّرَ عَلَيْهِ أَرْبَعًافَقُلْتُ لِلشَّعْبِيِّ مَنْ حَدَّثَكَ قَالَ الثِّقَةُ مَنْ شَهِدَهُ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah mengabarkan kepada kami [Ibnu Idris], Ia berkata; saya mendengar [Abu Ishaq] dari [Asy Sya'bi] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melewati sebuah kuburan yang masih basah (belum lama proses penguburannya), kemudian mereka berbaris untuk menshalatinya dan beliau bertakbir empat kali. Aku katakan kepada Asy Sya'bi; sipakah yang menceritakan kepada anda? Ia berkata; orang tsiqah orang yang menyaksikannya (peristiwa itu) yaitu [Ibnu Abbas]. "},"2706":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ ابْنِ أَبِي لَيْلَى قَالَكَانَ زَيْدٌ يَعْنِي ابْنَ أَرْقَمَ يُكَبِّرُ عَلَى جَنَائِزِنَا أَرْبَعًا وَإِنَّهُ كَبَّرَ عَلَى جَنَازَةٍ خَمْسًا فَسَأَلْتُهُ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُهَاقَالَ أَبُو دَاوُد وَأَنَا لِحَدِيثِ ابْنِ الْمُثَنَّى أَتْقَنُ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada kami [Syu'bah]. telah diriwayatkan dari jalur yang lain: telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah], dari ['Amr bin Murrah], dari [Ibnu Abu Laila], ia berkata; [Zaid yaitu Ibnu Arqam] bertakbir ketika menshalatkan jenazah kami empat kali (takbir). Dan ia pernah bertakbir ketika menshalatkan jenazah lima kali (takbir). Kemudian aku bertanya kepadanya. Kemudian ia berkata; dahulu Rasulullah shallallahu 'alaihi wasallam pernah bertakbir sebanyak itu. Abu Daud berkata; dan aku lebih yakin kepada hadits Ibnu Al Mutsanna. "},"2707":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ قَالَصَلَّيْتُ مَعَ ابْنِ عَبَّاسٍ عَلَى جَنَازَةٍ فَقَرَأَ بِفَاتِحَةِ الْكِتَابِ فَقَالَ إِنَّهَا مِنْ السُّنَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Sa'd Ibrahim] dari [Thalhah bin Abdullah bin 'Auf], ia berkata; aku pernah menshalatkan seorang jenazah bersama [Ibnu Abbas], ia membaca Al Fatihah, kemudian ia mengatakan; sesungguhnya hal tersebut adalah sunnah. "},"2708":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى الْحَرَّانِيُّ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا صَلَّيْتُمْ عَلَى الْمَيِّتِ فَأَخْلِصُوا لَهُ الدُّعَاءَ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya Al Harrani], telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim], dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian menshalatkan mayit, maka ikhlaskanlah doa untuknya.\""},"2709":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَبُو الْجُلَاسِ عُقْبَةُ بْنُ سَيَّارٍ حَدَّثَنِي عَلِيُّ بْنُ شَمَّاخٍ قَالَشَهِدْتُ مَرْوَانَ سَأَلَ أَبَا هُرَيْرَةَ كَيْفَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الْجَنَازَةِ قَالَ أَمَعَ الَّذِي قُلْتَ قَالَ نَعَمْ قَالَ كَلَامٌ كَانَ بَيْنَهُمَا قَبْلَ ذَلِكَ قَالَ أَبُو هُرَيْرَةَ اللَّهُمَّ أَنْتَ رَبُّهَا وَأَنْتَ خَلَقْتَهَا وَأَنْتَ هَدَيْتَهَا لِلْإِسْلَامِ وَأَنْتَ قَبَضْتَ رُوحَهَا وَأَنْتَ أَعْلَمُ بِسِرِّهَا وَعَلَانِيَتِهَا جِئْنَاكَ شُفَعَاءَ فَاغْفِرْ لَهُقَالَ أَبُو دَاوُد أَخْطَأَ شُعْبَةُ فِي اسْمِ عَلِيِّ بْنِ شَمَّاخٍ قَالَ فِيهِ عُثْمَانُ بْنُ شَمَّاسٍ وَسَمِعْتُ أَحْمَدَ بْنَ إِبْرَاهِيمَ الْمُوصِلِيَّ يُحَدِّثُ أَحْمَدَ بْنَ حَنْبَلٍ قَالَ مَا أَعْلَمُ أَنِّي جَلَسْتُ مِنْ حَمَّادِ بْنِ زَيْدٍ مَجْلِسًا إِلَّا نَهَى فِيهِ عَنْ عَبْدِ الْوَارِثِ وَجَعْفَرِ بْنِ سُلَيْمَانَ","id":"Telah menceritakan kepada kami [Abu Ma'mar Abdullah bin 'Amr], telah menceritakan kepada kami [Abdul Warits], telah menceritakan kepada kami [Abu Al Julas 'Uqbah bin Sayyar], telah menceritakan kepadaku [Ali bin Syammakh], ia berkata; aku menyaksikan Marwan bertanya kepada [Abu Hurairah]; bagaimana engkau mendengar Rasulullah shallallahu 'alaihi wasallam menshalati jenazah? ia berkata; apakah bersamaan dengan adanya ini engkau bertanya kepadaku? Ia berkata; Iya. Ali bin Syammakh berkata; yaitu perkataan yang terjadi diantara mereka berdua sebelum itu. Abu Hurairah berkata; Ya Allah, engkau adalah Tuhan jenazah tersebut, Engkau telah menciptakannya, dan Engkau telah memberinya petunjuk untuk memeluk agama Islam, dan Engkau telah mencabut nyawanya, Engkau lebih mengetahui terhadap rahasianya dan perkaranya yang nampak. Kami datang kepadaMu sebagai perantara, maka ampunilah baginya! Abu Daud berkata; Syu'bah salah mengenal nama Ali bin Syammakh. Dalam hal tersebut Utsman bin Syammas berkata; dan aku mendengar Ahmad bin Ibrahim Al Mushili menceritakan kepada Ahmad bin Hanbal, ia berkata; aku tidak mengetahui bahwa aku duduk di sebuah majelis Hammad bin Zaid melainkan ia melarang meriwayatkan dari Abdul Warits dan Ja'far bin Sulaiman. "},"2710":{"ar":"حَدَّثَنَا مُوسَى بْنُ مَرْوَانَ الرَّقِّيُّ حَدَّثَنَا شُعَيْبٌ يَعْنِي ابْنَ إِسْحَقَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَنَازَةٍ فَقَالَ اللَّهُمَّ اغْفِرْ لِحَيِّنَا وَمَيِّتِنَا وَصَغِيرِنَا وَكَبِيرِنَا وَذَكَرِنَا وَأُنْثَانَا وَشَاهِدِنَا وَغَائِبِنَا اللَّهُمَّ مَنْ أَحْيَيْتَهُ مِنَّا فَأَحْيِهِ عَلَى الْإِيمَانِ وَمَنْ تَوَفَّيْتَهُ مِنَّا فَتَوَفَّهُ عَلَى الْإِسْلَامِ اللَّهُمَّ لَا تَحْرِمْنَا أَجْرَهُ وَلَا تُضِلَّنَا بَعْدَهُ","id":"Telah menceritakan kepada kami [Musa bin Marwan Ar Raqqi] telah menceritakan kepada kami [Syu'aib bin Ishaq] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam penah menshalati jenazah kemudian beliau mengucapkan: ALLAAHUMMAGHFIR LIHAYYINAA WA MAYYITINA, WA SHAGHIIRINAA WA KABIIRINAA WA DZAKARINAA WA UNTSAANAA, WA SYAHIDINAA WA GHAAIBINAA. ALLAAHUMMA, MAN AHYAITAHU MINNAA FA AHYIHI 'ALAL IIMAAN WA MAN TAWAFFAITAHU MINNAA FATAWAFFAHU 'ALAL ISLAAM. ALLAHUMMA LAA TAHRIMAN AJRAHU WA LAA TUDHILLANAA BA'DAHU (ya Allah, ampunilah orang-orang yang masih hidup diantara kami, dan yang telah mati, anak kecil dan yang dewasa kami, laki-laki kami dan wanita kami, orang-orang yang hadir diantara kami dan yang tidak hadir. Ya Allah, siapapun diantara kami yang Engkau hidupkan maka hidupkanlah di atas keimanan dan siapapun diantara kami yang Engkau wafatkan maka wafatkanlah dalam keadaan beragama Islam, ya Allah, janganlah Engkau halangi kami dari mendapatkan pahalanya dan janganlah Engkau sesatkan kami setelah kematiannya!\""},"2711":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ ح و حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّا��ِيُّ أَخْبَرَنَا الْوَلِيدُ وَحَدِيثُ عَبْدِ الرَّحْمَنِ أَتَمُّ حَدَّثَنَا مَرْوَانُ بْنُ جَنَاحٍ عَنْ يُونُسَ بْنِ مَيْسَرَةَ بْنِ حَلْبَسٍ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ مِنْ الْمُسْلِمِينَ فَسَمِعْتُهُ يَقُولُ اللَّهُمَّ إِنَّ فُلَانَ بْنَ فُلَانٍ فِي ذِمَّتِكَ فَقِهِ فِتْنَةَ الْقَبْرِ قَالَ عَبْدُ الرَّحْمَنِ مِنْ ذِمَّتِكَ وَحَبْلِ جِوَارِكَ فَقِهِ مِنْ فِتْنَةِ الْقَبْرِ وَعَذَابِ النَّارِ وَأَنْتَ أَهْلُ الْوَفَاءِ وَالْحَمْدِ اللَّهُمَّ فَاغْفِرْ لَهُ وَارْحَمْهُ إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُقَالَ عَبْدُ الرَّحْمَنِ عَنْ مَرْوَانَ بْنِ جَنَاحٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi], telah menceritakan kepada kami [Al Walid], dan telah diriwayatkan dari jalur yang lain: telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada kami [Al Walid], -dan hadits Abdurrahman lebih sempurna- telah menceritakan kepada kami [Marwan bin Janah] dari [Yunus bin Maisarah bin Halbas] dari [Watsilah bin Al Asqa'], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersama kami menshalati (jenazah) seorang laki-laki muslim, kemudian aku mendengar beliau mengucapkan: \"Ya Allah, sesungguhnya Fulan bin Fulan berada dalam jaminanMu maka lindungilah dia dari Fitnah kubur.\" Sedang Abdurrahman berkata; dari jaminanMu. Berada dalam jaminan keamananMu, maka lindungilah dirinya dari fitnah kubur, serta adzab neraka. Engkau senantiasa menepati janji dan Pemilik segala pujian. Ya Allah, ampunilah dosanya dan sayangilah dia, sesungguhnya Engkau Maha Pengampun dan Maha Penyayang.\" Abdurrahman mengatakannya dari Marwan bin Janah. "},"2712":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ امْرَأَةً سَوْدَاءَ أَوْ رَجُلًا كَانَ يَقُمُّ الْمَسْجِدَ فَفَقَدَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عَنْهُ فَقِيلَ مَاتَ فَقَالَ أَلَا آذَنْتُمُونِي بِهِ قَالَ دُلُّونِي عَلَى قَبْرِهِ فَدَلُّوهُ فَصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], dan [Musaddad] mereka berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Abu Rafi'] dari [Abu Hurairah] bahwa seorang wanita hitam atau seorang laki-laki yang menyapu dan membersihkan masjid, kemudian Nabi shallallahu 'alaihi wasallam kehilangan dirinya, lalu beliau menanyakannya. Kemudian dikatakan; ia telah meninggal. Maka beliau berkata: \"Tidakkah kalian memberitahukan kepadaku?\" Beliau berkata: \"Tunjukkan kepadaku kuburannya!\" kemudian mereka menunjukkannya kepada beliau dan beliau menshalatkannya. "},"2713":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ قَالَ قَرَأْتُ عَلَى مَالِكِ بْنِ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى لِلنَّاسِ النَّجَاشِيَّ فِي الْيَوْمِ الَّذِي مَاتَ فِيهِ وَخَرَجَ بِهِمْ إِلَى الْمُصَلَّى فَصَفَّ بِهِمْ وَكَبَّرَ أَرْبَعَ تَكْبِيرَاتٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi], ia berkata; aku membacakan riwayat kepada [Malik bin Anas], dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab], dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam mengumumkan meninggalnya Najasyi kepada orang-orang (kaum muslimin) pada hari wafatnya. Dan beliau keluar bersama mereka menuju tempat shalat, lalu beliau berbaris bersama mereka dan bertakbir empat kali takbir. "},"2714":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَنْطَلِقَ إِلَى أَرْضِ النَّجَاشِيِّ فَذَكَرَ حَدِيثَهُ قَالَ النَّجَاشِيُّ أَشْهَدُ أَنَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ الَّذِي بَشَّرَ بِهِ عِيسَى ابْنُ مَرْيَمَ وَلَوْلَا مَا أَنَا فِيهِ مِنْ الْمُلْكِ لَأَتَيْتُهُ حَتَّى أَحْمِلَ نَعْلَيْهِ","id":"Telah menceritakan kepada kami ['Abbad bin Musa] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Israil] dari [Abu Ishaq] dari [Abu Burdah] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar pergi ke Negerinya Najasyi. kemudian ia menyebutkan haditsnya, An Najisyi berkata; aku bersaksi bahwa ia adalah Rasulullah shallallahu 'alaihi wasallam dan ia adalah orang yang dikabarkan oleh Isa bin Maryam, seandainya aku tidak mengurusi kerajaan niscaya aku akan mendatanginya hingga aku membawakan kedua sandalnya. "},"2715":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا سَعِيدُ بْنُ سَالِمٍ ح و حَدَّثَنَا يَحْيَى بْنُ الْفَضْلِ السِّجِسْتَانِيُّ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ إِسْمَعِيلَ بِمَعْنَاهُ عَنْ كَثِيرِ بْنِ زَيْدٍ الْمَدَنِيِّ عَنْ الْمُطَّلِبِ قَالَلَمَّا مَاتَ عُثْمَانُ بْنُ مَظْعُونٍ أُخْرِجَ بِجَنَازَتِهِ فَدُفِنَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا أَنْ يَأْتِيَهُ بِحَجَرٍ فَلَمْ يَسْتَطِعْ حَمْلَهُ فَقَامَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَسَرَ عَنْ ذِرَاعَيْهِ قَالَ كَثِيرٌ قَالَ الْمُطَّلِبُ قَالَ الَّذِي يُخْبِرُنِي ذَلِكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَأَنِّي أَنْظُرُ إِلَى بَيَاضِ ذِرَاعَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ حَسَرَ عَنْهُمَا ثُمَّ حَمَلَهَا فَوَضَعَهَا عِنْدَ رَأْسِهِ وَقَالَ أَتَعَلَّمُ بِهَا قَبْرَ أَخِي وَأَدْفِنُ إِلَيْهِ مَنْ مَاتَ مِنْ أَهْلِي","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] telah menceritakan kepada kami [Sa'id bin Salim], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Yahya bin Al Fadhl As Sijistani] telah menceritakan kepada kami [Hatim bin Isma'il] dengan maknanya; dari [Katsir bin Zaid Al Madani], dari [Al Muththalib], ia berkata; tatkala Utsman bin Mazh'un meninggal maka jenazahnya dikeluarkan dan dikuburkan. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan seseorang agar datang kepadanya membawa batu, namun ia tidak mampu membawanya. Kemudian beliau pergi menuju batu tersebut dan menyingsingkan kedua lengannya. -Katsir berkata; Al Muththalib berkata; telah berkata [orang yang mengabarkan hal tersebut kepadaku] dari Rasulullah shallallahu 'alaihi wasallam; sepertinya aku melihat putih kedua lengan Rasulullah shallallahu 'alaihi wasallam ketika beliau menyinsingkan keduanya. Kemudian beliau membawanya dan meletakkannya di sisi kepalanya. Beliau berkata: aku belajar menguburkan saudaranya dengannya dan kepadanya aku menguburkan keluarganya yang meninggal. "},"2716":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سَعْدٍ يَعْنِي ابْنَ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَسْرُ عَظْمِ الْمَيِّتِ كَكَسْرِهِ حَيًّا","id":"Telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Sa'd bin Sa'id?] dari ['Amrah binti Abdurrahman] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Mematahkan tulang orang yang mati seperti halnya mematahkannya ketika ia masih hidup.\""},"2717":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ حَدَّثَنَا حَكَّامُ بْنُ سَلْمٍ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّحْدُ لَنَا وَالشَّقُّ لِغَيْرِنَا","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il], telah menceritakan kepada kami [Hakkam bin Salm] dari [Ali bin Al A'la] dari [ayahnya] dari [Sa'id bin Jubair], dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Membuat lahad (menggali di samping kubur untuk tempat jenazah) adalah untuk kita, dan syaq (menggali lubang di tengah kuburan) adalah untuk orang selain kita.\""},"2718":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ عَامِرٍ قَالَغَسَّلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيٌّ وَالْفَضْلُ وَأُسَامَةُ بْنُ زَيْدٍ وَهُمْ أَدْخَلُوهُ قَبْرَهُ قَالَ حَدَّثَنَا مَرْحَبٌ أَوْ أَبُو مَرْحَبٍ أَنَّهُمْ أَدْخَلُوا مَعَهُمْ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ فَلَمَّا فَرَغَ عَلِيٌّ قَالَ إِنَّمَا يَلِي الرَّجُلَ أَهْلُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Amir], ia berkata; Ali, Al Fadhl, dan Usamah bin Zaid memandikan Rasulullah shallallahu 'alaihi wasallam dan mereka memasukkannya ke dalam kubur beliau. Ia berkata; telah menceritakan kepada kami [Marhab] atau Abu Marhab bahwa mereka memasukkan Abdurrahman bersama mereka, kemudian setelah selesai, Ali berkata; sesungguhnya yang mengurusi seseorang adalah keluarganya. "},"2719":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَخْبَرَنَا سُفْيَانُ عَنْ ابْنِ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي مَرْحَبٍأَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ نَزَلَ فِي قَبْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَأَنِّي أَنْظُرُ إِلَيْهِمْ أَرْبَعَةً","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah], telah mengabarkan kepada kami [Sufyan] dari [Ibnu Abu Khalid] dari [Asy Sya'bi] dari [Abu Marhab] bahwa Abdurrahman bin 'Auf turun ke kuburan Nabi shallallahu 'alaihi wasallam. Abu Marhab berkata; aku melihat mereka berjumlah empat orang. "},"2720":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَأَوْصَى الْحَارِثُ أَنْ يُصَلِّيَ عَلَيْهِ عَبْدُ اللَّهِ بْنُ يَزِيدَ فَصَلَّى عَلَيْهِ ثُمَّ أَدْخَلَهُ الْقَبْرَ مِنْ قِبَلِ رِجْلَيْ الْقَبْرِ وَقَالَ هَذَا مِنْ السُّنَّةِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq], ia berkata; Al Harits telah berwasiat agar [Abdullah bin Yazid] menshalatkannya. Lalu ia menshalatkannya, kemudian ia memasukkannya ke kuburan dari sebelah kaki kuburan. Dan ia berkata; ini termasuk sunnah. "},"2721":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ زَاذَانَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنَازَةِ رَجُلٍ مِنْ الْأَنْصَارِ فَانْتَهَيْنَا إِلَى الْقَبْرِ وَلَمْ يُلْحَدْ بَعْدُ فَجَلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَقْبِلَ الْقِبْلَةِ وَجَلَسْنَا مَعَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?] telah menceritakan kepada kami [jarir] dari [Al A'masy] dari [Al Minhal bin 'Amr] dari [Zadzan] dari [Al Bara` bin 'Azib] ia berkata; kami keluar bersama Rasulullah shallallahu 'alaihi wasallam mengantarkan sebuah jenazah seseorang dari kalangan anshar. Kemudin kami sampai di kuburan, dan belum selesai penggalian lahad, kemudian Nabi shallallahu 'alaihi wasallam duduk menghadap kiblat dan kami duduk bersama beliau. "},"2722":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ ح و حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي الصِّدِّيقِ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا وَضَعَ الْمَيِّتَ فِي الْقَبْرِ قَالَ بِسْمِ اللَّهِ وَعَلَى سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا لَفْظُ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abu Ash Shiddiq] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam apabila meletakkan mayit dalam kuburan beliau mengucapkan: \"BISMILLAAH WA 'ALAA MILLATI RASUULILLAAH\" (dengan nama Allah dan berada di atas sunnah Rasulullah shallallahu 'alaihi wasallam.\" dan ini adalah lafazh Muslim. "},"2723":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ نَاجِيَةَ بْنِ كَعْبٍ عَنْ عَلِيٍّ عَلَيْهِ السَّلَام قَالَقُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ عَمَّكَ الشَّيْخَ الضَّالَّ قَدْ مَاتَ قَالَ اذْهَبْ فَوَارِ أَبَاكَ ثُمَّ لَا تُحْدِثَنَّ شَيْئًا حَتَّى تَأْتِيَنِي فَذَهَبْتُ فَوَارَيْتُهُ وَجِئْتُهُ فَأَمَرَنِي فَاغْتَسَلْتُ وَدَعَا لِي","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Abu Ishaq] dari [Nahiyah bin Ka'b] dari [Ali] 'alaihis salam, ia berkata; aku katakan kepada Nabi shallallahu 'alaihi wasallam; sesunguhnya paman anda adalah orang tua yang sesat (Abu Thalib) telah meninggal. Beliau bersabda: \"Pergilah dan kuburkan ayahmu, kemudian janganlah engkau mengadakan sesuatu hingga aku datang kepadamu!\" kemudian aku datang dan telah menguburkannya kemudian datang kepadanya. Lalu beliau memerintahkanku untuk mandi, lalu aku mandi dan mendoakanku. "},"2724":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ أَنَّ سُلَيْمَانَ بْنَ الْمُغِيرَةِ حَدَّثَهُمْ عَنْ حُمَيْدٍ يَعْنِي ابْنَ هِلَالٍ عَنْ هِشَامِ بْنِ عَامِرٍ قَالَجَاءَتْ الْأَنْصَارُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فَقَالُوا أَصَابَنَا قَرْحٌ وَجَهْدٌ فَكَيْفَ تَأْمُرُنَا قَالَ احْفِرُوا وَأَوْسِعُوا وَاجْعَلُوا الرَّجُلَيْنِ وَالثَّلَاثَةَ فِي الْقَبْرِ قِيلَ فَأَيُّهُمْ يُقَدَّمُ قَالَ أَكْثَرُهُمْ قُرْآنًاقَالَ أُصِيبَ أَبِي يَوْمَئِذٍ عَامِرٌ بَيْنَ اثْنَيْنِ أَوْ قَالَ وَاحِدٌ حَدَّثَنَا أَبُو صَالِحٍ يَعْنِي الْأَنْطَاكِيَّ أَخْبَرَنَا أَبُو إِسْحَقَ يَعْنِي الْفَزَارِيَّ عَنْ الثَّوْرِيِّ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ بِإِسْنَادِهِ وَمَعْنَاهُ زَادَ فِيهِ وَأَعْمِقُوا حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا جَرِيرٌ حَدَّثَنَا حُمَيْدٌ يَعْنِي ابْنَ هِلَالٍ عَنْ سَعْدِ بْنِ هِشَامِ بْنِ عَامِرٍ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], bahwa [Sulaiman bin Al Mughirah] telah menceritakan kepada mereka dari [Humaid bin Hilal] dari [Hisyam bin 'Amir], ia berkata; orang-orang anshar datang kepada Rasulullah shallallahu 'alaihi wasallam pada saat perang Uhud kemudian berkata; kami telah tertimpa kekalahan dan kesusahan, maka apakah yang anda perintahkan kepada kami? Beliau berkata: \"Galilah lubang yang lebar dan masukkan dua atau tiga orang dalam satu kubur!\" Beliau ditanya; siapakah yang didahulukan? Beliau bersabda: \"Orang yang paling banyak hafal Al Qur'an.\" Hisyam bin Amir berkata; ayahku yaitu Amir pada saat itu terbunuh dan ia didahulukan diantara dua orang atau satu orang. Telah menceritakan kepada kami [Abu Shalih Al Anthaki], telah mengabarkan kepada kami [Abu Ishaq Al Fazari], dari [Ats Tsauri] dari [Ayyub] dari [Humaid bin Hilal] dengan sanad dan maknanya, dalam hadits tersebut ia menambahkan kata; dan dalamkan penggaliannya! Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Jarir], telah menceritakan kepada kami [Humaid bin Hilal] dari [Sa'd bin Hisyam bin Amir] dengan hadits ini. "},"2725":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي هَيَّاجٍ الْأَسَدِيِّ قَالَبَعَثَنِي عَلِيٌّ قَالَ لِي أَبْعَثُكَ عَلَى مَا بَعَثَنِي عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا أَدَعَ قَبْرًا مُشْرِفًا إِلَّا سَوَّيْتُهُ وَلَا تِمْثَالًا إِلَّا طَمَسْتُهُ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Sufyan] telah menceritakan kepada kami [Habib bin Abu Tsabit], dari [Abu Wail] dari [Abu Hayyaj Al Asadi], ia berkata; [Ali] telah mengutusku, ia berkata; aku mengutusmu sebagaimana Rasulullah shallallahu 'alaihi wasallam telah mengutusku, agar aku tidak meninggalkan kuburan yang ditinggikan kecuali aku meratakannya, dan tidak meninggalkan berhala kecuali aku hancurkan. "},"2726":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ أَبَا عَلِيٍّ الْهَمْدَانِيِّ حَدَّثَهُ قَالَكُنَّا مَعَ فَضَالَةَ بْنِ عُبَيْدٍ بِرُودِسَ مِنْ أَرْضِ الرُّومِ فَتُوُفِّيَ صَاحِبٌ لَنَا فَأَمَرَ فَضَالَةُ بِقَبْرِهِ فَسُوِّيَ ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِتَسْوِيَتِهَاقَالَ أَبُو دَاوُد رُودِسُ جَزِيرَةٌ فِي الْبَحْرِ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] Telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku ['Amr Al Harits] bahwa [Abu Ali Al Hamdani] telah menceritakan kepadanya, ia berkata; kami pernah bersama [Fudhalah bin 'Ubaid] di Rudis yang merupakan bagian dari negeri Romawi, kemudian seorang sahabat kami meninggal. Kemudian Fadhalah memerintahkan agar mengkuburkannya dan diratakan kuburan tersebut. Kemudian ia berkata; aku telah mendengar Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk meratakannya. Abu Daud berkata; Rudis adalah sebuah teluk di laut. "},"2727":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ هَانِئٍ عَنْ الْقَاسِمِ قَالَدَخَلَتْ عَلَى عَائِشَةَ فَقُلْتُ يَا أُمَّهْ اكْشِفِي لِي عَنْ قَبْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَاحِبَيْهِ رَضِيَ اللَّهُ عَنْهُمَا فَكَشَفَتْ لِي عَنْ ثَلَاثَةِ قُبُورٍ لَا مُشْرِفَةٍ وَلَا لَاطِئَةٍ مَبْطُوحَةٍ بِبَطْحَاءِ الْعَرْصَةِ الْحَمْرَاءِقَالَ أَبُو عَلِيٍّ يُقَالُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُقَدَّمٌ وَأَبُو بَكْرٍ عِنْدَ رَأْسِهِ وَعُمَرُ عِنْدَ رِجْلَيْهِ رَأْسُهُ عِنْدَ رِجْلَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Abu Fudaik], telah mengabarkan kepadaku ['Amr bin Utsman bin Hani`] dari [Al Qasim], ia berkata; aku menemui [Aisyah] kemudian aku katakan; wahai ibuku, perlihatkan kepadaku kuburan Nabi shallallahu 'alaihi wasallam, dan kedua sahabatnya radliallahu 'anhuma! Kemudian ia memperlihatkan tiga kuburan kepadaku yang tidak tinggi dan tidak rata dengan tanah di Bathha` halaman yang berwarna merah. Abu Ali berkata; dikatakan; sesungguhnya Rasulullah shallallahu 'alaihi wasallam di depan dan Abu Bakr di sisi kepalanya, sedang Umar berada di sisi kedua kakinya, kepalanya di sisi kedua kaki Rasulullah shallallahu 'alaihi wasallam. "},"2728":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ حَدَّثَنَا هِشَامٌ عَنْ عَبْدِ اللَّهِ بْنِ بَحِيرٍ عَنْ هَانِئٍ مَوْلَى عُثْمَانَ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَرَغَ مِنْ دَفْنِ الْمَيِّتِ وَقَفَ عَلَيْهِ فَقَالَ اسْتَغْفِرُوا لِأَخِيكُمْ وَسَلُوا لَهُ بِالتَّثْبِيتِ فَإِنَّهُ الْآنَ يُسْأَلُقَالَ أَبُو دَاوُد بَحِيرٌ ابْنُ رَيْسَانَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah menceritakan kepada kami [Hisyam] dari [Abdullah bin Bahir] dari [Hani`] mantan budak Utsman, dari [Utsman bin 'Affan], ia berkata; Nabi shallallahu 'alaihi wasallam apabila telah selesai dari menguburkan mayit beliau berkata: \"Mintakanlah ampunan untuk saudara kalian, dan mohonkanlah keteguhan untuknya, karena sesungguhnya sekarang ia sedang ditanya.\" Abu Daud berkata; Bahir bin Raisan. "},"2729":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَقْرَ فِي الْإِسْلَامِقَالَ عَبْدُ الرَّزَّاقِ كَانُوا يَعْقِرُونَ عِنْدَ الْقَبْرِ بَقَرَةً أَوْ شَاةً","id":"Telah menceritakan kepada kami [Yahya bin Musa Al Balkhi], telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Tsabit] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada 'aqr (menyembelih di kuburan) dalam Islam.\" Abdurrazzaq berkata; dahulu mereka menyembelih sapi atau kambing di sisi kuburan. "},"2730":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمًا فَصَلَّى عَلَى أَهْلِ أُحُدٍ صَلَاتَهُ عَلَى الْمَيِّتِ ثُمَّ انْصَرَفَحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ بِهَذَا الْحَدِيثِ قَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى قَتْلَى أُحُدٍ بَعْدَ ثَمَانِي سِنِينَ كَالْمُوَدِّعِ لِلْأَحْيَاءِ وَالْأَمْوَاتِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Al Laits] dari [Yazid? bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] bahwa Rasulullah shallallahu 'alaihi wasallam keluar pada suatu hari, kemudian ia menshalatkan para korban perang Uhud sebagaimana beliau menshalatkan orang yang meninggal, kemudian beliau pergi. Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Yahya bin Adam], telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Yahwah bin Syuraih] dari [Yazid? bin Abu Habib] dengan hadits ini. Ia berkata; sesungguhnya Nabi shallallahu 'alaihi wasallam menshalatkan orang-orang yang terbunuh pada perang Uhud setelah delapan tahun seperti orang yang hendak meninggalkan orang yang hidup dan mati. "},"2731":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَقْعُدَ عَلَى الْقَبْرِ وَأَنْ يُقَصَّصَ وَيُبْنَى عَلَيْهِحَدَّثَنَا مُسَدَّدٌ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى وَعَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ بِهَذَا الْحَدِيثِ قَالَ أَبُو دَاوُد قَالَ عُثْمَانُ أَوْ يُزَادَ عَلَيْهِ وَزَادَ سُلَيْمَانُ بْنُ مُوسَى أَوْ أَنْ يُكْتَبَ عَلَيْهِ وَلَمْ يَذْكُرْ مُسَدَّدٌ فِي حَدِيثِهِ أَوْ يُزَادَ عَلَيْهِ قَالَ أَبُو دَاوُد خَفِيَ عَلَيَّ مِنْ حَدِيثِ مُسَدَّدٍ حَرْفُ وَأَنْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Abu Az Zubair], bahwa ia mendengar [Jabir] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam melarang untuk duduk di atas kuburan dan mengecatnya serta membangun di atasnya. Telah menceritakan kepada kami [Musaddad] dan [Utsman bin Abu Syaibah?] mereka berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Ibnu Juraij] dari [Sulaiman bin Musa], dan dari [Abu Az Zubair] dari [Jabir] dengan hadits ini. Abu Daud berkata; Utsman berkata; atau ditambahkan sesuatu di atasnya. Sedang Sulaiman bin Musa berkata; atau dituliskan sesuatu di atasnya. Dan Musaddad tidak menyebutkan dalam hadits tersebut; atau ditambahkan sesuatu di atasnya. Abu Daud berkata; dan tidak aku ketahui dari hadits Musaddad satu huruf yaitu wa an (dan untuk..). "},"2732":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَاتَلَ اللَّهُ الْيَهُودَ اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah memerangi orang-orang yahudi, mereka menjadikan kuburan-kuburan para nabi mereka sebagai Masjid.\""},"2733":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ ال��َّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَجْلِسَ أَحَدُكُمْ عَلَى جَمْرَةٍ فَتُحْرِقَ ثِيَابَهُ حَتَّى تَخْلُصَ إِلَى جِلْدِهِ خَيْرٌ لَهُ مِنْ أَنْ يَجْلِسَ عَلَى قَبْرٍ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Khalid], telah menceritakan kepada kami [Suhail bin Abu Shalih], dari [ayahnya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, sekiranya salah seorang diantara kalian duduk di atas bara api sehingga membakar pakaiannya hingga sampai ke kulitnya, adalah lebih baik baginya daripada ia duduk di atas kuburan.\""},"2734":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ يَزِيدَ بْنِ جَابِرٍ عَنْ بُسْرِ بْنِ عُبَيْدِ اللَّهِ قَالَ سَمِعْتُ وَاثِلَةَ بْنَ الْأَسْقَعِ يَقُولُ سَمِعْتُ أَبَا مَرْثَدٍ الْغَنَوِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْلِسُوا عَلَى الْقُبُورِ وَلَا تُصَلُّوا إِلَيْهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada kami [Isa], telah menceritakan kepada kami [Abdurrahman bin Yazid? bin Jabir], dari [Busr bin 'Ubaidullah] ia berkata; saya mendengar [Watsilah bin Al Asqa'] berkata; saya mendengar [Abu Martsad Al Ghanawi] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian duduk di atas kuburan, dan jangan kalian melakukan shalat menghadap kepadanya.\""},"2735":{"ar":"حَدَّثَنَا سَهْلُ بْنُ بَكَّارٍ حَدَّثَنَا الْأَسْوَدُ بْنُ شَيْبَانَ عَنْ خَالِدِ بْنِ سُمَيْرٍ السَّدُوسِيِّ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ بَشِيرٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ اسْمُهُ فِي الْجَاهِلِيَّةِ زَحْمُ بْنُ مَعْبَدٍفَهَاجَرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا اسْمُكَ قَالَ زَحْمٌ قَالَ بَلْ أَنْتَ بَشِيرٌ قَالَ بَيْنَمَا أَنَا أُمَاشِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِقُبُورِ الْمُشْرِكِينَ فَقَالَ لَقَدْ سَبَقَ هَؤُلَاءِ خَيْرًا كَثِيرًا ثَلَاثًا ثُمَّ مَرَّ بِقُبُورِ الْمُسْلِمِينَ فَقَالَ لَقَدْ أَدْرَكَ هَؤُلَاءِ خَيْرًا كَثِيرًا وَحَانَتْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَظْرَةٌ فَإِذَا رَجُلٌ يَمْشِي فِي الْقُبُورِ عَلَيْهِ نَعْلَانِ فَقَالَ يَا صَاحِبَ السِّبْتِيَّتَيْنِ وَيْحَكَ أَلْقِ سِبْتِيَّتَيْكَ فَنَظَرَ الرَّجُلُ فَلَمَّا عَرَفَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلَعَهُمَا فَرَمَى بِهِمَا","id":"Telah menceritakan kepada kami [Sahl bin Bakkar], telah menceritakan kepada kami [Al Aswad bin Syaiban] dari [Khalid bin Sumair As Sadusi], dari [Basyir bin Nahik] dari [Basyir] mantan budak Rasulullah shallallahu 'alaihi wasallam yang pada masa jahiliyah bernama Zahm bin Ma'bad, kemudian ia berhijrah kepada Allah, lalu beliau berkata: \"Siapakah namamu?\" Ia berkata; Zahm. Beliau berkata: \"Bahkan, engkau adalah Basyir.\" Ia berkata; ketika aku berjalan bersama Rasulullah shallallahu 'alaihi wasallam, beliau melewati kuburan orang-orang musyri, lalu beliau berkata: \"Sungguh mereka telah mendahului mendapatkan kebaikan yang banyak.\" Beliau mengatakannya tiga kali. Kemudian beliau melalui kuburan orang-orang muslim, kemudian beliau berkata: \"Sungguh mereka telah mendapatkan kebaikan yang banyak.\" Dan beliau melihat seseorang yang berjalan diantara kuburan mengenakan dua sandal. Kemudian beliau berkata: \"Wahai pemilik dua sandal, lepaskan dua sandalmu!\" kemudian orang tersebut melihat dan ia kenal dengan Rasulullah shallallahu 'alaihi wasallam. Maka ia melepasnya dan meletakkannya. "},"2736":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ يَعْنِي ابْنَ عَطَاءٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ الْعَبْدَ إِذَا وُضِعَ فِي قَبْرِهِ وَتَوَلَّى عَنْهُ أَصْحَابُهُ إِنَّهُ لَيَسْمَعُ قَرْعَ نِعَالِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada kami [Abdul Wahhab bin 'Atho`] dari [Sa'id] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Sesungguhnya seorang hamba apabila telah diletakkan dalam kuburnya dan para pengantarnya telah pergi darinya, ia mendengar ketukan sandal mereka.\""},"2737":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سَعِيدِ بْنِ يَزِيدَ أَبِي مَسْلَمَةَ عَنْ أَبِي نَضْرَةَ عَنْ جَابِرٍ قَالَدُفِنَ مَعَ أَبِي رَجُلٌ فَكَانَ فِي نَفْسِي مِنْ ذَلِكَ حَاجَةٌ فَأَخْرَجْتُهُ بَعْدَ سِتَّةِ أَشْهُرٍ فَمَا أَنْكَرْتُ مِنْهُ شَيْئًا إِلَّا شُعَيْرَاتٍ كُنَّ فِي لِحْيَتِهِ مِمَّا يَلِي الْأَرْضَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hammad bin Zaid] dari [Sa'id bin Yazid? Abu Maslamah] dari [Abu Nadhrah], dan [Jabir] ia berkata; terdapat seorang laki-laki yang di kubur bersama ayahku. Dan dalam hatiku terdapat keinginan untuk mengeluarkannya. Kemudian setelah enam bulan aku keluarkan jasad ayahku, dan aku tidak mendapati perubahan sedikitpun darinya selain beberapa rambut yang ada di jenggotnya dan menyentuh tanah. "},"2738":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ بْنِ عَامِرٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَرُّوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَنَازَةٍ فَأَثْنَوْا عَلَيْهَا خَيْرًا فَقَالَ وَجَبَتْ ثُمَّ مَرُّوا بِأُخْرَى فَأَثْنَوْا عَلَيْهَا شَرًّا فَقَالَ وَجَبَتْ ثُمَّ قَالَ إِنَّ بَعْضَكُمْ عَلَى بَعْضٍ شُهَدَاءُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Syu'bah] dari [Ibrahim bin 'Amir], dari ['Amir bin Sa'd] dari [Abu Hurairah] ia berkata; orang-orang melewati Rasulullah shallallahu 'alaihi wasallam dengan membawa seorang jenazah, kemudian mereka memuji jenazah tersebut dengan baik, lalu beliau berkata: \"Telah wajib baginya surga.\" Kemudian mereka lewat dengan jenazah yang lain dan mereka lewat dengan membawa jenazah yang lain, dan mereka memberikan persaksian akan keburukannya. Lalu beliau berkata: \"Telah wajib baginya neraka.\" Kemudian beliau berkata: \"Sesungguhnya sebagian kalian adalah saksi bagi sebagian yang lain.\""},"2739":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ يَزِيدَ بْنِ كَيَسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْرَ أُمِّهِ فَبَكَى وَأَبْكَى مَنْ حَوْلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَأْذَنْتُ رَبِّي تَعَالَى عَلَى أَنْ أَسْتَغْفِرَ لَهَا فَلَمْ يُؤْذَنْ لِي فَاسْتَأْذَنْتُ أَنْ أَزُورَ قَبْرَهَا فَأَذِنَ لِي فَزُورُوا الْقُبُورَ فَإِنَّهَا تُذَكِّرُ بِالْمَوْتِ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada kami [Muhammad bin 'Ubaid] dari [Yazid? bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam datang ke kuburan ibunya, kemudian beliau menangi, dan orang-orang yang ada di sekitarnya menangis. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku telah meminta izin kepada Tuhanku ta'ala untuk memintakan ampunan baginya, namun aku tidak diperkenankan. Lalu aku meminta izin untuk mengunjungi kuburannya, lalu aku Dia memberiku izin. Maka ziarahilah kubur, karena sesungguhnya kuburan tersebut akan mengingatkanmu kepada kematian.\""},"2740":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا مُعَرِّفُ بْنُ وَاصِلٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَيْتُكُمْ عَنْ زِيَارَةِ الْقُبُورِ فَزُورُوهَا فَإِنَّ فِي زِيَارَتِهَا تَذْكِرَةً","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Mu'arrif bin Washil] dari [Muharib bin Ditsar] dari [Ibnu Buraidah] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah melarang kalian menziarahi kuburan, sekarang berziarahlah ke kuburan, karena dalam berziarah itu terdapat peringatan (mengingatkan kematian).\""},"2741":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ قَالَ سَمِعْتُ أَبَا صَالِحٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَائِرَاتِ الْقُبُورِ وَالْمُتَّخِذِينَ عَلَيْهَا الْمَسَاجِدَ وَالسُّرُجَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Syu'bah] dari [Muhammad bin Juhadah] ia berkata; saya mendengar [Abu Shalih] menceritakan dari [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam melaknat para wanita yang menziarahi kuburan, dan orang-orang yang menjadikannya sebagai masjid dan memberikan pelita. "},"2742":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْمَقْبَرَةِ فَقَالَ السَّلَامُ عَلَيْكُمْ دَارَ قَوْمٍ مُؤْمِنِينَ وَإِنَّا إِنْ شَاءَ اللَّهُ بِكُمْ لَاحِقُونَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Al 'Ala` bin Abdurrahman], dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam keluar menuju sebuah kuburan kemudian mengucapkan: \"ASSALAAMU 'ALAIKUM DAARA QAUMIN MUKMINIIN, WA INNAA INSYAA ALLAAHU BIKUM LAAHIQUUN\" (Semoga keselamatan terlimpah kepada kalian wahai penghuni kampung kaum mukminin, sesungguhnya insya Allah kami akan menyusul kalian).\""},"2743":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنِي عَمْرُو بْنُ دِينَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ وَقَصَتْهُ رَاحِلَتُهُ فَمَاتَ وَهُوَ مُحْرِمٌ فَقَالَ كَفِّنُوهُ فِي ثَوْبَيْهِ وَاغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّ اللَّهَ يَبْعَثُهُ يَوْمَ الْقِيَامَةِ يُلَبِّيقَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ يَقُولُ فِي هَذَا الْحَدِيثِ خَمْسُ سُنَنٍ كَفِّنُوهُ فِي ثَوْبَيْهِ أَيْ يُكَفَّنُ الْمَيِّتُ فِي ثَوْبَيْنِ وَاغْسِلُوهُ بِمَاءٍ وَسِدْرٍ أَيْ إِنَّ فِي الْغَسْلَاتِ كُلِّهَا سِدْرًا وَلَا تُخَمِّرُوا رَأْسَهُ وَلَا تُقَرِّبُوهُ طِيبًا وَكَانَ الْكَفَنُ مِنْ جَمِيعِ الْمَالِ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ عُبَيْدٍ الْمَعْنَى قَالَا حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو وَأَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ نَحْوَهُ قَالَ وَكَفِّنُوهُ فِي ثَوْبَيْنِ قَالَ أَبُو دَاوُد قَالَ سُلَيْمَانُ قَالَ أَيُّوبُ ثَوْبَيْهِ وَقَالَ عَمْرٌو ثَوْبَيْنِ وَقَالَ ابْنُ عُبَيْدٍ قَالَ أَيُّوبُ فِي ثَوْبَيْنِ وَقَالَ عَمْرٌو فِي ثَوْبَيْهِ زَادَ سُلَيْمَانُ وَحْدَهُ وَلَا تُحَنِّطُوهُ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ بِمَعْنَى سُلَيْمَانَ فِي ثَوْبَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan], telah menceritakan kepadaku ['Amr bin Dinar] dari [Sa'id bin Jubair], dari [Ibnu Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam dihadapkan kepada seorang laki-laki yang telah terjatuh dari kendaraannya kemudian meninggal dalam keadaan sedang berihram. Kemudian beliau berkata: \"Kafanilah ia dengan dua pakaiannya dan mandikan ia dengan air dan daun bidara. Dan janganlah kalian tutupi kepalanya, karena sesungguhnya Allah akan membangkitkannya pada Hari Kiamat dalam keadaan bertalbiyah.\" Abu Daud berkata; aku mendengar Ahmad bin Hanbal bekata dalam hadits ini; terdapat lima sunah, yaitu: kafanilah ia dalam dua kain, -yaitu mayit di kafani dalam dua kain. Mandikanlah dengan air dan daun bidara, yaitu dalam setiap pencucian terdapat duan bidara, dan janganlah kalian tutupi kepalanya, dan jangan kalian dekatkan dengan minyak wangi. Kafan adalah berasal dari seluruh hartanya. Telah menceritakan kepada kami [Sulaiman bin Harb], dan [Muhammad bin 'Ubaid] secara makna. Mereka berdua berkata; telah menceritakan kepada kami [Hammad] dari ['Amr] dan [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Abbas] seperti itu. Ia berkata; dan kafankanlah dia dalam dua kain. Abu Daud berkata; Sulaiman berkata; Ayyub berkata; dua kainnya. Sedangkan 'Amr berkata; dua kain. Ibnu 'Ubaid berkata; Ayyub berkata; dalam dua kain. Dan 'Amr berkata; dalam dua kainnya. Sulaiman sendiri menambahkan; dan janganlah kalian memakaikan minyak wangi kepadanya. Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dengan makna hadits Sulaiman mengenai dua kain."},"2744":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَوَقَصَتْ بِرَجُلٍ مُحْرِمٍ نَاقَتُهُ فَقَتَلَتْهُ فَأُتِيَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اغْسِلُوهُ وَكَفِّنُوهُ وَلَا تُغَطُّوا رَأْسَهُ وَلَا تُقَرِّبُوهُ طِيبًا فَإِنَّهُ يُبْعَثُ يُهِلُّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Al Hakam] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; terdapat seorang laki-laki yang terjatuh dari untanya hingga lehernya patah dan membunuhnya, kemudian orang tersebut dibawa kepada Rasulullah shallallahu 'alaihi wasallam, kemudian beliau berkata: \"Mandikan serta kafanilah dia, dan jangan kalian tutup kepalanya, serta jangan kalian dekatkan minyak wangi kepadanya. Karena sesungguhnya ia akan dibangkitkan dalam keadaan bertalbiyah.\""},"2745":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ مَصْبُورَةٍ كَاذِبًا فَلْيَتَبَوَّأْ بِوَجْهِهِ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzaz], telah menceritakan kepada kami [Yazid? bin Harun], telah mengabarkan kepada kami [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Imran bin Hushain], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah dengan dusta, maka hendaknya ia mempersiapkan tempatnya di neraka!\""},"2746":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَهَنَّادُ بْنُ السَّرِيِّ الْمَعْنَى قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ هُوَ فِيهَا فَاجِرٌ لِيَقْتَطِعَ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُفَقَالَ الْأَشْعَثُ فِيَّ وَاللَّهِ كَانَ ذَلِكَ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ لِلْيَهُودِيِّ احْلِفْ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفُ وَيَذْهَبُ بِمَالِي فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] dan [Hannad bin As Sari], mereka berdua berkata; telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Al A'masy], dari [Syaqiq] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah dalam keadaan berbuat dosa untuk memutuskan harta orang muslim, maka ia akan berjumpa dengan Allah dalam keadaan dimurkai.\" Al Asy'ats berkata; mengenai diriKu. Demi Allah, antara diriku dan antara seseorang yahudi terdapat lahan yang diperselisihkan, kemudian ia mengingkariku. Lalu aku datang bersamanya kepada Nabi shallallahu 'alaihi wasallam, kemudian Nabi shallallahu 'alaihi wasallam berkata kepadaku: \"Apakah engkau memiliki bukti?\" aku katakan; tidak. Beliau berkata kepada orang yahudi tersebut: \"Bersumpahlah!\" Aku katakan; wahai Rasulullah, jika demikian ia akan bersumpah dan pergi membawa hartaku. Kemudian Allah ta'ala menurunkan ayat: \"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit…..\" hinggga akhir ayat. "},"2747":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْفِرْيَابِيُّ حَدَّثَنَا الْحَارِثُ بْنُ سُلَيْمَانَ حَدَّثَنِي كُرْدُوسٌ عَنْ الْأَشْعَثِ بْنِ قَيْسٍأَنَّ رَجُلًا مِنْ كِنْدَةَ وَرَجُلًا مِنْ حَضْرَمَوْتَ اخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَرْضٍ مِنْ الْيَمَنِ فَقَالَ الْحَضْرَمِيُّ يَا رَسُولَ اللَّهِ إِنَّ أَرْضِي اغْتَصَبَنِيهَا أَبُو هَذَا وَهِيَ فِي يَدِهِ قَالَ هَلْ لَكَ بَيِّنَةٌ قَالَ لَا وَلَكِنْ أُحَلِّفُهُ وَاللَّهُ يَعْلَمُ أَنَّهَا أَرْضِي اغْتَصَبَنِيهَا أَبُوهُ فَتَهَيَّأَ الْكِنْدِيُّ لِلْيَمِينِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْتَطِعُ أَحَدٌ مَالًا بِيَمِينٍ إِلَّا لَقِيَ اللَّهَ وَهُوَ أَجْذَمُ فَقَالَ الْكِنْدِيُّ هِيَ أَرْضُهُ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Al Firyabi], telah menceritakan kepada kami [Al Harits bin Sulaiman], telah menceritakan kepadaku [Kurdus] dari [Al Asy'ats bin Qais], bahwa seorang laki-laki dari Kindah dan seorang laki-laki dari Hadhramaut memperkarakan kepada Nabi shallallahu 'alaihi wasallam di negeri Yaman. Kemudian orang Hadhrami tersebut berkata; wahai Rasulullah, sesungguhnya tanahku di ambil bapak orang ini, dan tanah itu ada di tangannya. Beliau berkata: \"Apakah engkau memiliki bukti?\" ia berkata; tidak akan tetapi aku minta ia untuk bersumpah, dan Allah mengetahui bahwa tanah tersebut adalah tanahku yang diambil bapaknya. Kemudian orang Kindah tersebut bersiap-siap untuk bersumpah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang mengambil harta dengan sumpah melainkan ia akan berjumpa dengan Allah dalam keadaan terpotong tangannya.\" Kemudian orang Kindi tersebut berkata; tanah tersebut adalah tanahnya. "},"2748":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عَلْقَمَةَ بْنِ وَائِلِ بْنِ حُجْرٍ الْحَضْرَمِيِّ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ مِنْ حَضْرَمَوْتَ وَرَجُلٌ مِنْ كِنْدَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْحَضْرَمِيُّ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا غَلَبَنِي عَلَى أَرْضٍ كَانَتْ لِأَبِي فَقَالَ الْكِنْدِيُّ هِيَ أَرْضِي فِي يَدِي أَزْرَعُهَا لَيْسَ لَهُ فِيهَا حَقٌّ قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْحَضْرَمِيِّ أَلَكَ بَيِّنَةٌ قَالَ لَا قَالَ فَلَكَ يَمِينُهُ قَالَ يَا رَسُولَ اللَّهِ إِنَّهُ فَاجِرٌ لَا يُبَالِي مَا حَلَفَ عَلَيْهِ لَيْسَ يَتَوَرَّعُ مِنْ شَيْءٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَكَ مِنْهُ إِلَّا ذَاكَ فَانْطَلَقَ لِيَحْلِفَ لَهُ فَلَمَّا أَدْبَرَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا لَئِنْ حَلَفَ عَلَى مَالٍ لِيَأْكُلَهُ ظَالِمًا لَيَلْقَيَنَّ اللَّهَ عَزَّ وَجَلَّ وَهُوَ عَنْهُ مُعْرِضٌ","id":"Telah menceritakan kepada kami [Hannad bin As Sari], telah menceritakan kepada kami [Al Ahwash] dari [Simak] dari ['Alqamah bin Wail bin Hujr Al Hadhrami], dari [ayahnya], ia berkata; terdapat seorang laki-laki yang datang dari Hadhramaut dan seorang laki-laki dari Kindah kepada Rasulullah shallallahu 'alaihi wasallam, kemudain berkata; wahai Rasulullah, sesungguhnya orang ini telah menguasai tanah yang dahulu adalah milik ayahku. Kemudian orang Kindi tersebut berkata; tanah tersebut adalah tanahku dan ada ditanganku serta aku yang menanamnya, ia tidak memiliki hak pada tanah tersebut. 'Alqamah bin Wail berkata; kemudian Nabi shallallahu 'alaihi wasallam berkata orang Hadhrami; apakah engkau memiliki bukti? Orang Hadhrami berkata; tidak. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Bagimu sumpahnya.\" Ia berkata; wahai Rasulullah, ia adalah orang yang suka berbuat dosa, ia tidak peduli apa yang sumpahi. Ia tidak menjaga diri dari sesuatupun. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Engkau hanya memiliki hal tersebut darinya.\" Kemudian orang tersebut hendak bersumpah, dan tatkala ia telah berpaling Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, sesungguhnya apabila ia bersumpah untuk memakan harta secara zhalim niscaya ia akan bertemu dengan Allah 'azza wajalla dalam keadaan berpaling darinya.\""},"2749":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا هَاشِمُ بْنُ هَاشِمٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ نِسْطَاسٍ مِنْ آلِ كَثِيرِ بْنِ الصَّلْتِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْلِفُ أَحَدٌ عِنْدَ مِنْبَرِي هَذَا عَلَى يَمِينٍ آثِمَةٍ وَلَوْ عَلَى سِوَاكٍ أَخْضَرَ إِلَّا تَبَوَّأَ مَقْعَدَهُ مِنْ النَّارِ أَوْ وَجَبَتْ لَهُ النَّارُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Ibnu Numair], telah menceritakan kepada kami [Hasyim bin Hasyim], telah mengabarkan kepadaku [Abdullah bin Nithas] dari keluarga Katsir bin Ash Shalt bahwa ia mendengar [Jabir bin Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang bersumpah di samping mimbarku ini dengan sumpah palsu walaupun untuk mendapatkan satu siwak, melainkan ia telah mempersiapkan tempatnya di neraka atau wajib baginya neraka.\""},"2750":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ فَقَالَ فِي حَلْفِهِ وَاللَّاتِ فَلْيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ وَمَنْ قَالَ لِصَاحِبِهِ تَعَالَ أُقَامِرْكَ فَلْيَتَصَدَّقْ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri], dari [Humaid bin Abdurrahman], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah dalam sumpahnya ia berkata; demi Lata, maka hendaknya ia mengucapkan LAA ILAAHA ILLAAHU. Dan barangsiapa yang berkata kepada sahabatnya; kemarilah aku beri engkau minum arak, maka hendaknya ia bersedekah dengan sesuatu!\""},"2751":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا عَوْفٌ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحْلِفُوا بِآبَائِكُمْ وَلَا بِأُمَّهَاتِكُمْ وَلَا بِالْأَنْدَادِ وَلَا تَحْلِفُوا إِلَّا بِاللَّهِ وَلَا تَحْلِفُوا بِاللَّهِ إِلَّا وَأَنْتُمْ صَادِقُونَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami ['Auf] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian bersumpah dengan nama bapak-bapak kalian, dan jangan pula dengan nama ibu-ibu kalian, serta dengan sekutu-sekutu! Dan janganlah kalian bersumpah kecuali dengan nama Allah, dan janganlah bersumpah dengan nama Allah kecuali kalian dalam keadaan benar.\""},"2752":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْرَكَهُ وَهُوَ فِي رَكْبٍ وَهُوَ يَحْلِفُ بِأَبِيهِ فَقَالَ إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْ فَمَنْ كَانَ حَالِفًا فَلْيَحْلِفْ بِاللَّهِ أَوْ لِيَسْكُتْحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِ��ٍ عَنْ أَبِيهِ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَ سَمِعَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ مَعْنَاهُ إِلَى بِآبَائِكُمْ زَادَ قَالَ عُمَرُ فَوَاللَّهِ مَا حَلَفْتُ بِهَذَا ذَاكِرًا وَلَا آثِرًا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], Telah menceritakan kepada kami [Zuhair], dari ['Ubaidullah bin Umar], dari [Nafi'] dari [Ibnu Umar], dari [Umar bin Al Khathab], bahwa Rasulullah shallallahu 'alaihi wasallam telah mendapatinya sementara ia berada diantara orang-orang yang melakukan safar, dan ia bersumpah dengan nama bapaknya. Kemudian beliau berkata: \"Sesungguhnya Allah melarang kalian dari bersumpah dengan nama bapak-bapak kalian. Barangsiapa yang bersumpah, maka hendaknya ia bersumpah dengan nama Allah atau hendaknya (lebih baik) ia diam.\" Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri], dari [Salim] dari [ayahnya] dari [Umar radliallahu 'anhu] ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam ……. Seperti makna hadits tersebut hingga lafazh; … dengan nama bapak-bapak kalian.\" Ia menambahkan, Umar berkata; demi Allah, aku tidak bersumpah dengan hal ini baik ingat atau tidak. "},"2753":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ سَمِعْتُ الْحَسَنَ بْنَ عُبَيْدِ اللَّهِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ قَالَسَمِعَ ابْنُ عُمَرَ رَجُلًا يَحْلِفُ لَا وَالْكَعْبَةِ فَقَالَ لَهُ ابْنُ عُمَرَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَلَفَ بِغَيْرِ اللَّهِ فَقَدْ أَشْرَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami [Ibnu Idris], ia berkata; saya mendengar [Al Hasan bin 'Ubaidullah] dari [Sa'd bin 'Ubaidah], ia berkata; [Ibnu Umar] mendengar seseorang bersumpah dengan mengatakan; tidak demi ka'bah. Kemudian Ibnu Umar berkata; sesungguhnya aku telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang bersumpah dengan selain nama Allah, maka sungguh ia telah berbuat syirik.\""},"2754":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ الْمَدَنِيُّ عَنْ أَبِي سُهَيْلٍ نَافِعِ بْنِ مَالِكِ بْنِ أَبِي عَامِرٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ يَعْنِي فِي حَدِيثِ قِصَّةِ الْأَعْرَابِيِّقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ وَأَبِيهِ إِنْ صَدَقَ دَخَلَ الْجَنَّةَ وَأَبِيهِ إِنْ صَدَقَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki], telah menceritakan kepada kami [Isma'il bin Ja'far Al Madani], dari [Abu Suhail Nafi' bin Malik bin Amir] dari [ayahnya] bahwa ia mendengar [Thalhah bin 'Ubaidullah] dalam hadits kisah seorang badui, Nabi shallallahu 'alaihi wasallam bersabda: \"Ia telah beruntung demi ayahnya apabila ia jujur, ia masuk surga demi ayahnya apabila ia jujur.\""},"2755":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا الْوَلِيدُ بْنُ ثَعْلَبَةَ الطَّائِيُّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ بِالْأَمَانَةِ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Al Walid bin Tsa'labah Ath Thai] dari [Ibnu Buraidah] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah dengan amanah, maka bukan dari golongan kami.\""},"2756":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ السَّامِيُّ حَدَّثَنَا حَسَّانُ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي الصَّائِغَ عَنْ عَطَاءٍ فِي اللَّغْوِ فِي الْيَمِينِ قَالَ قَالَتْ عَائِشَةُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هُوَ كَلَامُ الرَّجُلِ فِي بَيْتِهِ كَلَّا وَاللَّهِ وَبَلَى وَاللَّهِقَالَ أَبُو دَاوُد كَانَ إِبْرَاهِيمُ الصَّائِغُ رَجُلًا صَالِحًا قَتَلَهُ أَبُو مُسْلِمٍ بِعَرَنْدَسَ قَالَ وَكَانَ إِذَا رَفَعَ الْمِطْرَقَةَ فَسَمِعَ النِّدَاءَ سَيَّبَهَا قَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ دَاوُدُ بْنُ أَبِي الْفُرَاتِ عَنْ إِبْرَاهِيمَ الصَّائِغِ مَوْقُوفًا عَلَى عَائِشَةَ وَكَذَلِكَ رَوَاهُ الزُّهْرِيُّ وَعَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ وَمَالِكُ بْنُ مِغْوَلٍ وَكُلُّهُمْ عَنْ عَطَاءٍ عَنْ عَائِشَةَ مَوْقُوفًا","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah As Sami], telah menceritakan kepada kami [Hassan bin Ibrahim], telah menceritakan kepada kami [Ibrahim Ash Shaigh] dari ['Atha`] mengenai laghwu yamin (sumpah palsu, main-main), ia berkata; [Aisyah] berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Laghwu yamin adalah perkataan seseorang yang ia ucapkan di rumahnya; tidak demi Allah, dan benar demi Allah.\" Abu Daud berkata; Ibrahim Ash Shaigh adalah orang shalih, ia dibunuh oleh Abu Muslim di 'Arandas. 'Atho` berkata; ia apabila mengangkat palu kemudian mendengar suara adzan maka ia meninggalkannya. Abu Daud berkata; hadits ini diriwayatkan oleh [Daud bin Abu Al Furat] dari [Ibrahim Ash Shaigh] secara mauquf kepada [Aisyah]. Begitu juga diriwayatkan oleh [Az Zuhri], [Abdul Malik bin Abu Sulaiman], dan [Malik bin Mighwal], seluruh mereka dari [Atha'] dari [Aisyah] secara mauquf. "},"2757":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ أَخْبَرَنَا هُشَيْمٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا هُشَيْمٌ عَنْ عَبَّادِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينُكَ عَلَى مَا يُصَدِّقُكَ عَلَيْهَا صَاحِبُكَ قَالَ مُسَدَّدٌ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي صَالِحٍقَالَ أَبُو دَاوُد هُمَا وَاحِدٌ عَبْدُ اللَّهِ بْنُ أَبِي صَالِحٍ وَعَبَّادُ بْنُ أَبِي صَالِحٍ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun], ia berkata; telah mengabarkan kepada kami [Husyaim], dan telah diriwayatkan dari jalur yang lain: telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Husyaim] dari ['Abbad bin Abu Shalih], dari [ayahnya], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sumpahmu atas apa yang dibenarkan lawanmu.\" Musaddad berkata; telah mengabarkan kepadaku Abdullah bin Abu Shalih, Abu Daud berkata; keduanya adalah satu, yaitu Abdullah bin Abu Shalih serta 'Abbad bin Abu Shalih. "},"2758":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ النَّاقِدُ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الْأَعْلَى عَنْ جَدَّتِهِ عَنْ أَبِيهَا سُوَيْدِ بْنِ حَنْظَلَةَ قَالَخَرَجْنَا نُرِيدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَنَا وَائِلُ بْنُ حُجْرٍ فَأَخَذَهُ عَدُوٌّ لَهُ فَتَحَرَّجَ الْقَوْمُ أَنْ يَحْلِفُوا وَحَلَفْتُ أَنَّهُ أَخِي فَخَلَّى سَبِيلَهُ فَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ أَنَّ الْقَوْمَ تَحَرَّجُوا أَنْ يَحْلِفُوا وَحَلَفْتُ أَنَّهُ أَخِي قَالَ صَدَقْتَ الْمُسْلِمُ أَخُو الْمُسْلِمِ","id":"Telah menceritakan kepada kami ['Amr bin Muhammad An Naqid] telah menceritakan kepada kami [Abu Ahmad Az Zubairi], telah menceritakan kepada kami [Israil] dari [Ibrahim bin Al A'la], dari [neneknya] dari [ayahnya yaitu Suwaid bin Hanzhalah], ia berkata; kami keluar menuju kepada Rasulullah shallallahu 'alaihi wasallam dan kami bersama Wail bin Hujr. Kemudian ia ditangkap musuhnya, kemudian orang-orang enggan untuk bersumpah, dan aku bersumpah bahwa ia adalah saudaraku, kemudian ia melepaskannya. Lalu kami datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kepadanya bahwa orang-orang enggan bersumpah, dan aku bersumpah bahwa ia adalah saudaraku. Beliau bersabda: \"Engkau telah benar, seorang muslim adalah saudara muslim yang lain.\""},"2759":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي أَبُو قِلَابَةَ أَنَّ ثَابِتَ بْنَ الضَّحَّاكِ أَخْبَرَهُأَنَّهُ بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحْتَ الشَّجَرَةِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ بِمِلَّةٍ غَيْرِ مِلَّةِ الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ وَلَيْسَ عَلَى رَجُلٍ نَذْرٌ فِيمَا لَا يَمْلِكُهُ","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'], telah menceritakan kepada kami [Mu'awiyah bin Salam], dari [Yahya bin Abu Katsir], ia berkata; telah mengabarkan kepadaku [Abu Qilabah] bahwa [Tsabit bin Adh Dhahhak] telah mengabarkan kepadanya bahwa ia telah membai'at Rasulullah shallallahu 'alaihi wasallam di bawah pohon, bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang bersumpah dengan agama selain agama Islam secara dusta maka ia sebagaima yang ia katakan. Barang siapa yang membunuh dirinya dengan sesuatu maka ia akan diadzab dengan sesuatu tersebut pada Hari Kiamat. Dan tidak ada nadzar bagi seseorang dalam perkara yang tidak ia mampu.\""},"2760":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا حُسَيْنٌ يَعْنِي ابْنَ وَاقِدٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ فَقَالَ إِنِّي بَرِيءٌ مِنْ الْإِسْلَامِ فَإِنْ كَانَ كَاذِبًا فَهُوَ كَمَا قَالَ وَإِنْ كَانَ صَادِقًا فَلَنْ يَرْجِعَ إِلَى الْإِسْلَامِ سَالِمًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Zaid bin Al Hubab], telah menceritakan kepada kami [Husain bin Waqid] telah menceritakan kepadaku [Abdullah bin Buraidah], dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan mengatakan; sesungguhnya aku berlepas diri dari Islam, apabila ia berdusta maka ia seperti yang ia katakan, dan apabila ia benar maka ia tidak akan kembali kepada Islam dalam keadaan selamat.\""},"2761":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَحْيَى بْنُ الْعَلَاءِ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضَعَ تَمْرَةً عَلَى كِسْرَةٍ فَقَالَ هَذِهِ إِدَامُ هَذِهِحَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ أَبِي يَحْيَى عَنْ يَزِيدَ الْأَعْوَرِ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Yahya bin Al 'Ala`], dari [Muhammad bin Yahya bin Habban] dari [Yusuf bin Abdullah bin Abdullah bin Salam], ia berkata; aku melihat Nabi shallallahu 'alaihi wasallam meletakkan satu biji kurma di atas potongan roti kemudian mengatakan; \"Ini (kurma) adalah lauk untuk ini (potongan roti).\" Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Umar bin Hafash] telah menceritakan kepada kami [ayahku] dari [Muhammad bin Abi Yahya] dari [Yazid Al A'war] dari [Yusuf bin Abdullah bin Salam] seperti itu. "},"2762":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ فَقَالَ إِنْ شَاءَ اللَّهُ فَقَدْ اسْتَثْنَى","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] sampai kepada Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa yang bersumpah dan mengatakan; insya Allah, maka ia telah membuat pengecualian.\""},"2763":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَمُسَدَّدٌ وَهَذَا حَدِيثُهُ قَالَا حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ فَاسْتَثْنَى فَإِنْ شَاءَ رَجَعَ وَإِنْ شَاءَ تَرَكَ غَيْرَ حِنْثٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], dan [Musaddad] dan ini adalah haditsnya, mereka berdua mengatakan; telah menceritakan kepada kami [Abdul Warits] dari [Ayyub] dari [Nafi'], dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah dan mengucapkan insya Allah, apabila ia menghendaki maka ia kembali dan apabila ia menghendaki maka ia meninggalkannya tanpa berdosa.\""},"2764":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَأَكْثَرُ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْلِفُ بِهَذِهِ الْيَمِينِ لَا وَمُقَلِّبِ الْقُلُوبِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Musa bin 'Uqbah] dari [Salim] dari [Ibnu Umar] ia berkata; sumpah yang sering diucapkan Rasulullah shallallahu 'alaihi wasallam adalah dengan sumpah ini, 'Tidak, dan demi Dzat yang membolak-balikkan hati'. "},"2765":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ عَاصِمِ بْنِ شُمَيْخٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اجْتَهَدَ فِي الْيَمِينِ قَالَ وَالَّذِي نَفْسُ أَبِي الْقَاسِمِ بِيَدِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ikrimah bin 'Ammar], dari ['Ashim bin Syumaikh] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila serius (sungguh-sungguh) dalam bersumpah beliau mengatakan; demi Dzat yang jiwa Abu Al Qasim di tanganNya. "},"2766":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ أَخْبَرَنِي زَيْدُ بْنُ حُبَابٍ أَخْبَرَنِي مُحَمَّدُ بْنُ هِلَالٍ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُكَانَتْ يَمِينُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَلَفَ يَقُولُ لَا وَأَسْتَغْفِرُ اللَّهَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Aziz bin Abu Rizmah], telah mengabarkan kepadaku [Zaid bin Hubab], telah mengabarkan kepadaku [Muhammad bin Hilal], telah menceritakan kepadaku [ayahku] bahwa ia mendengar [Abu Hurairah] berkata; sumpah Rasulullah shallallahu 'alaihi wasallam apabila beliau bersumpah adalah mengucapkan: \"Tidak, dan aku beristighfar kepada Allah.\""},"2767":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَيَّاشٍ السَّمَعِيُّ الْأَنْصَارِيُّ عَنْ دَلْهَمِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ اللَّهِ بْنِ حَاجِبِ بْنِ عَامِرِ بْنِ الْمُنْتَفِقِ الْعُقَيْلِيِّ عَنْ أَبِيهِ عَنْ عَمِّهِ لَقِيطِ بْنِ عَامِرٍ قَالَ دَلْهَمٌ وَحَدَّثَنِيهِ أَيْضًا الْأَسْوَدُ بْنُ عَبْدِ اللَّهِ عَنْ عَاصِمِ بْنِ لَقِيطٍ أَنَّ لَقِيطَ بْنَ عَامِرٍخَرَجَ وَافِدًا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقِيطٌ فَقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ حَدِيثًا فِيهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَمْرُ إِلَهِكَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Ibrahim bin Hamzah], telah menceritakan kepada kami [Abdul Malik bin 'Ayyasy As Sam'i Al Anshari], dari [Dalham bin Al Aswad bin Abdullah bin Hajib bin Hajib bin 'Amir Al Muntafiq Al 'Uqaili] dari [ayahnya] dari [pamannya yaitu Laqith bin 'Amir], Dalham berkata; dan telah menceritakan kepadaku juga [Al Aswad bin Abdullah] dari ['Ashim bin Laqith] bahwa [Laqith bin 'Amir] keluar sebagai utusan kepada Nabi shallallahu 'alaihi wasallam, Laqith berkata; kemudian kami datang kepada Rasulullah shallallahu 'alaihi wasallam, …. Kemudian ia menyebutkan hadits yang dalam hadits tersebut Nabi shallallahu 'alaihi wasallam berkata: \"Demi Tuhanmu.\""},"2768":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ أَبَا بَكْرٍ أَقْسَمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْسِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas], bahwa Abu Bakr telah bersumpah kepada Nabi shallallahu 'alaihi wasallam kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan engkau bersumpah!\""},"2769":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ ابْنُ يَحْيَى كَتَبْتُهُ مِنْ كِتَابِهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ أَبُو هُرَيْرَةَ يُحَدِّثُ أَنَّ رَجُلًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أَرَى اللَّيْلَةَ فَذَكَرَ رُؤْيَا فَعَبَّرَهَا أَبُو بَكْرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَبْتَ بَعْضًا وَأَخْطَأْتَ بَعْضًا فَقَالَ أَقْسَمْتُ عَلَيْكَ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ لَتُحَدِّثَنِّي مَا الَّذِي أَخْطَأْتُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْسِمْحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ لَمْ يَذْكُرْ الْقَسَمَ زَادَ فِيهِ وَلَمْ يُخْبِرْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], Telah menceritakan kepada kami [Abdurrazzaq], Ibnu Yahya berkata; aku menulisnya dari bukunya, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah] dari [Ibnu Abbas], ia berkata; [Abu Hurairah] pernah menceritakan bahwa seorang laki-laki mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata; sesungguhnya semalam saya bermimpi…. Kemudian ia menyebutkan sebuah mimpi, lalu Abu Bakr menafsirkannya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Engkau benar sebagian dan salah sebagian.\" Lalu Abu Bakr berkata; wahai Rasulullah, aku bersumpah atas dirimu. Sungguh anda akan menceritakan kepadaku kesalahan apakah yang aku lakukan. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan engkau bersumpah!\" telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah mengabarkan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sulaiman bin Katsir] dari [Az Zuhri] dari ['Ubaidullah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam dengan hadits, ia tidak menyebutkan sumpah tersebut dan pada hadits tersebut ia menambahkan kata; beliau tidak mengabarkan kepadanya. "},"2770":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ أَوْ عَنْ أَبِي السَّلِيلِ عَنْهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ قَالَنَزَلَ بِنَا أَضْيَافٌ لَنَا قَالَ وَكَانَ أَبُو بَكْرٍ يَتَحَدَّثُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَقَالَ لَا أَرْجِعَنَّ إِلَيْكَ حَتَّى تَفْرُغَ مِنْ ضِيَافَةِ هَؤُلَاءِ وَمِنْ قِرَاهُمْ فَأَتَاهُمْ بِقِرَاهُمْ فَقَالُوا لَا نَطْعَمُهُ حَتَّى يَأْتِيَ أَبُو بَكْرٍ فَجَاءَ فَقَالَ مَا فَعَلَ أَضْيَافُكُمْ أَفَرَغْتُمْ مِنْ قِرَاهُمْ قَالُوا لَا قُلْتُ قَدْ أَتَيْتُهُمْ بِقِرَاهُمْ فَأَبَوْا وَقَالُوا وَاللَّهِ لَا نَطْعَمُهُ حَتَّى يَجِيءَ فَقَالُوا صَدَقَ قَدْ أَتَانَا بِهِ فَأَبَيْنَا حَتَّى تَجِيءَ قَالَ فَمَا مَنَعَكُمْ قَالُوا مَكَانَكَ قَالَ وَاللَّهِ لَا أَطْعَمُهُ اللَّيْلَةَ قَالَ فَقَالُوا وَنَحْنُ وَاللَّهِ لَا نَطْعَمُهُ حَتَّى تَطْعَمَهُ قَالَ مَا رَأَيْتُ فِي الشَّرِّ كَاللَّيْلَةِ قَطُّ قَالَ قَرِّبُوا طَعَامَكُمْ قَالَ فَقَرَّبَ طَعَامَهُمْ فَقَالَ بِسْمِ اللَّهِ فَطَعِمَ وَطَعِمُوا فَأُخْبِرْتُ أَنَّهُ أَصْبَحَ فَغَدَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِالَّذِي صَنَعَ وَصَنَعُوا قَالَ بَلْ أَنْتَ أَبَرُّهُمْ وَأَصْدَقُهُمْحَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا سَالِمُ بْنُ نُوحٍ وَعَبْدُ الْأَعْلَى عَنْ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ بِهَذَا الْحَدِيثِ نَحْوَهُ زَادَ عَنْ سَالِمٍ فِي حَدِيثِهِ قَالَ وَلَمْ يَبْلُغْنِي كَفَّارَةٌ","id":"Telah menceritakan kepada kami [Muammal bin Hisyam], telah menceritakan kepada kami [Isma'il] dari [Al Jurairi], dan [Abu Utsman] atau dari [Abu As Salil], dari [Abdurrahman bin Abu Bakr], ia berkata; terdapat beberapa tamu yang singgah pada kami. Ia berkata; dan Abu Bakr sedang berbicara di rumah Rasulullah shallallahu 'alaihi wasallam pada malam tersebut. Ia berkata; sungguh aku tidak akan pulang hingga engkau selesai dari menjamu mereka dan memberi makan mereka. Para tamu tersebut berkata; kami tidak akan memakannya hingga Abu Bakr datang. Kemudian Abu Bakr bertanya kepada keluarganya; apa yang dilakukan para tamu kalian? Apakah kalian selesai dari memberi makan mereka? Mereka berkata; tidak. Aku katakan; aku telah datang kepada mereka dengan membawa makan untuk mereka. Kemudian mereka menolak dan berkata; demi Allah kami tidak akan memakannya hingga ia datang. Kemudian para tamu tersebut berkata; benar, ia telah datang kepada kami dengan membawanya kepada kami. Lalu kami menolak hingga engkau datang. Abu Bakr berkata; apa yang menghalangimuuntuk memakannya? Mereka berkata; kedudukannmu. Abu Bakr berkata; demi Allah aku tidak akan memakannya malam ini sama sekali. Kemudian mereka berkata; dan kami, demi Allah, tidak akan memakannya hingga engkau memakannya. Dekatkan makanan kalian. Abdurrahman berkata; kemudian ia mendekatkan makanan mereka dan berkata; bismillah. Lalu ia makan dan merekapun makan. Lalu aku diberitahu bahwa Abu Bakr pada pagi harinya pergi kepada Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kepada beliau apa yang telah ia perbuat dan apa yang mereka perbuat. Beliau berkata: \"Bahkan engkau adalah orang yang terbaik diantara mereka dan paling benar.\" Telah menceritakan kepada kami [Ibnu Al Mutsanna], telah menceritakan kepada kami [Salim bin Nuh] serta [Abdul A'la] dari [Al Jurairi], dari [Abu Utsman] dari [Abdurrahman bin Abu Bakr] dengan hadits ini seperti itu. Ia tambahkan dari Salim dalam haditsnya ia berkata; dan tidak sampai kepadaku kafarah. "},"2771":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حَبِيبٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِأَنَّ أَخَوَيْنِ مِنْ الْأَنْصَارِ كَانَ بَيْنَهُمَا مِيرَاثٌ فَسَأَلَ أَحَدُهُمَا صَاحِبَهُ الْقِسْمَةَ فَقَالَ إِنْ عُدْتَ تَسْأَلُنِي عَنْ الْقِسْمَةِ فَكُلُّ مَالٍ لِي فِي رِتَاجِ الْكَعْبَةِ فَقَالَ لَهُ عُمَرُ إِنَّ الْكَعْبَةَ غَنِيَّةٌ عَنْ مَالِكَ كَفِّرْ عَنْ يَمِينِكَ وَكَلِّمْ أَخَاكَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَمِينَ عَلَيْكَ وَلَا نَذْرَ فِي مَعْصِيَةِ الرَّبِّ وَفِي قَطِيعَةِ الرَّحِمِ وَفِيمَا لَا تَمْلِكُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal], telah menceritakan kepada kami [Yazid? bin Zurai'], telah menceritakan kepada kami [Habib Al Mu'allim] dari ['Amr bin Syu'aib] dari [Sa'id bin Al Musayyab] bahwa dua orang bersaudara dari kalangan anshar, diantara mereka terdapat warisan. Kemudian salah seorang diantara mereka meminta pembagian kepada saudaranya tersebut. Kemudian ia berkata; apabila engkau kembali meminta pembagian kepadaku maka seluruh hartaku ada di pintu Ka'bah. Kemudian [Umar] berkata; kepadanya; sesungguhnya Ka'bah tidak butuh kepada hartamu. Bayarlah kafarah sumpahmu, dan berbicaralah dengan saudaramu. Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidak boleh ada sumpah atas dirimu, tidak boleh ada nadzardalam bermaksiat kepada Tuhan (Allah), dan dalam memutuskan hubungan kekerabatan, serta dalam perkara yang tidak engkau mampu.\""},"2772":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنِي أَبُو عَبْدِ الرَّحْمَنِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نَذْرَ إِلَّا فِيمَا يُبْتَغَى بِهِ وَجْهُ اللَّهِ وَلَا يَمِينَ فِي قَطِيعَةِ رَحِمٍ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah Adh Dhabbi], telah menceritakan kepada kami [Al Mughirah bin Abdurrahman], telah menceritakan kepadaku [Abu Abdurrahman] dari ['Amr bin Syu'aib], dari [ayahnya], dari [kakeknya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar kecuali pada sesuatu yang diharapkan padanya wajah Allah, dan tidak boleh ada sumpah dalam memutuskan hubungan kekerabatan.\""},"2773":{"ar":"حَدَّثَنَا الْمُنْذِرُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ الْأَخْنَسِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ وَلَا يَمِينَ فِيمَا لَا يَمْلِكُ ابْنُ آدَمَ وَلَا فِي مَعْصِيَةِ اللَّهِ وَلَا فِي قَطِيعَةِ رَحِمٍ وَمَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى غَيْرَهَا خَيْرًا مِنْهَا فَلْيَدَعْهَا وَلْيَأْتِ الَّذِي هُوَ خَيْرٌ فَإِنَّ تَرْكَهَا كَفَّارَتُهَاقَالَ أَبُو دَاوُد الْأَحَادِيثُ كُلُّهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلْيُكَفِّرْ عَنْ يَمِينِهِ إِلَّا فِيمَا لَا يَعْبَأُ بِهِ قَالَ أَبُو دَاوُد قُلْتُ لِأَحْمَدَ رَوَى يَحْيَى بْنُ سَعِيدٍ عَنْ يَحْيَى بْنِ عُبَيْدِ اللَّهِ فَقَالَ تَرَكَهُ بَعْدَ ذَلِكَ وَكَانَ أَهْلًا لِذَلِكَ قَالَ أَحْمَدُ أَحَادِيثُهُ مَنَاكِيرُ وَأَبُوهُ لَا يُعْرَفُ","id":"Telah menceritakan kepada kami [Al Mundzir bin Al Walid], telah menceritakan kepada kami [Abdullah bin Bakr], telah menceritakan kepada kami ['Ubaidullah bin Al Akhnas], dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dan sumpah dalam perkara yang tidak dimiliki anak Adam, dan dalam bermaksiat kepada Allah, serta dalam memutuskan hubungan kekerabatan. Barangsiapa yang bersumpah kemudian melihat yang lainnya lebih baik darinya, maka hendaknya ia meninggalkannya dan melakukan yang lebih baik darinya, maka sesungguhnya meninggalkannya adalah kafarah baginya.\" Abu Daud berkata; seluruh hadits tersebut berasal dari Nabi shallallahu 'alaihi wasallam: hendaknya ia membayar kafarah untuk sumpahnya kecuali dalam perkara yang tidak dipedulikan.\" Abu Daud berkata; aku katakan kepada Ahmad, Yahya bin Sa'id telah meriwayatkan dari Yahya bin 'Ubaidullah. Kemudian ia berkata; ia meninggalkannya setelah itu, dan ia adalah orang yang ahli untuk itu. Ahmad berkata; hadits-haditsnya adalah hadits-hadits yang munkar, dan ayahnya tidak dikenal. "},"2774":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِي يَحْيَى عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلَيْنِ اخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّالِبَ الْبَيِّنَةَ فَلَمْ تَكُنْ لَهُ بَيِّنَةٌ فَاسْتَحْلَفَ الْمَطْلُوبَ فَحَلَفَ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلَى قَدْ فَعَلْتَ وَلَكِنْ قَدْ غُفِرَ لَكَ بِإِخْلَاصِ قَوْلِ لَا إِلَهَ إِلَّا اللَّهُقَالَ أَبُو دَاوُد يُرَادُ مِنْ هَذَا الْحَدِيثِ أَنَّهُ لَمْ يَأْمُرْهُ بِالْكَفَّارَةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami ['Atho` bin As Saib] dari [Abu Yahya] dari [Ibnu Abbas] bahwa dua orang laki-laki mempermasalahkan kepada Nabi shallallahu 'alaihi wasallam, kemudian Nabi shallallahu 'alaihi wasallam meminta penuntut agar mendatangkan bukti, dan ia tidak memiliki bukti. Kemudian beliau meminta agar orang yang dituntut untuk bersumpah, lalu ia bersumpah dengan nama Allah yang tidak ada tuhan yang berhak disembah kecuali Dia. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya, sungguh engkau telah melakukan, akan tetapi engkau telah mendapat ampunan karena keikhlasan ucapanmu LAA ILAAHA ILLALLAAH.\" Abu Daud berkata; yang dimaksudkan dari hadits ini adalah bahwa beliau tidak memerintahkannya agar membayar kafarah."},"2775":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي وَاللَّهِ إِنْ شَاءَ اللَّهُ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا كَفَّرْتُ عَنْ يَمِينِي وَأَتَيْتُ الَّذِي هُوَ خَيْرٌ أَوْ قَالَ إِلَّا أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَكَفَّرْتُ يَمِينِي","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hammad], telah menceritakan kepada kami [Ghailan bin Jarir], dari [Abu Burdah], dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Demi Allah, insya Allah aku tidak bersumpah dengan suatu sumpah kemudian aku melihat yang lainnya lebih baik darinya kecuali aku membayar kafarah sumpahku dan aku melakukan yang lebih baik.\" Atau beliau mengatakan: \"melainkan aku melakukan yang lebih baik dan membayar kafarah sumpahku.\""},"2776":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ وَمَنْصُورٌ يَعْنِي ابْنَ زَاذَانَ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَقَالَ قَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ بْنَ سَمُرَةَ إِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ يَمِينَكَقَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ يُرَخِّصُ فِيهَا الْكَفَّارَةَ قَبْلَ الْحِنْثِ حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ نَحْوَهُ قَالَ فَكَفِّرْ عَنْ يَمِينِكَ ثُمَّ ائْتِ الَّذِي هُوَ خَيْرٌ قَالَ أَبُو دَاوُد أَحَادِيثُ أَبِي مُوسَى الْأَشْعَرِيِّ وَعَدِيِّ بْنِ حَاتِمٍ وَأَبِي هُرَيْرَةَ فِي هَذَا الْحَدِيثِ رُوِيَ عَنْ كُلِّ وَاحِدٍ مِنْهُمْ فِي بَعْضِ الرِّوَايَةِ الْحِنْثُ قَبْلَ الْكَفَّارَةِ وَفِي بَعْضِ الرِّوَايَةِ الْكَفَّارَةُ قَبْلَ الْحِنْثِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah Al Bazzaz], telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Yunus], dan [Manshur bin Zadzan] dari [Al Hasan] dari [Abdurrahman bin Samurah] ia berkata; Nabi shallallahu 'alaihi wasallam berkata kepadaku: \"Wahai Abdurrahman bin Samurah, apabila engkau bersumpah kemudian engkau melihat selainnya lebih baik maka lakukan yang lebih baik dan bayarlah kafarah sumpahmu.\" Abu Daud berkata; aku mendengar Ahmad memberikan keringanan untuk membayar kafarah sebelum membatalkan sumpah. Telah menceritakan kepada kami [Yahya bin Khalaf], telah menceritakan kepada kami [Abdul A'la], telah menceritakan kepada kami [Sa'id] dari [Qatadah], dari [Al Hasan] dari [Abdurrahman bin Samurah] seperti itu. Ia berkata; bayarlah kafarah sumpahmu kemudian lakukan sesuatu yang lebih baik. Abu Daud berkata; hadits-hadits Abu Musa Al Asy'ari dan 'Adi bin Hatim serta Abu Hurairah dalam hadits ini diriwayatkan dari setiap mereka dalam sebagian riwayat: membatalkan sumpah sebelum kafarah, dan dalam sebagian riwayat kafarah sebelum membatalkan sumpah. "},"2777":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ قَالَ قَرَأْتُ عَلَى أَنَسِ بْنِ عِيَاضٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ حَرْمَلَةَ عَنْ أُمِّ حَبِيبٍ بِنْتِ ذُؤَيْبِ بْنِ قَيْسٍ الْمُزَنِيَّةِ وَكَانَتْ تَحْتَ رَجُلٍ مِنْهُمْ مِنْ أَسْلَمَ ثُمَّ كَانَتْ تَحْتَ ابْنِ أَخٍ لِصَفِيَّةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ ابْنُ حَرْمَلَةَ فَوَهَبَتْ لَنَا أُمُّ حَبِيبٍ صَاعًا حَدَّثَتْنَا عَنْ ابْنِ أَخِي صَفِيَّةَ عَنْ صَفِيَّةَ أَنَّهُ صَاعُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَنَسٌ فَجَرَّبْتُهُ أَوْ قَالَ فَحَزَرْتُهُ فَوَجَدْتُهُ مُدَّيْنِ وَنِصْفًا بِمُدِّ هِشَامٍ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], ia berkata; aku membacakan riwayat kepada [Anas bin 'Iyadh], ia berkata; telah menceritakan kepadaku [Abdurrahman bin Harmalah], dari [Ummu Habib binti Dzuaib bin Qais Al Muzaniyyah], dan dahulu ia adalah isteri seorang laki-laki diantara mereka yang berasal dari Aslam, kemudian menjadi isteri anak saudara Shafiyyah isteri Nabi shallallahu 'alaihi wasallam. Ibnu Harmalah berkata; Ummu Habib menghadiahkan kepada kami satu sha'. Ia telah menceritakan kepada kami dari [anak saudara Shafiyyah], dari [Shafiyyah] bahwa sha' tersebut adalah sha' Nabi shallallahu 'alaihi wasallam. anas berkata; kemudian aku mencobanya, atau ia berkata; kemudian aku memperkirakannya dan aku dapatkan sha' tersebut sama dengan dua mud setengah menurut ukuran mud (milik) Hisyam (Hisyam bin Abdul Malik). "},"2778":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُحَمَّدِ بْنِ خَلَّادٍ أَبُو عُمَرَ قَالَكَانَ عِنْدَنَا مَكُّوكٌ يُقَالُ لَهُ مَكُّوكُ خَالِدٍ وَكَانَ كَيْلَجَتَيْنِ بِكَيْلَجَةِ هَارُونَقَالَ مُحَمَّدٌ صَاعُ خَالِدٍ صَاعُ هِشَامٍ يَعْنِي ابْنَ عَبْدِ الْمَلِكِ","id":"Telah menceritakan kepada kami [Muhammad bin Muhammad bin Khallad Abu Umar], ia berkata; kami memiliki takaran yang disebut Makkuk Khalid, dan hal itu adalah (setara) dua kilo dengan kiloan Harun. Muhammad berkata sha' Khalid adalah (setara) sha' Hisyam bin Abdul Malik. "},"2779":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُحَمَّدِ بْنِ خَلَّادٍ أَبُو عُمَرَ حَدَّثَنَا مُسَدَّدٌ عَنْ أُمَيَّةَ بْنِ خَالِدٍ قَالَلَمَّا وُلِّيَ خَالِدٌ الْقَسْرِيُّ أَضْعَفَ الصَّاعَ فَصَارَ الصَّاعُ سِتَّةَ عَشَرَ رِطْلًاقَالَ أَبُو دَاوُد مُحَمَّدُ بْنُ مُحَمَّدِ بْنِ خَلَّادٍ قَتَلَهُ الزِّنْجُ صَبْرًا فَقَالَ بِيَدِهِ هَكَذَا وَمَدَّ أَبُو دَاوُدَ يَدَهُ وَجَعَلَ بُطُونَ كَفَّيْهِ إِلَى الْأَرْضِ قَالَ وَرَأَيْتُهُ فِي النَّوْمِ فَقُلْتُ مَا فَعَلَ اللَّهُ بِكَ قَالَ أَدْخَلَنِي الْجَنَّةَ فَقُلْتُ فَلَمْ يَضُرَّكَ الْوَقْفُ","id":"Telah menceritakan kepada kami [Muhammad bin Muhammad bin Khallad Abu Umar], telah menceritakan kepada kami [Musaddad] dari [Umayyah bin Khalid], ia berkata; tatkala Khalid Al Qasri ditunjuk sebagai gubernur ia melipatkan sha' sehinngga satu sha' adalah enam belas rithl. Abu Daud berkata; Muhammad bin Muhammad Khallad dibunuh oleh Az Zinj dengan cara dijadikan sasaran. Kemudian ia berkata dengan tangannya seperti ini, Abu Daud membentangkan tangannya dan menjadikan bagian dalam kedua telapaknya menghadap ke bumi. Ia berkata; dan aku melihatkan dalam tidur, lalu aku katakan; apa yang Allah lakukan terhadapmu? Ia berkata; Allah memasukkanku ke Surga. Maka aku berkata; memauqufkan hadits tidaklah memadharatkanmu. "},"2780":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ الْحَجَّاجِ الصَّوَّافِ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ جَارِيَةٌ لِي صَكَكْتُهَا صَكَّةً فَعَظَّمَ ذَلِكَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَفَلَا أُعْتِقُهَا قَالَ ائْتِنِي بِهَا قَالَ فَجِئْتُ بِهَا قَالَ أَيْنَ اللَّهُ قَالَتْ فِي السَّمَاءِ قَالَ مَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ أَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ الشَّرِيدِ أَنَّ أُمَّهُ أَوْصَتْهُ أَنْ يَعْتِقَ عَنْهَا رَقَبَةً مُؤْمِنَةً فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي أَوْصَتْ أَنْ أُعْتِقَ عَنْهَا رَقَبَةً مُؤْمِنَةً وَعِنْدِي جَارِيَةٌ سَوْدَاءُ نُوبِيَّةٌ فَذَكَرَ نَحْوَهُ قَالَ أَبُو دَاوُد خَالِدُ بْنُ عَبْدِ اللَّهِ أَرْسَلَهُ لَمْ يَذْكُرْ الشَّرِيدَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Al Hajjaj Ash Shawwaf] telah menceritakan kepadaku [Yahya bin Abu Katsir], dari [Hilal bin Abu Maimunah] dari ['Atha` bin Yasar] dari [Mu'awiyah bin Al Hakam As Sulami], ia berkata; aku katakan; wahai Rasulullah, terdapat seorang budak wanita yang telah aku pukul dengan keras. Kemudian Rasulullah shallallahu 'alaihi wasallam menganggap hal tersebut sesuatu yang besar terhadap diriku, lalu aku katakan; tidakkah saya memerdekakannya? Beliau berkata: \"Bawa dia kepadaku!\" Kemudian aku membawanya kepada beliau. Beliau bertanya: \"Dimanakah Allah?\" Budak wanita tersebut berkata; di langit. Beliau berkata: \"Siapakah aku?\" Budak tersebut berkata; engkau adalah Rasulullah.\"Beliau berkata; bebaskan dia! Sesungguhnya ia adalah seorang wanita mukmin.\" Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Asy Syarid] bahwa ibunya telah berwasiat kepadanya agar membebaskan untuknya seorang budak wanita mukmin. Kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, sesungguhnya ibuku telah berwasiat agar saya membebaskan untuknya seorang budak wanita mukmin, dan saya memiliki seorang budak wanita hitam dari Nubiyah… kemudian ia menyebutkan hadits seperti itu. Abu Daud berkata; Khalid bin Abdullah telah memursalkannya dan ia tidak menyebutkan Asy Syarid. "},"2781":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ الْجَوْزَجَانِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنِي الْمَسْعُودِيُّ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَارِيَةٍ سَوْدَاءَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ عَلَيَّ رَقَبَةً مُؤْمِنَةً فَقَالَ لَهَا أَيْنَ اللَّهُ فَأَشَارَتْ إِلَى السَّمَاءِ بِأُصْبُعِهَا فَقَالَ لَهَا فَمَنْ أَنَا فَأَشَارَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِلَى السَّمَاءِ يَعْنِي أَنْتَ رَسُولُ اللَّهِ فَقَالَ أَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Ya'qub Al Jauzajani], telah menceritakan kepada kami [Yazid? bin Harun], ia berkata; telah mengabarkan kepadaku [Al Mas'udi] dari ['Aun bin Abdullah] dari [Abdullah bin 'Utbah] dari [Abu Hurairah] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dengan membawa seorang budak wanita hitam, kemudian ia berkata; wahai Rasulullah, sesungguhnya saya berkewajiban membebaskan budak mukmin. Kemudian beliau bersabda: \"Di manakah Allah?\" kemudian ia mengisyaratkan ke langit dengan jari-jarinya. Kemudian beliau berkata kepadanya: \"Siapakah aku?\" kemudian ia menunjuk kepada Nabi shallallahu 'alaihi wasallam dan ke langit yang maksudnya adalah engkau adalah Rasulullah. Maka beliau berkata: \"Bebaskan dia, sesungguhnya ia adalah wanita mukminah.\""},"2782":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَاللَّهِ لَأَغْزُوَنَّ قُرَيْشًا وَاللَّهِ لَأَغْزُوَنَّ قُرَيْشًا وَاللَّهِ لَأَغْزُوَنَّ قُرَيْشًا ثُمَّ قَالَ إِنْ شَاءَ اللَّهُقَالَ أَبُو دَاوُد وَقَدْ أَسْنَدَ هَذَا الْحَدِيثَ غَيْرُ وَاحِدٍ عَنْ شَرِيكٍ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَسْنَدَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و قَالَ الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ شَرِيكٍ ثُمَّ لَمْ يَغْزُهُمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Syarik] dari [Simak] dari [Ikrimah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah, sungguh aku akan memerangi Quraisy, demi Allah, sungguh aku akan memerangi Quraisy, demi Allah, sungguh aku akan memerangi Quraisy.\" Kemudian beliau bersabda: \"insya Allah.\" Abu Daud berkata; hadits ini sanadnya telah disebutkan [lebih dari satu orang] dari [Syarik] dari [Simak], dari [Ikrimah], dari [Ibnu Abbas], dan ia menyebutkan sanadnya dari Nabi shallallahu 'alaihi wasallam. Al Walid bin Muslim berkata dari Syarik; kemudian beliau tidak memerangi mereka. "},"2783":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا ابْنُ بِشْرٍ عَنْ مِسْعَرٍ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ يَرْفَعُهُ قَالَوَاللَّهِ لَأَغْزُوَنَّ قُرَيْشًا ثُمَّ قَالَ إِنْ شَاءَ اللَّهُ ثُمَّ قَالَ وَاللَّهِ لَأَغْزُوَنَّ قُرَيْشًا إِنْ شَاءَ اللَّهُ ثُمَّ قَالَ وَاللَّهِ لَأَغْزُوَنَّ قُرَيْشًا ثُمَّ سَكَتَ ثُمَّ قَالَ إِنْ شَاءَ اللَّهُقَالَ أَبُو دَاوُد زَادَ فِيهِ الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ شَرِيكٍ قَالَ ثُمَّ لَمْ يَغْزُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah mengabarkan kepada kami [Ibnu Bisyr] dari [Mis'ar] dari [Simak] dari [Ikrimah] dan ia memarfu'kannya. Beliau berkata: \"Demi Allah, sungguh aku akan memerangi Quraisy.\" Kemudian beliau berkata: \"Insya Allah.\" Kemudian beliau bersabda: \"Demi Allah, sungguh aku akan memerangi Quraisy, insya Allah.\" Kemudian beliau bersabda: \"Demi Allah, sungguh aku akan memerangi Quraisy.\" Kemudian beliau diam, kemudian berkata: \"insya Allah.\" Abu Daud berkata; menambahkan padanya terdapat [Al Walid bin Muslim], dari [Syarik], ia berkata; kemudian beliau tidak memerangi mereka. "},"2784":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ قَالَ عُثْمَانُ الْهَمْدَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ النَّذْرِ ثُمَّ اتَّفَقَا وَيَقُولُ لَا يَرُدُّ شَيْئًا وَإِنَّمَا يُسْتَخْرَجُ بِهِ مِنْ الْبَخِيلِ قَالَ مُسَدَّدٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّذْرُ لَا يَرُدُّ شَيْئًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Jarir bin Abdul Hamid], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Abdullah bin Murrah], Utsman bin Al Hamdani berkata; dari [Abdullah bin Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam mulai melarang dari bernadzar. Kemudian lafazh mereka sama; dan beliau berkata: \"Nadzar tersebut tidak mengembalikan sesuatu. Sesungguhnya nadzar dikeluarkan dari orang yang bakhil.\" Musaddad berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nadzar tidak mengembalikan sesuatu.\""},"2785":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ قَالَ قُرِئَ عَلَى الْحَارِثِ بْنِ مِسْكِينٍ وَأَنَا شَاهِدٌ أَخْبَرَكُمْ ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَأْتِي ابْنَ آدَمَ النَّذْرُ الْقَدَرَ بِشَيْءٍ لَمْ أَكُنْ قَدَّرْتُهُ لَهُ وَلَكِنْ يُلْقِيهِ النَّذْرُ الْقَدَرَ قَدَّرْتُهُ يُسْتَخْرَجُ مِنْ الْبَخِيلِ يُؤْتِي عَلَيْهِ مَا لَمْ يَكُنْ يُؤْتِي مِنْ قَبْلُ","id":"Telah menceritakan kepada kami [Abu Daud], ia berkata; telah dibacakan riwayat kepada [Al Harits bin Miskin], sementara aku menyaksikan. Telah mengabarkan kepada kalian [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Malik] dari [Abu Az Zinad], dari [Abdurrahman bin Hurmuz] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Tidaklah nadzar mendatangi Adam menuju kepada takdir dengan membawa sesuatu pun yang belum Aku takqirkan untuknya, akan tetapi nadzar tersebut mempertemukannya dengan takdir yang telah Aku takdirkan. Nadzar dikeluarkan dari orang yang bakhil, ia memberi karena nadzar tersebut sesuatu yang belum pernah ia berikan sebelumnya.\""},"2786":{"ar":"حَدَّثَنَا الْقَعْنَبِىُّ عَنْ مَالِكٍ عَنْ طَلْحَةَ بْنِ عَبْدِ الْمَلِكِ الْأَيْلِيِّ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ وَمَنْ نَذَرَ أَنْ يَعْصِيَ اللَّهَ فَلَا يَعْصِهِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik], dari [Thalhah bin Abdul Malik Al Aili], dari [Al Qasim] dari [Aisyah] radliallahu 'anha ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bernadzar untuk mentaati Allah, maka hendaknya ia mentaatiNya dan barangsiapa yang bernadzar untuk bermaksiat kepada Allah maka janganlah ia bermaksiat (melakukannya).\""},"2787":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نَذْرَ فِي مَعْصِيَةٍ وَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍحَدَّثَنَا ابْنُ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ بِمَعْنَاهُ وَإِسْنَادِهِ قَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ يَقُولُ قَالَ ابْنُ الْمُبَارَكِ يَعْنِي فِي هَذَا الْحَدِيثِ حَدَّثَ أَبُو سَلَمَةَ فَدَلَّ ذَلِكَ عَلَى أَنَّ الزُّهْرِيَّ لَمْ يَسْمَعْهُ مِنْ أَبِي سَلَمَةَ و قَالَ أَحْمَدُ بْنُ مُحَمَّدٍ وَتَصْدِيقُ ذَلِك مَا حَدَّثَنَا أَيُّوبُ يَعْنِي ابْنَ سُلَيْمَانَ قَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ يَقُولُ أَفْسَدُوا عَلَيْنَا هَذَا الْحَدِيثَ قِيلَ لَهُ وَصَحَّ إِفْسَادُهُ عِنْدَكَ وَهَلْ رَوَاهُ غَيْرُ ابْنِ أَبِي أُوَيْسٍ قَالَ أَيُّوبُ كَانَ أَمْثَلَ مِنْهُ يَعْنِي أَيُّوبَ بْنَ سُلَيْمَانَ بْنِ بِلَالٍ وَقَدْ رَوَاهُ أَيُّوبُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim Abu Ma'mar], telah menceritakan kepada kami [Abdullah bin Al Mubarak], dari [Yunus] dari [Az Zuhri] dari [Abu Salamah] dari [Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam bermaksiat, dan kafarahnya adalah kafarah sumpah.\" Telah menceritakan kepada kami [Ibnu As Sarah], ia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dengan makna dan sanadnya. Abu Daud berkata; aku mendengar Ahmad berkata; Ibnu Al Mubarak telah mengabarkan kepadaku dalam hadits ini; Abu Salamah telah menceritakan ……… Hal tersebut menunjukkan bahwa Az Zuhri tidak menengarnya dari Abu Salamah. Ahmad bin Muhammad berkata; dan yang membenarkan hal tersebut adalah apa yang telah diceritakan Ayyub bin Sulaiman. Abu Daud berkata; aku telah mendengar Ahmad bin Hanbal berkata; mereka telah merusak hadits ini terhadap kami. Dikatakan kepadanya; perusakan itu benar menurutmu, apakah ada yang meriwayatkannya selain Ibnu Abu Uwais? Ia berkata; Ayyub, ia paling mirip dengannya. Yaitu Ayyub bin Sulaiman bin Bilal, dan hadits tersebut telah diriwayatkan oleh Ayyub. "},"2788":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنَا أَيُّوبُ بْنُ سُلَيْمَانَ عَنْ أَبِي بَكْرِ بْنِ أَبِي أُوَيْسٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ ابْنِ أَبِي عَتيِقٍ وَمُوسَى بْنِ عُقْبَةَ عَنْ ابْنِ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ أَرْقَمَ أَنَّ يَحْيَى بْنَ أَبِي كَثِيرٍ أَخْبَرَهُ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ فِي مَعْصِيَةٍ وَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍقَالَ أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ إِنَّمَا الْحَدِيثُ حَدِيثُ عَلِيِّ بْنِ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَادَ أَنَّ سُلَيْمَانَ بْنَ أَرْقَمَ وَهِمَ فِيهِ وَحَمَلَهُ عَنْهُ الزُّهْرِيُّ وَأَرْسَلَهُ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَحِمَهَا اللَّهُ قَالَ أَبُو دَاوُد رَوَى بَقِيَّةُ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ الزُّبَيْرِ بِإِسْنَادِ عَلِيِّ بْنِ الْمُبَارَكِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ayyub bin Sulaiman] dari [Abu Bakr bin Abu Uwais] dari [Sulaiman bin Bilal] dari [Ibnu Abu 'Atiq] dan [Musa bin 'Uqbah] dari [Ibnu Syihab] dari [Sulaiman bin Arqam] bahwa [Yahya bin Abu Katsir] telah mengabarkan kepadanya dari [Abu Salamah] dari [Aisyah radliallahu 'anha], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam berbuat maksiat, dan kafarahnya adalah kafarah sumpah.\" Ahmad bin Muhammad Al Marwazi berkata; sesungguhnya hadits tersebut adalah hadits [Ali bin Al Mubarak] dari [Yahya bin Abu Katsir] dari [Muhammad bin Az Zubair] dari [ayahnya] dari [Imran bin Hushain] dari Nabi shallallahu 'alaihi wasallam. Yang ia maksudkan adalah bahwa Sulaiman bin Arqam telah salah dalam hadits tersebut. Az Zuhri membawakan hadits tersebut darinya dan ia memursalkannya dari Abu Salamah dari Aisyah rahimahullah. Abu Daud berkata; [Baqiyyah] telah meriwayatkan dari [Al Auza'i] dari [Yahya] dari [Muhammad bin Az Zubair] dengan sanad Ali bin Al Mubarak seperti itu. "},"2789":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ قَالَ أَخْبَرَنِي يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ زَحْرٍ أَنَّ أَبَا سَعِيدٍ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ مَالِكٍ أَخْبَرَهُ أَنَّ عُقْبَةَ بْنَ عَامِرٍ أَخْبَرَهُأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أُخْتٍ لَهُ نَذَرَتْ أَنْ تَحُجَّ حَافِيَةً غَيْرَ مُخْتَمِرَةٍ فَقَالَ مُرُوهَا فَلْتَخْتَمِرْ وَلْتَرْكَبْ وَلْتَصُمْ ثَلَاثَةَ أَيَّامٍحَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ كَتَبَ إِلَيَّ يَحْيَى بْنُ سَعِيدٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ زَحْرٍ مَوْلًى لِبَنِي ضَمْرَةَ وَكَانَ أَيَّمَا رَجُلٍ أَنَّ أَبَا سَعِيدٍ الرُّعَيْنِيَّ أَخْبَرَهُ بِإِسْنَادِ يَحْيَى وَمَعْنَاهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan], ia berkata; telah mengabarkan kepadaku [Yahya bin Sa'id Al Anshari], telah mengabarkan kepadaku ['Ubaidullah bin Zahr] bahwa [Abu Sa'id] telah mengabarkan kepadanya bahwa [Abdullah bin Malik] telah mengabarkan kepadanya bahwa ['Uqbah bin 'Amir] telah mengabarkan kepadanya bahwa ia pernah bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai saudara wanitanya yang bernadzar untuk berhaji dengan tidak beralas kaki dan tidak bertutup kepala. Kemudian beliau berkata: \"Perintahkan dia agar menutup kepala, menaiki kendaraan serta berpuasa tiga hari.\" Telah menceritakan kepada kami [Makhlad bin Khalid], telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Ibnu Juraij], ia berkata; [Yahya bin Sa'id] telah menulis surat kepadaku; telah mengabarkan kepadaku ['Ubaidullah bin Zahr] mantan budak Bani Dhamrah bahwa [Abu Sa'id Ar Ru'aini] telah mengabarkan kepadanya dengan sanad Yahya dan maknanya. "},"2790":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا شَرِيكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طَلْحَةَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أُخْتِي نَذَرَتْ يَعْنِي أَنْ تَحُجَّ مَاشِيَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَا يَصْنَعُ بِشَقَاءِ أُخْتِكَ شَيْئًا فَلْتَحُجَّ رَاكِبَةً وَلْتُكَفِّرْ عَنْ يَمِينِهَا","id":"Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub] telah menceritakan kepada kami [Abu An Nadhr], telah menceritakan kepada kami [Syarik], dari [Muhammad bin Abdurrahman] mantan budak keluarga Thalhah, dari [Kuraib] dari [Ibnu abbas] ia berkata; telah datang seorang laki-laki kepada Nabi shallallahu 'alaihi wasallam dan berkata; sesungguhnya saudara wanitaku telah bernadzar untuk berhaji dengan berjalan kaki. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah tidak membuat sesuatupun dengan penderitaan saudarimu, hendaknya ia berhaji dengan berkendaraan dan membayar kafarah sumpahnya.\""},"2791":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ أُخْتَ عُقْبَةَ بْنِ عَامِرٍ نَذَرَتْ أَنْ تَمْشِيَ إِلَى الْبَيْتِ فَأَمَرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَرْكَبَ وَتُهْدِيَ هَدْيًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Abu Al Walid], telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] bahwa saudari 'Uqbah bin 'Amir telah bernadzar untuk berjalan kaki menuju Ka'bah kemudian Nabi shallallahu 'alaihi wasallam memerintahkannya agar berkendaraan dan menyembelih kurban. "},"2792":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا بَلَغَهُ أَنَّ أُخْتَ عُقْبَةَ بْنِ عَامِرٍ نَذَرَتْ أَنْ تَحُجَّ مَاشِيَةً قَالَ إِنَّ اللَّهَ لَغَنِيٌّ عَنْ نَذْرِهَا مُرْهَا فَلْتَرْكَبْقَالَ أَبُو دَاوُد رَوَاهُ سَعِيدُ بْنُ أَبِي عَرُوبَةَ نَحْوَهُ وَخَالِدٌ عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ أَنَّ أُخْتَ عُقْبَةَ بْنِ عَامِرٍ بِمَعْنَى هِشَامٍ وَلَمْ يَذْكُرْ الْهَدْيَ وَقَالَ فِيهِ مُرْ أُخْتَكَ فَلْتَرْكَبْ قَالَ أَبُو دَاوُد رَوَاهُ خَالِدٌ عَنْ عِكْرِمَةَ بِمَعْنَى هِشَامٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam tatkala telah sampai kepadanya bahwa saudari 'Uqbah bin 'Amir bernadzar untuk berhaji dengan berjalan kaki, maka beliau berkata: \"Sesungguhnya Allah tidak butuh kepada nadzarnya. Perintahkan dia agar berkendaraan.\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Sa'id bin Abi 'Arubah] seperti itu. Dan oleh [Khalid] dari [Ikrimah], dari Nabi shallallahu 'alaihi wasallam seperti itu. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Ibnu Abu Adi], dari [Qatadah] dari [Ikrimah] bahwa saudari Uqbah bin Amir …… seperti makna hadits Hisyam tanpa menyebutkan kurban. Dan padanya beliau berkata: \"Perintahkan saudarimu agar berkendaraan!\" Abu Daud berkata; hadits tersebut diriwayatkan oleh Khalid dari Ikrimah sama dengan makna hadits Hisyam. "},"2793":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَبَيْنَمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ إِذَا هُوَ بِرَجُلٍ قَائِمٍ فِي الشَّمْسِ فَسَأَلَ عَنْهُ قَالُوا هَذَا أَبُو إِسْرَائِيلَ نَذَرَ أَنْ يَقُومَ وَلَا يَقْعُدَ وَلَا يَسْتَظِلَّ وَلَا يَتَكَلَّمَ وَيَصُومَ قَالَ مُرُوهُ فَلْيَتَكَلَّمْ وَلْيَسْتَظِلَّ وَلْيَقْعُدْ وَلْيُتِمَّ صَوْمَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Wuhaib], telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; ketika Nabi shallallahu 'alaihi wasallam berkhutbah, tiba-tiba terdapat seorang laki-laki yang berdiri di bawah terik matahari. Kemudian beliau bertanya mengenainya. Mereka berkata; orang ini adalah Abu Israil, ia bernadzar untuk berdiri dan tidak duduk, serta tidak bernaung, tidak berbicara, dan berpuasa. Beliau berkata: \"Perintahkan dia agar berbicara, bernaung, duduk dan menyempurnakan puasanya!\""},"2794":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يُهَادَى بَيْنَ ابْنَيْهِ فَسَأَلَ عَنْهُ فَقَالُوا نَذَرَ أَنْ يَمْشِيَ فَقَالَ إِنَّ اللَّهَ لَغَنِيٌّ عَنْ تَعْذِيبِ هَذَا نَفْسَهُ وَأَمَرَهُ أَنْ يَرْكَبَقَالَ أَبُو دَاوُد رَوَاهُ عَمْرُو بْنُ أَبِي عَمْرٍو عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Humaid Ath Thawil] dari [Tsabit Al Bunani] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam melihat seorang laki-laki yang dipapah daintara dua orang anaknya. Kemudian beliau bertanya mengenainya, lalu mereka berkata; ia telah bernadzar untuk berjalan. Kemudian beliau berkata: \"Sesungguhnya Allah tidak butuh penyiksaan orang ini terhadap dirinya.\" Dan beliau memerintahkannya agar berkendaraan. Abu Daud berkata; dan hadits tersebut diriwayatkan oleh ['Amr bin Abu 'Amr], dari [Al A'raj], dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"2795":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ السُّلَمِيُّ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ يَعْنِي ابْنَ طَهْمَانَ عَنْ مَطَرٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ أُخْتَ عُقْبَةَ بْنِ عَامِرٍ نَذَرَتْ أَنْ تَحُجَّ مَاشِيَةً وَأَنَّهَا لَا تُطِيقُ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَغَنِيٌّ عَنْ مَشْيِ أُخْتِكَ فَلْتَرْكَبْ وَلْتُهْدِ بَدَنَةً","id":"Telah menceritakan kepada kami [Ahmad bin Hafsh bin Abdullah As Sulami], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Mathar] dari [Ikrimah] dari [Ibnu Abbas], bahwa saudari 'Uqbah bin 'Amir telah bernadzar untuk berhaji dengan berjalan kaki, dan ia tidak mampu melakukan hal tersebut. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Sesungguhnya Allah tidak butuh kepada jalannya saudarimu, hendaknya ia berkendaraan dan menyembelih kurban.\""},"2796":{"ar":"حَدَّثَنَا شُعَيْبُ بْنُ أَيُّوبَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ عِكْرِمَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّأَنَّهُ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُخْتِي نَذَرَتْ أَنْ تَمْشِيَ إِلَى الْبَيْتِ فَقَالَ إِنَّ اللَّهَ لَا يَصْنَعُ بِمَشْيِ أُخْتِكَ إِلَى الْبَيْتِ شَيْئًا","id":"Telah menceritakan kepada kami [Syu'aib bin Ayyub], telah menceritakan kepada kami [Mu'awiya bin Hisyam] dari [Sufyan] dari [ayahnya], dari [Ikrimah] dari ['Uqbah bin 'Amir Al Juhani] bahwa ia berkata kepada Nabi shallallahu 'alaihi wasallam; sesungguhnya saudariku bernadzar untuk berjalan menuju Ka'bah. Kemudian beliau berkata: \"Sesungguhnya Allah tidak berbuat sesuatu dengan berjalannya saudarimu ke Ka'bah.\""},"2797":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا حَبِيبٌ الْمُعَلِّمُ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَجُلًا قَامَ يَوْمَ الْفَتْحِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ لِلَّهِ إِنْ فَتَحَ اللَّهُ عَلَيْكَ مَكَّةَ أَنْ أُصَلِّيَ فِي بَيْتِ الْمَقْدِسِ رَكْعَتَيْنِ قَالَ صَلِّ هَاهُنَا ثُمَّ أَعَادَ عَلَيْهِ فَقَالَ صَلِّ هَاهُنَا ثُمَّ أَعَادَ عَلَيْهِ فَقَالَ شَأْنُكَ إِذَنْقَالَ أَبُو دَاوُد رُوِيَ نَحْوُهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو عَاصِمٍ ح و حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ الْمَعْنَى حَدَّثَنَا رَوْحٌ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي يُوسُفُ بْنُ الْحَكَمِ بْنِ أَبِي سُفْيَانَ أَنَّهُ سَمِعَ حَفْصَ بْنَ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَعَمْرًو وَقَالَ عَبَّاسٌ ابْنُ حَنَّةَ أَخْبَرَاهُ عَنْ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ رِجَالٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْخَبَرِ زَادَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي بَعَثَ مُحَمَّدًا بِالْحَقِّ لَوْ صَلَّيْتَ هَاهُنَا لَأَجْزَأَ عَنْكَ صَلَاةً فِي بَيْتِ الْمَقْدِسِ قَالَ أَبُو دَاوُد رَوَاهُ الْأَنْصَارِيُّ عَنْ ابْنِ جُرَيْجٍ فَقَالَ جَعْفَرُ بْنُ عُمَرَ وَقَالَ عَمْرُو بْنُ حَيَّةَ وَقَالَ أَخْبَرَاهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَعْن رِجَالٌ مَنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Habib Al Mu'allim] dari ['Atha` bin Abu Rabah] dari [Jabir bin Abdullah] bahwa seseorang berdiri pada saat penaklukan Mekkah, kemudian berkata; wahai Rasulullah, sesungguhnya saya telah bernadzar untuk Allah, seandainya Allah menaklukkan Mekkah melalui anda maka saya akan melakukan shalat di Baitul Maqdis sebanyak dua raka'at. Beliau bersabda: \"Shalatlah di sini!\" Kemudian ia mengulang perkataannya kepada beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Shalatlah di sini!\" Kemudian ia mengulang perkataan kepada beliau. Maka beliau berkata: \"Terserah engkau, jika demikian.\" Abu Daud berkata; telah diriwayatkan seperti itu dari [Abdurrahman bin 'Auf] dari Nabi shallallahu 'alaihi wasallam. telah menceritakan kepada kami [Makhlad bin Khalid] telah menceritakan kepada kami [Abu 'Ashim]. Dan telah menceritakan kepada kami [Abbas Al 'Anbary] secara makna, telah menceritakan kepada kami [Rauh] dari [Ibnu Juraij] telah mengabarkan kepadaku [Yusuf bin Al Hakam bin Abu Sufyan] bahwasanya dia telah mendengar [Hafash bin Umar bin Abdurrahman bin Auf] dan [Amru], dan berkata Abbas bin Hannah, keduanya telah mengabarkan kepadanya dari [Umar bin Abdurrahman bin 'Auf] dari [seseorang dari sahabat Nabi shallallahu 'alaihi wasallam] dengan hadits ini. Ia menambahkan; kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang telah mengutus Muhammad dengan kebenaran. Seandainya engkau melakukan shalat di sini niscaya hal tersebut mencukupkan bagimu shalat dari melakukan shalat di Baitul Maqdis.\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Al Anshari] dari [Ibnu Juraij], [Ja'far bin Umar] berkata; dan ['Amr bin Hayyah] berkata; dan ia telah mengatakan; mereka berdua mengabarkan kepadanya dari [Abdurrahman bin 'Auf] dan dari [seseorang dari sahabat Nabi shallallahu 'alaihi wasallam]. "},"2798":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ سَعْدَ بْنَ عُبَادَةَ اسْتَفْتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُمِّي مَاتَتْ وَعَلَيْهَا نَذْرٌ لَمْ تَقْضِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْضِهِ عَنْهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi] ia berkata; aku membacakan riwayat kepada [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Abdullah bin Abbas], bahwa Sa'd bin 'Ubadah telah meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata; sesungguhnya ibuku telah meninggal, dan ia memiliki tanggungan nadzar yang belum beliau tunaikan. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Tunaikan nadzar tersebut untuknya!\""},"2799":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةً رَكِبَتْ الْبَحْرَ فَنَذَرَتْ إِنْ نَجَّاهَا اللَّهُ أَنْ تَصُومَ شَهْرًا فَنَجَّاهَا اللَّهُ فَلَمْ تَصُمْ حَتَّى مَاتَتْ فَجَاءَتْ ابْنَتُهَا أَوْ أُخْتُهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهَا أَنْ تَصُومَ عَنْهَاحَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ بُرَيْدَةَ أَنَّ امْرَأَةً أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كُنْتُ تَصَدَّقْتُ عَلَى أُمِّي بِوَلِيدَةٍ وَإِنَّهَا مَاتَتْ وَتَرَكَتْ تِلْكَ الْوَلِيدَةَ قَالَ قَدْ وَجَبَ أَجْرُكِ وَرَجَعَتْ إِلَيْكِ فِي الْمِيرَاثِ قَالَتْ وَإِنَّهَا مَاتَتْ وَعَلَيْهَا صَوْمُ شَهْرٍ فَذَكَرَ نَحْوَ حَدِيثِ عَمْرٍو","id":"Telah menceritakan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa seorang wanita mengarungi bahtera, kemudian ia bernadzar seandainya Allah menyelamatkannya maka ia akan berpuasa satu bulan. Kemudian Allah menyelamatkannya dan ia tidak berpuasa hingga ia meninggal. Lalu anak wanitanya atau saudara wanitanya datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memerintahkannya agar berpuasa untuknya. Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Abdullah bin 'Atho`] dari [Abdullah bin Buraidah] dari [ayahnya] bahwa seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; dahulu aku pernah mensedekahkan budak wanita kepada ibuku, dan ia meninggal dalam keadaan memiliki tanggungan puasa satu bulan. Kemudian Buraidah menyebutkan hadits 'Amr tersebut. "},"2800":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى قَالَ سَمِعْتُ الْأَعْمَشَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ الْمَعْنَى عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةً جَاءَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّهُ كَانَ عَلَى أُمِّهَا صَوْمُ شَهْرٍ أَفَأَقْضِيهِ عَنْهَا فَقَالَ لَوْ كَانَ عَلَى أُمِّكِ دَيْنٌ أَكُنْتِ قَاضِيَتَهُ قَالَتْ نَعَمْ قَالَ فَدَيْنُ اللَّهِ أَحَقُّ أَنْ يُقْضَى","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] ia berkata; saya mendengar [Al A'masy].. dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami [Abu Mu'awiyah] dan [Al A'masy] secara makna, dari [Muslim Al Bathin] dari [Sa'id bin Jubair], dari [Ibnu Abbas] bahwa seorang wanita telah datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; sesungguhnya ibuku memiliki tanggungan puasa satu bulan. Apakah boleh saya menunaikan puasa tersebut untuknya? Kemudian beliau berkata: \"Seandainya ibumu memiliki tanggungan hutang apakah engkau akan menunaikannya?\" Ia berkata; ya. Beliau berkata: \"Maka hutang Allah lebih berhak untuk ditunaikan.\""},"2801":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَاتَ وَعَلَيْهِ صِيَامٌ صَامَ عَنْهُ وَلِيُّهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku ['Amr bin Al Harits] dari ['Ubaidullah bin Abu Ja'far] dari [Muhammad bin Ja'far bin Az Zubair] dari ['Urwah] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meninggal dalam keadaan memiliki tanggungan puasa, maka walinya berpuasa (sebagai pengganti) untuknya.\""},"2802":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْحَارِثُ بْنُ عُبَيْدٍ أَبُو قُدَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ امْرَأَةً أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ أَنْ أَضْرِبَ عَلَى رَأْسِكَ بِالدُّفِّ قَالَ أَوْفِي بِنَذْرِكِ قَالَتْ إِنِّي نَذَرْتُ أَنْ أَذْبَحَ بِمَكَانِ كَذَا وَكَذَا مَكَانٌ كَانَ يَذْبَحُ فِيهِ أَهْلُ الْجَاهِلِيَّةِ قَالَ لِصَنَمٍ قَالَتْ لَا قَالَ لِوَثَنٍ قَالَتْ لَا قَالَ أَوْفِي بِنَذْرِكِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Al Harits bin 'Ubaid Abu Qudamah] dari ['Ubaidullah bin Al Akhnas] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa seorang wanita telah datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, sesungguhnya saya telah bernadzar untuk memukul rebana di hadapan anda. Beliau berkata: \"Penuhi nadzarmu!\" Ia berkata; sesungguhnya saya bernadzar untuk menyembelih di tempat ini dan ini. Yaitu tempat yang dahulu orang-orang Jahiliyah menyembelih padanya. Beliau berkata: \"Untuk patung?\" Ia berkata; tidak. Beliau berkata: \"Untuk berhala?\" Ia berkata; tidak. Beliau berkata: \"Penuhi nadzarmu!\""},"2803":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو قِلَابَةَ قَالَ حَدَّثَنِي ثَابِتُ بْنُ الضَّحَّاكِ قَالَنَذَرَ رَجُلٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْحَرَ إِبِلًا بِبُوَانَةَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي نَذَرْتُ أَنْ أَنْحَرَ إِبِلًا بِبُوَانَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ كَانَ فِيهَا وَثَنٌ مِنْ أَوْثَانِ الْجَاهِلِيَّةِ يُعْبَدُ قَالُوا لَا قَالَ هَلْ كَانَ فِيهَا عِيدٌ مِنْ أَعْيَادِهِمْ قَالُوا لَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْفِ بِنَذْرِكَ فَإِنَّهُ لَا وَفَاءَ لِنَذْرٍ فِي مَعْصِيَةِ اللَّهِ وَلَا فِيمَا لَا يَمْلِكُ ابْنُ آدَمَ","id":"Telah menceritakan kepada kami [Abu Daud bin Rusyid] telah menceritakan kepada kami [Syu'aib bin Ishaq] dari [Al Auza'i] dari [Yahya bin Abu Katsir] ia berkata; [Abu Qilabah] ia berkata; telah menceritakan kepadaku [Tsabit bin Adh Dhahhak] ia berkata; seorang laki-laki bernadzar pada zaman Rasulullah shallallahu 'alaihi wasallam untuk menyembelih unta di Buwanah. Kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; sesungguhnya saya telah bernadzar untuk menyembelih unta di Buwanah. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah padanya terdapat berhala diantara berhala-berhala jahiliyah yang disembah?\" Mereka berkata; tidak. Beliau berkata: \"Apakah padanya terdapat hari besar diantara hari-hari besar mereka?\" Mereka berkata; tidak. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penuhi nadzarmu, sesungguhnya tidak boleh memenuhi nadzar dalam bermaksiat kepada Allah, dalam perkara yang tidak dimiliki anak Adam.\""},"2804":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ بْنِ مِقْسَمٍ الثَّقَفِيُّ مِنْ أَهْلِ الطَّائِفِ قَالَ حَدَّثَتْنِي سَارَّةُ بِنْتُ مِقْسَمٍ الثَّقَفِيِّ أَنَّهَا سَمِعَتْ مَيْمُونَةَ بِنْتَ كَرْدَمٍ قَالَتْخَرَجْتُ مَعَ أَبِي فِي حِجَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعْتُ النَّاسَ يَقُولُونَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلْتُ أُبِدُّهُ بَصَرِي فَدَنَا إِلَيْهِ أَبِي وَهُوَ عَلَى نَاقَةٍ لَهُ مَعَهُ دِرَّةٌ كَدِرَّةِ الْكُتَّابِ فَسَمِعْتُ الْأَعْرَابَ وَالنَّاسَ يَقُولُونَ الطَّبْطَبِيَّةَ الطَّبْطَبِيَّةَ فَدَنَا إِلَيْهِ أَبِي فَأَخَذَ بِقَدَمِهِ قَالَتْ فَأَقَرَّ لَهُ وَوَقَفَ فَاسْتَمَعَ مِنْهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ إِنْ وُلِدَ لِي وَلَدٌ ذَكَرٌ أَنْ أَنْحَرَ عَلَى رَأْسِ بُوَانَةَ فِي عَقَبَةٍ مِنْ الثَّنَايَا عِدَّةً مِنْ الْغَنَمِ قَالَ لَا أَعْلَمُ إِلَّا أَنَّهَا قَالَتْ خَمْسِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ بِهَا مِنْ الْأَوْثَانِ شَيْءٌ قَالَ لَا قَالَ فَأَوْفِ بِمَا نَذَرْتَ بِهِ لِلَّهِ قَالَتْ فَجَمَعَهَا فَجَعَلَ يَذْبَحُهَا فَانْفَلَتَتْ مِنْهَا شَاةٌ فَطَلَبَهَا وَهُوَ يَقُولُ اللَّهُمَّ أَوْفِ عَنِّي نَذْرِي فَظَفِرَهَا فَذَبَحَهَاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ مَيْمُونَةَ بِنْتِ كَرْدَمِ بْنِ سُفْيَانَ عَنْ أَبِيهَا نَحْوَهُ مُخْتَصَرٌ مِنْهُ شَيْءٌ قَالَ هَلْ بِهَا وَثَنٌ أَوْ عِيدٌ مِنْ أَعْيَادِ الْجَاهِلِيَّةِ قَالَ لَا قُلْتُ إِنَّ أُمِّي هَذِهِ عَلَيْهَا نَذْرٌ وَمَشْيٌ أَفَأَقْضِيهِ عَنْهَا وَرُبَّمَا قَالَ ابْنُ بَشَّارٍ أَنَقْضِيهِ عَنْهَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Yazid? bin Harun], telah menceritakan kepada kami [Abdullah bin Yazid? bin Miqsam Ats Tsaqafi] dari penduduk Thaif, ia berkata; telah menceritakan kepadaku [Sarrah binti Miqsam Ats Tsaqafi] bahwa ia telah mendengar [Maimunah binti Kardam], ia berkata; aku pernah keluar bersama ayahku ketika Rasulullah shallallahu 'alaihi wasallam melakukan haji, kemudian aku melihat Rasulullah shallallahu 'alaihi wasallam dan aku mendengar orang-orang berkata; Rasulullah shallallahu 'alaihi wasallam. Lalu aku memandangnya dengan tajam, kemudian ayahku mendekat kepada beliau sementera beliau berada di atas untanya. Kemudian beliau berhenti dan mendengar darinya dengan membawa cambuk seperti cambuk orang mengajar anak-anak. Kemudian aku mendengar orang-orang dan orang-orang badui berkata; jangan bersuara! Jangan bersuara! Jangan bersuara! Kemudian ayahku mendekat kepada beliau, mengambil posisi di hadapan beliau, dan mengakui risalah serta kenabian beliau dan beliau berhenti serta mendengarkan darinya. Kemudian ia berkata; wahai Rasulullah, sesungguhnya aku telah bernadzar, apabila anakku terlahirkan laki-laki maka aku akan menyembelih di puncak Buwanah beberapa ekor kambing. Yazid? bin Miqsam mengatakan; yang aku ketahui hanya ia mengatakan; lima ekor. Kemudian Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah padanya terdapat sebagian berhala?\" Ia berkata; tidak. Beliau bersabda: \"Penuhilah apa yang engkau nadzarkan untuk Allah!\" Maimunah binti Kardam berkata; kemudian ia mengumpulkan kambing-kambing tersebut dan menyembelihnya. Lalu terdapat satu ekor kambing yang kabur. Lalu ia mencarinya dan berdoa; ya Allah, penuhkanlah nadzarku. Lalu ia mendapatkan kambing tersebut lalu menyembelihnya. Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abu Bakr Al Hanafi], telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari ['Amr bin Syu'aib], dari [Maimunah binti Kardam bin Sufyan] dari [ayahnya] seperti itu secara ringkas. Beliau bersabda: \"Apakah padanya terdapat berhala, atau hari besar jahiliyah?\" Ia berkata; tidak. aku katakan; sesungguhnya ibuku memiliki tanggungan nadzar dan berjalan. Apakah aku boleh menunaikan untuknya? Dan Ibnu Basysyar berkata; apakah aku boleh menunaikannya? Beliau berkata: \"Ya.\""},"2805":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ عِيسَى قَالَا حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَكَانَتْ الْعَضْبَاءُ لِرَجُلٍ مِنْ بَنِي عُقَيْلٍ وَكَانَتْ مِنْ سَوَابِقِ الْحَاجِّ قَالَ فَأُسِرَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي وَثَاقٍ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حِمَارٍ عَلَيْهِ قَطِيفَةٌ فَقَالَ يَا مُحَمَّدُ عَلَامَ تَأْخُذُنِي وَتَأْخُذُ سَابِقَةَ الْحَاجِّ قَالَ نَأْخُذُكَ بِجَرِيرَةِ حُلَفَائِكَ ثَقِيفَ قَالَ وَكَانَ ثَقِيفُ قَدْ أَسَرُوا رَجُلَيْنِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَقَدْ قَالَ فِيمَا قَالَ وَأَنَا مُسْلِمٌ أَوْ قَالَ وَقَدْ أَسْلَمْتُ فَلَمَّا مَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد فَهِمْتُ هَذَا مِنْ مُحَمَّدِ بْنِ عِيسَى نَادَاهُ يَا مُحَمَّدُ يَا مُحَمَّدُ قَالَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِيمًا رَفِيقًا فَرَجَعَ إِلَيْهِ فَقَالَ مَا شَأْنُكَ قَالَ إِنِّي مُسْلِمٌ قَالَ لَوْ قُلْتَهَا وَأَنْتَ تَمْلِكُ أَمْرَكَ أَفْلَحْتَ كُلَّ الْفَلَاحِ قَالَ أَبُو دَاوُد ثُمَّ رَجَعْتُ إِلَى حَدِيثِ سُلَيْمَانَ قَالَ يَا مُحَمَّدُ إِنِّي جَائِعٌ فَأَطْعِمْنِي إِنِّي ظَمْآنٌ فَاسْقِنِي قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ حَاجَتُكَ أَوْ قَالَ هَذِهِ حَاجَتُهُ فَفُودِيَ الرَّجُلُ بَعْدُ بِالرَّجُلَيْنِ قَالَ وَحَبَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَضْبَاءَ لِرَحْلِهِ قَالَ فَأَغَارَ الْمُشْرِكُونَ عَلَى سَرْحِ الْمَدِينَةِ فَذَهَبُوا بِالْعَضْبَاءِ قَالَ فَلَمَّا ذَهَبُوا بِهَا وَأَسَرُوا امْرَأَةً مِنْ الْمُسْلِمِينَ قَالَ فَكَانُوا إِذَا كَانَ اللَّيْلُ يُرِيحُونَ إِبِلَهُمْ فِي أَفْنِيَتِهِمْ قَالَ فَنُوِّمُوا لَيْلَةً وَقَامَتْ الْمَرْأَةُ فَجَعَلَتْ لَا تَضَعُ يَدَهَا عَلَى بَعِيرٍ إِلَّا رَغَا حَتَّى أَتَتْ عَلَى الْعَضْبَاءِ قَالَ فَأَتَتْ عَلَى نَاقَةٍ ذَلُولٍ مُجَرَّسَةٍ قَالَ فَرَكِبَتْهَا ثُمَّ جَعَلَتْ لِلَّهِ عَلَيْهَا إِنْ نَجَّاهَا اللَّهُ لَتَنْحَرَنَّهَا قَالَ فَلَمَّا قَدِمَتْ الْمَدِينَةَ عُرِفَتْ النَّاقَةُ نَاقَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُخْبِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ فَأَرْسَلَ إِلَيْهَا فَجِيءَ بِهَا وَأُخْبِرَ بِنَذْرِهَا فَقَالَ بِئْسَ مَا جَزَيْتِيهَا أَوْ جَزَتْهَا إِنْ اللَّهُ أَنْجَاهَا عَلَيْهَا لَتَنْحَرَنَّهَا لَا وَفَاءَ لِنَذْرٍ فِي مَعْصِيَةِ اللَّهِ وَلَا فِيمَا لَا يَمْلِكُ ابْنُ آدَمَقَالَ أَبُو دَاوُد وَالْمَرْأَةُ هَذِهِ امْرَأَةُ أَبِي ذَرٍّ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Muhammad bin Isa], mereka berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain], ia berkata; dahulu 'Adhba` (unta Rasulullah shallallahu 'alaihi wasallam) dahulu adalah milik seorang laki-laki dari Bani 'Uqail, unta tersebut termasuk unta yang mendahului orang yang berhaji. kemudian ia ditawan, kemudian Rasulullah shallallahu 'alaihi wasallam mendatanginya sementara orang tersebut terikat. Beliau berada di atas untanya mengenakan selimut. Lalu ia berkata; wahai Muhammad, kenapa engkau menangkapku dan mengambil unta yang mendahului orang yang berhaji (yaitu Al 'Adhba`)? Beliau berkata: \"Kami menangkapmu karena kesalahan sekutumu yaitu Tsaqif.\" Tsaqif telah menawan dua orang sahabat Nabi shallallahu 'alaihi wasallam. ia bekata; sungguh beliau telah mengucapakan apa yang beliau ucapkan sementara aku adalah seorang muslim. Atau ia mengatakan; telah masuk Islam. Kemudian tatkala Nabi shallallahu 'alaihi wasallam telah pergi…… Abu Daud berkata; aku mengetahui hal ini dari Muhammad bin Isa. Ia memanggil; wahai Muhammad! Wahai Muhammad! Dan Rasulullah shallallahu 'alaihi wasallam adalah orang yang penyayang dan lembut. Kemudian beliau kembali kepadanya dan berkata; ada apa denganmu? Ia berkata; aku adalah seorang muslim. Beliau berkata; \"Jika engkau mengatakan demikian sementara engkau memiliki urusanmu maka engkau sangat beruntung.\" Abu Daud berkata; kemudian aku kembali kepada hadits Sulaiman, ia berkata; wahai Muhammad, aku lapar maka berilah aku makan, dan aku haus, maka berilah aku minum. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini adalah hajatmu.\" Kemudian orang tersebut ditebus setelah itu dengan dua orang laki-laki. Ia berkata; dan Rasulullah shallallahu 'alaihi wasallam menahan Al 'Adhba` untuk kendaraan beliau. Kemudian orang-orang musyrik menyerang serambi Madinah dengan tiba-tiba dan membawa Al 'Adhba`. Ia berkata; kemudian tatkala mereka telah pergi membawanya dan menawan seorang wanita, ia berkata; apabila malam hari mereka mengistirahatkan unta mereka di halaman mereka. Ia berkata; kemudian suatu makam mereka tertidur, dan wanita tersebut berdiri dan tidaklah ia meletakkan kedua tangannya di atas unta melainkan unta tersebut bersuara hingga ia datang kepada Al 'Adhba`. Ia berkata; kemudian ia mendatangi unta yang menurut dan telah teruji, kemudian ia menungganginya dan bernadzar seandainya Allah menyelamatkannya niscaya ia akan menyembelihnya. Imran berkata; kemudian di saat ia telah sampai maka unta tersebut dikenali yaitu unta Rasulullah shallallahu 'alaihi wasallam. Kemudian Nabi shallallahu 'alaihi wasallam diberitahu mengenai hal tersebut. Lalu beliau mengirim utusan kepada wanita tersebut dan iapun dihadapkan, dan beliau diberitahu mengenai nadzarnya. Kemudian beliau berkata: \"Sungguh buruk balasan yang engkau berikan.\" Atau \"yang diberikan wanita tersebut apabila Allah menyelamatkannya niscaya ia akan menyembelihnya. Tidak boleh menunaikan nadzar dalam berbuat kemaksiatan kepada Allah, dan dalam perkara yang tidak dimiliki anak Adam.\" Abu Dzar berkata; dan wanita ini adalah isteri Abu Dzar. "},"2806":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَابْنُ السَّرْحِ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ قَالَ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ وَكَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ عَنْ كَعْبِ بْنِ مَالِكٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ مِنْ تَوْبَتِي أَنْ أَنْخَلِعَ مِنْ مَالِي صَدَقَةً إِلَى اللَّهِ وَإِلَى رَسُولِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ عَلَيْكَ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَ قَالَ فَقُلْتُ إِنِّي أُمْسِكُ سَهْمِيَ الَّذِي بِخَيْبَرَحَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ أَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تِيبَ عَلَيْهِ إِنِّي أَنْخَلِعُ مِنْ مَالِي فَذَكَرَ نَحْوَهُ إِلَى خَيْرٌ لَكَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud], dan [Ibnu As Sarh] mereka berdua berkata; telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] ia berkata; [Ibnu Syihab] berkata; telah mengabarkan kepadaku [Abdurrahman bin Abdullah bin Ka'b bin Malik] bahwa [Abdullah bin Ka'b] -dan ia adalah penuntun Ka'b ketika Ka'b mengalami buta mata. Dari [Ka'b] ia berkata; aku katakan; wahai Rasulullah, sesungguhnya diantara taubatku adalah melepaskan sebagian hartaku sebagai sedekah kepada Allah dan kepada rasulNya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tahanlah sebagian hartamu, hal itu lebih baik bagimu!\" Maka aku katakan; sesungguhnya saya telah menahan saham saya yang ada di Khaibar. Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abdullah bin Ka'b bin Malik], dari [ayahnya] bahwa ia berkata kepada Rasulullah shallallahu 'alaihi wasallam ketika diterima taubatnya; sesungguhnya saya melepaskan sebagian dari hartaku …… kemudian ia menyebutkan seperti hadits tersebut hingga kata; lebih baik bagimu. "},"2807":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّهُ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ أَبُو لُبَابَةَ أَوْ مَنْ شَاءَ اللَّهُ إِنَّ مِنْ تَوْبَتِي أَنْ أَهْجُرَ دَارَ قَوْمِي الَّتِي أَصَبْتُ فِيهَا الذَّنْبَ وَأَنْ أَنْخَلِعَ مِنْ مَالِي كُلِّهِ صَدَقَةً قَالَ يُجْزِئُ عَنْكَ الثُّلُثُحَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنِي مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ كَعْبِ بْنِ مَالِكٍ قَالَ كَانَ أَبُو لُبَابَةَ فَذَكَرَ مَعْنَاهُ وَالْقِصَّةُ لِأَبِي لُبَابَةَ قَالَ أَبُو دَاوُد رَوَاهُ يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ بَعْضِ بَنِي السَّائِبِ ابْنِ أَبِي لُبَابَةَ وَرَوَاهُ الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ حُسَيْنِ بْنِ السَّائِبِ بْنِ أَبِي لُبَابَةَ مِثْلَهُ","id":"Telah menceritakan kepadaku ['Ubaidullah bin Umar], telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Ibnu Ka'b bin Malik] dari [ayahnya] bahwa ia berkata kepada Nabi shallallahu 'alaihi wasallam, atau [Abu Lubabah] atau orang yang Allah kehendaki; sesungguhnya diantara bukti taubatku adalah aku tinggalkan negeri kaumku yang padanya aku melakukan dosa, dan melepas sebagian dari hartaku semua sebagai sedekah. Beliau bersabda: \"Cukup bagimu melepaskan sepertiga.\" Telah menceritakan kepada kami [Muhammad bin Al Mutawakkil] telah menceritakan kepada kami [Abdurrazzaq], ia berkata; telah mengabarkan kepadaku [Ma'mar] dari [Az Zuhri], ia berkata; telah mengabarkan kepadaku [Ibnu Ka'b bin Malik] ia berkata; [Abu Lubabah] ….. kemudian ia menyebutkan maknanya. Dan kisah mengenai Abu Lubabah dikatakan Abu Daud; telah diriwayatkan oleh [Yunus] dari [Ibnu Syihab], dari [sebagian Bani As Saib bin Abu Lubabah], dan telah diriwayatkan oleh [Az Zubaidi] dari [Az Zuhri] dari [Husain bin As Saib bin Abu Lubabah] seperti itu. "},"2808":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ قَالَ ابْنُ إِسْحَقَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ فِي قِصَّتِهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ مِنْ تَوْبَتِي إِلَى اللَّهِ أَنْ أَخْرُجَ مِنْ مَالِي كُلِّهِ إِلَى اللَّهِ وَإِلَى رَسُولِهِ صَدَقَةً قَالَ لَا قُلْتُ فَنِصْفُهُ قَالَ لَا قُلْتُ فَثُلُثُهُ قَالَ نَعَمْ قُلْتُ فَإِنِّي سَأُمْسِكُ سَهْمِي مِنْ خَيْبَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Hasan bin Ar Rabi'], telah menceritakan kepada kami [Ibnu Idris] ia berkata; [Ibnu Ishaq] beliau berkata: telah menceritakan kepadaku [Az Zuhri], dari [Abdurrahman bin Abdullah bin Ka'b] dari [ayahnya], dari [kakeknya] mengenai kisahnya, ia berkata; aku katakan; wahai Rasulullah, sesungguhnya diantara taubatku kepada Allah adalah keluar dari sebagian hartaku semua sebagai sedekah kepada Allah dan RasulNya. Beliau berkata: \"Tidak.\" Aku katakan; setengahnya. Beliau berkata: \"Tidak.\" Aku katakan; sepertiga. Beliau berkata: \"Ya.\" Aku katakan; aku akan menahan sahamku di Khaibar. "},"2809":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ التِّنِّيسِيُّ عَنْ ابْنِ أَبِي فُدَيْكٍ قَالَ حَدَّثَنِي طَلْحَةُ بْنُ يَحْيَى الْأَنْصَارِيُّ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَذَرَ نَذْرًا لَمْ يُسَمِّهِ فَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ وَمَنْ نَذَرَ نَذْرًا فِي مَعْصِيَةٍ فَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ وَمَنْ نَذَرَ نَذْرًا لَا يُطِيقُهُ فَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ وَمَنْ نَذَرَ نَذْرًا أَطَاقَهُ فَلْيَفِ بِهِقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ وَكِيعٌ وَغَيْرُهُ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي الْهِنْدِ أَوْقَفُوهُ عَلَى ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Ja'far bin Musafir At Tinnisi] dari [Ibnu Abu Fudaik], ia berkata; telah menceritakan kepadaku [Thalhah bin Yahya Al Anshari] dari [Abdullah bin Sa'id bin Abu Hindun], dari [Bukair bin Abdullah bin Al Asyajj] dari [Kuraib], dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bernadzar dengan tidak menyebutkannya, maka kafarahnya adalah kafarah sumpah. Dan barangsiapa yang bernadzar dalam kemaksiatan maka kafarahnya adalah kafarah bersumpah, dan barangsiapa yang bernadzar sesuatu yang tidak ia mampu maka kafarahnya adalah kafarah puasa. Dan barangsiapa yang bernadzar sesuatu yang ia mampu; maka hendaknya ia memenuhinya.\" Abu Daud berkata; hadits ini diriwayatkan Waki' dan yang lainnya dari Abdullah bin Sa'id bin Abu Al Hind, mereka telah menganggapnya muquf pada Ibnu Abbas. "},"2810":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبَّادٍ الْأَزْدِيُّ حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي ابْنَ عَيَّاشٍ عَنْ مُحَمَّدٍ مَوْلَى الْمُغِيرَةِ قَالَ حَدَّثَنِي كَعْبُ بْنُ عَلْقَمَةَ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَفَّارَةُ النَّذْرِ كَفَّارَةُ الْيَمِينِقَالَ أَبُو دَاوُد وَرَوَاهُ عَمْرُو بْنُ الْحَارِثِ عَنْ كَعْبِ بْنِ عَلْقَمَةَ عَنْ ابْنِ شِمَاسَةَ عَنْ عُقْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ أَنَّ سَعِيدَ بْنَ الْحَكَمِ حَدَّثَهُمْ أَخْبَرَنَا يَحْيَى يَعْنِي بْنَ أَيُّوبَ حَدَّثَنِي كَعْبُ بْنُ عَلْقَمَةَ أَنَّهُ سَمِعَ ابْنَ شِمَاسَةَ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Harun bin 'Abbad Al Azdi] telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Muhammad] mantan budak Al Mughirah, ia berkata; telah menceritakan kepadaku [Ka'bin bin 'Alqamah] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kafarah nadzar adalah kafarah sumpah.\" Abu Daud berkata; dan hadits tersebut telah diriwayatkan ['Amr bin Al Harits] dari [Ka'b bin 'Alqamah] dari [Ibnu Syimasah] dari ['Uqbah], telah menceritakan kepada kami [Muhammad bin 'Auf] bahwa [Sa'id bin Al Hakam] telah menceritakan kepada mereka; telah mengabarkan kepada kami [Yahya yaitu Ibnu Ayyub] telah menceritakan kepadaku [Ka'b bin 'Alqamah] bahwa ia mendengar [Ibnu Syimasah] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"2811":{"ar":"أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ فِي الْجَاهِلِيَّةِ أَنْ أَعْتَكِفَ فِي الْمَسْجِدِ الْحَرَامِ لَيْلَةً فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْفِ بِنَذْرِكَ","id":"[Ahmad bin Hanbal] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar], dari [Umar radliallahu 'anhu] bahwasanya dia berkata; wahai Rasulullah, sesungguhnya saya bernadzar pada masa jahiliyah untuk beri'tikaf di Masji Al Haram pada malam hari. Kemudian Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Penuhilah nadzarmu.\""},"2812":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُسَمَّى السَّمَاسِرَةَ فَمَرَّ بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّانَا بِاسْمٍ هُوَ أَحْسَنُ مِنْهُ فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّ الْبَيْعَ يَحْضُرُهُ اللَّغْوُ وَالْحَلْفُ فَشُوبُوهُ بِالصَّدَقَةِحَدَّثَنَا الْحُسَيْنُ بْنُ عِيسَى الْبِسْطَامِيُّ وَحَامِدُ بْنُ يَحْيَى وَعَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ جَامِعِ بْنِ أَبِي رَاشِدٍ وَعَبْدِ الْمَلِكِ بْنِ أَعْيَنَ وَعَاصِمٌ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ بِمَعْنَاهُ قَالَ يَحْضُرُهُ الْكَذِبُ وَالْحَلْفُ و قَالَ عَبْدُ اللَّهِ الزُّهْرِيُّ اللَّغْوُ وَالْكَذِبُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Wail] dari [Qais bin Abu Gharazah], ia berkata; kami pada zaman Rasulullah shallallahu 'alaihi wasallam diberi nama para calo, kemudian Rasulullah shallallahu 'alaihi wasallam lewat di hadapan kami, dan menamai kami dengan nama yang lebih baik darinya. Beliau mengatakan: \"Wahai para pedagang, sesungguhnya dalam transksi jual beli itu diwarnai tindakan sia-sia dan pengucapan sumpah, maka bersihkanlah jual beli tersebut dengan bersedekah!\" telah menceritakan kepada kami [Al Husain bin Isa Al Bisthami], dan [Hamid bin Yahya], serta [Abdullah bin Muhammad Az Zuhri], mereka mengatakan; telah menceritakan kepada kami [Sufyan], dari [Jami' bin Abu Rasyid], [Abdul Malik bin A'yan] dan ['Ashim] dari [Abu Wail] dari [Qais bin Abu Gharazah] dengan makna hadits tersebut, ia berkata; dihadiri ucapan dusta dan sumpah. Abdullah Az Zuhri mengatakan; perbuatan sia-sia dan ucapan dusta. "},"2813":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَمْرٍو يَعْنِي ابْنَ أَبِي عَمْرٍو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا لَزِمَ غَرِيمًا لَهُ بِعَشَرَةِ دَنَانِيرَ فَقَالَ وَاللَّهِ لَا أُفَارِقُكَ حَتَّى تَقْضِيَنِي أَوْ تَأْتِيَنِي بِحَمِيلٍ فَتَحَمَّلَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهُ بِقَدْرِ مَا وَعَدَهُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَيْنَ أَصَبْتَ هَذَا الذَّهَبَ قَالَ مِنْ مَعْدِنٍ قَالَ لَا حَاجَةَ لَنَا فِيهَا وَلَيْسَ فِيهَا خَيْرٌ فَقَضَاهَا عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari ['Amr bin Abu 'Amr] dari [Ikrimah] dari [Ibnu Abbas] bahwa seorang laki-laki tidak meninggalkan orang yang yang berhutang kepadanya sepuluh dinar, ia berkata; demi Allah, aku tidak akan meninggalkanmu hingga engkau membayar atau engkau datang kepadaku membawa orang yang akan bertanggung jawab. Kemudian Nabi shallallahu 'alaihi wasallam menanggungnya, kemudian ia datang dengan membawa uang sebesar yang telah ia janjikan. Kemudian Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Dari mana engkau mendapatkan emas ini?\" Ia berkata; dari barang tambang. Beliau bersabda: \"Kami tidak butuh kepadanya, tidak ada kebaikan padanya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam membayarkan hutang tersebut untuknya. "},"2814":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا أَبُو شِهَابٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ وَلَا أَسْمَعُ أَحَدًا بَعْدَهُ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْحَلَالَ بَيِّنٌ وَإِنَّ الْحَرَامَ بَيِّنٌ وَبَيْنَهُمَا أُمُورٌ مُشْتَبِهَاتٌ وَأَحْيَانًا يَقُولُ مُشْتَبِهَةٌ وَسَأَضْرِبُ لَكُمْ فِي ذَلِكَ مَثَلًا إِنَّ اللَّهَ حَمَى حِمًى وَإِنَّ حِمَى اللَّهِ مَا حَرَّمَ وَإِنَّهُ مَنْ يَرْعَى حَوْلَ الْحِمَى يُوشِكُ أَنْ يُخَالِطَهُ وَإِنَّهُ مَنْ يُخَالِطُ الرِّيبَةَ يُوشِكُ أَنْ يَجْسُرَحَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ الشَّعْبِيِّ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِهَذَا الْحَدِيثِ قَالَ وَبَيْنَهُمَا مُشَبَّهَاتٌ لَا يَعْلَمُهَا كَثِيرٌ مِنْ النَّاسِ فَمَنْ اتَّقَى الشُّبُهَاتِ اسْتَبْرَأَ عِرْضَهُ وَدِينَهُ وَمَنْ وَقَعَ فِي الشُّبُهَاتِ وَقَعَ فِي الْحَرَامِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], ia berkata; telah menceritakan kepada kami [Abu Syihab], telah menceritakan kepada kami [Ibnu 'Aun] dari [Asy Sya'bi], ia berkata; saya mendengar [An Nu'man bin Basyir], dan aku tidak mendengar seorangpun setelahnya. Ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perkara yang halal itu jelas, serta yang haram jelas dan diantara keduanya terdapat dan diantara keduanya terdapat perkara-perkara yang samar. Dan akan aku berikan contoh hal tersebut. Sesungguhnya Allah melindungi daerah terlarang, dan sesungguhnya daerah terlarang Allah adalah apa yang Dia haramkan. Dan sesungguhnya orang yang menggembala di sekitar daerah larangan hampir memasukinya, dan sesungguhnya orang memasuki perkara yang meragukan hampir terjerumus dalam perkara yang haram.\" Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada kami [Isa] telah menceritakan kepada kami [Zakariya] dari [Amir Asy Sya'bi] ia berkata; saya mendengar [An Nu'man bin Basyir], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda dengan hadits ini. Beliau berkata: \"Dan diantara keduanya terdapat perkara samar, yang tidak diketahui oleh kebanyakan orang. Barangsiapa yang menghindari perkara-perkara yang samar maka ia telah membersihkan kehormatan dan agamanya, dan barangsiapa yang terjerumus dlam perkara yang samar maka ia terjerumus dalam perkara yang haram.\""},"2815":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَبَّادُ بْنُ رَاشِدٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ أَبِي خَيْرَةَ يَقُولُ حَدَّثَنَا الْحَسَنُ مُنْذُ أَرْبَعِينَ سَنَةً عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا خَالِدٌ عَنْ دَاوُدَ يَعْنِي ابْنَ أَبِي هِنْدٍ وَهَذَا لَفْظُهُ عَنْ سَعِيدِ بْنِ أَبِي خَيْرَةَ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَأْتِيَنَّ عَلَى النَّاسِ زَمَانٌ لَا يَبْقَى أَحَدٌ إِلَّا أَكَلَ الرِّبَا فَإِنْ لَمْ يَأْكُلْهُ أَصَابَهُ مِنْ بُخَارِهِقَالَ ابْنُ عِيسَى أَصَابَهُ مِنْ غُبَارِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami ['Abbad bin Rasyid], ia berkata; saya mendengar [Sa'id bin Abu Khairah] ia berkata; telah menceritakan kepada kami [Al Hasan] sejak empat puluh tahun, dari [Abu Hurairah], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: …. Dan telah diriwayatkan dari jalur yang lain. Dan telah menceritakan kepada kami [Wahb bin Baqiyyah], telah mengabarkan kepada kami [Khalid], dari [Daud bin Abu Hindun], dan ini adalah lafazhnya. Dari [Sa'id bin Abu Khairah], dari [Al Hasan] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh akan datang kepada manusia suatu zaman dimana tidak ada seorangpun melainkan ia akan makan riba, jika tidak memakannya maka ia terkena sebagian dari uapnya.\" Ibnu Isa berkata; terkena sebagian dari debunya. "},"2816":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا ابْنُ إِدْرِيسَ أَخْبَرَنَا عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنَازَةٍ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْقَبْرِ يُوصِي الْحَافِرَ أَوْسِعْ مِنْ قِبَلِ رِجْلَيْهِ أَوْسِعْ مِنْ قِبَلِ رَأْسِهِ فَلَمَّا رَجَعَ اسْتَقْبَلَهُ دَاعِي امْرَأَةٍ فَجَاءَ وَجِيءَ بِالطَّعَامِ فَوَضَعَ يَدَهُ ثُمَّ وَضَعَ الْقَوْمُ فَأَكَلُوا فَنَظَرَ آبَاؤُنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلُوكُ لُقْمَةً فِي فَمِهِ ثُمَّ قَالَ أَجِدُ لَحْمَ شَاةٍ أُخِذَتْ بِغَيْرِ إِذْنِ أَهْلِهَا فَأَرْسَلَتْ الْمَرْأَةُ قَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أَرْسَلْتُ إِلَى الْبَقِيعِ يَشْتَرِي لِي شَاةً فَلَمْ أَجِدْ فَأَرْسَلْتُ إِلَى جَارٍ لِي قَدْ اشْتَرَى شَاةً أَنْ أَرْسِلْ إِلَيَّ بِهَا بِثَمَنِهَا فَلَمْ يُوجَدْ فَأَرْسَلْتُ إِلَى امْرَأَتِهِ فَأَرْسَلَتْ إِلَيَّ بِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْعِمِيهِ الْأُسَارَى","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah mengabarkan kepada kami [Ibnu Idris], telah mengabarkan kepada kami ['Ashim bin Kulaib], dari [ayahnya] dari [seorang laki-laki anshar], ia berkata; kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam mengantarkan jenazah, kemudian aku melihat Rasulullah shallallahu 'alaihi wasallam berada di atas kubur berwasiat kepada orang yang menggali: \"Perluaslah dari sisi kedua kakinya, perluaslah dari sisi kepalanya.\" Kemudian tatkala kembali, beliau disambut utusan seorang wanita yang mengundang Rasulullah shallallahu 'alaihi wasallam untuk makan, kemudian beliau datang dan makanan pun dihidangkan. Lalu beliau meletakkan tangannya pada makan kemudian orang-orang meletakkan tangan mereka pada makanan, lalu mereka makan. Kemudian orang-orang melihat Rasulullah shallallahu 'alaihi wasallam mengunyah makanan di mulutnya, kemudian beliau berkata: \"Saya dapatkan daging kambing yang diambil tanpa seizin pemiliknya.\" Kemudian wanita tersebut mengirim utusan, ia berkata; wahai Rasulullah, sesungguhnya saya telah mengirim utusan ke Baqi' untuk membelikan kambing, lalu aku tidak mendapatinya. Lalu aku mengirim utusan kepada tetanggaku yang telah membeli kambing agar ia mengirimnya kepadaku dan diganti dengan harganya, namun aku tidak mendapatkanya. Lalu aku mengirim utusan kepada isterinya, kemudian wanita tersebut mengirimkan kambing tersebut kepadaku. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: \"Berilah makan para tawanan!\""},"2817":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سِمَاكٌ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ أَبِيهِ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آكِلَ الرِّبَا وَمُؤْكِلَهُ وَشَاهِدَهُ وَكَاتِبَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Simak], telah menceritakan kepadaku [Abdurrahman bin Abdullah bin Mas'ud], dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam melaknat orang yang makan riba, orang yang memberi makan riba, saksinya dan penulisnya. "},"2818":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا شَبِيبُ بْنُ غَرْقَدَةَ عَنْ سُلَيْمَانَ بْنِ عَمْرٍو عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ يَقُولُ أَلَا إِنَّ كُلَّ رِبًا مِنْ رِبَا الْجَاهِلِيَّةِ مَوْضُوعٌ لَكُمْ رُءُوسُ أَمْوَالِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ أَلَا وَإِنَّ كُلَّ دَمٍ مِنْ دَمِ الْجَاهِلِيَّةِ مَوْضُوعٌ وَأَوَّلُ دَمٍ أَضَعُ مِنْهَا دَمُ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ كَانَ مُسْتَرْضِعًا فِي بَنِي لَيْثٍ فَقَتَلَتْهُ هُذَيْلٌ قَالَ اللَّهُمَّ هَلْ بَلَّغْتُ قَالُوا نَعَمْ ثَلَاثَ مَرَّاتٍ قَالَ اللَّهُمَّ اشْهَدْ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Al Ahwash], telah menceritakan kepada kami [Syabib bin Gharqadah], dari [Sulaiman bin 'Amr], dari [ayahnya] ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam ketika haji wada' berkata: \"Ketahuilah bahwa seluruh riba dari riba jahiliyah telah dibatalkan, bagi kalian modal kalian, dengan tidak menzhalimi dan tidak dizhalimi. Ketahuilah bahwa seluruh darah dari darah pada masa jahiliyah telah digugurkan, dan darah pertama yang aku gugurkan adalah darah Al Harits bin Abdul Muththalib, dahulu ia disusui seseorang dari Bani Laits, kemudian ia dibunuh orang-orang Hudzail.\" Beliau berkata: \"Ya Allah, saksikanlah. Apakah aku telah menyampaikan?\" mereka berkata; ya. Tiga kali. Beliau berkata; ya Allah, saksikanlah. Beliau mengucapkannya sebanyak tiga kali. "},"2819":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ قَالَ لِي ابْنُ الْمُسَيَّبِ إِنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحَلِفُ مَنْفَقَةٌ لِلسِّلْعَةِ مَمْحَقَةٌ لِلْبَرَكَةِقَالَ ابْنُ السَّرْحِ لِلْكَسْبِ و قَالَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh] telah menceritakan kepada kami [Ibnu Wahb], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami ['Anbasah] dari [Yunus] dari [Ibnu Syihab], ia berkata; [Ibnu Al Musayyab] berkata kepadaku; sesungguhnya [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sumpah itu melariskan barang dan menghilangkan berkah.\" Ibnu As Sarh berkata; menghilangkan usaha. Dan ia berkata dari Sa'id bin Al Musayyab dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam. "},"2820":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكِ بْنِ حَرْبٍ حَدَّثَنِي سُوَيْدُ بْنُ قَيْسٍ قَالَجَلَبْتُ أَنَا وَمَخْرَفَةُ الْعَبْدِيُّ بَزًّا مِنْ هَجَرَ فَأَتَيْنَا بِهِ مَكَّةَ فَجَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي فَسَاوَمَنَا بِسَرَاوِيلَ فَبِعْنَاهُ وَثَمَّ رَجُلٌ يَزِنُ بِالْأَجْرِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زِنْ وَأَرْجِحْحَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ الْمَعْنَى قَرِيبٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ أَبِي صَفْوَانَ بْنِ عُمَيْرَةَ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ قَبْلَ أَنْ يُهَاجِرَ بِهَذَا الْحَدِيثِ وَلَمْ يَذْكُرْ يَزِنُ بِأَجْرٍ قَالَ أَبُو دَاوُد رَوَاهُ قَيْسٌ كَمَا قَالَ سُفْيَانُ وَالْقَوْلُ قَوْلُ سُفْيَانَ حَدَّثَنَا ابْنُ أَبِي رِزْمَةَ سَمِعْتُ أَبِي يَقُولُ قَالَ رَجُلٌ لِشُعْبَةَ خَالَفَكَ سُفْيَانَ قَالَ دَمَغْتَنِي وَبَلَغَنِي عَنْ يَحْيَى بْنِ مَعِينٍ قَالَ كُلُّ مَنْ خَالَفَ سُفْيَانَ فَالْقَوْلُ قَوْلُ سُفْيَانَ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ قَالَ كَانَ سُفْيَانُ أَحْفَظَ مِنِّي","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Sufyan] dari [Simak bin Harb], telah menceritakan kepadaku [Suwaid bin Qais], ia berkata; aku dan Makhramah menyambut jenis pakaian dari sutera yang datang dari Hajar menuju Mekkah, kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi kami dengan berjalan kaki kemudian beliau menawar beberapa celana panjang dari kami kemudian kami menjualnya kepada beliau, dan disana terdapat tukang penimbang yang melakukan penimbangan dengan diberi diupah. Kemudian beliau berkata kepada tukang penimbang tersebut: \"Timbanglah dan penuhilah (sempurnakanlah) timbangan..\" telah menceritakan kepada kami [Hafshah bin Umar] dan [Muslim bin Ibrahim] secara makna hampir sama. Mereka berdua berkata; telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari [Abu Shafwan bin 'Umairah], ia berkata; aku datang kepada Rasulullah shallallahu 'alaihi wasallam di Mekkah sebelum beliau berhijrah, -ia menceritakan dengan hadits ini dan tidak menyebutkan; menimbang dengan diberi upah. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Qais], sebagaimana yang dikatakan Sufyan. Dan perkataan yang benar adalah perkataan Sufyan. Telah menceritakan kepada kami Ibnu Abu Rizmah; aku mendengar ayahku berkata; seorang laki-laki berkata kepada Syu'bah, Sufyan telah menyelisihimu. Engkau telah melukaiku, telah sampai kepadaku khabar dari Yahya bin Ma'in, ia berkata; seluruh orang yang menyelisihi Sufyan, maka perkataan yang benar adalah perkataan Sufyan. Telah menceritakan kepada kami Ahmad bin Hanbal, telah menceritakan kepada kami Waki' dari Syu'bah ia berkata; Sufyan lebih hafal dariku. "},"2821":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ دُكَيْنٍ حَدَّثَنَا سُفْيَانُ عَنْ حَنْظَلَةَ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَزْنُ وَزْنُ أَهْلِ مَكَّةَ وَالْمِكْيَالُ مِكْيَالُ أَهْلِ الْمَدِينَةِقَالَ أَبُو دَاوُد وَكَذَا رَوَاهُ الْفِرْيَابِيُّ وَأَبُو أَحْمَدَ عَنْ سُفْيَانَ وَافَقَهُمَا فِي الْمَتْنِ و قَالَ أَبُو أَحْمَدَ عَنْ ابْنِ عَبَّاسٍ مَكَانَ ابْنِ عُمَرَ وَرَوَاهُ الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ حَنْظَلَةَ قَالَ وَزْنُ الْمَدِينَةِ وَمِكْيَالُ مَكَّةَ قَالَ أَبُو دَاوُد وَاخْتُلِفَ فِي الْمَتْنِ فِي حَدِيثِ مَالِكِ بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Ibnu Dukain], telah menceritakan kepada kami [Sufyan], dari [Hanzhalah] dari [Thawus] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Timbangan yang menjadi standar ukuran adalah timbangan penduduk Mekkah, takaran yang menjadi standar ukuran adalah takaran penduduk Madinah.\" Abu Daud berkata; demikian ini yang diriwayatkan oleh [Al Firyabi], dan [Abu Ahmad], dari [Sufyan]. Dan keduanya sama dalam matan. [Abu Ahmad] berkata; dari [Ibnu Abbas]. Sebagai ganti Ibnu Umar. Hadits tersebut diriwayatkan oleh [Al Walid bin Muslim] dari [Hanzhalah]. Ia berkata; timbangan Madinah dan takaran Mekkah. Abu Daud berkata; dan telah diperselisihkan dalam matan pada hadits Malik bin Dinar, dari 'Atha`, dari Nabi shallallahu 'alaihi wasallam dalam hal ini."},"2822":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ الشَّعْبِيِّ عَنْ سَمْعَانَ عَنْ سَمُرَةَ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَاهُنَا أَحَدٌ مِنْ بَنِي فُلَانٍ فَلَمْ يُجِبْهُ أَحَدٌ ثُمَّ قَالَ هَاهُنَا أَحَدٌ مِنْ بَنِي فُلَانٍ فَلَمْ يُجِبْهُ أَحَدٌ ثُمَّ قَالَ هَاهُنَا أَحَدٌ مِنْ بَنِي فُلَانٍ فَقَامَ رَجُلٌ فَقَالَ أَنَا يَا رَسُولَ اللَّهِ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَنَعَكَ أَنْ تُجِيبَنِي فِي الْمَرَّتَيْنِ الْأُولَيَيْنِ أَمَا إِنِّي لَمْ أُنَوِّهْ بِكُمْ إِلَّا خَيْرًا إِنَّ صَاحِبَكُمْ مَأْسُورٌ بِدَيْنِهِ فَلَقَدْ رَأَيْتُهُ أَدَّى عَنْهُ حَتَّى مَا بَقِيَ أَحَدٌ يَطْلُبُهُ بِشَيْءٍقَالَ أَبُو دَاوُد سَمْعَانُ بْنُ مُشَنِّجٍ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abu Al Ahwash] dari [Sa'id bin Masruq], dari [Asy Sya'bi], dari [Sam'an] dari [Samurah], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami, kemudian beliau berkata: \"Apakah di sini terdapat seseorang dari Bani Fulan?\" kemudian terdapat seorang laki-laki yang berdiri dan berkata; saya wahai Rasulullah. Kemudian beliau shallallahu 'alaihi wasallam berkata: \"Apa yang menghalangimu untuk menjawabku, pada dua pertanyaan pertama? Adapun aku, maka tidaklah aku menyebutkan kepada kalian kecuali kebaikan. Sesungguhnya sahabat kalian tertahan dengan hutangnya.\" Sungguh aku melihatnya telah membayar hutang tersebut untuknya hingga tidak tersisa seorangpun yang menuntut sesuatu kepadanya. Abu Daud berkata; Sam'an bin Musyannij. "},"2823":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ أَنَّهُ سَمِعَ أَبَا عَبْدِ اللَّهِ الْقُرَشِيَّ يَقُولُ سَمِعْتُ أَبَا بُرْدَةَ بْنَ أَبِي مُوسَى الْأَشْعَرِيَّ يَقُولُ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ أَعْظَمَ الذُّنُوبِ عِنْدَ اللَّهِ أَنْ يَلْقَاهُ بِهَا عَبْدٌ بَعْدَ الْكَبَائِرِ الَّتِي نَهَى اللَّهُ عَنْهَا أَنْ يَمُوتَ رَجُلٌ وَعَلَيْهِ دَيْنٌ لَا يَدَعُ لَهُ قَضَاءً","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], telah menceritakan kepadaku [Sa'i bin Abu Ayyub], bahwa ia telah mendengar [Abu Abdullah Al Qurasyi] berkata; aku mendengar [Abu Burdah bin Abu Musa Al Asy'ari] berkata dari [ayahnya], dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Sesungguhnya dosa terbesar di sisi Allah yang akan dibawa seorang hamba bertemu denganNya setelah dosa-dosa besar yang telah Allah larang adalah seseorang meninggal dalam keadaan menanggung hutang yang tidak mampu ia lunasi.\""},"2824":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّي عَلَى رَجُلٍ مَاتَ وَعَلَيْهِ دَيْنٌ فَأُتِيَ بِمَيِّتٍ فَقَالَ أَعَلَيْهِ دَيْنٌ قَالُوا نَعَمْ دِينَارَانِ قَالَ صَلُّوا عَلَى صَاحِبِكُمْ فَقَالَ أَبُو قَتَادَةَ الْأَنْصَارِيُّ هُمَا عَلَيَّ يَا رَسُولَ اللَّهِ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا فَتَحَ اللَّهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا أَوْلَى بِكُلِّ مُؤْمِنٍ مِنْ نَفْسِهِ فَمَنْ تَرَكَ دَيْنًا فَعَلَيَّ قَضَاؤُهُ وَمَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَقُتَيْبَةُ بْنُ سَعِيدٍ عَنْ شَرِيكٍ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ رَفَعَهُ قَالَ عُثْمَانُ و حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ اشْتَرَى مِنْ عِيرٍ تَبِيعًا وَلَيْسَ عِنْدَهُ ثَمَنُهُ فَأُرْبِحَ فِيهِ فَبَاعَهُ فَتَصَدَّقَ بِالرِّبْحِ عَلَى أَرَامِلِ بَنِي عَبْدِ الْمُطَّلِبِ وَقَالَ لَا أَشْتَرِي بَعْدَهَا شَيْئًا إِلَّا وَعِنْدِي ثَمَنُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutawakkil Al 'Asqalani], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam tidak menshalatkan seseorang yang meninggal dalam keadaan menanggung hutang. Kemudian beliau dihadapkan kepada seorang yang telah meninggal, lalu beliau bertanya: \"Apakah ia memiliki tanggungan hutang?\" Mereka berkata; Iya, dua dinar. Beliau berkata: \"Shalatkan sahabat kalian!\" kemudian Abu Qatadah Al Anshari berkata; keduanya menjadi tanggunganku wahai Rasulullah! Jabir berkata; kemudian Rasulullah shallallahu 'alaihi wasallam menshalatkannya. Kemudian tatkala Allah memberikan kemenangan kepada Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Aku adalah lebih utama (lebih berhak) terhadap orang mukmin daripada dirinya sendiri. Barangsiapa yang meninggalkan hutang maka menjadi tanggunganku, dan barangsiapa yang meninggalkan harta maka untuk pewarisnya.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], dan [Qutaibah bin Sa'id], dari [Syarik] dari [Simak], dari [Ikrimah] dan ia memarfu'kannya. [Utsman] berkata; dan telah menceritakan kepada kami [Waki'] dari [Syarik], dari [Simak], dari [Ikrimah], dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti itu. Ia berkata; ia membeli sapi yang berumur satu tahun dari sebuah kafilah, sementara ia tidak memiliki uang untuk membayarnya. Kemudian ia mendapat keuntungan dan ia pun menjualnya. Lalu ia mensedekahkan keuntungan tersebut kepada para janda Bani Abdul Muththalib. Ia berkata; setelah itu tidaklah aku membeli sesuatu, melainkan aku memiliki uang untuk harganya. "},"2825":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَطْلُ الْغَنِيِّ ظُلْمٌ وَإِذَا أُتْبِعَ أَحَدُكُمْ عَلَى مَلِيءٍ فَلْيَتْبَعْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik], dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penangguhan orang yang kaya (dalam melunasi hutang) adalah kezhaliman, dan apabila salah seorang di antara kalian diikutkan (hutangnya dipindahkan, hiwalah) kepada orang yang kaya, hendaknya ia mengikuti!\""},"2826":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي رَافِعٍ قَالَاسْتَسْلَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَكْرًا فَجَاءَتْهُ إِبِلٌ مِنْ الصَّدَقَةِ فَأَمَرَنِي أَنْ أَقْضِيَ الرَّجُلَ بَكْرَهُ فَقُلْتُ لَمْ أَجِدْ فِي الْإِبِلِ إِلَّا جَمَلًا خِيَارًا رَبَاعِيًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِهِ إِيَّاهُ فَإِنَّ خِيَارَ النَّاسِ أَحْسَنُهُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Rafi'], ia berkata; Rasulullah shallallahu 'alaihi wasallam menghutang seekor unta muda, kemudian terdapat unta zakat yang datang kepada beliau. Lalu beliau memerintahkanku agar mengembalikan unta muda tersebut kepada yang punya. Lalu aku katakan; saya tidak mendapatkan di antara unta tersebut selain unta pilihan yang berumur empat tahun. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Berikan kepadanya, sesungguhnya sebaik-baik orang adalah yang terbaik dalam menunaikan hutang.\""},"2827":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ مِسْعَرٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَكَانَ لِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَيْنٌ فَقَضَانِي وَزَادَنِي","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Yahya] dari [Mas'ar] dari [Muharib bin Ditsar], ia berkata; saya mendengar [Jabir bin Abdullah] berkata; dahulu aku memiliki piutang pada Rasulullah shallallahu 'alaihi wasallam, kemudian beliau membayar piutangku dan memberikan lebih (dari jumlah yang dipinjam). "},"2828":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسٍ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذَّهَبُ بِالْوَرِقِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالْبُرُّ بِالْبُرِّ رِبًا إِلَّا هَاءَ وَهَاءَ وَالتَّمْرُ بِالتَّمْرِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالشَّعِيرُ بِالشَّعِيرِ رِبًا إِلَّا هَاءَ وَهَاءَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik], dari [Ibnu Syihab], dari [Malik bin Aus] dari [Umar] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas ditukar dengan perak adalah riba, kecuali diserahkan secara tunai, gandum ditukar dengan gandum adalah riba kecuali diserahkan secara tunai, kurma ditukar dengan kurma adalah riba kecuali diserahkan secara tubai, jewawut ditukar dengan jewawut adalah riba kecuali diserahkan secara tunai.\""},"2829":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي الْخَلِيلِ عَنْ مُسْلِمٍ الْمَكِّيِّ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الذَّهَبُ بِالذَّهَبِ تِبْرُهَا وَعَيْنُهَا وَالْفِضَّةُ بِالْفِضَّةِ تِبْرُهَا وَعَيْنُهَا وَالْبُرُّ بِالْبُرِّ مُدْيٌ بِمُدْيٍ وَالشَّعِيرُ بِالشَّعِيرِ مُدْيٌ بِمُدْيٍ وَالتَّمْرُ بِالتَّمْرِ مُدْيٌ بِمُدْيٍ وَالْمِلْحُ بِالْمِلْحِ مُدْيٌ بِمُدْيٍ فَمَنْ زَادَ أَوْ ازْدَادَ فَقَدْ أَرْبَى وَلَا بَأْسَ بِبَيْعِ الذَّهَبِ بِالْفِضَّةِ وَالْفِضَّةُ أَكْثَرُهُمَا يَدًا بِيَدٍ وَأَمَّا نَسِيئَةً فَلَا وَلَا بَأْسَ بِبَيْعِ الْبُرِّ بِالشَّعِيرِ وَالشَّعِيرُ أَكْثَرُهُمَا يَدًا بِيَدٍ وَأَمَّا نَسِيئَةً فَلَاقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ سَعِيدُ بْنُ أَبِي عَرُوبَةَ وَهِشَامٌ الدَّسْتُوَائِيُّ عَنْ قَتَادَةَ عَنْ مُسْلِمِ بْنِ يَسَارٍ بِإِسْنَادِهِ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْخَبَرِ يَزِيدُ وَيَنْقُصُ وَزَادَ قَالَ فَإِذَا اخْتَلَفَتْ هَذِهِ الْأَصْنَافُ فَبِيعُوا كَيْفَ شِئْتُمْ إِذَا كَانَ يَدًا بِيَدٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Bisyr bin Umar], telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abu Al Khalil] dari [Muslim Al Makki] dari [Abu Al Asy'ats Ash Shan'ani] dari ['Ubadah bin Ash Shamit], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas dengan emas baik yang masih murni maupun mata uangnya, perak dengan perak baik yang masih murni maupun mata uangnya, gandum dengan gandum satu mudyu (takaran penduduk Syam sama dengan dua setengah sha') dengan satu mudyu, jewawut dengan jewawut satu mudyu dengan satu mudyu, kurma dengan kurma satu mudyu dengan satu mudyu, garam dengan garam satu mudyu dengan satu mudyu, barangsiapa yang menambah atau minta tambah maka sungguh ia telah melakukan riba. Tidak mengapa menjual emas dengan perak dan perak lebih banyak apabila secara langsung, adapun dengan cara menunda maka tidak boleh, dan tidak mengapa menjual gandum dengan jewawut dan jewawut lebih banyak apabila secara langsung, adapun dengan menunda maka tidak boleh.\" Abu Daud berkata; hadits ini diriwayatkan oleh [Sa'id bin Abu 'Arubah] dan [Hisyam Ad Dastuwai] dari [Qatadah] dari [Muslim bin Yasar] dengan sanadnya. Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah?] telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sufyan] dari [Khalid] dari [Abu Qilabah], dari [Abu Al Asy'ats Ash Shan'ani], dari ['Ubadah bin Ash Shamit], dari Nabi shallallahu 'alaihi wasallam bersabda: dengan hadits ini, dan dengan menambah serta mengurangi. Ia tambahkan; beliau bersabda: \"Apabila jenisnya berbeda, maka juallah dengan cara yang kalian kehendaki, apabila dilakukan secara langsung.\""},"2830":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَحْمَدُ بْنُ مَنِيعٍ قَالُوا حَدَّثَنَا ابْنُ الْمُبَارَكِ ح و حَدَّثَنَا ابْنُ الْعَلَاءِ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ سَعِيدِ بْنِ يَزِيدَ قَالَ حَدَّثَنِي خَالِدُ بْنُ أَبِي عِمْرَانَ عَنْ حَنَشٍ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ بِقِلَادَةٍ فِيهَا ذَهَبٌ وَخَرَزٌ قَالَ أَبُو بَكْرٍ وَابْنُ مَنِيعٍ فِيهَا خَرَزٌ مُعَلَّقَةٌ بِذَهَبٍ ابْتَاعَهَا رَجُلٌ بِتِسْعَةِ دَنَانِيرَ أَوْ بِسَبْعَةِ دَنَانِيرَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَتَّى تُمَيِّزَ بَيْنَهُ وَبَيْنَهُ فَقَالَ إِنَّمَا أَرَدْتُ الْحِجَارَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَتَّى تُمَيِّزَ بَيْنَهُمَا قَالَ فَرَدَّهُ حَتَّى مُيِّزَ بَيْنَهُمَاو قَالَ ابْنُ عِيسَى أَرَدْتُ التِّجَارَةَ قَالَ أَبُو دَاوُد وَكَانَ فِي كِتَابِهِ الْحِجَارَةُ فَغَيَّرَهُ فَقَالَ التِّجَارَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], dan [Abu Bakr bin Abu Syaibah?] serta [Ahmad bin Mani'], mereka berkata; telah menceritakan kepada kami [Ibnu Al Mubarak] dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibnu Al 'Ala`], telah mengabarkan kepada kami [Ibnu Al Mubarak], dari [Sa'id bin Yazid?], ia berkata; telah menceritakan kepadaku [Khalid bin Abu Imran] dari [Hanasy] dari [Fadhalah bin 'Ubaid], ia berkata; Nabi shallallahu 'alaihi wasallam pada saat perang Khaibar diberi sebuah kalung yang padanya terdapat emas dan manik-manik. Abu Bakr dan Ibnu Mani' berkata; padanya terdapat manik-manik yang tergantung dengan emas. Yang dibeli oleh seseorang dengan harga sembilan dinar atau tujuh dinar. Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh, hingga engkau memisahkan antara emas dan manik-manik tersebut.\" Kemudian ia mengembalikannya hingga terpisahkan antara keduanya. Ibnu Isa berkata; aku ingin at tijarah (berdagang). Abu Daud berkata; dalam tulisannya adalah al hijarah (bebatuan). Kemudian ia mengubahnya, lalu ia berkata; at tijarah (perdagangan). "},"2831":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي شُجَاعٍ سَعِيدِ بْنِ يَزِيدَ عَنْ خَالِدِ بْنِ أَبِي عِمْرَانَ عَنْ حَنَشٍ الصَّنْعَانِيِّ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ قَالَاشْتَرَيْتُ يَوْمَ خَيْبَرَ قِلَادَةً بِاثْنَيْ عَشَرَ دِينَارًا فِيهَا ذَهَبٌ وَخَرَزٌ فَفَصَّلْتُهَا فَوَجَدْتُ فِيهَا أَكْثَرَ مِنْ اثْنَيْ عَشَرَ دِينَارًا فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تُبَاعُ حَتَّى تُفَصَّلَ","id":"Telah menceritakan kepada kami [Quaibah bin Sa'id], telah menceritakan kepada kami [Al Laits] dari [Abu Syuja' Sa'id bin Yazid?] dari [Khalid bin Abu Imran], dari [Hanasy Ash Shan'ani], dari [Fadhalah bin 'Ubaid], ia berkata; pada saat perang Khaibar, aku membeli kalung dengan harga dua belas dinar, padanya terdapat emas dan manik-manik. Kemudian aku memisahkannya dan aku dapatkan padanya lebih dari dua belas dinar. Kemudian aku sebutkan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, lalu beliau berkata: \"Tidak boleh dijual hingga dipisahkan (antara emas dan manik-manik tersebut).\""},"2832":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي جَعْفَرٍ عَنْ الْجُلَاحِ أَبِي كَثِيرٍ حَدَّثَنِي حَنَشٌ الصَّنْعَانِيُّ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ نُبَايِعُ الْيَهُودَ الْأُوقِيَّةَ مِنْ الذَّهَبِ بِالدِّينَارِ قَالَ غَيْرُ قُتَيْبَةَ بِالدِّينَارَيْنِ وَالثَّلَاثَةِ ثُمَّ اتَّفَقَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبِيعُوا الذَّهَبَ بِالذَّهَبِ إِلَّا وَزْنًا بِوَزْنٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Al Laits] dari [Ibnu Abu Ja'far], dari [Al Julah Abu Katsir], telah menceritakan kepadaku [Hanasy Ash Shan'ani], dari [Fadhlah bin 'Ubaid], ia berkata; kami pernah bersama Rasulullah shallallahu 'alaihi wasallam pada saat perang khaibar, kami menjual emas kepada orang-orang yahudi dengan dinar. Selain Qutaibah berkata; dengan dua dan tiga dinar. Kemudian lafazh mereka sama; kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjual emas dengan emas kecuali dengan timbangan yang sama.\""},"2833":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَمُحَمَّدُ بْنُ مَحْبُوبٍ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَكُنْتُ أَبِيعُ الْإِبِلَ بِالْبَقِيعِ فَأَبِيعُ بِالدَّنَانِيرِ وَآخُذُ الدَّرَاهِمَ وَأَبِيعُ بِالدَّرَاهِمِ وَآخُذُ الدَّنَانِيرَ آخُذُ هَذِهِ مِنْ هَذِهِ وَأُعْطِي هَذِهِ مِنْ هَذِهِ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِ حَفْصَةَ فَقُلْتُ يَا رَسُولَ اللَّهِ رُوَيْدَكَ أَسْأَلُكَ إِنِّي أَبِيعُ الْإِبِلَ بِالْبَقِيعِ فَأَبِيعُ بِالدَّنَانِيرِ وَآخُذُ الدَّرَاهِمَ وَأَبِيعُ بِالدَّرَاهِمِ وَآخُذُ الدَّنَانِيرَ آخُذُ هَذِهِ مِنْ هَذِهِ وَأُعْطِي هَذِهِ مِنْ هَذِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا بَأْسَ أَنْ تَأْخُذَهَا بِسِعْرِ يَوْمِهَا مَا لَمْ تَفْتَرِقَا وَبَيْنَكُمَا شَيْءٌحَدَّثَنَا حُسَيْنُ بْنُ الْأَسْوَدِ حَدَّثَنَا عُبَيْدُ اللَّهِ أَخْبَرَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ بِإِسْنَادِهِ وَمَعْنَاهُ وَالْأَوَّلُ أَتَمُّ لَمْ يَذْكُرْ بِسِعْرِ يَوْمِهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], serta [Muhammad bin Mahbub] dan maknanya satu, mereka berkata; telah menceritakan kepada kami [Hammad] dari [Simak bin Harb], dari [Sa'id bin Jubair], dari [Ibnu Umar] ia berkata; dahulu aku menjual unta di Baqi', aku menjual dengan dinar dan mengambil dirham, dan menjual dengan dirham dan mengambil dinar, aku mengambil ini sebagai ganti dari ini, dan memberikan ini sebagai ganti dari ini. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam sementara beliau berada di rumah Hafshah. Lalu aku katakan; wahai Rasulullah, sebentar! Saya ingin bertanya. Saya menjual unta di Baqi' dengan dinar, dan mengambil dirham, menjual dengan dirham dan mengambil dinar. Saya mengambil ini sebagai ganti dari ini, dan memberi ini sebagai ganti dari ini. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak mengapa engkau mengambilnya dengan nilai harga pada hari itu selama kalian belum berpisah, sementara di antara kalian terdapat sesuatu (yang belum diserahkan).\" Telah menceritakan kepada kami [Husain bin Al Aswad], telah menceritakan kepada kami ['Ubaidullah] telah mengabarkan kepada kami [Israil] dari [Simak] dengan sanad dan maknanya, -dan hadits yang pertama lebih sempurna-, ia tidak menyebutkan kata: \"nilai harga pada hari.\""},"2834":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْحَيَوَانِ بِالْحَيَوَانِ نَسِيئَةً","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Qatadah] dari [Al Hasan], dari [Samurah] bahwa Nabi shallallahu 'alaihi wasallam telah melarang menjual hewan dengan hewan dengan cara penangguhan. "},"2835":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُسْلِمِ بْنِ جُبَيْرٍ عَنْ أَبِي سُفْيَانَ عَنْ عَمْرِو بْنِ حَرِيشٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يُجَهِّزَ جَيْشًا فَنَفِدَتْ الْإِبِلُ فَأَمَرَهُ أَنْ يَأْخُذَ فِي قِلَاصِ الصَّدَقَةِ فَكَانَ يَأْخُذُ الْبَعِيرَ بِالْبَعِيرَيْنِ إِلَى إِبِلِ الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Hammad bin Salamah], dari [Muhammad bin Ishaq], dari [Yazid? bin Abu Habib], dari [Muslim bin Jubair], dari [Abu Sufyan], dari ['Amr bin Harisy] dari [Abdullah bin 'Amr], bahwa Rasulullah shallallahu 'alaihi wasallam telah memerintahkannya agar mempersiapkan tentara, hingga habis unta beliau, lalu beliau memerintahkan agar mengambil dari unta zakat. Beliau mengambil satu ekor dengan mengembalikan dua ekor unta hingga waktu diperoleh unta untuk zakat. "},"2836":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدٍ الْهَمْدَانِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ الثَّقَفِيُّ أَنَّ اللَّيْثَ حَدَّثَهُمْ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى عَبْدًا بِعَبْدَيْنِ","id":"Telah menceritakan kepada kami [Yazid? bin Khalid Al Hamdani], dan [Qutaibah bin Sa'id Ats Tsaqafi], bahwa [Al Laits] telah menceritakan kepada mereka dari [Abu Az Zubair] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam membeli seorang budak dibayar dengan dua orang budak. "},"2837":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ أَنَّ زَيْدًا أَبَا عَيَّاشٍ أَخْبَرَهُأَنَّهُ سَأَلَ سَعْدَ بْنَ أَبِي وَقَّاصٍ عَنْ الْبَيْضَاءِ بِالسُّلْتِ فَقَالَ لَهُ سَعْدٌ أَيُّهُمَا أَفْضَلُ قَالَ الْبَيْضَاءُ فَنَهَاهُ عَنْ ذَلِكَ وَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْأَلُ عَنْ شِرَاءِ التَّمْرِ بِالرُّطَبِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَنْقُصُ الرُّطَبُ إِذَا يَبِسَ قَالُوا نَعَمْ فَنَهَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَقَالَ أَبُو دَاوُد رَوَاهُ إِسْمَعِيلُ بْنُ أُمَيَّةَ نَحْوَ مَالِكٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah], dari [Malik], dari [Abdullah bin Yazid?], bahwa [Zaid Abu 'Ayyasy] telah mengabarkan kepadanya bahwa ia bertanya kepada [Sa'd bin Abu Waqqash] mengenai menjual jewawut dengan sult (semacam jewawut yang tidak berbulu). Kemudian Sa'd berkata kepadanya; manakah yang lebih baik? Ia berkata; jewawut. Kemudian Sa'd melarang dari hal tersebut, dan ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam ditanya mengenai pembelian kurma dengan ruthab (kurma yang belum matang). Kemudian beliau berkata: \"Apakah ruthab akan berkurang apabila kering?\" Mereka berkata; Iya. Kemudian Rasulullah shallallahu 'alaihi wasallam melarangnya dari hal tersebut. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Isma'il bin Umayyah] seperti hadits Malik. "},"2838":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَنَّ أَبَا عَيَّاشٍ أَخْبَرَهُ أَنَّهُ سَمِعَ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الرُّطَبِ بِالتَّمْرِ نَسِيئَةًقَالَ أَبُو دَاوُد رَوَاهُ عِمْرَانُ بْنُ أَبِي أَنَسٍ عَنْ مَوْلًى لِبَنِي مَخْزُومٍ عَنْ سَعْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Nafi' Abu Taubah], telah menceritakan kepada kami [Mu'awiyah bin Sallam], dari [Yahya bin Abu Katsir], telah mengabarkan kepada kami [Abdullah] bahwa [Abu 'Ayyasy] telah mengabarkan kepadanya bahwa ia mendengar [Sa'd bin Abu Waqqash] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual ruthab dengan kurma secara dengan penundaan. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Imran bin Abu Anas] dari [mantan budak Bani Makhzum], dari [Sa'd] dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"2839":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ بِالتَّمْرِ كَيْلًا وَعَنْ بَيْعِ الْعِنَبِ بِالزَّبِيبِ كَيْلًا وَعَنْ بَيْعِ الزَّرْعِ بِالْحِنْطَةِ كَيْلًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], telah menceritakan kepada kami [Ibnu Abu Zaidah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menjual buah dengan kurma secara takaran, dan dari penjualan anggur dengan kismis secara takaran, dan dari penjualan tanaman dengan gandum secara takaran. "},"2840":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي بَيْعِ الْعَرَايَا بِالتَّمْرِ وَالرُّطَبِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Kharijah bin Tsabit] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam telah memberikan keringanan untuk menjual 'araya (ruthab atau anggur di atas pohon) dengan kurma dan ruthab. "},"2841":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ التَّمْرِ بِالتَّمْرِ وَرَخَّصَ فِي الْعَرَايَا أَنْ تُبَاعَ بِخَرْصِهَا يَأْكُلُهَا أَهْلُهَا رُطَبًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual kurma dengan kurma, dan memberikan keringanan dalam 'araya (ruthab atau anggur di atas pohon) yang dijual dengan menaksirnya, yang dimakan pemiliknya dalam keadaan berupa ruthab. "},"2842":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ مَوْلَى ابْنِ أَبِي أَحْمَدَ قَالَ أَبُو دَاوُد وَقَالَ لَنَا الْقَعْنَبِيُّ فِيمَا قَرَأَ عَلَى مَالِكٍ عَنْ أَبِي سُفْيَانَ وَاسْمُهُ قُزْمَانُ مَوْلَى ابْنِ أَبِي أَحْمَدَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي بَيْعِ الْعَرَايَا فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ أَوْ فِي خَمْسَةِ أَوْسُقٍ شَكَّ دَاوُدُ بْنُ الْحُصَيْنِقَالَ أَبُو دَاوُد حَدِيثُ جَابِرٍ إِلَى أَرْبَعَةِ أَوْسُقٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Daud bin Al Hushain] dari [mantan budak Ibnu Abu Ahmad]. Abu Daud berkata; Al Qo'naby berkata kepada kami dari riwayat yang dia baca kepada Malik dari Abu Sufyan dan namanya adalah Quzman budak Ibnu Abi Ahmad dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam telah memberikan keringanan untuk menjual 'araya kurang dari lima wasaq atau seukuran lima wasaq. Daud bin Al Hushain merasa ragu. Abu Daud berkata; hadits Jabir mengatakan; hingga empat wasaq. "},"2843":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ الْأَنْصَارِيِّ أَنَّهُ قَالَالْعَرِيَّةُ الرَّجُلُ يُعْرِي النَّخْلَةَ أَوْ الرَّجُلُ يَسْتَثْنِي مِنْ مَالِهِ النَّخْلَةَ أَوْ الِاثْنَتَيْنِ يَأْكُلُهَا فَيَبِيعُهَا بِتَمْرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Hamdani] telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Amr bin Al Harits] dari [Abdu Rabbihi bin Sa'id Al Anshari] bahwa ia berkata; 'ariyah adalah seseorang menyewakan pohon kurma atau seseorang mengecualikan satu atau dua pohon kurma dari hartanya yang ia makan dan menjualnya dengan kurma. "},"2844":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ عَبْدَةَ عَنْ ابْنِ إِسْحَقَ قَالَالْعَرَايَا أَنْ يَهَبَ الرَّجُلُ لِلرَّجُلِ النَّخَلَاتِ فَيَشُقُّ عَلَيْهِ أَنْ يَقُومَ عَلَيْهَا فَيَبِيعُهَا بِمِثْلِ خَرْصِهَا","id":"Telah menceritakan kepada kami [Hannad bin As Sari] dari [Abdah] dari [Ibnu Ishaq] ia berkata; 'araya adalah seseorang memberikan beberapa pohon kurma kepada seseorang, kemudian orang-orang tersebut merasa terganggu dengan apa yang dilakukan orang yang diberi tersebut terhadap beberapa pohon kurma tersebut, kemudian ia membelinya dengan seukuran penaksiran buah yang ada di pohon tersebut. "},"2845":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثِّمَارِ حَتَّى يَبْدُوَ صَلَاحُهَا نَهَى الْبَائِعَ وَالْمُشْتَرِيَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang menjual buah hingga nampak kelayakannya, beliau melarang penjual dan pembeli. "},"2846":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ النَّخْلِ حَتَّى يَزْهُوَ وَعَنْ السُّنْبُلِ حَتَّى يَبْيَضَّ وَيَأْمَنَ الْعَاهَةَ نَهَى الْبَائِعَ وَالْمُشْتَرِيَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual pohon kurma hingga matang (buahnya), dan dari menjual bulir hingga berwarna putih dan aman dari musibah, beliau melarang penjual dan pembeli. "},"2847":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خُمَيْرٍ عَنْ مَوْلًى لِقُرَيْشٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْغَنَائِمِ حَتَّى تُقَسَّمَ وَعَنْ بَيْعِ النَّخْلِ حَتَّى تُحْرَزَ مِنْ كُلِّ عَارِضٍ وَأَنْ يُصَلِّيَ الرَّجُلُ بِغَيْرِ حِزَامٍ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari] telah menceritakan kepada kami [Syu'bah] dari [Yazid? bin Khumair] dari [mantan budak Quraisy] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari menjual rampasan perang hingga dibagi, dan dari menjual pohon kurma hingga terjaga dari musibah yang datang dan seseorang melakukan shalat tanpa mengikat pakaian. "},"2848":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَلِيمِ بْنِ حَيَّانَ أَخْبَرَنَا سَعِيدُ بْنُ مِينَاءَ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُبَاعَ الثَّمَرَةُ حَتَّى تُشْقِحَ قِيلَ وَمَا تُشْقِحُ قَالَ تَحْمَارُّ وَتَصْفَارُّ وَيُؤْكَلُ مِنْهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] telah menceritakan kepada kami [Yahya bin Sa'id], dari [Salim bin Hayyan] telah mengabarkan kepada kami [Sa'id bin Mina`], ia berkata; aku mendengar [Jabir bin Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang menjual buah hingga hingga tusyqif. Ia ditanya apa makna tusyqif? Ia berkata; memerah dan menguning dan dapat dimakan. "},"2849":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو الْوَلِيدِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْعِنَبِ حَتَّى يَسْوَدَّ وَعَنْ بَيْعِ الْحَبِّ حَتَّى يَشْتَدَّ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abu Al Walid] dari [Hammad bin Salamah] dari [Humaid] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam melarang menjual anggur hingga menghitam, dan (melarang) menjual biji hingga mengeras. "},"2850":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ بْنُ خَالِدٍ حَدَّثَنِي يُونُسُ قَالَ سَأَلْتُ أَبَا الزِّنَادِ عَنْ بَيْعِ الثَّمَرِ قَبْلَ أَنْ يَبْدُوَ صَلَاحُهُ وَمَا ذُكِرَ فِي ذَلِكَ فَقَالَ كَانَ عُرْوَةُ بْنُ الزُّبَيْرِ يُحَدِّثُ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَكَانَ النَّاسُ يَتَبَايَعُونَ الثِّمَارَ قَبْلَ أَنْ يَبْدُوَ صَلَاحُهَا فَإِذَا جَدَّ النَّاسُ وَحَضَرَ تَقَاضِيهِمْ قَالَ الْمُبْتَاعُ قَدْ أَصَابَ الثَّمَرَ الدُّمَانُ وَأَصَابَهُ قُشَامٌ وَأَصَابَهُ مُرَاضٌ عَاهَاتٌ يَحْتَجُّونَ بِهَا فَلَمَّا كَثُرَتْ خُصُومَتُهُمْ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَالْمَشُورَةِ يُشِيرُ بِهَا فَإِمَّا لَا فَلَا تَتَبَايَعُوا الثَّمَرَةَ حَتَّى يَبْدُوَ صَلَاحُهَا لِكَثْرَةِ خُصُومَتِهِمْ وَاخْتِلَافِهِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami ['Anbasah bin Khalid] telah menceritakan kepadaku [Yunus], ia berkata; aku bertanya kepada [Abu Az Zinad] mengenai penjualan buah sebelum nampak kelayakannya, dan apa yang diceritakan mengenai hal tersebut. Ia berkata; ['Urwah bin Az Zubair] menceritakan dari [Sahl bin Abu Hatsmah] dari [Zaid bin Tsabit], ia berkata; dahulu orang-orang saling berjual beli buah sebelum nampak kelayakannya. Kemudian apabila orang-orang telah memotong kurma, dan telah hadir tuntutan hutang mereka, maka pembeli berkata; buahnya telah membusuk, dan telah mengering serta terkena penyakit dan bencana. Mereka berhujjah dengannya, kemudian tatkala telah banyak perselisihan mereka di sisi Nabi shallallahu 'alaihi wasallam maka Rasulullah shallallahu 'alaihi wasallam bersabda seperti suatu isyarat yang beliau tunjukkan, apabila tidak maka beliau mengatakan: \"Janganlah kalian berjual beli buah hingga, nampak kelayakannya!\" karena banyak perselisihan dan perbedaan mereka. "},"2851":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ الطَّالَقَانِيُّ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ حَتَّى يَبْدُوَ صَلَاحُهُ وَلَا يُبَاعُ إِلَّا بِالدِّينَارِ أَوْ بِالدِّرْهَمِ إِلَّا الْعَرَايَا","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il Ath Thalaqni], telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atha`] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menjual buah hingga nampak kelayakannya, dan tidak dijual kecual dengan dinar atau dirham kecuali 'araya. "},"2852":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَيَحْيَى بْنُ مَعِينٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ سُلَيْمَانَ بْنِ عَتِيقٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ السِّنِينَ وَوَضَعَ الْجَوَائِحَقَالَ أَبُو دَاوُد لَمْ يَصِحَّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الثُّلُثِ شَيْءٌ وَهُوَ رَأْيُ أَهْلِ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Yahya bin Ma'in], mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Humaid Al A'raj] dari [Sulaiman bin 'Atiq] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam melarang menjual sinin (menjual buah kurma untuk beberapa tahun sebelum nampak buahnya), dan beliau menggugurkan jual beli lantaran terdapat bencana yang menimpa tanaman."},"2853":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي الزُّبَيْرِ وَسَعِيدِ بْنِ مِينَاءَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُعَاوَمَةِ وَقَالَ أَحَدُهُمَا بَيْعُ السِّنِينَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Az Zubair] dan [Sa'id bin Mina`] dari [Jabir bin Abdullah], bahwa Nabi shallallahu 'alaihi wasallam melarang dari mu'awamah (menjual kurma di pohon untuk beberapa tahun sebelum nampak). Sedang salah seorang dari mereka berdua mengatakan; menjual sinin. "},"2854":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ وَعُثْمَانُ ابْنَا أَبِي شَيْبَةَ قَالَا حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْغَرَرِزَادَ عُثْمَانُ وَالْحَصَاةِ","id":"Telah menceritakan kepada kami [Abu Bakr] dan [Utsman] dua anak Abu Syaibah?, mereka berkata; telah menceritakan kepada kami [Ibnu Idris] dari ['Ubaidullah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam melarang menjual secara ghaghar (transaksi jual beli yang mengandung unsur ketidakjelasan, penipuan, pertaruhan, dan hal-hal yang merugikan), sedang Utsman menambahkan dan hashah (transaksi jual beli yang dilakukan oleh dua orang tetapi barangnya belum jelas, kemudian untuk menentukannya salah satu dari mereka melempar hashat (kerikil), maka barang yang terkena kerikil itulah yang dijual). "},"2855":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَهَذَا لَفْظُهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعَتَيْنِ وَعَنْ لِبْسَتَيْنِ أَمَّا الْبَيْعَتَانِ فَالْمُلَامَسَةُ وَالْمُنَابَذَةُ وَأَمَّا اللِّبْسَتَانِ فَاشْتِمَالُ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ الرَّجُلُ فِي ثَوْبٍ وَاحِدٍ كَاشِفًا عَنْ فَرْجِهِ أَوْ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ زَادَ وَاشْتِمَالُ الصَّمَّاءِ أَنْ يَشْتَمِلَ فِي ثَوْبٍ وَاحِدٍ يَضَعُ طَرَفَيْ الثَّوْبِ عَلَى عَاتِقِهِ الْأَيْسَرِ وَيُبْرِزُ شِقَّهُ الْأَيْمَنَ وَالْمُنَابَذَةُ أَنْ يَقُولَ إِذَا نَبَذْتُ إِلَيْكَ هَذَا الثَّوْبَ فَقَدْ وَجَبَ الْبَيْعُ وَالْمُلَامَسَةُ أَنْ يَمَسَّهُ بِيَدِهِ وَلَا يَنْشُرُهُ وَلَا يُقَلِّبُهُ فَإِذَا مَسَّهُ وَجَبَ الْبَيْعُ حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ بْنُ خَالِدٍ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدِ بْنِ أَبِي وَقَّاصٍ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ سُفْيَانَ وَعَبْدِ الرَّزَّاقِ جَمِيعًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Ahmad bin 'Amr bin As Sarh], dan ini adalah lafazhnya. Mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Atha` bin Yazid? Al Laitsi] dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam melarang dari dua macam jual beli dan dua pakaian. Adapun dua macam jual beli yaitu mulamasah (jual beli pakaian yang dilakukan oleh dua orang dengan cara menyentuhnya (lams) dari luar tanpa membukanya dan tidak mengetahui apa yang ada di dalamnya) dan munabadzah (seseorang berkata; lemparkan kepadaku apa yang ada padamu dan aku akan melemparkan sesuatu yang ada padaku, dan hal tersebut dianggap sebagai proses jual beli). Adapun dua pakaian adalah isytimal shamma` (melilitkan pakaian yang tidak ada tempat keluar untuk tangan) dan seseorang membungkus dirinya dengan satu kain dan membuka kemaluannya atau tidak ada sesuatupun kain yang menutupi kemaluannya. Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri], dari ['Atha` bin Yazid? Al Laitsi] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini. Ia menambahkan; dan isytimal shama` adalah berselimut dalam satu kain, meletakkan dua ujung kain pada pundaknya sebelah kiri, dan membuka sebelah kanan. Sedangkan munabadzah adalah dengan mengatakan; apabila aku lemparkan kepadamu pakaian ini maka telah sah jual beli. Dan mulamasah adalah menyentuh kain dengan tangannya dan tidak membukanya serta membalikkannya. Apabila ia menyentuhnya maka telah sah jual beli. Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami ['Anbasah bin Khalid], telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab], ia berkata; telah mengabarkan kepadaku ['Amir bin Sa'dan bin Abu Waqqash] bahwa [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang dengan makna hadits Sufyan dan Abdurrazzaq seluruhnya. "},"2856":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ حَبَلِ الْحَبَلَةِحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ و قَالَ وَحَبَلُ الْحَبَلَةِ أَنْ تُنْتَجَ النَّاقَةُ بَطْنَهَا ثُمَّ تَحْمِلُ الَّتِي نُتِجَتْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari menjual habalil hablah. Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Yahya] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti itu. Dan perowi berkata; habalul hablah yaitu seekor unta hamil kemudian janinnya hamil. "},"2857":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا صَالِحُ بْنُ عَامِرٍ قَالَ أَبُو دَاوُد كَذَا قَالَ مُحَمَّدٌ حَدَّثَنَا شَيْخٌ مِنْ بَنِي تَمِيمٍ قَالَخَطَبَنَا عَلِيُّ بْنُ أَبِي طَالِبٍ أَوْ قَالَ قَالَ عَلِيٌّ قَالَ ابْنُ عِيسَى هَكَذَا حَدَّثَنَا هُشَيْمٌ قَالَ سَيَأْتِي عَلَى النَّاسِ زَمَانٌ عَضُوضٌ يَعَضُّ الْمُوسِرُ عَلَى مَا فِي يَدَيْهِ وَلَمْ يُؤْمَرْ بِذَلِكَ قَالَ اللَّهُ تَعَالَى{ وَلَا تَنْسَوْا الْفَضْلَ بَيْنَكُمْ }وَيُبَايِعُ الْمُضْطَرُّونَ وَقَدْ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْمُضْطَرِّ وَبَيْعِ الْغَرَرِ وَبَيْعِ الثَّمَرَةِ قَبْلَ أَنْ تُدْرِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Shalih bin 'Amir], Abu Daud berkata; demikianlah yang dikatakan Muhammad, telah menceritakan kepada kami [Syaikh] dari Bani Tamim, ia berkata; [Ali bin Abu Thalib] berkhutbah kepada kami, -atau ia mengatakan; Ali berkata; …. Ibnu Isa berkata; demikianlah Husyaim menceritakan kepada kami, ia berkata; akan datang kepada manusia suatu zaman yang menggigit, orang yang berkelapangan menggigit apa yang ada pada keduanya dan tidak diperintahkan untuk itu. Allah Ta'ala berfirman: \"Dan janganlah kalian melupakan keutamaan diantara kalian.\" Dan orang-orang yang terdesak (dalam kondisi terpaksa) melakukan jual beli, sementara Nabi shallallahu 'alaihi wasallam telah melarang dari penjualan orang yang terdesak (dalam kondisi terpaksa), serta penjualan secara gharar (menipu), dan menjual buah sebelum sampai waktunya. "},"2858":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْمِصِّيصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ الزِّبْرِقَانِ عَنْ أَبِي حَيَّانَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَفَعَهُ قَالَإِنَّ اللَّهَ يَقُولُ أَنَا ثَالِثُ الشَّرِيكَيْنِ مَا لَمْ يَخُنْ أَحَدُهُمَا صَاحِبَهُ فَإِذَا خَانَهُ خَرَجْتُ مِنْ بَيْنِهِمَا","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Mishshishi], telah menceritakan kepada kami [Muhammad bin Az Zibriqan], dari [Abu Hayyan At Taimi], dari [ayahnya] dari [Abu Hurairah] dan ia merafa'kannya. Ia berkata; sesungguhnya Allah berfirman: \"Aku adalah pihak ketiga dari dua orang yang bersekutu, selama tidak ada salah seorang diantara mereka yang berkhianat kepada sahabatnya. Apabila ia telah mengkhianatinya, maka aku keluar dari keduanya.\""},"2859":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ حَدَّثَنِي الْحَيُّ عَنْ عُرْوَةَ يَعْنِي ابْنَ أَبِي الْجَعْدِ الْبَارِقِيَّ قَالَأَعْطَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِينَارًا يَشْتَرِي بِهِ أُضْحِيَّةً أَوْ شَاةً فَاشْتَرَى شَاتَيْنِ فَبَاعَ إِحْدَاهُمَا بِدِينَارٍ فَأَتَاهُ بِشَاةٍ وَدِينَارٍ فَدَعَا لَهُ بِالْبَرَكَةِ فِي بَيْعِهِ كَانَ لَوْ اشْتَرَى تُرَابًا لَرَبِحَ فِيهِحَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ حَدَّثَنَا أَبُو الْمُنْذِرِ حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ هُوَ أَخُو حَمَّادِ بْنِ زَيْدٍ حَدَّثَنَا الزُّبَيْرُ بْنُ الْخِرِّيتِ عَنْ أَبِي لَبِيدٍ حَدَّثَنِي عُرْوَةُ الْبَارِقِيُّ بِهَذَا الْخَبَرِ وَلَفْظُهُ مُخْتَلِفٌ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari [Syabib bin Qarqadah], telah menceritakan kepadaku [Al Hayyu] dari ['Urwah bin Abu Al Ja'dan Al Bariqi], ia berkata; Nabi shallallahu 'alaihi wasallam telah memberinya uang satu dinar agar ia belikan satu ekor hewan kurban atau satu ekor kambing. Kemudian ia membeli dua ekor kambing lalu ia menjual salah satunya dengan harga satu dinar. Kemudian ia datang kepada beliau dengan membawa satu ekor kambing dan uang satu dinar. Kemudian beliau mendoakannya agar mendapatkan berkah dalam jual belinya. Ia apabila membeli tanah niscaya mendapatkan keuntungan. Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah], telah menceritakan kepada kami [Abu Al Mundzir], telah menceritakan kepada kami [Sa'id bin Zaid yaitu saudara Hammad bin Zaid], telah menceritakan kepada kami [Az Zubair bin Al Khirrit], dari [Abu Labid] telah menceritakan kepadaku [Urwah Al Bariqi] dengan hadits ini dan lafazhnya diperselisihkan. "},"2860":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ الْعَبْدِيُّ أَخْبَرَنَا سُفْيَانُ حَدَّثَنِي أَبُو حُصَيْنٍ عَنْ شَيْخٍ مِنْ أَهْلِ الْمَدِينَةِ عَنْ حَكِيمِ بْنِ حِزَامٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مَعَهُ بِدِينَارٍ يَشْتَرِي لَهُ أُضْحِيَّةً فَاشْتَرَاهَا بِدِينَارٍ وَبَاعَهَا بِدِينَارَيْنِ فَرَجَعَ فَاشْتَرَى لَهُ أُضْحِيَّةً بِدِينَارٍ وَجَاءَ بِدِينَارٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَصَدَّقَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَعَا لَهُ أَنْ يُبَارَكَ لَهُ فِي تِجَارَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir Al 'Abdi], telah mengabarkan kepada kami [Sufyan], telah menceritakan kepadaku [Abu Hushain], dari [seorang syekh dari penduduk Madinah] dari [Hakim bin Hizam] bahwa Rasulullah shallallahu 'alaihi wasallam telah mengutus dengan membawa uang satu dinar agar ia belikan satu ekor hewan kurban. Kemudian ia membelinya dengan harga satu dinar, dan ia menjualnya seharga dua dinar, lalu ia kembali dan membeli seekor hewan kurban dengan harga satu dinar. Dan ia datang dengan membawa satu uang dinar kepada Nabi shallallahu 'alaihi wasallam. kemudian Nabi shallallahu 'alaihi wasallam mensedekahkan uang tersebut dan mendoakannya agar diberi berkah dalam perdagangannya. "},"2861":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُمَرُ بْنُ حَمْزَةَ أَخْبَرَنَا سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَكُونَ مِثْلَ صَاحِبِ فَرْقِ الْأَرُزِّ فَلْيَكُنْ مِثْلَهُ قَالُوا وَمَنْ صَاحِبُ فَرْقِ الْأَرُزِّ يَا رَسُولَ اللَّهِ فَذَكَرَ حَدِيثَ الْغَارِ حِينَ سَقَطَ عَلَيْهِمْ الْجَبَلُ فَقَالَ كُلُّ وَاحِدٍ مِنْهُمْ اذْكُرُوا أَحْسَنَ عَمَلِكُمْ قَالَ وَقَالَ الثَّالِثُ اللَّهُمَّ إِنَّكَ تَعْلَمُ أَنِّي اسْتَأْجَرْتُ أَجِيرًا بِفَرْقِ أَرُزٍّ فَلَمَّا أَمْسَيْتُ عَرَضْتُ عَلَيْهِ حَقَّهُ فَأَبَى أَنْ يَأْخُذَهُ وَذَهَبَ فَثَمَّرْتُهُ لَهُ حَتَّى جَمَعْتُ لَهُ بَقَرًا وَرِعَاءَهَا فَلَقِيَنِي فَقَالَ أَعْطِنِي حَقِّي فَقُلْتُ اذْهَبْ إِلَى تِلْكَ الْبَقَرِ وَرِعَائِهَا فَخُذْهَا فَذَهَبَ فَاسْتَاقَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami [Abu Usamah], telah menceritakan kepada kami [Umar bin Hamzah] telah mengabarkan kepada kami [Salim bin Abdullah] dari [ayahnya] ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diantara kalian yang mampu seperti takaran beras, maka hendaknya ia menjadi seperti dia!\" Mereka bertanya; siapakah pemilik takaran beras itu Rasulullah? Kemudian beliau menyebutkan kisah gua ketika meruntuhi mereka, kemudian setiap mereka berkata; ingatlah amalan kalian yang terbaik! Beliau mengatakan: \"Dan orang yang ketiga berkata; ya Allah, engkau mengetahui bahwa aku telah mempekerjakan orang dengan upah satu farq beras. Kemudian tatkala sore hari aku memberikan haknya kepadanya. Namun ia menolak untuk mengambil, dan ia pergi. Kemudian aku mengembangkan untuknya aku dapat mengumpulkan sapi dan para penggembalanya. Lalu ia mendatangiku dan berkata; berikan hakku kepadaku! Lalu aku katakan; pergilah kepada sapi-sapi itu dan para penggembalanya, dan ambillah! Lalu ia pergi dan menggiring sapi-sapi tersebut.\""},"2862":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَاشْتَرَكْتُ أَنَا وَعَمَّارٌ وَسَعْدٌ فِيمَا نُصِيبُ يَوْمَ بَدْرٍ قَالَ فَجَاءَ سَعْدٌ بِأَسِيرَيْنِ وَلَمْ أَجِئْ أَنَا وَعَمَّارٌ بِشَيْءٍ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu 'Ubaidah] dari [Abdullah] ia berkata; aku dan 'Ammar serta Sa'd bersekutu pada apa yang kami dapatkan ketika perang Badr, Abdullah berkata; kemudian Sa'd membawa dua orang tawanan sementara aku dan 'Ammar tidak membawa sesuatu pun. "},"2863":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُمَا كُنَّا نَرَى بِالْمُزَارَعَةِ بَأْسًا حَتَّى سَمِعْتُ رَافِعَ بْنَ خَدِيجٍ يَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا فَذَكَرْتُهُ لِطَاوُسٍ فَقَالَ قَالَ لِي ابْنُ عَبَّاسٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَنْهَ عَنْهَا وَلَكِنْ قَالَ لَأَنْ يَمْنَحَ أَحَدُكُمْ أَرْضَهُ خَيْرٌ مِنْ أَنْ يَأْخُذَ عَلَيْهَا خَرَاجًا مَعْلُومًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari ['Amr bin Dinar], ia berkata; aku mendengar [Ibnu Umar] berkata; kami menganggap muzara'ah adalah sesuatu yang diperbolehkan hingga aku mendengar Rafi' bin Khadij berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang darinya. Kemudian aku ceritakan hal tersebut kepada Thawus. Lalu ia berkata; Ibnu Abba berkata kepadaku; sesungguhnya Rasulullah shallallahu 'alaihi wasallam tidak melarang darinya. Akan tetapi beliau bersabda: \"Sungguh, salah seorang diantara kalian memberikan tanahnya kepada saudaranya adalah lebih baik daripada ia mengambil upah tertentu atas tanah tersebut.\""},"2864":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ عُلَيَّةَ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ الْمَعْنَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ بْنِ مُحَمَّدِ بْنِ عَمَّارٍ عَنْ الْوَلِيدِ بْنِ أَبِي الْوَلِيدِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ قَالَقَالَ زَيْدُ بْنُ ثَابِتٍ يَغْفِرُ اللَّهُ لِرَافِعِ بْنِ خَدِيجٍ أَنَا وَاللَّهِ أَعْلَمُ بِالْحَدِيثِ مِنْهُ إِنَّمَا أَتَاهُ رَجُلَانِ قَالَ مُسَدَّدٌ مِنْ الْأَنْصَارِ ثُمَّ اتَّفَقَا قَدْ اقْتَتَلَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ هَذَا شَأْنَكُمْ فَلَا تُكْرُوا الْمَزَارِعَزَادَ مُسَدَّدٌ فَسَمِعَ قَوْلَهُ لَا تُكْرُوا الْمَزَارِعَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah?], telah menceritakan kepada kami [Ibnu 'Ulayyah], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr] secara makna, dari [Abdurrahman bin Ishaq] dari [Abu 'Ubaidah bin Muhammad bin 'Ammar] dari [Al Walid bin Abu Al Walid], dari ['Urwah bin Az Zubair], ia berkata; [Zaid bin Tsabit] berkata; semoga Allah mengampuni Rafi' bin Khudaij, demi Allah aku lebih mengetahui hadits daripadanya. Sesungguhnya terdapat dua orang yang datang kepada beliau. -Musaddad berkata; dari kalangan anshar-. Kemudian lafazh mereka sama: saling bermusuhan. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila hal ini adalah kemauan kalian, maka janganlah kalian menyewakan lahan pertanian!\" Musaddad menambahkan; maka ia mendengar perkataan beliau: \"Janganlah kalian menyewakan lahan pertanian!\""},"2865":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ عِكْرِمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَبِيبَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدٍ قَالَكُنَّا نُكْرِي الْأَرْضَ بِمَا عَلَى السَّوَاقِي مِنْ الزَّرْعِ وَمَا سَعِدَ بِالْمَاءِ مِنْهَا فَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ وَأَمَرَنَا أَنْ نُكْرِيَهَا بِذَهَبٍ أَوْ فِضَّةٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami [Yazid? bin Harun] telah mengabarkan kepada kami [Ibrahim bin Sa'd] dari [Muhammad bin Ikrimah bin Abdurrahman bin Al Harits bin Hisyam] dari [Muhammad bin Abdurrahman bin Abu Labibah] dari [Sa'id bin Al Musayyab], dari [Sa'd] ia berkata; dahulu kami menyewakan tanah dengan upah tanaman yang tumbuh di atas sungai-sungai kecil serta sungai-sungai yang mengalir airnya tersebut. Kemudian Rasulullah shallallahu 'alaihi wasallam melarang kami dari hal tersebut dan beliau memerintahkan kami untuk menyewakannya dengan upah emas atau perak. "},"2866":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى حَدَّثَنَا الْأَوْزَاعِيُّ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ كِلَاهُمَا عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ وَاللَّفْظُ لِلْأَوْزَاعِيِّ حَدَّثَنِي حَنْظَلَةُ بْنُ قَيْسٍ الْأَنْصَارِيُّ قَالَسَأَلْتُ رَافِعَ بْنَ خَدِيجٍ عَنْ كِرَاءِ الْأَرْضِ بِالذَّهَبِ وَالْوَرِقِ فَقَالَ لَا بَأْسَ بِهَا إِنَّمَا كَانَ النَّاسُ يُؤَاجِرُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا عَلَى الْمَاذِيَانَاتِ وَأَقْبَالِ الْجَدَاوِلِ وَأَشْيَاءَ مِنْ الزَّرْعِ فَيَهْلَكُ هَذَا وَيَسْلَمُ هَذَا وَيَسْلَمُ هَذَا وَيَهْلَكُ هَذَا وَلَمْ يَكُنْ لِلنَّاسِ كِرَاءٌ إِلَّا هَذَا فَلِذَلِكَ زَجَرَ عَنْهُ فَأَمَّا شَيْءٌ مَضْمُونٌ مَعْلُومٌ فَلَا بَأْسَ بِهِوَحَدِيثُ إِبْرَاهِيمَ أَتَمُّ و قَالَ قُتَيْبَةُ عَنْ حَنْظَلَةَ عَنْ رَافِعٍ قَالَ أَبُو دَاوُد رِوَايَةُ يَحْيَى بْنِ سَعِيدٍ عَنْ حَنْظَلَةَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepada kami [Isa], telah menceritakan kepada kami [Al Auza'i], dan telah diriwayatkan dari jalur yang lain: Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits], keduanya berasal dari [Rabi'ah bin Abu Abdurrahman], sedangkan lafazhnya adalah lafazh Al Auza'i. telah menceritakan kepadaku [Hanzhalah bin Qais Al Anshari], ia berkata; aku bertanya kepada [Rafi' bin Khadij] mengenai penyewaan tanah dengan emas dan perak. Kemudian ia berkata; tidak mengapa. Sesungguhnya orang-orang dahulu pada masa Rasulullah shallallahu 'alaihi wasallam menyewakan dengan upah apa yang tumbuh di kedua sisi saluran air, dan rumput-rumput sungai serta berbagai hal dari pertanian. Kemudian ada yang rusak dan ada yang baik, dan orang-orang tidak memiliki cara menyewakan kecuali seperti ini. Oleh karena itu beliau melarang dari hal tersebut. Adapun sesuatu yang terjamin dan diketahui maka tidak mengapa. Dan hadits Ibrahim lebih sempurna. Qutaibah berkata; dari Hanzhalah, dari Rafi'. Abu Daud berkata; riwayat Yahya bin Sa'id dari Hanzhalah seperti ini. "},"2867":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ حَنْظَلَةَ بْنِ قَيْسٍأَنَّهُ سَأَلَ رَافِعَ بْنَ خَدِيجٍ عَنْ كِرَاءِ الْأَرْضِ فَقَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كِرَاءِ الْأَرْضِ فَقَالَ أَبِالذَّهَبِ وَالْوَرِقِ فَقَالَ أَمَّا بِالذَّهَبِ وَالْوَرِقِ فَلَا بَأْسَ بِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Rabi'ah bin Abu Abdurrahman] dari [Hanzhalah bin Qais] bahwa ia bertanya kepada [Rafi' bin Khadij] mengenai penyewaan tanah. Kemudian ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang dari penyewaan tanah. Kemudian Hanzhalah berkata; apakah (boleh) jika dilakukan dengan upah emas dan perak? Rafi' berkata; adapun dengan upah emas dan perak, maka tidak mengapa. "},"2868":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي عَنْ جَدِّي اللَّيْثِ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ ابْنَ عُمَرَ كَانَ يَكْرِي أَرْضَهُ حَتَّى بَلَغَهُ أَنَّ رَافِعَ بْنَ خَدِيجٍ الْأَنْصَارِيَّ حَدَّثَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْهَى عَنْ كِرَاءِ الْأَرْضِ فَلَقِيَهُ عَبْدُ اللَّهِ فَقَالَ يَا ابْنَ خَدِيجٍ مَاذَا تُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كِرَاءِ الْأَرْضِ قَالَ رَافِعٌ لِعَبْدِ اللَّهِ بْنِ عُمَرَ سَمِعْتُ عَمَّيَّ وَكَانَا قَدْ شَهِدَا بَدْرًا يُحَدِّثَانِ أَهْلَ الدَّارِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ كِرَاءِ الْأَرْضِ قَالَ عَبْدُ اللَّهِ وَاللَّهِ لَقَدْ كُنْتُ أَعْلَمُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْأَرْضَ تُكْرَى ثُمَّ خَشِيَ عَبْدُ اللَّهِ أَنْ يَكُونَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْدَثَ فِي ذَلِكَ شَيْئًا لَمْ يَكُنْ عَلِمَهُ فَتَرَكَ كِرَاءَ الْأَرْضِقَالَ أَبُو دَاوُد رَوَاهُ أَيُّوبُ وَعُبَيْدُ اللَّهِ وَكَثِيرُ بْنُ فَرْقَدٍ وَمَالِكٌ عَنْ نَافِعٍ عَنْ رَافِعٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ الْأَوْزَاعِيُّ عَنْ حَفْصِ بْنِ عِنَانٍ الْحَنَفِيِّ عَن�� نَافِعٍ عَنْ رَافِعٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَلِكَ رَوَاهُ زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ الْحَكَمِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ أَتَى رَافِعًا فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ نَعَمْ وَكَذَا قَالَ عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ أَبِي النَّجَاشِيِّ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِ الصَّلَاة وَالسَّلَامُ وَرَوَاهُ الْأَوْزَاعِيُّ عَنْ أَبِي النَّجَاشِيِّ عَنْ رَافِعِ بْنِ خَدِيجٍ عَنْ عَمِّهِ ظُهَيْرِ بْنِ رَافِعٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد أَبُو النَّجَاشِيِّ عَطَاءُ بْنُ صُهَيْبٍ","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib bin Al Laits], telah menceritakan kepadaku [ayahku] dari [kakekku yaitu Al Laits], telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab], telah mengabarkan kepadaku [Salim bin Abdullah bin Umar] bahwa [Ibnu Umar] dahulu menyewakan tanahnya hingga sampai kepadanya bahwa [Rafi' bin Khadij Al Anshari] telah menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang menyewakan tanah, kemudian Abdullah bertemu dengannya dan berkata; wahai Ibnu Khadij, apa yang engkau ceritakan dari Rasulullah shallallahu 'alaihi wasallam mengenai penyewaan tanah? Rafi' berkata kepada Abdullah bin Umar; aku mendengar [dua pamanku] dan mereka adalah orang-orang yang menghadiri perang Badr, mereka menceritakan kepada penghuni rumah bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari penyewaan tanah. Abdullah berkata; Demi Allah, sungguh pada masa Rasulullah shallallahu 'alaihi wasallam aku mengetahui bahwa tanah boleh disewakan. Kemudian Abdullah khawatir Rasulullah shallallahu 'alaihi wasallam telah melakukan sesuatu yang baru yang tidak ia ketahui. Maka ia meninggalkan penyewaan tanah. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Ayyub], ['Ubaidullah], [Katsir bin Farqad], dan [Malik] dari [Nafi'] dari [Rafi'] dari Nabi shallallahu 'alaihi wasallam. Dan telah diriwayatkan oleh [Al Auza'i] dari [Hafsh bin 'Inan Al Hanafi], dari [Nafi'], dari [Rafi'], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam ….. Dan begitu juga diriwayatkan oleh [Zaid bin Abu Unaisah], dari [Al Hakam] dari [Nafi'] dari [Ibnu Umar] bahwa ia datang kepada [Rafi'] dan berkata; apakah engkau mendengar Rasulullah shallallahu 'alaihi wasallam? kemudian ia berkata; ya. Dan begitulah yang dikatakan [Ikrimah bin 'Ammar] dari [Abu An Najasyi] dari [Rafi' bin Khadij], ia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam. Dan telah diriwayatkan oleh [Al Auza'i] dari [Abu An Najasyi] dari [Rafi' bin Khadij] dari [pamannya yaitu Zhahir bin Rafi'] dari Nabi shallallahu 'alaihi wasallam. Abu Daud berkata; Abu An Najasyi adalah 'Atha` bin Shuhaib."},"2869":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ أَنَّ رَافِعَ بْنَ خَدِيجٍ قَالَكُنَّا نُخَابِرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَنَّ بَعْضَ عُمُومَتِهِ أَتَاهُ فَقَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَمْرٍ كَانَ لَنَا نَافِعًا وَطَوَاعِيَةُ اللَّهِ وَرَسُولِهِ أَنْفَعُ لَنَا وَأَنْفَعُ قَالَ قُلْنَا وَمَا ذَاكَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ فَلْيُزْرِعْهَا أَخَاهُ وَلَا يُكَارِيهَا بِثُلُثٍ وَلَا بِرُبُعٍ وَلَا بِطَعَامٍ مُسَمًّىحَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ قَالَ كَتَبَ إِلَيَّ يَعْلَى بْنُ حَكِيمٍ أَنِّي سَمِعْتُ سُلَيْمَانَ بْنَ يَسَارٍ بِمَعْنَى إِسْنَادِ عُبَيْدِ اللَّهِ وَحَدِيثِهِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah], telah menceritakan kepada kami [Khalid bin Al Harits], telah menceritakan kepada kami [Sa'id] dari [Ya'laa bin Hakim], dari [Sulaiman bin Yasar] bahwa [Rafi' bin Khadij] berkata; dahulu kami pernah melakukan mukhabarah (menyewakan tanah kepada petani dengan upah sebagian hasil bumi seperti sepertiga atau seperempat) pada masa Rasulullah shallallahu 'alaihi wasallam. kemudian ia menyebutkan bahwa [sebagian pamannya] datang kepadanya dan berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang dari suatu perkara yang dahulu memberikan manfaat kepada kami sedangkan mentaati Allah dan RasulNya adalah lebih bermanfaat bagi kita. Rafi' berkata; maka kami katakan; apakah itu? Ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memiliki tanah maka hendaknya ia menanamnya atau meminta saudaranya untuk menanamnya, dan tidak menyewakannya dengan sepertiga dan seperempat dan tidak pula dengan upah makanan tertentu.\" Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub], ia berkata; [Ya'laa] menulis surat kepadaku; bahwa aku telah mendengar [Sulaiman bin Yasar], dengan makna sanad 'Ubaidullah dan haditsnya. "},"2870":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عُمَرُ بْنُ ذَرٍّ عَنْ مُجَاهِدٍ عَنْ ابْنِ رَافِعِ بْنِ خَدِيجٍ عَنْ أَبِيهِ قَالَجَاءَنَا أَبُو رَافِعٍ مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَمْرٍ كَانَ يَرْفُقُ بِنَا وَطَاعَةُ اللَّهِ وَطَاعَةُ رَسُولِهِ أَرْفَقُ بِنَا نَهَانَا أَنْ يَزْرَعَ أَحَدُنَا إِلَّا أَرْضًا يَمْلِكُ رَقَبَتَهَا أَوْ مَنِيحَةً يَمْنَحُهَا رَجُلٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah?], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Umar bin Dzar] dari [Mujahid] dari [Ibnu Rafi' bin Khadij], dari [ayahnya], ia berkata; [Abu Rafi'] telah datang kepada kami dari sisi Rasulullah shallallahu 'alaihi wasallam kemudian berkata; Rasulullah shallallahu 'alaihi wasallam melarang kami dari suatu perkara yang beliau berikan keringanan kepada kami, dan ketaatan kepada Allah serta RasulNya lebih ringan bagi kami. Beliau melarang salah seorang diantara kami untuk menanam kecuali tanah yang ia miliki atau pemberian yang telah diberikan seseorang kepadanya. "},"2871":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ أَنَّ أُسَيْدَ بْنَ ظُهَيْرٍ قَالَجَاءَنَا رَافِعُ بْنُ خَدِيجٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَاكُمْ عَنْ أَمْرٍ كَانَ لَكُمْ نَافِعًا وَطَاعَةُ اللَّهِ وَطَاعَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْفَعُ لَكُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَاكُمْ عَنْ الْحَقْلِ وَقَالَ مَنْ اسْتَغْنَى عَنْ أَرْضِهِ فَلْيَمْنَحْهَا أَخَاهُ أَوْ لِيَدَعْقَالَ أَبُو دَاوُد وَهَكَذَا رَوَاهُ شُعْبَةُ وَمُفَضَّلُ بْنُ مُهَلْهَلٍ عَنْ مَنْصُورٍ قَالَ شُعْبَةُ أُسَيْدٌ ابْنُ أَخِي رَافِعِ بْنِ خَديِجٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Manshur], dari [Mujahid] bahwa [Usaid bin Zhuhair] berkata; [Rafi' bin Khudaij] telah datang kepada kami dan berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kalian dari suatu perkara yang dahulu memberikan manfaat kepada kalian, sedang ketaatan kepada Allah dan Rasulullah shallallahu 'alaihi wasallam adalah lebih bermanfaat bagi kalian. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang kalian dari haql (menjual gandum dalam bulirnya dengan gandum yang bersih dalam timbangan tertentu), beliau bersabda: \"Barangsiapa yang tidak membutuhkan tanahnya maka hendaknya ia memberikannya kepada saudaranya atau membiarkannya!\" Abu Daud berkata; dan demikianlah hadits tersebut diriwayatkan oleh [Syu'bah] dan [Mufadhdhal bin Muhalhal], dari [Manshur]. Syu'bah berkata; Usaid adalah anak saudara Rafi' bin Khadij. "},"2872":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى حَدَّثَنَا أَبُو جَعْفَرٍ الْخَطْمِيُّ قَالَ بَعَثَنِي عَمِّي أَنَا وَغُلَامًا لَهُ إِلَى سَعِيدِ بْنِ الْمُسَيَّبِ قَالَفَقُلْنَا لَهُ شَيْءٌ بَلَغَنَا عَنْكَ فِي الْمُزَارَعَةِ قَالَ كَانَ ابْنُ عُمَرَ لَا يَرَى بِهَا بَأْسًا حَتَّى بَلَغَهُ عَنْ رَافِعِ بْنِ خَدِيجٍ حَدِيثٌ فَأَتَاهُ فَأَخْبَرَهُ رَافِعٌ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى بَنِي حَارِثَةَ فَرَأَى زَرْعًا فِي أَرْضِ ظُهَيْرٍ فَقَالَ مَا أَحْسَنَ زَرْعَ ظُهَيْرٍ قَالُوا لَيْسَ لِظُهَيْرٍ قَالَ أَلَيْسَ أَرْضُ ظُهَيْرٍ قَالُوا بَلَى وَلَكِنَّهُ زَرْعُ فُلَانٍ قَالَ فَخُذُوا زَرْعَكُمْ وَرُدُّوا عَلَيْهِ النَّفَقَةَقَالَ رَافِعٌ فَأَخَذْنَا زَرْعَنَا وَرَدَدْنَا إِلَيْهِ النَّفَقَةَ قَالَ سَعِيدٌ أَفْقِرْ أَخَاكَ أَوْ أَكْرِهِ بِالدَّرَاهِمِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Yahya], telah menceritakan kepada kami [Abu Ja'far Al Khathmi], ia berkata; pamanku mengutusku dan budaknya kepada [Sa'id bin Al Muasayyab], ia berkata; kemudian kami mengatakan kepadanya; apakah ada sesuatu yang telah sampai kepadamu mengenai muzara'ah. Ia berkata; dahulu Ibnu Umar melihatnya sebagai sesuatu yang diperbolehkan hingga sampai kepadanya hadits dari [Rafi' bin Khadij], kemudian ia datang kepadanya, lalu Rafi' mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam telah datang kepada Bani Haritsah lalu beliau melihat tanaman di tanah Zhuhair. Kemudian beliau berkata; betapa indah tanaman Zhuhair. Orang-orang berkata; itu bukan milik Zhuhair. Beliau berkata; bukankah itu adalah tanah milik Zhuhair? Mereka berkata; benar, akan tetapi tanamannya adalah tanaman Fulan. Beliau berkata: \"Ambillah tanaman kalian dan kembalikan pembiayaannya kepadanya.\" Rafi' berkata; kemudian kami mengambil tanaman kami dan kami mengembalikan pembiayaan kepadanya. Sa'id berkata; \"Berikan kepada saudaramu atau sewakan dengan upah beberapa dirham!\""},"2873":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا طَارِقُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ وَقَالَ إِنَّمَا يَزْرَعُ ثَلَاثَةٌ رَجُلٌ لَهُ أَرْضٌ فَهُوَ يَزْرَعُهَا وَرَجُلٌ مُنِحَ أَرْضًا فَهُوَ يَزْرَعُ مَا مُنِحَ وَرَجُلٌ اسْتَكْرَى أَرْضًا بِذَهَبٍ أَوْ فِضَّةٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Al Ahwash], telah menceritakan kepada kami [Thariq bin Abdurrahman] dari [Sa'id bin Al Musayyab], dari [Rafi' bin Khadij], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari muhaqalah (menjual gandum dalam bulirnya dengan gandum yang bersih dalam timbangan tertentu), dan muzabanah (menjual kurma kering dengan ruthab, dan menjual anggur dengan kismis secara takaran). Sesungguhnya yang boleh menanam Abu Daud tiga, yaitu: seseorang yang memiliki tanah dan ia yang menanaminya, dan seseorang yang diberi tanah dan ia yang menanami apa yang ia diberikan kepadanya, serta seseorang yang menyewa tanah dengan upah emas atau perak. "},"2874":{"ar":"قَالَ أَبُو دَاوُد قَرَأْتُ عَلَى سَعِيدِ بْنِ يَعْقُوبَ الطَّالْقَانِيِّ قُلْتُ لَهُ حَدَّثَكُمْ ابْنُ الْمُبَارَكِ عَنْ سَعِيدٍ أَبِي شُجَاعٍ حَدَّثَنِي عُثْمَانُ بْنُ سَهْلِ بْنِ رَافِعِ بْنِ خَدِيجٍ قَالَإِنِّي لَيَتِيمٌ فِي حِجْرِ رَافِعِ بْنِ خَدِيجٍ وَحَجَجْتُ مَعَهُ فَجَاءَهُ أَخِي عِمْرَانُ بْنُ سَهْلٍ فَقَالَ أَكْرَيْنَا أَرْضَنَا فُلَانَةَ بِمِائَتَيْ دِرْهَمٍ فَقَالَ دَعْهُ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ كِرَاءِ الْأَرْضِ","id":"Telah berkata Abu Daud; aku membacakan riwayat kepada [Sa'id bin Ya'qub Ath Thalqani], aku katakan kepadanya; telah menceritakan kepada kalian [Ibnu Al Mubarak], dari [Sa'id Abu Syuja'], telah menceritakan kepadaku [Utsman bin Sahl bin Rafi' bin Khadij], ia berkata; sungguh aku dahulu adalah seorang anak yatim di dalam asuhan [Rafi' bin Khadij], dan aku pernah berhaji bersamanya. Kemudian saudara Imran bin Sahl datang kepadanya dan berkata; kami menyewakan tanah kami kepada Fulanah dengan upah dua ratus dirham. Kemudian ia berkata; tinggalkan pekerjaan tersebut, karena sesungguhnya Nabi shallallahu 'alaihi wasallam melarang dari menyewakan tanah. "},"2875":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا بُكَيْرٌ يَعْنِي ابْنَ عَامِرٍ عَنْ ابْنِ أَبِي ��ُعْمٍ حَدَّثَنِي رَافِعُ بْنُ خَدِيجٍأَنَّهُ زَرَعَ أَرْضًا فَمَرَّ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَسْقِيهَا فَسَأَلَهُ لِمَنْ الزَّرْعُ وَلِمَنْ الْأَرْضُ فَقَالَ زَرْعِي بِبَذْرِي وَعَمَلِي لِي الشَّطْرُ وَلِبَنِي فُلَانٍ الشَّطْرُ فَقَالَ أَرْبَيْتُمَا فَرُدَّ الْأَرْضَ عَلَى أَهْلِهَا وَخُذْ نَفَقَتَكَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Al Fadhl bin Dukain], telah menceritakan kepada kami [Bukair bin Amir] dari [Ibnu Abu Nu'm], telah menceritakan kepadaku [Rafi' bin Khadij], bahwa ia menanami sebuah lahan, kemudian Nabi shallallahu 'alaihi wasallam melewatinya sementara ia sedang mengairi lahan tersebut. Kemudian beliau bertanya: \"Milik siapakah tanaman dan milik siapa tanah itu?\" Kemudian ia berkata; tanam saya dengan benih dan kerja saya, saya mendapatkan setengah bagian, dan Bani Fulan mendapatkan setengah. Kemudian beliau berkata: \"Kalian telah melakukan riba, kembalikan tanah tersebut kepada pemiliknya dan ambillah pembiayaanmu!\""},"2876":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ عَطَاءٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ زَرَعَ فِي أَرْضِ قَوْمٍ بِغَيْرِ إِذْنِهِمْ فَلَيْسَ لَهُ مِنْ الزَّرْعِ شَيْءٌ وَلَهُ نَفَقَتُهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Syarik] dari [Abu Ishaq], dari ['Atha`] dari [Rafi' bin Khadij], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menanam di tanah suatu kaum tanpa seizin mereka, maka ia tidak memiliki hak dari tanamannya sedikitpun, dan baginya pembiayaannya.\""},"2877":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا إِسْمَعِيلُ ح و حَدَّثَنَا مُسَدَّدٌ أَنَّ حَمَّادًا وَعَبْدَ الْوَارِثِ حَدَّثَاهُمْ كُلُّهُمْ عَنْ أَيُّوبَ عَنْ أَبِي الزُّبَيْرِ قَالَ عَنْ حَمَّادٍ وَسَعِيدِ بْنِ مِينَاءَ ثُمَّ اتَّفَقُوا عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ وَالْمُخَابَرَةِ وَالْمُعَاوَمَةِ قَالَ عَنْ حَمَّادٍ و قَالَ أَحَدُهُمَا وَالْمُعَاوَمَةِ وَقَالَ الْآخَرُ بَيْعُ السِّنِينَ ثُمَّ اتَّفَقُوا وَعَنْ الثُّنْيَا وَرَخَّصَ فِي الْعَرَايَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Isma'il], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad] bahwa [Hammad] dan [Abdul Warits], telah menceritakan kepada mereka, seluruh mereka dari [Ayyub], dari [Abu Az Zubair], ia berkata; dari [Hammad] dan [Sa'id bin Mina`], dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang muhaqalah (menjual gandum dalam bulirnya dengan gandum yang bersih), dan muzabanah (menjual kurma kering dengan ruthab, dan menjual anggur dengan kismis secara takaran), mukhabarah (menyewakan tanah kepada petani dengan upah sebagian hasil bumi seperti sepertiga atau seperempat), dan mu'awamah (menjual buah untuk beberapa tahun sebelum buah tersebut nampak). Sedang yang lainnya mengatakan; bai'us sinin. Kemudian lafazh mereka sama; dan dari tsunya (mengecualikan sesuatu yang tidak jelas dalam jual beli) dan memberikan keringanan dalam hal 'araya (menjual ruthab atau anggur di atas pohon dengan kurma atau kismis dengan menaksirnya). "},"2878":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عُمَرُ بْنُ يَزِيدَ السَّيَّارِيُّ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ يُونُسَ بْنِ عُبَيدٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُزَابَنَةِ وَالْمُحَاقَلَةِ وَعَنْ الثُّنْيَا إِلَّا أَنْ يُعْلَمَ","id":"Telah menceritakan kepada kami [Abu Hafsh Umar bin Yazid? As Sayyari], telah menceritakan kepada kami ['Abbad bin Al 'Awwam], dari [Sufyan bin Husain], dari [Yunus bin 'Ubaid] dari ['Atha`] dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang muzabanah (menjual kurma kering dengan ruthab, dan menjual anggur dengan kismis secara takaran), dan muhaqalah (menjual gandum dalam bulirnya dengan gandum yang bersih) serta tsunya (mengecualikan sesuatu dalam jual beli) kecuali apabila diketahui. "},"2879":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا ابْنُ رَجَاءٍ يَعْنِي الْمَكِّيَّ قَالَ ابْنُ خُثَيْمٍ حَدَّثَنِي عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ لَمْ يَذَرْ الْمُخَابَرَةَ فَلْيَأْذَنْ بِحَرْبٍ مِنْ اللَّهِ وَرَسُولِهِ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], telah menceritakan kepada kami [Ibnu Raja` Al Makki], ia berkata; [Ibnu Khutsaim] menceritakan kepadaku dari [Abu Az Zubair] dari [Jabir bin Abdullah], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang tidak meninggalkan mukhabarah, maka hendaknya ia mengumumkan peperangan dengan Allah dan RasulNya!\""},"2880":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُمَرُ بْنُ أَيُّوبَ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ ثَابِتِ بْنِ الْحَجَّاجِ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُخَابَرَةِ قُلْتُ وَمَا الْمُخَابَرَةُ قَالَ أَنْ تَأْخُذَ الْأَرْضَ بِنِصْفٍ أَوْ ثُلُثٍ أَوْ رُبْعٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah?], telah menceritakan kepada kami [Umar bin Ayyub], dari [Ja'far bin Buqan], dari [Tsabit bin Al Hajjaj], dari [Zaid bin Tsabit], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari mukhabarah. Aku katakan; apakah mukhabrah itu? Ia berkata; engkau mengambil tanah dengan upah setengah atau sepertiga atau seperempat. "},"2881":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَلَ أَهْلَ خَيْبَرَ بِشَطْرِ مَا يَخْرُجُ مِنْ ثَمَرٍ أَوْ زَرْعٍ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Yahya], dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam mempekerjakan penduduk Khaibar dengan upah setengah buah atau tanaman yang keluar. "},"2882":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ اللَّيْثِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ يَعْنِي ابْنَ غَنَجٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَفَعَ إِلَى يَهُودِ خَيْبَرَ نَخْلَ خَيْبَرَ وَأَرْضَهَا عَلَى أَنْ يَعْتَمِلُوهَا مِنْ أَمْوَالِهِمْ وَأَنَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَطْرَ ثَمَرَتِهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], dari [Al Laits] dari [Muhammad bin Abdurrahman bin Ghanaj] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam menyerahkan pohon kurma dan tanah Khaibar kepada orang-orang yahudi Khaibar, agar mereka mengolahnya dengan modal mereka dan Rasulullah shallallahu 'alaihi wasallam mendapatkan setengah buahnya. "},"2883":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الرَّقِّيُّ حَدَّثَنَا عُمَرُ بْنُ أَيُّوبَ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَافْتَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ وَاشْتَرَطَ أَنَّ لَهُ الْأَرْضَ وَكُلَّ صَفْرَاءَ وَبَيْضَاءَ قَالَ أَهْلُ خَيْبَرَ نَحْنُ أَعْلَمُ بِالْأَرْضِ مِنْكُمْ فَأَعْطِنَاهَا عَلَى أَنَّ لَكُمْ نِصْفَ الثَّمَرَةِ وَلَنَا نِصْفٌ فَزَعَمَ أَنَّهُ أَعْطَاهُمْ عَلَى ذَلِكَ فَلَمَّا كَانَ حِينَ يُصْرَمُ النَّخْلُ بَعَثَ إِلَيْهِمْ عَبْدَ اللَّهِ بْنَ رَوَاحَةَ فَحَزَرَ عَلَيْهِمْ النَّخْلَ وَهُوَ الَّذِي يُسَمِّيهِ أَهْلُ الْمَدِينَةِ الْخَرْصَ فَقَالَ فِي ذِهْ كَذَا وَكَذَا قَالُوا أَكْثَرْتَ عَلَيْنَا يَا ابْنَ رَوَاحَةَ فَقَالَ فَأَنَا أَلِي حَزْرَ النَّخْلِ وَأُعْطِيكُمْ نِصْفَ الَّذِي قُلْتُ قَالُوا هَذَا الْحَقُّ وَبِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ قَدْ رَضِينَا أَنْ نَأْخُذَهُ بِالَّذِي قُلْتَحَدَّثَنَا عَلِيُّ بْنُ سَهْلٍ الرَّمْلِيُّ حَدَّثَنَا زَيْدُ بْنُ أَبِي الزَّرْقَاءِ عَنْ جَعْفَرِ بْنِ بُرْقَانَ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ فَحَزَرَ وَقَالَ عِنْدَ قَوْلِهِ وَكُلَّ صَفْرَاءَ وَبَيْضَاءَ يَعْنِي الذَّهَبَ وَالْفِضَّةَ لَهُ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا كَثِيرٌ يَعْنِي ابْنَ هِشَامٍ عَنْ جَعْفَرِ بْنِ بُرْقَانَ حَدَّثَنَا مَيْمُونٌ عَنْ مِقْسَمٍ أَنَّ النَّبِيَّ صَلَّى ال��َّهُ عَلَيْهِ وَسَلَّمَ حِينَ افْتَتَحَ خَيْبَرَ فَذَكَرَ نَحْوَ حَدِيثِ زَيْدٍ قَالَ فَحَزَرَ النَّخْلَ وَقَالَ فَأَنَا أَلِي جُذَاذَ النَّخْلِ وَأُعْطِيكُمْ نِصْفَ الَّذِي قُلْتُ","id":"Telah menceritakan kepada kami [Ayyub bin Muhammad Ar Raqqi], telah menceritakan kepada kami [Umar bin Ayyub], telah menceritakan kepada kami [Ja'far bin Burqan], dari [Maimun bin Mahran], dari [Miqsam] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam menaklukkan Khaibar dan beliau memberi syarat bahwa tanah dan seluruh emas dan perak adalah untuk beliau. Penduduk Khaibar berkata; kami lebih mengetahui mengenai tanah tersebut daripada kalian, maka berikan kepada kami dan kalian mendapatkan setengah buahnya dan kami mendapatkan setengah. Ibnu Abbas mengaku bahwa beliau memberikan tanah tersebut kepada mereka dengan syarat hal tersebut. Kemudian tatkala telah sampai waktu pemotongan kurma, beliau mengutus kepada mereka Abdullah bin Rawahah. Kemudian ia memperkirakan kurma untuk mereka yang penduduk Madinah namakan khirsh. Kemudian ia berkata; dalam pohon-pohon ini terdapat sekian dan sekian. Mereka berkata; engkau telah memperbanyak atas kami wahai Ibnu Rawahah! Maka ia berkata; aku yang menaksirkan dan memberi kepada kalian setengah yang aku katakan. Mereka berkata; ini adalah benar, dan dengannya langit dan bumi tegak. Kami rela mengambilnya sesuai dengan apa yang engkau katakan. Telah menceritakan kepada kami [Ali bin Sahl Ar Ramli], telah menceritakan kepada kami [Zaid bin Abu Az Zarqa`] dari [Ja'far bin Burqan] dengan sanad dan maknanya. Ia berkata; kemudian Abdullah bin Rawahah menaksir. Dan ia berkata ketika mengatakan; dan seluruh yang kuning dan putih; yaitu emas dan perak untuknya. Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada kami [Katsir bin Hisyam] dari [Ja'far bin Burqan], telah menceritakan kepada kami [Maimun] dari [Miqsam], bahwa Nabi shallallahu 'alaihi wasallam ketika menaklukkan Khaibar…. Kemudian ia menyebutkan seperti hadits Zaid. Ia berkata; kemudian ia menaksir pohon kurma tersebut, dan ia berkata; aku yang memotong kurma, dan memberi kalian setengah yang aku katakan. "},"2884":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أُخْبِرْتُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْعَثُ عَبْدَ اللَّهِ بْنَ رَوَاحَةَ فَيَخْرُصُ النَّخْلَ حِينَ يَطِيبُ قَبْلَ أَنْ يُؤْكَلَ مِنْهُ ثُمَّ يُخَيِّرُ يَهُودَ يَأْخُذُونَهُ بِذَلِكَ الْخَرْصِ أَوْ يَدْفَعُونَهُ إِلَيْهِمْ بِذَلِكَ الْخَرْصِ لِكَيْ تُحْصَى الزَّكَاةُ قَبْلَ أَنْ تُؤْكَلَ الثِّمَارُ وَتُفَرَّقَ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], telah menceritakan kepada kami [Hajjaj], dari [Ibnu Juraij], ia berkata; aku telah diberitahu dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] radliallahu 'anha, ia berkata; Nabi shallallahu 'alaihi wasallam mengutus Abdullah bin Rawahah, dan mentaksirkan kurma ketika telah matang sebelum dimakan. Kemudian ia memberikan pilihan kepada orang-orang yahudi, dan mereka mengambilnya dengan penaksiran tersebut, atau mereka menyerahkan kurma tersebut kepada orang-orang yahudi dengan penaksiaran tersebut, agar zakat dapat dihitung sebelum buah dimakan dan dipisahkan."},"2885":{"ar":"حَدَّثَنَا ابْنُ أَبِي خَلَفٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَابِقٍ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّهُ قَالَأَفَاءَ اللَّهُ عَلَى رَسُولِهِ خَيْبَرَ فَأَقَرَّهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا كَانُوا وَجَعَلَهَا بَيْنَهُ وَبَيْنَهُمْ فَبَعَثَ عَبْدَ اللَّهِ بْنَ رَوَاحَةَ فَخَرَصَهَا عَلَيْهِمْحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَمُحَمَّدُ بْنُ بَكْرٍ قَالَا حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ خَرَصَهَا ابْنُ رَوَاحَةَ أَرْبَعِينَ أَلْفَ وَسْقٍ وَزَعَمَ أَنَّ الْيَهُودَ لَمَّا خَيَّرَهُمْ ابْنُ رَوَاحَةَ أَخَذُوا الثَّمَرَ وَعَلَيْهِمْ عِشْرُونَ أَلْفَ وَسْقٍ","id":"Telah menceritakan kepada kami [Ibnu Abu Khalaf], telah menceritakan kepada kami [Muhammad bin Sabiq] dari [Ibrahim bin Thahman] dari [Abu Az Zubair] dari [Jabir] bahwa ia berkata; Allah telah memberikan Khaibar sebagai fai` (harta rampasan tanpa adanya peperangan) kepada RasulNya, kemudian Rasulullah shallallahu 'alaihi wasallam membiarkan mereka sebagaimana dahulu. Dan beliau menjadikan Khaibar hasilnya dibagi antara beliau dan mereka (orang-orang yahudi). Kemudian beliau mengutus Abdullah bin Rawahah, lalu ia menaksirkannya untuk mereka. Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq] dan [Muhammad bin Bakr], mereka berkata; Telah menceritakan kepada kami [Ibnu Juraij], telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar [Jabir bin Abdullah] berkata; Ibnu Rawahah menaksirkan untuk kami empat puluh ribu wasaq. Ia mengaku bahwa orang-orang yahudi tatkala Ibnu Rawahah memberikan pilihan kepada mereka maka mereka mengambil buah dan menanggung dua puluh ribu wasaq. "},"2886":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ وَحُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الرُّوَاسِيُّ عَنْ مُغِيرَةَ بْنِ زِيَادٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ الْأَسْوَدِ بْنِ ثَعْلَبَةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَعَلَّمْتُ نَاسًا مِنْ أَهْلِ الصُّفَّةِ الْكِتَابَ وَالْقُرْآنَ فَأَهْدَى إِلَيَّ رَجُلٌ مِنْهُمْ قَوْسًا فَقُلْتُ لَيْسَتْ بِمَالٍ وَأَرْمِي عَنْهَا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ لَآتِيَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَأَسْأَلَنَّهُ فَأَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ رَجُلٌ أَهْدَى إِلَيَّ قَوْسًا مِمَّنْ كُنْتُ أُعَلِّمُهُ الْكِتَابَ وَالْقُرْآنَ وَلَيْسَتْ بِمَالٍ وَأَرْمِي عَنْهَا فِي سَبِيلِ اللَّهِ قَالَ إِنْ كُنْتَ تُحِبُّ أَنْ تُطَوَّقَ طَوْقًا مِنْ نَارٍ فَاقْبَلْهَاحَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ وَكَثِيرُ بْنُ عُبَيْدٍ قَالَا حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي بِشْرُ بْنُ عَبْدِ اللَّهِ بْنِ يَسَارٍ قَالَ عَمْرٌو و حَدَّثَنِي عُبَادَةُ بْنُ نُسَيٍّ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ نَحْوَ هَذَا الْخَبَرِ وَالْأَوَّلُ أَتَمُّ فَقُلْتُ مَا تَرَى فِيهَا يَا رَسُولَ اللَّهِ فَقَالَ جَمْرَةٌ بَيْنَ كَتِفَيْكَ تَقَلَّدْتَهَا أَوْ تَعَلَّقْتَهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah?], telah menceritakan kepada kami [Waki'] dan [Humaid bin Abdurrahman Ar Ruwasi], dari [Al Mughirah bin Ziyad] dari ['Ubadah bin Nusai] dari [Al Aswad bin Tsa'labah] dari ['Ubadah bin Ash Shamit] ia berkata; aku mengajari orang-orang ahli Shuffah menulis dan membaca, kemudian terdapat seseorang di antara yang memberiku hadiah sebuah busur panah. Kemudian aku katakan; busur bukanlah sebuah harta, dan aku akan menggunakannya untuk memanah di jalan Allah 'azza wajalla. Sungguh aku akan datang kepada Rasulullah shallallahu 'alaihi wasallam dan bertanya kepada beliau. Kemudian aku datang kepada beliau dan aku katakan; wahai Rasulullah, seorang laki-laki di antara orang-orang yang aku ajari menulis dan membaca telah memberiku hadiah sebuah busur panah, dan busur bukanlah merupakan harta dan aku akan menggunakannya untuk memanah di jalan Allah. Beliau berkata: \"Apabila engkau ingin dikalungi dengan kalung dari api maka terimalah!\" telah menceritakan kepada kami ['Amr bin Utsman] dan [Katsir bin 'Ubaid], mereka berkata; telah menceritakan kepada kami [Baqiyyah], telah menceritakan kepadaku [Bisyr bin Abdullah bin Yasar]. ['Amr] berkata; dan telah menceritakan kepadaku ['Ubadah bin Nusai], dari [Junadah bin Abu Umayyah], dari ['Ubadah bin Ash Shamit], seperti hadits ini. Dan hadits yang pertama lebih sempurna. Kemudian aku katakan; bagaimana pendapat engkau, wahai Rasulullah? Kemudian beliau bersabda: \"Itu adalah bara di antara dua pundakmu, engkau memakainya sebagai kalung atau menggantungkanya.\""},"2887":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَهْطًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلَقُوا فِي سَفْرَةٍ سَافَرُوهَا فَنَزَلُوا بِحَيٍّ مِنْ أَحْيَاءِ الْعَرَبِ فَاسْتَضَافُوهُمْ فَأَبَوْا أَنْ يُضَيِّفُوهُمْ قَالَ فَلُدِغَ سَيِّدُ ذَلِكَ الْحَيِّ فَشَفَوْا لَهُ بِكُلِّ شَيْءٍ لَا يَنْفَعُهُ شَيْءٌ فَقَالَ بَعْضُهُمْ لَوْ أَتَيْتُمْ هَؤُلَاءِ الرَّهْطَ الَّذِينَ نَزَلُوا بِكُمْ لَعَلَّ أَنْ يَكُونَ عِنْدَ بَعْضِهِمْ شَيْءٌ يَنْفَعُ صَاحِبَكُمْ فَقَالَ بَعْضُهُمْ إِنَّ سَيِّدَنَا لُدِغَ فَشَفَيْنَا لَهُ بِكُلِّ شَيْءٍ فَلَا يَنْفَعُهُ شَيْءٌ فَهَلْ عِنْدَ أَحَدٍ مِنْكُمْ شَيْءٌ يَشْفِي صَاحِبَنَا يَعْنِي رُقْيَةً فَقَالَ رَجُلٌ مِنْ الْقَوْمِ إِنِّي لَأَرْقِي وَلَكِنْ اسْتَضَفْنَاكُمْ فَأَبَيْتُمْ أَنْ تُضَيِّفُونَا مَا أَنَا بِرَاقٍ حَتَّى تَجْعَلُوا لِي جُعْلًا فَجَعَلُوا لَهُ قَطِيعًا مِنْ الشَّاءِ فَأَتَاهُ فَقَرَأَ عَلَيْهِ بِأُمِّ الْكِتَابِ وَيَتْفِلُ حَتَّى بَرِئَ كَأَنَّمَا أُنْشِطَ مِنْ عِقَالٍ فَأَوْفَاهُمْ جُعْلَهُمْ الَّذِي صَالَحُوهُ عَلَيْهِ فَقَالُوا اقْتَسِمُوا فَقَالَ الَّذِي رَقَى لَا تَفْعَلُوا حَتَّى نَأْتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْتَأْمِرَهُ فَغَدَوْا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرُوا ذَلِكَ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَيْنَ عَلِمْتُمْ أَنَّهَا رُقْيَةٌ أَحْسَنْتُمْ وَاضْرِبُوا لِي مَعَكُمْ بِسَهْمٍحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَخِيهِ مَعْبَدِ بْنِ سِيرِينَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri], bahwa beberapa orang sahabat Rasulullah shallallahu 'alaihi wasallam pergi dalam suatu safar yang mereka lakukan. Kemudian mereka singgah di sebuah kampung diantara kampung-kampung Arab. Lalu mereka bertamu kepada penduduk tersebut, namun mereka enggan untuk menjadikan para sahabat tersebut sebagai tamu. Abu Sa'id berkata; kemudian pemimpin kampung tersebut tersengat. Lalu mereka menyebar untuk mencarikan obat untuknya, namun tidak ada sesutupun yang memberinya manfaat. Kemudian sebagian mereka berkata; seandainya kalian datang kepada orang-orang yang singgah kepada kalian tersebut bisa jadi mereka memiliki sesuatu yang bermanfaat untuk sahabat kalian. Kemudian sebagian mereka berkata; sesungguhnya pemiimpin kami tersengat, kemudian kami menyebar untuk mencarikan obat untuknya, namun tidak ada sesuatupun yang bermanfaat baginya, apakah salah seorang diantara kalian memiliki sesuatu yaitu jampi yang dapat menyembuhkan sahabat kami? Kemudian salah seorang diantara orang-orang tersebut berkata; sungguh aku akan menjampinya, akan tetapi kami bertamu kepada kalian namun kalian menolak untuk menjadikan kami sebagai tamu. Aku tidak akan menjampi hingga kalian memberikan hadiah kepadaku. Kemudian mereka memberikan kepadanya sekelompok kambing. Lalu ia datang kepada orang yang tersengat tersebut dan membacakan padanya Surat Al Fatihah, dan meludah hingga ia sembuh, seolah-olah ia terbebas dari belenggu. Lalu ia memenuhi hadiah yang mereka janjikan. Kemudian para sahabat tersebut membagi kambing tersebut. Kemudian orang yang menjampi berkata; jangan kalian lakukan hingga kita datang kepada Rasulullah shallallahu 'alaihi wasallam dan meminta pendapat beliau. Kemudian mereka pergi kepada Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau. Lalu beliau berkata: \"Dari mana kalian mengetahui bahwa surat tersebut adalah jampi? Kalian telah berlaku baik, berilah aku bagian bersama kalian!\" Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Yazid? bin Harun], telah mengabarkan kepada kami [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [saudaranya yaitu Ma'bad bin Sirin] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini. "},"2888":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ خَارِجَةَ بْنِ الصَّلْتِ عَنْ عَمِّهِأَنَّهُ مَرَّ بِقَوْمٍ فَأَتَوْهُ فَقَالُوا إِنَّكَ جِئْتَ مِنْ عِنْدِ هَذَا الرَّجُلِ بِخَيْرٍ فَارْقِ لَنَا هَذَا الرَّجُلَ فَأَتَوْهُ بِرَجُلٍ مَعْتُوهٍ فِي الْقُيُودِ فَرَقَاهُ بِأُمِّ الْقُرْآنِ ثَلَاثَةَ أَيَّامٍ غُدْوَةً وَعَشِيَّةً وَكُلَّمَا خَتَمَهَا جَمَعَ بُزَاقَهُ ثُمَّ تَفَلَ فَكَأَنَّمَا أُنْشِطَ مِنْ عِقَالٍ فَأَعْطَوْهُ شَيْئًا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ لَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلْ فَلَعَمْرِي لَمَنْ أَكَلَ بِرُقْيَةٍ بَاطِلٍ لَقَدْ أَكَلْتَ بِرُقْيَةٍ حَقٍّ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah], dari [Abdullah bin Abu As Safar] dari [Asy Sya'bi], dari [Kharijah bin Ash Shalt], dari [pamannya] bahwa ia pernah melewati sebuah kaum, kemudian mereka mendatanginya dan berkata; engkau datang dari sisi orang ini (Rasulullah shallallahu 'alaihi wasallam) dengan membawa kebaikan, maka jampilah orang ini untuk kami! Kemudian mereka membawa orang yang hilang akalnya dalam keadaan terbaring. Lalu paman Kharijah menjampinya dengan Al Fatihah selama tiga hari pagi dan sore, setiap kali ia menyelesaikan membaca Al Fatihah mengumpulkan ludahnya kemudian meludah. Maka orang-orang tersebut seolah-olah telah terlepas dari belenggu. Lalu mereka memberinya sesuatu, kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal kepada beliau. Nabi shallallahu 'alaihi wasallam bersabda: \"Makanlah, sungguh ada orang yang makan dengan jampi yang batil, sementara engkau makan dengan jampi yang benar.\""},"2889":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ أَخْبَرَنَا أَبَانُ عَنْ يَحْيَى عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ يَعْنِي ابْنَ قَارِظٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ رَافِعِ بْنِ خَدِيجٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَسْبُ الْحَجَّامِ خَبِيثٌ وَثَمَنُ الْكَلْبِ خَبِيثٌ وَمَهْرُ الْبَغِيِّ خَبِيثٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah mengabarkan kepada kami [Aban] dari [Yahya] dari [Ibrahim bin Abdullah bin Qarizh], dari [As Saib bin Yazid?] dari [Rafi' bin Khadij], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penghasilan tukang bekam adalah kotor, dan harga (uang penjualan) anjing adalah kotor, serta upah pelacur adalah kotor.\""},"2890":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ مُحَيِّصَةَ عَنْ أَبِيهِأَنَّهُ اسْتَأْذَنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِجَارَةِ الْحَجَّامِ فَنَهَاهُ عَنْهَا فَلَمْ يَزَلْ يَسْأَلُهُ وَيَسْتَأْذِنُهُ حَتَّى أَمَرَهُ أَنْ أَعْلِفْهُ نَاضِحَكَ وَرَقِيقَكَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah], dari [Malik] dari [Ibnu Syihab] dari [Ibnu Muhayyishah] dari [ayahnya] bahwa ia meminta izin kepada Rasulullah shallallahu 'alaihi wasallam untuk menyewakan tukang bekam, kemudian beliau melarangnya. Namun ia terus memohon dan minta izin hingga beliau memerintahkannya: \"Berilah makan untamu yang digunakan untuk mengairi air, serta budakmu!\""},"2891":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍقَالَ احْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَعْطَى الْحَجَّامَ أَجْرَهُ وَلَوْ عَلِمَهُ خَبِيثًا لَمْ يُعْطِهِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yazid? bin Zurai'], telah menceritakan kepada kami [Khalid], dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam berbekam dan memberikan upah kepada tukang bekam. Seandainya beliau meyakininya sebagai sesuatu yang buruk, niscaya beliau tidak memberinya. "},"2892":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَحَجَمَ أَبُو طَيْبَةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ لَهُ بِصَاعٍ مِنْ تَمْرٍ وَأَمَرَ أَهْلَهُ أَنْ يُخَفِّفُوا عَنْهُ مِنْ خَرَاجِهِ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Humaid Ath Thawil], dari [Anas bin Malik], bahwa ia berkata; Abu Thaibah membekam Rasulullah shallallahu 'alaihi wasallam dan beliau memerintahkan agar ia diberi satu sha' kurma dan memerintahkan para majikannya agar meringankan upeti darinya. "},"2893":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ قَالَ سَمِعْتُ أَبَا حَازِمٍ سَمِعَ أَبَا هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْإِمَاءِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Syu'bah], dari [Muhammad bin Juhadah], ia berkata; saya mendengar [Abu Hazim] mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari hasil pelacuran budak wanita. "},"2894":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عِكْرِمَةُ حَدَّثَنِي طَارِقُ بْنُ عَبْدِ الرَّحْمَنِ الْقُرَشِيُّ قَالَجَاءَ رَافِعُ بْنُ رِفَاعَةَ إِلَى مَجْلِسِ الْأَنْصَارِ فَقَالَ لَقَدْ نَهَانَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَوْمَ فَذَكَرَ أَشْيَاءَ وَنَهَى عَنْ كَسْبِ الْأَمَةِ إِلَّا مَا عَمِلَتْ بِيَدِهَا وَقَالَ هَكَذَا بِأَصَابِعِهِ نَحْوَ الْخَبْزِ وَالْغَزْلِ وَالنَّفْشِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Hasyim bin Al Qasim], telah menceritakan kepada kami [Ikrimah], telah menceritakan kepadaku [Thariq bin Abdurrahman Al Qurasyi], ia berkata; [Rafi' bin Rifa'ah] telah datang ke majelis orang-orang anshar dan berkata; sungguh Nabi shallallahu 'alaihi wasallam telah melarang kami pada hari ini. Kemudian ia menyebutkan beberapa hal. Dan beliau melarang dari hasil kerja budak yang berzina kecuali apa yang ia lakukan dengan tangannya. Dan ia mengucapkannya denangan jari-jarinya seperti membuat roti, memintal dan mengurai wol. "},"2895":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عُبَيْدِ اللَّهِ يَعْنِي ابْنَ هُرَيْرٍ عَنْ أَبِيهِ عَنْ جَدِّهِ رَافِعٍ هُوَ ابْنُ خَدِيجٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْأَمَةِ حَتَّى يُعْلَمَ مِنْ أَيْنَ هُوَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Abu Fudaik] dari ['Ubaidullah bin Hurair] dari [ayahnya] dari [kakeknya yaitu Rafi' bin Khudaij] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari hasil pelacuran budak wanita hingga diketahui dari mana hasil tersebut diperoleh. "},"2896":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah menceritakan kepada kami [Qutaibah], dari [Sufyan], dari [Az Zuhri], dari [Abu Bakr bin Abdurrahman] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam bahwa beliau telah melarang uang hasil dari penjualan anjing, upah pezina, dan upah dukun. "},"2897":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَسْبِ الْفَحْلِ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad], telah menceritakan kepada kami [Isma'il], dari [Ali bin Al Hakam], dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari upah dari hewan pejantan. "},"2898":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَاجِدَةَ قَالَقَطَعْتُ مِنْ أُذُنِ غُلَامٍ أَوْ قُطِعَ مِنْ أُذُنِي فَقَدِمَ عَلَيْنَا أَبُو بَكْرٍ حَاجًّا فَاجْتَمَعْنَا إِلَيْهِ فَرَفَعَنَا إِلَى عُمَرَ بْنِ الْخَطَّابِ فَقَالَ عُمَرُ إِنَّ هَذَا قَدْ بَلَغَ الْقِصَاصَ ادْعُوا لِي حَجَّامًا لِيَقْتَصَّ مِنْهُ فَلَمَّا دُعِيَ الْحَجَّامُ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنِّي وَهَبْتُ لِخَالَتِي غُلَامًا وَأَنَا أَرْجُو أَنْ يُبَارَكَ لَهَا فِيهِ فَقُلْتُ لَهَا لَا تُسَلِّمِيهِ حَجَّامًا وَلَا صَائِغًا وَلَا قَصَّابًاقَالَ أَبُو دَاوُد رَوَى عَبْدُ الْأَعْلَى عَنْ ابْنِ إِسْحَقَ قَالَ ابْنُ مَاجِدَةَ رَجُلٌ مَنْ بَنِي سَهْمٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا سَلَمَةُ بْنُ الْفَضْلِ حَدَّثَنَا ابْنُ إِسْحَقَ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ الْحُرَقِيِّ عَنْ ابْنِ مَاجِدَةَ السَّهْمِيِّ عَنْ عُمَرَ بْنِ الْخَطَّابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ حَدَّثَنَا الْفَضْلُ بْنُ يَعْقُوبَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنَا الْعَلَاءُ بْنُ عَبْدِ الرَّحْمَنِ الْحُرَقِيُّ عَنْ ابْنِ مَاجِدَةَ السَّهْمِيِّ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Muhammad bin Ishaq], dari [Al 'Ala` bin Abdurrahman], dari [Abu Majidah] ia berkata; aku telah memotong sebagian dari telinga seorang budak, atau sebagian dari telinga budakku telah terpotong. Kemudian Abu Bakr datang kepada kami dalam keadaan melakukan haji. Kemudian kami berkumpul kepadanya, lalu ia melaporkan kami kepada Umar bin Al Khathab, kemudian [Umar] berkata; sesungguhnya ini telah sampai kepada qishash, panggilkan tukang bekam agar ia membalasnya. Kemudian tatkala tukang bekam tersebut dipanggil ia berkata; aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku telah memberikan kepada bibiku seorang budak, dan aku berharap ia mendapatkan berkah pada diri budak tersebut.\" Kemudian aku katakan kepadanya; janganlah engkau serahkan ia kepada tukang bekam dan tukang pembuat perhiasan serta penjagal! Abu Daud berkata; [Abdul A'laa] telah meriwayatkan dari [Ibnu Ishaq], [Ibnu Majidah] seorang laki-laki dari Bani Sahm berkata; dari [Umar bin Al Khathab]. Telah menceritakan kepada kami [Yusuf bin Musa], telah menceritakan kepada kami [Salamah bin Al Fadhl], telah menceritakan kepada kami [Ibnu Ishaq] dari [Al 'Ala` bin Abdurrahman Al Huraqi], dari [Ibnu Majidah As Sahmi], dan [Umar bin Al Khathab], dari Nabi shallallahu 'alaihi wasallam seperti itu. Telah menceritakan kepada kami [Al Fadhl bin Ya'qub] telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq], telah menceritakan kepada kami [Al 'Alaa bin Abdurrahman Al Huraqi], dari [Ibnu Majidah As Sahmi] dari [Umar bin Al Khathab radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"2899":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَاعَ عَبْدًا وَلَهُ مَالٌ فَمَالُهُ لِلْبَائِعِ إِلَّا أَنْ يَشْتَرِطَهُ الْمُبْتَاعُ وَمَنْ بَاعَ نَخْلًا مُؤَبَّرًا فَالثَّمَرَةُ لِلْبَائِعِ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُحَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِصَّةِ الْعَبْدِ وَعَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِصَّةِ النَّخْلِ قَالَ أَبُو دَاوُد وَاخْتَلَفَ الزُّهْرِيُّ وَنَافِعٌ فِي أَرْبَعَةِ أَحَادِيثَ هَذَا أَحَدُهَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Sufyan], dari [Az Zuhri], dari [Salim], dari [ayahnya], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang menjual budak dan budak tersebut memiliki harta, maka hartanya adalah milik penjual, kecuali pembeli mensyaratkannya, dan barangsiapa yang menjual pohon kurma yang telah dikawinkan maka buahnya adalah untuk pembeli, kecuali pembeli mensyaratkannya.\" Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Nafi'] dari [Ibnu Umar] dari [Umar] dari Rasulullah shallallahu 'alaihi wasallam dengan kisah seorang budak, dan dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan kisah pohon kurma. Abu Daud berkata; Az Zuhri dan Nafi' berselisih dalam empat hadits. Hadits ini adalah salah satunya. "},"2900":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي سَلَمَةُ بْنُ كُهَيْلٍ حَدَّثَنِي مَنْ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَاعَ عَبْدًا وَلَهُ مَالٌ فَمَالُهُ لِلْبَائِعِ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya], dari [Sufyan], telah menceritakan kepadaku [Salamah bin Kuhail], telah menceritakan kepadaku [orang yang mendengar] [Jabir bin Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menjual budak dan ia (budak) memiliki harta, maka hartanya adalah milik penjual kecuali pembeli mensyaratkannya.\""},"2901":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِعْ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ وَلَا تَلَقَّوْا السِّلَعَ حَتَّى يُهْبَطَ بِهَا الْأَسْوَاقَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sebagian dari kalian menjual barang yang masih ada dalam penawaran orang lain, dan janganlah menyambut (membeli) barang hingga sampai ke pasar.\""},"2902":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عَمْرٍو الرَّقِّيَّ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ تَلَقِّي الْجَلَبِ فَإِنْ تَلَقَّاهُ مُتَلَقٍّ مُشْتَرٍ فَاشْتَرَاهُ فَصَاحِبُ السِّلْعَةِ بِالْخِيَارِ إِذَا وَرَدَتْ السُّوقَقَالَ أَبُو عَلِيٍّ سَمِعْتُ أَبَا دَاوُدَ يَقُولُ قَالَ سُفْيَانُ لَا يَبِعْ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ أَنْ يَقُولَ إِنَّ عِنْدِي خَيْرًا مِنْهُ بِعَشَرَةٍ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Nafi' Abu Taubah] telah menceritakan kepada kami ['Ubaidullah bin 'Amr Ar Raqqi], dari [Ayyub] dari [Ibnu Sirin] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menyambut barang dagangan sebelum masuk pasar. Apabila terdapat terdapat pembeli yang menyambutnya kemudian membelinya maka pemilik barang memiliki hak memiliki hak untuk memilih apabila barang tersebut telah sampai ke pasar. Abu Ali berkata; aku saya mendengar Abu Daud berkata; Sufyan berkata; jangan sebagian kalian menjual barang yang masih ada dalam penawaran orang lain, dengan mengatakan; sesungguhnya aku memiliki yang lebih baik daripada itu dengan harga sepuluh. "},"2903":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنَاجَشُوا","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin sarah], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri], dari [Sa'id bin Al Musayyab], dari [Abu Hurairah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melakukan najsy.\" "},"2904":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعَ حَاضِرٌ لِبَادٍفَقُلْتُ مَا يَبِيعُ حَاضِرٌ لِبَادٍ قَالَ لَا يَكُونُ لَهُ سِمْسَارًا","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang orang yang bermukim (orang kota) menjualkan barang orang yang datang dari desa. Aku katakan apa maksud tidak boleh orang yang bermukim (orang kota) menjualkan barang orang yang datang dari desa? Ia berkata; tidak boleh ia menjadi calo. "},"2905":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ أَنَّ مُحَمَّدَ بْنَ الزِّبْرِقَانِ أَبَا هَمَّامٍ حَدَّثَهُمْ قَالَ زُهَيْرٌ وَكَانَ ثِقَةً عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ حَاضِرٌ لِبَادٍ وَإِنْ كَانَ أَخَاهُ أَوْ أَبَاهُقَالَ أَبُو دَاوُد سَمِعْت حَفْصَ بْنَ عُمَرَ يَقُولُ حَدَّثَنَا أَبُو هِلَالٍ حَدَّثَنَا مُحَمَّدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ كَانَ يُقَالُ لَا يَبِيعُ حَاضِرٌ لِبَادٍ وَهِيَ كَلِمَةٌ جَامِعَةٌ لَا يَبِيعُ لَهُ شَيْئًا وَلَا يَبْتَاعُ لَهُ شَيْئًا","id":"Telah menceritakan kepada kami [Zuhair bin Harb] bahwa [Muhammad bin Az Zibriqan Abu Hammam] telah menceritakan kepada mereka, Zuhair berkata; dan ia adalah orang yang tsiqah, dari [Yunus] dari [Al Hasan] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh orang yang bermukim (orang kota) menjualkan barang orang yang datang dari desa walaupun ia adalah saudaranya atau ayahnya.\" Abu Daud berkata; saya mendengar Hafsh bin Umar berkata; telah menceritakan kepada kami Abu Hilal, telah menceritakan kepada kami Muhammad dari Anas bin Malik ia berkata; dahulu pernah dikatakan; Tidak boleh orang yang bermukim menjualkan orang pelosok. Hal tersebut merupakan sebuah kalimat yang mencakup tidak boleh menjualkan sesuatu untuknya dan tidak boleh membelikan sesuatu untuknya. "},"2906":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ سَالِمٍ الْمَكِّيِّ أَنَّ أَعْرَابِيًّا حَدَّثَهُأَنَّهُ قَدِمَ بِحَلُوبَةٍ لَهُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَ عَلَى طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ فَقَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَبِيعَ حَاضِرٌ لِبَادٍ وَلَكِنْ اذْهَبْ إِلَى السُّوقِ فَانْظُرْ مَنْ يُبَايِعُكَ فَشَاوِرْنِي حَتَّى آمُرَكَ أَوْ أَنْهَاكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Muhammad bin Ishaq], dari [Salim Al Makki] bahwa [seorang badui] telah menceritakan kepadanya bahwa ia datang dengan membawa kambing perahan pada zaman Rasulullah shallallahu 'alaihi wasallam. kemudian ia singgah pada [Thalhah bin 'Ubaidullah], kemudian berkata; sesungguhnya Nabi shallallahu 'alaihi wasallam telah melarang orang yang bermukim (orang kota) menjualkan barang orang yang datang dari desa, akan tetapi pergilah ke pasar dan lihatlah siapakah yang berjual beli denganmu, kemudian mintalah petunjuk kepadaku hingga aku memerintahkan atau melarangmu. "},"2907":{"ar":"حَدَّثَنَا عُبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبِعْ حَاضِرٌ لِبَادٍ وَذَرُوا النَّاسَ يَرْزُقُ اللَّهُ بَعْضَهُمْ مِنْ بَعْضٍ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah orang yang bermukim 9orang kota) menjualkan barang orang yang datang dari desa. Biarkan orang-orang sebagian mereka Allah beri rizqi dari sebagian yang lain!\""},"2908":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَلَقَّوْا الرُّكْبَانَ لِلْبَيْعِ وَلَا يَبِعْ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ وَلَا تُصَرُّوا الْإِبِلَ وَالْغَنَمَ فَمَنْ ابْتَاعَهَا بَعْدَ ذَلِكَ فَهُوَ بِخَيْرِ النَّظَرَيْنِ بَعْدَ أَنْ يَحْلُبَهَا فَإِنْ رَضِيَهَا أَمْسَكَهَا وَإِنْ سَخِطَهَا رَدَّهَا وَصَاعًا مِنْ تَمْرٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik], dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyambut para pedagang yang datang ke pasar untuk menjual, dan janganlah sebagian kalian menjual barang yang ada dalam penawaran oang lain, dan janganlah menahan kantong susu unta dan kambing (tidak memerahnya agar kelihatan susunya banyak). Barangsiapa yang membelinya setelah itu maka ia memiliki hak memilih antara dua pendapat setelah memerahnya, apabila ia merelakannya maka ia menahannya dan apabila ia tidak merelakannya maka ia mengembalikannya di tambah satu sha' kurma.\""},"2909":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ وَهِشَامٌ وَحَبِيبٌ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اشْتَرَى شَاةً مُصَرَّاةً فَهُوَ بِالْخِيَارِ ثَلَاثَةَ أَيَّامٍ إِنْ شَاءَ رَدَّهَا وَصَاعًا مِنْ طَعَامٍ لَا سَمْرَاءَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Ayyub] dan [Hisyam] serta [Habib] dari [Muhammad bin Sirin] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli kambing yang telah ditahan kantong susunya (tidak diperah), maka ia memiliki hak memilih selama tiga hari. Apabila ia menghendaki maka ia mengembalikannya ditambah satu sha' makanan tidak mesti harus gandum samra`.\""},"2910":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَخْلَدٍ التَّمِيمِيُّ حَدَّثَنَا الْمَكِّيُّ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي زِيَادٌ أَنَّ ثَابِتًا مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ زَيْدٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اشْتَرَى غَنَمًا مُصَرَّاةً احْتَلَبَهَا فَإِنْ رَضِيَهَا أَمْسَكَهَا وَإِنْ سَخِطَهَا فَفِي حَلْبَتِهَا صَاعٌ مِنْ تَمْرٍ","id":"Telah menceritakan kepada kami [Abdullah bin Makhlad At Taimi], telah menceritakan kepada kami [Al Makki bin Ibrahim], telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Ziyad] bahwa [Tsabit] mantan budak Abdurrahman bin Zaid telah mengabarkan kepadanya bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membeli kambing yang telah ditahan kantong susunya, dan ia telah memerahnya apabila ia merelakannya maka ia menahannya, dan apabila tidak merelakannya maka pengganti susu yang diperah adalah satu sha' kurma.\""},"2911":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا صَدَقَةُ بْنُ سَعِيدٍ عَنْ جُمَيْعِ بْنِ عُمَيْرٍ التَّيْمِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتَاعَ مُحَفَّلَةً فَهُوَ بِالْخِيَارِ ثَلَاثَةَ أَيَّامٍ فَإِنْ رَدَّهَا رَدَّ مَعَهَا مِثْلَ أَوْ مِثْلَيْ لَبَنِهَا قَمْحًا","id":"Telah menceritakan kepada kami [Abu Kamil], telah menceritakan kepada kami [Abdul Wahid], telah menceritakan kepada kami [Shadaqah bin Sa'id], dari [Jumai' bin 'Umair At Taimi], ia berkata; aku mendengar [Abdullah bin Umar] berkata; Rasulullah shallallahu 'alaihi wasallam berkata; \"Barangsiapa yang membeli hewan yang tidak diperah susunya, maka ia memiliki hak memilih selama tiga hari, apabila ia mengembalikannya maka ia mengembalikannya disertai gandum seperti susu tersebut atau dua kali susunya.\""},"2912":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا خَالِدٌ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ مَعْمَرِ بْنِ أَبِي مَعْمَرٍ أَحَدِ بَنِي عَدِيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْتَكِرُ إِلَّا خَاطِئٌفَقُلْتُ لِسَعِيدٍ فَإِنَّكَ تَحْتَكِرُ قَالَ وَمَعْمَرٌ كَانَ يَحْتَكِرُ قَالَ أَبُو دَاوُد وَسَأَلْتُ أَحْمَدَ مَا الْحُكْرَةُ قَالَ مَا فِيهِ عَيْشُ النَّاسِ قَالَ أَبُو دَاوُد قَالَ الْأَوْزَاعِيُّ الْمُحْتَكِرُ مَنْ يَعْتَرِضُ السُّوقَ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah], telah mengabarkan kepada kami [Khalid] dari ['Amr bin Yahya], dari [Muhammad bin 'Amr bin 'Atho`] dari [Sa'id bin Al Musayyab] dari [Ma'mar bin Abu Ma'mar] salah satu Bani Adi bin Ka'b, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang menimbun barang, kecuali tela berbuat salah.\" Kemudian aku katakan kepada Sa'id; sesungguhnya engkau menimbun. Ia berkata; dan Ma'mar pernah menimbun. Abu Daud berkata; dan aku bertanya kepada Ahmad; apakah hukrah itu? Ia berkata; sesuatu yang padanya terdapat kehidupan manusia. Abu Daud berkata; Al Auza'i berkata; muhtakir adalah orang yang datang ke pasar untuk membeli apa yang dibutuhkan orang-orang dan menyimpannya. "},"2913":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَيَّاضٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ الْفَيَّاضِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَلَيْسَ فِي التَّمْرِ حُكْرَةٌقَالَ ابْنُ الْمُثَنَّى قَالَ عَنْ الْحَسَنِ فَقُلْنَا لَهُ لَا تَقُلْ عَنْ الْحَسَنِ قَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ عِنْدَنَا بَاطِلٌ قَالَ أَبُو دَاوُد كَانَ سَعِيدُ بْنُ الْمُسَيِّبِ يَحْتَكِرُ النَّوَى وَالْخَبَطَ وَالْبِزْرَ و سَمِعْت أَحْمَدَ بْنَ يُونُسَ يَقُولُ سَأَلْتُ سُفْيَانَ عَنْ كَبْسِ الْقَتِّ فَقَالَ كَانُوا يَكْرَهُونَ الْحُكْرَةَ وَسَأَلْتُ أَبَا بَكْرِ بْنَ عَيَّاشٍ فَقَالَ اكْبِسْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Fayyadh], telah menceritakan kepada kami [ayahku]. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibnu Al Mutsanna], telah menceritakan kepada kami [Yahya bin Al Fayyadh], telah menceritakan kepada kami [Hammam] dari [Qatadah], ia berkata; tidak ada penimbunan dalam kurma. Ibnu Al Mutsanna berkata dari [Al Hasan], kemudian kami katakan kepadanya; jangan engkau katakan; dari Al Hasan! Abu Daud berkata; hadits ini menurut kami adalah batil. Abu Daud berkata; dahulu Sa'id bin Al Musayyab menimbun biji kurma, dedaunan yang berguguran, serta bebijian. Dan aku mendengar Ahmad bin Yunus berkata; aku mendengar Sufyan mengenai menimbun Al Qatt (jenis tumbuh-tumbuhan), ia berkata; dahulu mereka tidak suka menimbun. Dan aku bertanya kepada Abu Bakr bin 'Ayyasy, kemudian ia berkata; timbunlah! "},"2914":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ فَضَاءٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُكْسَرَ سِكَّةُ الْمُسْلِمِينَ الْجَائِزَةُ بَيْنَهُمْ إِلَّا مِنْ بَأْسٍ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Mu'tamir], ia berkata; saya mendengar [Muhammad bin Fadha`] menceritakan dari [ayahnya] dari ['Alqamah bin Abdullah] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang untuk memecah mata uang muslimin yang diperbolehkan diantara mereka kecuali karena perkara yang mengharuskannya. "},"2915":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ أَنَّ سُلَيْمَانَ بْنَ بِلَالٍ حَدَّثَهُمْ قَالَ حَدَّثَنِي الْعَلَاءُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا جَاءَ فَقَالَ يَا رَسُولَ اللَّهِ سَعِّرْ فَقَالَ بَلْ أَدْعُو ثُمَّ جَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ سَعِّرْ فَقَالَ بَلْ اللَّهُ يَخْفِضُ وَيَرْفَعُ وَإِنِّي لَأَرْجُو أَنْ أَلْقَى اللَّهَ وَلَيْسَ لِأَحَدٍ عِنْدِي مَظْلَمَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Utsman Ad Dimasyqi] bahwa [Sulaiman bin Bilal] telah menceritakan kepada mereka, ia berkata; telah menceritakan kepadaku [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] bahwa seseorang datang dan berkata; wahai Rasulullah, tetapkanlah harga! Kemudian beliau berkata: \"Allahlah yang menurunkan dan menaikkan, dan sesungguhnya aku berharap untuk bertemu dengan Allah sementara aku tidak memiliki dosa kezhaliman kepada seorangpun.\""},"2916":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ وَقَتَادَةُ وَحُمَيْدٌ عَنْ أَنَسٍ قَالَالنَّاسُ يَا رَسُولَ اللَّهِ غَلَا السِّعْرُ فَسَعِّرْ لَنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ هُوَ الْمُسَعِّرُ الْقَابِضُ الْبَاسِطُ الرَّازِقُ وَإِنِّي لَأَرْجُو أَنْ أَلْقَى اللَّهَ وَلَيْسَ أَحَدٌ مِنْكُمْ يُطَالِبُنِي بِمَظْلَمَةٍ فِي دَمٍ وَلَا مَالٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah?], telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Maslamah], telah mengabarkan kepada kami [Tsabit] dari [Anas bin Malik] dan [Qatadah], serta [Humaid] dari [Anas], orang-orang berkata; wahai Rasulullah, harta telah melonjang, maka tetapkanlah harga untuk kami! Maka beliau berkata: \"Sesungguhnya Allahlah yang menentukan harga, Yang menggenggam dan Yang menghamparkan, dan Pemberi rizqi. Dan sungguh aku berharap berjumpa dengan Allah sementara tidak ada seorang pun dari kalian yang menuntutku karena suatu kezhaliman dalam hal darah, dan harta.\""},"2917":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِرَجُلٍ يَبِيعُ طَعَامًا فَسَأَلَهُ كَيْفَ تَبِيعُ فَأَخْبَرَهُ فَأُوحِيَ إِلَيْهِ أَنْ أَدْخِلْ يَدَكَ فِيهِ فَأَدْخَلَ يَدَهُ فِيهِ فَإِذَا هُوَ مَبْلُولٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ غَشَّحَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ عَنْ عَلِيٍّ عَنْ يَحْيَى قَالَ كَانَ سُفْيَانُ يَكْرَهُ هَذَا التَّفْسِيرَ لَيْسَ مِنَّا لَيْسَ مِثْلَنَا","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal], telah menceritakan kepada kami [Sufyan bin 'Uyainah], dari [Al 'Ala`] dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam melewati seorang laki-laki yang membeli makanan, kemudian ia bertanya kepadanya; bagaimana engkau berjualan? Kemudian orang tersebut memberitahukan kepada beliau bagaimana ia berjualan. Kemudian Rasulullah shallallahu 'alaihi wasallam diberi wahyu; masukkan tanganmu ke dalam makanan tersebut! Kemudian beliau memasukkan tangannya ke dalamnya, dan ternyata makanan tersebut basah. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan dari golongan kami orang yang menipu.\""},"2918":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُتَبَايِعَانِ كُلُّ وَاحِدٍ مِنْهُمَا بِالْخِيَارِ عَلَى صَاحِبِهِ مَا لَمْ يَفْتَرِقَا إِلَّا بَيْعَ الْخِيَارِحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ أَوْ يَقُولُ أَحَدُهُمَا لِصَاحِبِهِ اخْتَرْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang saling berjual beli, keduanya memiliki hak memilih terhadap sahabatnya selama mereka belum berpisah. Kecuali jual beli dengan syarat memiliki hak memilih.\" Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan maknanya, ia berkata; atau salah seorang diantara mereka berdua berkata kepada sahabatnya; pilihlah. "},"2919":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُتَبَايِعَانِ بِالْخِيَارِ مَا لَمْ يَفْتَرِقَا إِلَّا أَنْ تَكُونَ صَفْقَةَ خِيَارٍ وَلَا يَحِلُّ لَهُ أَنْ يُفَارِقَ صَاحِبَهُ خَشْيَةَ أَنْ يَسْتَقِيلَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari ['Amr bin Syu'aib] dari [ayahnya] dari [Abdullah bin 'Amr bin Al 'Ash] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang saling berjual beli memiliki hak memilih selama mereka belum berpisah, kecuali jual beli tersebut adalah jual beli dengan syarat adanya hak memilih, dan tidak halal baginya untuk meninggalkan sahabatnya karena khawatir membatalkan jual beli.\""},"2920":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ عَنْ جَمِيلِ بْنِ مُرَّةَ عَنْ أَبِي الْوَضِيءِ قَالَغَزَوْنَا غَزْوَةً لَنَا فَنَزَلْنَا مَنْزِلًا فَبَاعَ صَاحِبٌ لَنَا فَرَسًا بِغُلَامٍ ثُمَّ أَقَامَا بَقِيَّةَ يَوْمِهِمَا وَلَيْلَتِهِمَا فَلَمَّا أَصْبَحَا مِنْ الْغَدِ حَضَرَ الرَّحِيلُ فَقَامَ إِلَى فَرَسِهِ يُسْرِجُهُ فَنَدِمَ فَأَتَى الرَّجُلَ وَأَخَذَهُ بِالْبَيْعِ فَأَبَى الرَّجُلُ أَنْ يَدْفَعَهُ إِلَيْهِ فَقَالَ بَيْنِي وَبَيْنَكَ أَبُو بَرْزَةَ صَاحِبُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيَا أَبَا بَرْزَةَ فِي نَاحِيَةِ الْعَسْكَرِ فَقَالَا لَهُ هَذِهِ الْقِصَّةَ فَقَالَ أَتَرْضَيَانِ أَنْ أَقْضِيَ بَيْنَكُمَا بِقَضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَاقَالَ هِشَامُ بْنُ حَسَّانَ حَدَّثَ جَمِيلٌ أَنَّهُ قَالَ مَا أَرَاكُمَا افْتَرَقْتُمَا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Hammad] dari [Jamil bin Murrah], dari [Abu Al Wadhi`], ia berkata; kami melakukan peperangan kami, kemudian kami singgah di suatu tempat. Kemudian seorang sahabat kami menjual kuda dengan seorang budak. Kemudian mereka berdua tinggal pada sisa hari dan malam mereka berdua. Kemudian pada keesokan hari pasukan datang, kemudian pergi kepada kudanya untuk memberinya pelana. Maka ia merasa menyesal, lalu ia datang kepada laki-laki pemilik budak tersebut dan ingin membeli kuda tersebut. Lalu laki-laki pemilik budak tersebut menolak untuk menyerahkannya kepadanya. Lalu ia berkata; antaraku dan dirimu terdapat [Abu Barzah] seorang sahabat Nabi shallallahu 'alaihi wasallam. kemudian mereka berdua datang kepada Abu Barzah di pinggir pasukan. Kemudian mereka berdua menceritakan kisah ini kepadanya. Lalu ia berkata; apakah kalian berdua rela aku putuskan diantara kalian berdua dengan keputusan Rasulullah shallallahu 'alaihi wasallam? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang saling berjual beli memiliki hak memilih selama belum berpisah.\" [Hisyam bin Hassan] berkata; telah menceritakan kepada kami [Jamil] bahwa ia berkata; aku melihat kalian berdua tidak berpisah. "},"2921":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمٍ الْجَرْجَرَائِيُّ قَالَ مَرْوَانُ الْفَزَارِيُّ أَخْبَرَنَا عَنْ يَحْيَى بْنِ أَيُّوبَ قَالَكَانَ أَبُو زُرْعَةَ إِذَا بَايَعَ رَجُلًا خَيَّرَهُ قَالَ ثُمَّ يَقُولُ خَيِّرْنِي وَيَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَفْتَرِقَنَّ اثْنَانِ إِلَّا عَنْ تَرَاضٍ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim Al Jarjarai], ia berkata; [Marwan Al Fazari] telah mengabarkan kepada kami, dari [Yahya bin Ayyub], ia berkata; [Abu Zur'ah] apabila melakukan jual beli dengan seseorang maka ia memberinya kebebasan memilih. Kemudian ia berkata; berilah aku kebebasan memilih! Dan ia berkata; aku mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah dua orang berpisah kecuali dengan saling rela.\""},"2922":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ حَكِيمِ بْنِ حِزَامٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَفْتَرِقَا فَإِنْ صَدَقَا وَبَيَّنَا بُورِكَ لَهُمَا فِي بَيْعِهِمَا وَإِنْ كَتَمَا وَكَذَبَا مُحِقَتْ الْبَرَكَةُ مِنْ بَيْعِهِمَاقَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ سَعِيدُ بْنُ أَبِي عَرُوبَةَ وَحَمَّادٌ وَأَمَّا هَمَّامٌ فَقَالَ حَتَّى يَتَفَرَّقَا أَوْ يَخْتَارَا ثَلَاثَ مِرَارٍ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah], dari [Qatadah] dari [Abu Al Khalil] dari [Abdullah bin Al Harits] dari [Hakim bin Hizam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang saling berjual beli memiliki khiyar (hak memilih) selama mereka belum berpisah. Apabila mereka jujur dan memberikan penjelasan (terus terang dalam muamalah mereka), maka mereka akan diberi berkah dalam jual beli mereka. Dan apabila mereka menyembunyikan kekurangan dan berdusta, maka berkah akan terhapus dari jual beli mereka.\" Abu Daud berkata; dan demikianlah hadits tersebut diriwayatkan oleh [Sa'id bin Abu 'Arubah], dan [Hammad]. Adapun [Hammam], ia berkata; hingga mereka berpisah, atau memilih tiga kali. "},"2923":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا حَفْصٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَقَالَ مُسْلِمًا أَقَالَهُ اللَّهُ عَثْرَتَهُ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in] telah menceritakan kepada kami [Hafsh] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberikan persetujuan kepada seorang muslim untuk membatalkan jual belinya, maka Allah akan mengapuni kesalahannya.\""},"2924":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ عَنْ يَحْيَى بْنِ زَكَرِيَّا عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَاعَ بَيْعَتَيْنِ فِي بَيْعَةٍ فَلَهُ أَوْكَسُهُمَا أَوْ الرِّبَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dari [Yahya bin Zakaria] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melakukan dua transaksi dalam satu transaksi maka baginya kekurangannya atau riba.\""},"2925":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي حَيْوَةُ بْنُ شُرَيْحٍ ح و حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ التِّنِّيسِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَحْيَى الْبُرُلُّسِيُّ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ عَنْ إِسْحَقَ أَبِي عَبْدِ الرَّحْمَنِ قَالَ سُلَيْمَانُ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْخُرَاسَانِيِّ أَنَّ عَطَاءً الْخُرَاسَانِيَّ حَدَّثَهُ أَنَّ نَافِعًا حَدَّثَهُ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا تَبَايَعْتُمْ بِالْعِينَةِ وَأَخَذْتُمْ أَذْنَابَ الْبَقَرِ وَرَضِيتُمْ بِالزَّرْعِ وَتَرَكْتُمْ الْجِهَادَ سَلَّطَ اللَّهُ عَلَيْكُمْ ذُلًّا لَا يَنْزِعُهُ حَتَّى تَرْجِعُوا إِلَى دِينِكُمْقَالَ أَبُو دَاوُد الْإِخْبَارُ لِجَعْفَرٍ وَهَذَا لَفْظُهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Haiwah bin Syuraih]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ja'far bin Musafir At Tinnisi] telah menceritakan kepada kami [Abdullah bin Yahya Al Burullussi] telah menceritakan kepada kami [Haiwah bin Syuraih] dari [Ishaq bin Abu Abdurrahman] dan [Sulaiman] berkata dari [Abu Abdurrahman Al Khurasani] bahwa ['Atha Al Khurasani] menceritakan kepadanya bahwa [Nafi'] telah menceritakan kepadanya dari [Ibnu Umar] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian berjual beli secara cara 'inah, mengikuti ekor sapi, ridla dengan bercocok tanam dan meninggalkan jihad, maka Allah akan menguasakan kehinaan atas kalian. Allah tidak akan mencabutnya dari kalian hingga kalian kembali kepada agama kalian.\" Abu Daud berkata, \"Ini adalah riwayat Ja'far, dan hadits ini adalah lafadznya.\""},"2926":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ أَبِي الْمِنْهَالِ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَهُمْ يُسْلِفُونَ فِي التَّمْرِ السَّنَةَ وَالسَّنَتَيْنِ وَالثَّلَاثَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَسْلَفَ فِي تَمْرٍ فَلْيُسْلِفْ فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Sufyan] dari [Ibnu Najih] dari [Abdullah bin Katsir] dari [Abu Al Minhal] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam datang ke Madinah sementara penduduk Madinah menghutangkan kurma selama satu tahun, dua tahun serta tiga tahun. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menghutangkan kurma, maka hendaknya ia menghutangkan dalam takaran yang diketahui, dan timbangan yang diketahui serta tempo yang diketahui.\"\""},"2927":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا ابْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنِي مُحَمَّدٌ أَوْ عَبْدُ اللَّهِ بْنُ مُجَالِدٍ قَالَاخْتَلَفَ عَبْدُ اللَّهِ بْنُ شَدَّادٍ وَأَبُو بُرْدَةَ فِي السَّلَفِ فَبَعَثُونِي إِلَى ابْنِ أَبِي أَوْفَى فَسَأَلْتُهُ فَقَالَ إِنْ كُنَّا نُسْلِفُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ فِي الْحِنْطَةِ وَالشَّعِيرِ وَالتَّمْرِ وَالزَّبِيبِ زَادَ ابْنُ كَثِيرٍ إِلَى قَوْمٍ مَا هُوَ عِنْدَهُمْ ثُمَّ اتَّفَقَا وَسَأَلْتُ ابْنَ أَبْزَي فَقَالَ مِثْلَ ذَلِكَحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى وَابْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْمُجَالِدِ وَقَالَ عَبْدُ الرَّحْمَنِ عَنْ ابْنِ أَبِي الْمُجَالِدِ بِهَذَا الْحَدِيثِ قَالَ عِنْدَ قَوْمٍ مَا هُوَ عِنْدَهُمْ قَالَ أَبُو دَاوُد الصَّوَابُ ابْنُ أَبِي الْمُجَالِدِ وَشُعْبَةُ أَخْطَأَ فِيهِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Katsir] telah mengabarkan kepada kami [Syu'bah] telah mengabarkan kepadaku [Muhammad atau Abdullah bin Mujalid] ia berkata, \"Abdullah bin Syaddad dan Abu Burdah berselisih mengenai jual beli salaf. Kemudian mereka mengirim aku kepada Ibnu Abu Aufa untuk bertanya kepadanya. [Ibnu Abu Aufa] lalu berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar kami pernah menjual jewawut, kurma dan kismis secara salaf - [Ibnu Katsir] menambahkan- kepada suatu kaum yang tidak memiliki barang tersebut -Kemudian keduanya sepakat pada lafazh-, dan aku bertanya kepada [Ibnu Abza], lalu ia mengatakan seperti itu.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Yahya] dan [Ibnu Mahdi] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu Al Mujalid] dan Abdurrahman menyebutkan hadits ini dari Ibnu Abu Al Mujalid. Ia berkata, \"Pada suatu kaum yang tidak memiliki barang tersebut.\" Abu Daud berkata, \"Yang benar adalah Ibnu Abu Al Mujalid, dan Syu'bah dalam hal ini.\" "},"2928":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي غَنِيَّةَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى الْأَسْلَمِيِّ قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّامَ فَكَانَ يَأْتِينَا أَنْبَاطٌ مِنْ أَنْبَاطِ الشَّامِ فَنُسْلِفُهُمْ فِي الْبُرِّ وَالزَّيْتِ سِعْرًا مَعْلُومًا وَأَجَلًا مَعْلُومًا فَقِيلَ لَهُ مِمَّنْ لَهُ ذَلِكَ قَالَ مَا كُنَّا نَسْأَلُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa] telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Abdul Malik bin Abu Ghaniyyah] telah menceritakan kepadaku [Abu Ishaq] dari [Abdullah bin Abu Aufa Al Aslami] ia berkata, \"Kami berperang bersama Rasulullah shallallahu 'alaihi wasallam di Syam. Dahulu para pedagang Syam datang kepada kami, lalu kami menjual gandum dan minyak secara salam dengan harga yang diketahui, dan tempo yang diketahui.\" Ia ditanya, \"Dari mana ia mendapatkan riwayat itu?\" Ia menjawab, \"Kami tidak bertanya kepada mereka. "},"2929":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ رَجُلٍ نَجْرَانِيٍّ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا أَسْلَفَ رَجُلًا فِي نَخْلٍ فَلَمْ تُخْرِجْ تِلْكَ السَّنَةَ شَيْئًا فَاخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بِمَ تَسْتَحِلُّ مَالَهُ ارْدُدْ عَلَيْهِ مَالَهُ ثُمَّ قَالَ لَا تُسْلِفُوا فِي النَّخْلِ حَتَّى يَبْدُوَ صَلَاحُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dari [seorang Najran] dari [Ibnu Umar] bahwa seorang laki-laki telah menjual kurma kepada seseorang secara salaf. Kemudian pada tahun itu, pohon kurma tersebut tidak berbuah sedikitpun. Lalu mereka mengadukan kepada Nabi shallallahu 'alaihi wasallam, beliau lalu menjawab: \"Dengan alasan apakah engkau menghalalkan hartanya? Kembalikan harta tersebut kepadanya!\" Kemudian beliau berkata: \"Janganlah kalian menjual kurma dalam pohon secara salaf hingga nampak kematangannya buah tersebut!\" "},"2930":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو بَدْرٍ عَنْ زِيَادِ بْنِ خَيْثَمَةَ عَنْ سَعْدٍ يَعْنِي الطَّائِيَّ عَنْ عَطِيَّةَ بْنِ سَعْدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَسْلَفَ فِي شَيْءٍ فَلَا يَصْرِفْهُ إِلَى غَيْرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu Badr] dari [Ziyad bin Khaitsamah] dari [Sa'd Ath Thai] dari ['Athiyyah bin Sa'dan] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjual sesuatu secara salaf, maka janganlah ia mengalihkannya kepada pihak lain.\""},"2931":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَأُصِيبَ رَجُلٌ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثِمَارٍ ابْتَاعَهَا فَكَثُرَ دَيْنُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَصَدَّقُوا عَلَيْهِ فَتَصَدَّقَ النَّاسُ عَلَيْهِ فَلَمْ يَبْلُغْ ذَلِكَ وَفَاءَ دَيْنِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذُوا مَا وَجَدْتُمْ وَلَيْسَ لَكُمْ إِلَّا ذَلِكَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Bukair] dari ['Iyadl bin Abdullah] dari [Abu Sa'id Al Khudri] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam ada seorang laki-laki mengalami kerugian pada buah kurma yang ia beli sehingga hutangnya menjadi banyak. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Bersedekahlah kalian kepadanya!\" Maka orang-orang pun bersedekah kepadanya, namun hal itu belum dapat membayar hutangnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah apa yang kalian dapatkan, kalian tidak memiliki sesutupun kecuali hal tersebut.\""},"2932":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ وَأَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ الْمَعْنَى أَنَّ أَبَا الزُّبَيْرِ الْمَكِّيَّ أَخْبَرَهُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ بِعْتَ مِنْ أَخِيكَ تَمْرًا فَأَصَابَتْهَا جَائِحَةٌ فَلَا يَحِلُّ لَكَ أَنْ تَأْخُذَ مِنْهُ شَيْئًا بِمَ تَأْخُذُ مَالَ أَخِيكَ بِغَيْرِ حَقٍّ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] dan [Ahmad bin Sa'id Al Mahdani] mereka berkata; telah mengabarkan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Ibnu Juraij]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Ma'mar] telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] secara makna, bahwa [Abu Az Zubair Al Makki] mengabarkan kepadanya dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau menjual kurma kepada saudaramu kemudian kurma tersebut rusak, maka tidak halal bagimu untuk mengambil sesuatupun darinya, dengan alasan apakah engkau mengambil harta saudaramu tidak dengan hak.\""},"2933":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عُثْمَانُ بْنُ الْحَكَمِ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَالْجَوَائِحُ كُلُّ ظَاهِرٍ مُفْسِدٍ مِنْ مَطَرٍ أَوْ بَرَدٍ أَوْ جَرَادٍ أَوْ رِيحٍ أَوْ حَرِيقٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Utsman bin Al Hakam] dari [Ibnu Juraij] dari ['Atha] ia berkata, \"Jaihah adalah setiap fenomena yang merusak, berupa hujan, musim dingin, belalang atau angin atau kebakaran.\""},"2934":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عُثْمَانُ بْنُ الْحَكَمِ عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّهُ قَالَلَا جَائِحَةَ فِيمَا أُصِيبَ دُونَ ثُلُثِ رَأْسِ الْمَالِقَالَ يَحْيَى وَذَلِكَ فِي سُنَّةِ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Utsman bin Al Hakam] dari [Yahya bin Sa'id] bahwa ia berkata, \"Tidak disebut jaihah jika musibah yang menimpa tanaman itu kurang dari dari sepertiga modal.\" Yahya berkata, \"Ini adalah sesuatu yang biasa di antara orang-orang Muslim.\" "},"2935":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُمْنَعُ فَضْلُ الْمَاءِ لِيُمْنَعَ بِهِ الْكَلَأُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh menahan kelebihan air untuk menghalangi tumbuhnya rumput.\""},"2936":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ يَوْمَ الْقِيَامَةِ رَجُلٌ مَنَعَ ابْنَ السَّبِيلِ فَضْلَ مَاءٍ عِنْدَهُ وَرَجُلٌ حَلَفَ عَلَى سِلْعَةٍ بَعْدَ الْعَصْرِ يَعْنِي كَاذِبًا وَرَجُلٌ بَايَعَ إِمَامًا فَإِنْ أَعْطَاهُ وَفَى لَهُ وَإِنْ لَمْ يُعْطِهِ لَمْ يَفِ لَهُحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ وَقَالَ فِي السِّلْعَةِ بِاللَّهِ لَقَدْ أُعْطِيَ بِهَا كَذَا وَكَذَا فَصَدَّقَهُ الْآخَرُ فَأَخَذَهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang tidak Allah ajak bicara kepada mereka pada Hari Kiamat; seorang laki-laki yang menghalangi Ibnu Sabil untuk mendapatkan kelebihan air yang ada padanya, seorang laki-laki yang bersumpah palsu untuk menjual barang setelah 'Ashar, dan seorang laki-laki yang membai'at seorang imam, apabila Imam tersebut memberi sesuatu kepadanya maka ia penuhi haknya, namun jika Imam tersebut tidak memberi maka ia tidak memenuhi haknya.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dengan sanad dan maknanya. Ia sebutkan, \"Tidak mensucikan mereka dan bagi mereka siksa yang pedih.\" Ia juga menyebutkan, \"(bersumpah) dengan Allah, 'Sungguh aku diberi tawaran sekian dan sekian'. Lalu orang pun percaya dan membelinya.\""},"2937":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا كَهْمَسٌ عَنْ سَيَّارِ بْنِ مَنْظُورٍ رَجُلٌ مِنْ بَنِي فَزَارَةَ عَنْ أَبِيهِ عَنْ امْرَأَةٍ يُقَالُ لَهَا بُهَيْسَةُ عَنْ أَبِيهَا قَالَتْاسْتَأْذَنَ أَبِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ بَيْنَهُ وَبَيْنَ قَمِيصِهِ فَجَعَلَ يُقَبِّلُ وَيَلْتَزِمُ ثُمَّ قَالَ يَا نَبِيَّ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمَاءُ قَالَ يَا نَبِيَّ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمِلْحُ قَالَ يَا نَبِيَّ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ أَنْ تَفْعَلَ الْخَيْرَ خَيْرٌ لَكَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Kahmas] dari [Sayyar bin Manzhur] seorang laki-laki dari Bani Fazarah, dari [Ayahnya] dari seorang wanita yang dipanggil [Buhaisah] dari [Ayahnya] ia berkata, \"Ayahku minta izin kepada Nabi shallallahu 'alaihi wasallam, kemudian ia masuk di antara badan dan jubahnya, lalu mencium dan merangkulnya. Kemudian ia berkata, \"Wahai Nabi Allah, apakah yang tidak boleh untuk ditahan?\" Beliau menjawab: \"Air.\" Ia bertanya lagi, \"Wahai Nabi Allah, apakah yang tidak boleh untuk ditahan?\" Beliau menjawab: \"Garam.\" Ia bertanya lagi, \"Wahai Nabi Allah, apakah yang tidak boleh untuk ditahan?\" Beliau menjawab: \"Engkau berbuat kebaikan lebih baik bagimu.\""},"2938":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ اللُّؤْلُؤِيُّ أَخْبَرَنَا حَرِيزُ بْنُ عُثْمَانَ عَنْ حِبَّانَ بْنِ زَيْدٍ الشَّرْعَبِيِّ عَنْ رَجُلٍ مِنْ قَرْنٍ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ حَدَّثَنَا أَبُو خِدَاشٍ وَهَذَا لَفْظُ عَلِيٍّ عَنْ رَجُلٍ مِنْ الْمُهَاجِرِينَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا أَسْمَعُهُ يَقُولُ الْمُسْلِمُونَ شُرَكَاءُ فِي ثَلَاثٍ فِي الْكَلَإِ وَالْمَاءِ وَالنَّارِ","id":"Telah menceritakan kepada kami [Ali bin Al Ja'dan Al Lu`lui] telah mengabarkan kepada kami [Hariz bin Utsman] dari [Hibban bin Zaid Asy Syar'i] dari [seorang laki-laki Qarn]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Hariz bin Utsman] telah menceritakan kepada kami [Abu Khidasy] dan ini adalah lafazh Ali, dari [seorang laki-laki Muhajirin] sahabat Nabi shallallahu 'alaihi wasallam, ia berkata, \"Aku pernah berperang bersama Nabi shallallahu 'alaihi wasallam tiga kali, aku mendengar beliau bersabda: \"Orang-orang Muslim bersekutu dalam hal rumput, air dan api.\""},"2939":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنِ الْعَطَّارُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الْمِنْهَالِ عَنْ إِيَاسِ بْنِ عَبْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ فَضْلِ الْمَاءِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Daud bin Abdurrahman Al 'Aththar] dari ['Amru bin Dinar] dari [Abu Al Minhal] dari [Iyas bin Abdu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang menjual kelebihan air.\""},"2940":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ ح و حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ وَعَلِيُّ بْنُ بَحْرٍ قَالَا حَدَّثَنَا عِيسَى وَقَالَ إِبْرَاهِيمُ أَخْبَرَنَا عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الْكَلْبِ وَالسِّنَّوْرِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ar Rabi' bin Nafi' Abu Taubah] dan [Ali bin Bahr] mereka berkata; telah menceritakan kepada kami [Isa] dan [Ibrahim] telah mengabarkan kepada kami dari [Al A'masy] dari [Abu Sufyan] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam melarang uang dari hasil penjualan anjing serta kucing.\""},"2941":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا عُمَرُ بْنُ زَيْدٍ الصَّنْعَانِيُّ أَنَّهُ سَمِعَ أَبَا الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الْهِرَّةِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Umar bin Zaid Ash Shan'ani] bahwa ia mendengar [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari hasil penjualan kucing.\""},"2942":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Bakr bin Abdurrahman] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau melarang dari hasil penjualan anjing, upah pezina dan dukun.\""},"2943":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عَمْرٍو عَنْ عَبْدِ الْكَرِيمِ عَنْ قَيْسِ بْنِ حَبْتَرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَإِنْ جَاءَ يَطْلُبُ ثَمَنَ الْكَلْبِ فَامْلَأْ كَفَّهُ تُرَابًا","id":"Telah menceritakan kepada kami [Ar Rabi' bin Nafi' Abu Taubah] telah menceritakan kepada kami ['Ubaidullah bin 'Amru] dari [Abdul Karim] dari [Qais bin Habtar] dari [Abdullah bin Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari hasil penjualan anjing, dan jika penjual tersebut datang meminta uang penjualan anjing maka penuhilah telapak tangannya dengan tanah.\""},"2944":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَوْنُ ابْنُ أَبِي جُحَيْفَةَ أَنَّ أَبَاهُ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الْكَلْبِ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku ['Aun bin Abu Juhaifah] bahwa [Ayahnya] berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang dari hasil penjualan anjing.\""},"2945":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي مَعْرُوفُ بْنُ سُوَيْدٍ الْجُذَامِيُّ أَنَّ عُلَيَّ بْنَ رَبَاحٍ اللَّخْمِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ ثَمَنُ الْكَلْبِ وَلَا حُلْوَانُ الْكَاهِنِ وَلَا مَهْرُ الْبَغِيِّ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Ma'ruf bin Suwaid Al Judzami] bahwa [Ali bin Rabah Al Lakhmi] telah menceritakan kepadanya, bahwa ia mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal uang hasil penjualan anjing, upah dukun dan upah pezina.\""},"2946":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَبْدِ الْوَهَّابِ بْنِ بُخْتٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ حَرَّمَ الْخَمْرَ وَثَمَنَهَا وَحَرَّمَ الْمَيْتَةَ وَثَمَنَهَا وَحَرَّمَ الْخِنْزِيرَ وَثَمَنَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Abdul Wahhab bin Bukht] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah mengharamkan khamer dan uang penjualannya, mengharamkan bangkai serta uang hasil penjualannya, serta mengharamkan babi dan uang hasil penjualannya.\""},"2947":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَامَ الْفَتْحِ وَهُوَ بِمَكَّةَ إِنَّ اللَّهَ حَرَّمَ بَيْعَ الْخَمْرِ وَالْمَيْتَةَ وَالْخِنْزِيرَ وَالْأَصْنَامَ فَقِيلَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ شُحُومَ الْمَيْتَةِ فَإِنَّهُ يُطْلَى بِهَا السُّفُنُ وَيُدْهَنُ بِهَا الْجُلُودُ وَيَسْتَصْبِحُ بِهَا النَّاسُ فَقَالَ لَا هُوَ حَرَامٌ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ قَاتَلَ اللَّهُ الْيَهُودَ إِنَّ اللَّهَ لَمَّا حَرَّمَ عَلَيْهِمْ شُحُومَهَا أَجْمَلُوهُ ثُمَّ بَاعُوهُ فَأَكَلُوا ثَمَنَهُحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ قَالَ كَتَبَ إِلَيَّ عَطَاءٌ عَنْ جَابِرٍ نَحْوَهُ لَمْ يَقُلْ هُوَ حَرَامٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari ['Atha bin Abu Rabah] dari [Jabir bin Abdullah] bahwa saat ia sedang berada di Makkah ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada saat penaklukan Makkah: \"Sesungguhnya Allah telah mengharamkan penjualan arak, bangkai, babi, serta berhala.\" Kemudian beliau ditanya, \"Wahai Rasulullah, bagaimana pendapat anda tentang lemak bangkai, sesungguhnya lemak biasa digunakan untuk mengecat perahu, meminyaki kulit dan menyalakan lampu?\" Beliau bersabda: \"Tidak boleh, karena ia adalah haram.\" Beliau menambahkan: \"Semoga Allah memerangi orang-orang Yahudi, ketika Allah mengharamkan lemak, mereka mencairkannya kemudian menjualnya dan memakan hasil penjualannya.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu 'Ashim] dari [Abdul Hamid bin Ja'far] dari [Yazid bin Abu Habib] ia berkata, \" ['Atha] menulis surat kepadaku dari [Jabir] seperti itu, namun ia tidak menyebutkan bahwa lemak adalah haram.\""},"2948":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ بِشْرَ بْنَ الْمُفَضَّلِ وَخَالِدَ بْنَ عَبْدِ اللَّهِ حَدَّثَاهُمْ الْمَعْنَى عَنْ خَالِدٍ الْحَذَّاءِ عَنْ بَرَكَةَ قَالَ مُسَدَّدٌ فِي حَدِيثِ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ بَرَكَةَ أَبِي الْوَلِيدِ ثُمَّ اتَّفَقَا عَنْ ابْنِ عَبَّاسٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا عِنْدَ الرُّكْنِ قَالَ فَرَفَعَ بَصَرَهُ إِلَى السَّمَاءِ فَضَحِكَ فَقَالَ لَعَنَ اللَّهُ الْيَهُودَ ثَلَاثًا إِنَّ اللَّهَ حَرَّمَ عَلَيْهِمْ الشُّحُومَ فَبَاعُوهَا وَأَكَلُوا أَثْمَانَهَا وَإِنَّ اللَّهَ إِذَا حَرَّمَ عَلَى قَوْمٍ أَكْلَ شَيْءٍ حَرَّمَ عَلَيْهِمْ ثَمَنَهُ وَلَمْ يَقُلْ فِي حَدِيثِ خَالِدِ بْنِ عَبْدِ اللَّهِ الطَّحَّانِ رَأَيْتُ وَقَالَ قَاتَلَ اللَّهُ الْيَهُودَ","id":"Telah menceritakan kepada kami [Musaddad] bahwa [Bisyr bin Al Mufadldlal] dan [Khalid bin Abdullah] telah mengabarkan kepada mereka secara makna, dari [Khalid Al Hadzdza`] dari [Barakah] -Musaddad menyebutkan dalam hadits Khalid bin Abdullah; dari Barakah Abu Al Walid, kemudian keduanya sepakat- dari [Ibnu Abbas] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam sedang duduk di rukun. Kemudian beliau mengangkat pandangannya ke langit seraya tertawa. Beliau bersabda: \"Semoga Allah melaknat orang-orang Yahudi -Beliau mengucapkannya sebanyak tiga kali-, sesungguhnya Allah telah mengharamkan lemak atas mereka, kemudian mereka menjual dan memakan hasil penjualannya. Sungguh, jika Allah telah mengharamkan suatu kaum untuk memakan sesuatu, maka Allah pun mengharamkan hasil penjualannya.\" Namun dalam hadits Khalid bin Abdullah Ath Thahhan tidak disebutkan lafadz, \"Aku melihat.\" Beliau mengatakan: \"Semoga Allah melaknat orang-orang yahudi.\""},"2949":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ وَوَكِيعٌ عَنْ طُعْمَةَ بْنِ عَمْرٍو الْجَعْفَرِيِّ عَنْ عُمَرَ بْنِ بَيَانٍ التَّغْلِبِيِّ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَاعَ الْخَمْرَ فَلْيُشَقِّصْ الْخَنَازِيرَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] ia berkata; telah menceritakan kepada kami [Ibnu Idris] dan [Waki'] dari [Thu'mah bin 'Amru Al Ja'fari] dari [Umar bin Bayan At Taghlabi] dari ['Urwah bin Al Mughirah bin Syu'bah] dari [Al Mughirah bin Syu'bah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjual arak, maka hendaknya ia menghalalkan babi!\""},"2950":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ الْآيَاتُ الْأَوَاخِرُ مِنْ سُورَةِ الْبَقَرَةِ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُنَّ عَلَيْنَا وَقَالَ حُرِّمَتْ التِّجَارَةُ فِي الْخَمْرِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ الْآيَاتُ الْأَوَاخِرُ فِي الرِّبَا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Adl Dluha] dari [Masruq] dari [Aisyah] ia berkata, \"Tatkala beberapa ayat terakhir Surat Al Baqarah turun Rasulullah shallallahu 'alaihi wasallam keluar dan membacakannya kepada kami. Beliau bersabda: \"Perdagangan arak telah diharamkan.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dengan sanad dan maknanya, ia berkata, \"Yaitu ayat-ayat terakhir mengenai riba.\""},"2951":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَسْتَوْفِيَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli makanan, maka janganlah ia menjualnya hingga ia menerimanya.\""},"2952":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ قَالَكُنَّا فِي زَمَنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبْتَاعُ الطَّعَامَ فَيَبْعَثُ عَلَيْنَا مَنْ يَأْمُرُنَا بِانْتِقَالِهِ مِنْ الْمَكَانِ الَّذِي ابْتَعْنَاهُ فِيهِ إِلَى مَكَانٍ سِوَاهُ قَبْلَ أَنْ نَبِيعَهُ يَعْنِي جُزَافًا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami membeli makanan, kemudian beliau memerintahkan kepada dengan mengutus seseorang agar kami memindahkan makanan tersebut dari tempat kami membelinya ke tempat lain, sebelum kami menjualnya dengan tanpa penakaran dan penimbangan.\""},"2953":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَكَانُوا يَتَبَايَعُونَ الطَّعَامَ جُزَافًا بِأَعْلَى السُّوقِ فَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعُوهُ حَتَّى يَنْقُلُوهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] ia berkata, \"Dahulu orang-orang berjual beli makanan dengan tanpa penakaran dan panimbangan di atas pasar, kemudian Rasulullah shallallahu 'alaihi wasallam melarangnya hingga mereka memindahkannya.\""},"2954":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا عَمْرٌو عَنْ الْمُنْذِرِ بْنِ عُبَيْدٍ الْمَدِينِيِّ أَنَّ الْقَاسِمَ بْنَ مُحَمَّدٍ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَبِيعَ أَحَدٌ طَعَامًا اشْتَرَاهُ بِكَيْلٍ حَتَّى يَسْتَوْفِيَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepada kami ['Amru] dari [Al Mundzir bin 'Ubaid Al Madini] bahwa [Al Qasim bin Muhammad] telah menceritakan kepadanya, bahwa [Abdullah bin Umar] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam melarang seseorang menjual makanan yang telah ia beli dengan takaran hingga ia menerima makanan tersebut.\""},"2955":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ وَعُثْمَانُ ابْنَا أَبِي شَيْبَةَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَكْتَالَهُزَادَ أَبُو بَكْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍ لِمَ قَالَ أَلَا تَرَى أَنَّهُمْ يَتَبَايَعُونَ بِالذَّهَبِ وَالطَّعَامُ مُرَجًّى","id":"Telah menceritakan kepada kami [Abu Bakr] serta [Utsman] keduanya adalah anak Abu Syaibah, mereka berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ibnu Thawus] dari [Ayahnya] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli makanan, maka janganlah ia menjualnya hingga menakarnya.\" Abu Bakr menambahkan, \"Ia berkata, \"Kemudian aku sampaikan kepada Ibnu Abbas dengan apa yang ia katakan, \"Tidakkah engkau melihat bahwa mereka melakukan jual beli dengan dengan emas, sementara makanan tersebut tertunda (belum diserahkan).\""},"2956":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَسُلَيْمَانُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ وَهَذَا لَفْظُ مُسَدَّدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَرَى أَحَدُكُمْ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَقْبِضَهُ قَالَ سُلَيْمَانُ بْنُ حَرْبٍ حَتَّى يَسْتَوْفِيَهُ زَادَ مُسَدَّدٌ قَالَ وَقَالَ ابْنُ عَبَّاسٍ وَأَحْسِبُ أَنَّ كُلَّ شَيْءٍ مِثْلَ الطَّعَامِ","id":"Telah menceritakan kepada kami [Musaddad] dan [Sulaiman bin Harb] mereka berkata; telah menceritakan kepada kami [Hammad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] -dan ini adalah lafazh Musaddad- dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang diantara kalian membeli makanan, maka janganlah ia menjualnya kembali hingga ia menerimanya.\" [Sulaiman bin Harb] menyebutkan, \"Hingga ia memenuhinya.\" [Musaddad] menambahkan, \"Ia berkata, \"Ibnu Abbas berkata, \"Menurutku bahwa segala sesuatu (berlaku hukumnya) seperti makanan.\""},"2957":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَرَأَيْتُ النَّاسَ يُضْرَبُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَرَوْا الطَّعَامَ جُزَافًا أَنْ يَبِيعُوهُ حَتَّى يُبْلِغَهُ إِلَى رَحْلِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam aku lihat orang-orang dipukul jika membeli makanan Juzaman (tanpa ditakar dan ditimbang), kemudian menjualnya kembali, kecuali ia membawanya terlebih dahulu ke tempat tinggalnya.\""},"2958":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ الْوَهْبِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ أَبِي الزِّنَادِ عَنْ عُبَيْدِ بْنِ حُنَيْنٍ عَنْ ابْنِ عُمَرَ قَالَابْتَعْتُ زَيْتًا فِي السُّوقِ فَلَمَّا اسْتَوْجَبْتُهُ لِنَفْسِي لَقِيَنِي رَجُلٌ فَأَعْطَانِي بِهِ رِبْحًا حَسَنًا فَأَرَدْتُ أَنْ أَضْرِبَ عَلَى يَدِهِ فَأَخَذَ رَجُلٌ مِنْ خَلْفِي بِذِرَاعِي فَالْتَفَتُّ فَإِذَا زَيْدُ بْنُ ثَابِتٍ فَقَالَ لَا تَبِعْهُ حَيْثُ ابْتَعْتَهُ حَتَّى تَحُوزَهُ إِلَى رَحْلِكَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ تُبَاعَ السِّلَعُ حَيْثُ تُبْتَاعُ حَتَّى يَحُوزَهَا التُّجَّارُ إِلَى رِحَالِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Auf Ath Thai] telah menceritakan kepada kami [Ahmad bin Khalid Al Wahbi] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Abu Az Zinad] dari ['Ubaid bin Hunain] dari [Ibnu Umar] ia berkata, \"Aku pernah membeli minyak di pasar, kemudian ketika minyak tersebut telah menjadi hak milikku, ada seorang laki-laki datang kepadaku dan memberiku keuntungan yang baik. Maka ketika aku ingin membuat kesepatakan dengan orang tersebut, seorang laki-laki memegang lenganku dari belakang hingga aku pun menoleh, ternyata laki-laki itu adalah [Zaid bin Tsabit]. Ia lalu berkata, \"Jangan engkau menjualnya di tempat engkau membelinya hingga engkau membawanya ke tempat tinggalmu! Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang untuk menjual barang ditempat pembeliannya hingga para penjual tersebut memindahnya ke tempat tinggal mereka.\""},"2959":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا ذَكَرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ يُخْدَعُ فِي الْبَيْعِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَايَعْتَ فَقُلْ لَا خِلَابَةَفَكَانَ الرَّجُلُ إِذَا بَايَعَ يَقُولُ لَا خِلَابَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa seorang laki-laki menyebutkan kepada Rasulullah shallallahu 'alaihi wasallam bahwa dirinya telah ditipu dalam jual beli. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau melakukan transaksi jual beli maka katakanlah, 'Tidak boleh ada penipuan'.\" Setelah itu jika laki-laki tersebut melakukan transaksi jual beli ia selalu mengatakan, 'Tidak boleh ada penipuan'.\""},"2960":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأُرُزِّيُّ وَإِبْرَاهِيمُ بْنُ خَالِدٍ أَبُو ثَوْرٍ الْكَلْبِيُّ الْمَعْنَى قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ مُحَمَّدٌ عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ أَخْبَرَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَبْتَاعُ وَفِي عُقْدَتِهِ ضَعْفٌ فَأَتَى أَهْلُهُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا نَبِيَّ اللَّهِ احْجُرْ عَلَى فُلَانٍ فَإِنَّهُ يَبْتَاعُ وَفِي عُ��ْدَتِهِ ضَعْفٌ فَدَعَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَاهُ عَنْ الْبَيْعِ فَقَالَ يَا نَبِيَّ اللَّهِ إِنِّي لَا أَصْبِرُ عَنْ الْبَيْعِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كُنْتَ غَيْرَ تَارِكٍ الْبَيْعَ فَقُلْ هَاءَ وَهَاءَ وَلَا خِلَابَةَقَالَ أَبُو ثَوْرٍ عَنْ سَعِيدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Al Aruzzi] dan [Ibrahim bin Khalid Abu Tsaur Al Kalbi] secara makna, mereka berkata; telah menceritakan kepada kami [Abdul Wahhab], Muhammad Abdul Wahhab bin 'Atha berkata; telah mengabarkan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] bahwa pada masa Rasulullah shallallahu 'alaihi wasallam ada seorang laki-laki membeli sesuatu sementara dia adalah seorang yang akalnya lemah. Kemudian keluarganya datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Nabi Allah, batalkanlah jual belinya, sebab ia melakukan transaksi jual beli padahal akalnya lemah.\" Nabi shallallahu 'alaihi wasallam kemudian memanggil dan melarangnya melakukan berjual beli. Lalu ia berkata; wahai Nabi Allah, sesungguhnya aku tidak bisa bersabar untuk berjual beli. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau tidak dapat meninggalkan jual beli, maka lakukanlah dengan kontan dan tidak ada penipuan.\" [Abu Tsaur] menyebutkan dari [Sa'id].\""},"2961":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ قَرَأْتُ عَلَى مَالِكِ بْنِ أَنَسٍ أَنَّهُ بَلَغَهُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْعُرْبَانِقَالَ مَالِكٌ وَذَلِكَ فِيمَا نَرَى وَاللَّهُ أَعْلَمُ أَنْ يَشْتَرِيَ الرَّجُلُ الْعَبْدَ أَوْ يَتَكَارَى الدَّابَّةَ ثُمَّ يَقُولُ أُعْطِيكَ دِينَارًا عَلَى أَنِّي إِنْ تَرَكْتُ السِّلْعَةَ أَوْ الْكِرَاءَ فَمَا أَعْطَيْتُكَ لَكَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] ia berkata; aku membacakannya di hadapan [Malik bin Anas] bahwa [telah disampaikan seseorang] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari jual beli 'Uryan.\" Malik berkata, \"Jual beli Uryan menurut kami -wallahu a'lam- seseorang membeli seorang budak atau menyewa kendaraan kemudian berkata, 'Aku akan memberimu satu dinar, namun jika aku tidak jadi membeli barang tersebut atau tidak jadi menyewanya, maka apa yang telah aku beri menjadi hakku kembali.\""},"2962":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَيَا رَسُولَ اللَّهِ يَأْتِينِي الرَّجُلُ فَيُرِيدُ مِنِّي الْبَيْعَ لَيْسَ عِنْدِي أَفَأَبْتَاعُهُ لَهُ مِنْ السُّوقِ فَقَالَ لَا تَبِعْ مَا لَيْسَ عِنْدَكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Yusuf bin Mahik] dari [Hakim bin Hizam] ia berkata, \"Wahai Rasulullah, seorang laki-laki datang kepadaku ingin membeli sesuatu yang tidak aku miliki, apakah boleh aku membelikan untuknya dari pasar? Beliau bersabda: \"Janganlah engkau menjual apa yang tidak engkau miliki!\""},"2963":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ حَدَّثَنِي أَبِي عَنْ أَبِيهِ حَتَّى ذَكَرَ عَبْدَ اللَّهِ بْنَ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ سَلَفٌ وَبَيْعٌ وَلَا شَرْطَانِ فِي بَيْعٍ وَلَا رِبْحُ مَا لَمْ تَضْمَنْ وَلَا بَيْعُ مَا لَيْسَ عِنْدَكَ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il] dari [Ayyub] telah menceritakan kepadaku ['Amru bin Syu'aib] telah menceritakan kepadaku [Ayahku] dari [Ayahnya] hingga ia menyebutkan [Abdullah bin 'Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal menjual sesuatu dengan syarat memberikan hutangan, dua syarat dalam satu transaksi, keuntungan menjual sesuatu yang belum engkau jamin, serta menjual sesuatu yang bukan milikmu.\""},"2964":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ عَنْ زَكَرِيَّا حَدَّثَنَا عَامِرٌ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبِعْتُهُ يَعْنِي بَعِيرَهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاشْتَرَطْتُ حُمْلَانَهُ إِلَى أَهْلِي قَالَ فِي آخِرِهِ تُرَانِي إِنَّمَا مَاكَسْتُكَ لِأَذْهَبَ بِجَمَلِكَ خُذْ جَمَلَكَ وَثَمَنَهُ فَهُمَا لَكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Zakaria] telah menceritakan kepada kami [Amir] dari [Jabir bin Abdullah] ia berkata, \"Aku menjualnya -yaitu untanya- kepada Nabi shallallahu 'alaihi wasallam dan aku mensyaratkan untuk aku naiki hingga sampai kepada keluargaku. Pada akhirnya beliau bersabda: \"Apakah kamu mengira aku menawarmu untuk membawa pergi untamu? Ambillah untamu dan uang penjualannya, keduanya untukmu!\""},"2965":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُهْدَةُ الرَّقِيقِ ثَلَاثَةُ أَيَّامٍحَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ بِإِسْنَادِهِ وَمَعْنَاهُ زَادَ إِنْ وَجَدَ دَاءً فِي الثَّلَاثِ لَيَالِي رُدَّ بِغَيْرِ بَيِّنَةٍ وَإِنْ وَجَدَ دَاءً بَعْدَ الثَّلَاثِ كُلِّفَ الْبَيِّنَةَ أَنَّهُ اشْتَرَاهُ وَبِهِ هَذَا الدَّاءُ قَالَ أَبُو دَاوُد هَذَا التَّفْسِيرُ مِنْ كَلَامِ قَتَادَةَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban] dari [Qatadah] dari [Al Hasan] dari ['Uqbah bin Amir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Garansi (penjualan) seorang budak adalah tiga hari.\" Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepadaku [Abdushshamad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dengan sanad dan maknanya, ia menambahkan, \"Apabila ia mendapatkan penyakit dalam tiga malam, maka budak tersebut dikembalikan tanpa harus ada bukti, jika ia mendapati penyakit setelah tiga malam, maka ia harus menunjukkan bukti bahwa saat membeli budak tersebut dalam keadaan telah berpenyakit.\" Abu Daud berkata, \"Ini adalah penafsiran dari perkataan Qatadah.\""},"2966":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ مَخْلَدِ بْنِ خُفَافٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَرَاجُ بِالضَّمَانِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Makhlad bin Khufaf] dan ['Urwah] dari [Aisyah] radliallahu 'anha, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemanfaatan barang itu berbalas penjaminan.\" "},"2967":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ عَنْ سُفْيَانَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مَخْلَدِ بْنِ خُفَافٍ الْغِفَارِيِّ قَالَكَانَ بَيْنِي وَبَيْنَ أُنَاسٍ شَرِكَةٌ فِي عَبْدٍ فَاقْتَوَيْتُهُ وَبَعْضُنَا غَائِبٌ فَأَغَلَّ عَلَيَّ غَلَّةً فَخَاصَمَنِي فِي نَصِيبِهِ إِلَى بَعْضِ الْقُضَاةِ فَأَمَرَنِي أَنْ أَرُدَّ الْغَلَّةَ فَأَتَيْتُ عُرْوَةَ بْنَ الزُّبَيْرِ فَحَدَّثْتُهُ فَأَتَاهُ عُرْوَةُ فَحَدَّثَهُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَرَاجُ بِالضَّمَانِ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] dari [Sufyan] dari [Muhammad bin 'Abdurrahman] dari [Makhlad bin Khufaf Al Ghifari] ia berkata, \"Aku pernah berserikat dengan seseorang dalam kepemilikan seorang budak, lalu aku memberi dia makan dan sebagian kami tidak ada di tempat, hingga budak tersebut memberiku manfaat. Kemudian orang tersebut mempermasalahkan bagianku kepada sebagian hakim, lalu hakim tersebut memerintahkan agar aku mengembalikan manfaat tersebut. Maka aku pun datang kepada 'Urwah bin Az Zubair dan menceritakan hal tersebut kepadanya. Kemudian ['Urwah] mendatangi hakim tersebut dan menceritakan kepadanya sebuah hadits dari [Aisyah] radliallahu 'anha dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Pemanfaatan barang itu berbalas penjaminan.\" "},"2968":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مَرْوَانَ حَدَّثَنَا أَبِي حَدَّثَنَا مُسْلِمُ بْنُ خَالِدٍ الزَّنْجِيُّ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَجُلًا ابْتَاعَ غُلَامًا فَأَقَامَ عِنْدَهُ مَا شَاءَ اللَّهُ أَنْ يُقِيمَ ثُمَّ وَجَدَ بِهِ عَيْبًا فَخَاصَمَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّهُ عَلَيْهِ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ قَدْ اسْتَغَلَّ غُلَامِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَرَاجُ بِالضَّمَانِقَالَ أَبُو دَاوُد هَذَا إِسْنَادٌ لَيْسَ بِذَاكَ","id":"Telah menceritakan kepada kami [Ibrahim bin Marwan] telah menceritakan kepada kami [Bapakku] dari [Muslim bin Khalid Az Zanji] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anhuma, bahwa seorang laki-laki membeli seorang budak kemudian budak tersebut tinggal bersamanya selama yang Allah kehendaki. Laki-laki itu kemudian mendapatkan aib pada budak tersebut. Beliau kemudian mengembalikan budak tersebut kepada orang yang penjualnya sehingga ia pun berkata, \"Wahai Rasulullah, ia telah mengambil manfaat dari budakku!\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemanfaatan barang itu berbalas penjaminan.\" "},"2969":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي عَنْ أَبِي عُمَيْسٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ قَيْسِ بْنِ مُحَمَّدِ بْنِ الْأَشْعَثِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَاشْتَرَى الْأَشْعَثُ رَقِيقًا مِنْ رَقِيقِ الْخُمْسِ مِنْ عَبْدِ اللَّهِ بِعِشْرِينَ أَلْفًا فَأَرْسَلَ عَبْدُ اللَّهِ إِلَيْهِ فِي ثَمَنِهِمْ فَقَالَ إِنَّمَا أَخَذْتُهُمْ بِعَشَرَةِ آلَافٍ فَقَالَ عَبْدُ اللَّهِ فَاخْتَرْ رَجُلًا يَكُونُ بَيْنِي وَبَيْنَكَ قَالَ الْأَشْعَثُ أَنْتَ بَيْنِي وَبَيْنَ نَفْسِكَ قَالَ عَبْدُ اللَّهِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا اخْتَلَفَ الْبَيِّعَانِ وَلَيْسَ بَيْنَهُمَا بَيِّنَةٌ فَهُوَ مَا يَقُولُ رَبُّ السِّلْعَةِ أَوْ يَتَتَارَكَانِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا ابْنُ أَبِي لَيْلَى عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ أَنَّ ابْنَ مَسْعُودٍ بَاعَ مِنْ الْأَشْعَثِ بْنِ قَيْسٍ رَقِيقًا فَذَكَرَ مَعْنَاهُ وَالْكَلَامُ يَزِيدُ وَيَنْقُصُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [Ayahku] dari [Abu 'Umais] telah mengabarkan kepadaku [Abdurrahman bin Qais bin Muhammad bin Al Asy'ats] dari [Ayahnya] dari [Kakeknya] ia berkata, \"Al Asy'ats membeli seorang budak (bagian dari seperlima harta ghanimah) dari Abdullah dengan harga dua puluh ribu. Kemudian Abdullah mengirim seseorang kepada Al Asy'ats untuk meminta harga budak tersebut. Al Asy'ats pun berkata, \"Aku membelinya dengan harga sepuluh ribu.\" Lalu Abdullah berkata, \"Pilihlah seorang penengah antara diriku dan dirimu!\" Al Asy'ats berkata, \"Engkau adalah penengah antara aku dan dirimu.\" Abdullah berkata, \"Sesungguhnya aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila dua orang yang saling berjual beli berselisih dan di antara mereka tidak ada bukti, maka yang kuat adalah perkataan pemilik barang (penjual), atau mereka berdua membatalkan jual beli.\" Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Ibnu Abu Laila] dari [Al Qasim bin Abdurrahman] dari [Ayahnya] bahwa [Ibnu Mas'ud] telah menjual budak kepada Al Asy'ats bin Qais…. kemudian ia menyebutkan makna hadits tersebut, sementara pembicaraan itu adakalanya mengalami penambahan dan pengurangan.\""},"2970":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّفْعَةُ فِي كُلِّ شِرْكٍ رَبْعَةٍ أَوْ حَائِطٍ لَا يَصْلُحُ أَنْ يَبِيعَ حَتَّى يُؤْذِنَ شَرِيكَهُ فَإِنْ بَاعَ فَهُوَ أَحَقُّ بِهِ حَتَّى يُؤْذِنَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Syuf'ah (hak membeli terlebih dahulu) terdapat pada setiap rumah yang ditempati, atau kebun. Tidak selayaknya untuk menjualnya hingga memberitahukan kepada sekutunya, apabila ia menjualnya maka sekutunya tersebut lebih berhak untuk membelinya kecuali ia memberi izin kepadanya.\""},"2971":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَإِنَّمَا جَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّفْعَةَ فِي كُلِّ مَا لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَصُرِّفَتْ الطُّرُقُ فَلَا شُفْعَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah bin Abdurrahman] dari [Jabir bin Abdullah] ia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam menjadikan syuf'ah ada pada setiap sesuatu yang tidak dapat dibagi, jika sudah ada batas atau jalan (yang membedakan letak lokasi), maka tidak ada syu'ah.\" "},"2972":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ أَوْ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ أَوْ عَنْهُمَا جَمِيعًا عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قُسِّمَتْ الْأَرْضُ وَحُدَّتْ فَلَا شُفْعَةَ فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Al Hasan bin Ar Rabi'] telah menceritakan kepada kami [Ibnu Idris] dari [Ibnu Juraij] dari [Ibnu Syihab Az Zuhri] dari [Abu Salamah] atau dari [Sa'id bin Al Musayyab] atau dari keduanya, dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila lahan telah dibagi dan diberi batas maka tidak ada syuf'ah padanya.\" "},"2973":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ سَمِعَ عَمْرَو بْنَ الشَّرِيدِ سَمِعَ أَبَا رَافِعٍسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْجَارُ أَحَقُّ بِسَقَبِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] ia mendengar ['Amru bin Asy Syarid] ia mendengar [Abu Rafi'] mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tetangga lebih berhak terhadap apa yang dekat dengan rumahnya.\""},"2974":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَارُ الدَّارِ أَحَقُّ بِدَارِ الْجَارِ أَوْ الْأَرْضِ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tetangga rumah lebih berhak terhadap rumah tetangganya atau lahannya.\""},"2975":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَارُ أَحَقُّ بِشُفْعَةِ جَارِهِ يُنْتَظَرُ بِهَا وَإِنْ كَانَ غَائِبًا إِذَا كَانَ طَرِيقُهُمَا وَاحِدًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abdul Malik] dari ['Atha] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tetangga lebih berhak untuk membeli rumah tetangganya, ia ditunggu walaupun ia sedang tidak berada di rumah, apabila jalan mereka berdua adalah satu.\""},"2976":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ ح و حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ الْمَعْنَى عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ أَفْلَسَ فَأَدْرَكَ الرَّجُلُ مَتَاعَهُ بِعَيْنِهِ فَهُوَ أَحَقُّ بِهِ مِنْ غَيْرِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [An Nufaili] telah menceritakan kepada kami [Zuhair] secara makna, dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Umar bin Abdul Aziz] dari [Abu Bakr bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lelaki mana saja yang mengalami kebangkrutan kemudian orang lain mendapatkan barangnya, maka ia lebih berhak terhadapnya daripada selainnya.\""},"2977":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ بَاعَ مَتَاعًا فَأَفْلَسَ الَّذِي ابْتَاعَهُ وَلَمْ يَقْبِضْ الَّذِي بَاعَهُ مِنْ ثَمَنِهِ شَيْئًا فَوَجَدَ مَتَاعَهُ بِعَيْنِهِ فَهُوَ أَحَقُّ بِهِ وَإِنْ مَاتَ الْمُشْتَرِي فَصَاحِبُ الْمَتَاعِ أُسْوَةُ الْغُرَمَاءِحَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَى حَدِيثِ مَالِكٍ زَادَ وَإِنْ كَانَ قَدْ قَضَى مِنْ ثَمَنِهَا شَيْئًا فَهُوَ أُسْوَةُ الْغُرَمَاءِ فِيهَا حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْجَبَّارِ يَعْنِي الْخَبَايِرِيَّ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ عَيَّاشٍ عَنْ الزُّبَيْدِيِّ قَالَ أَبُو دَاوُد وَهُوَ مُحَمَّدُ بْنُ الْوَلِيدِ أَبُو الْهُذَيْلِ الْحِمْصِيُّ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ فَإِنْ كَانَ قَضَاهُ مِنْ ثَمَنِهَا شَيْئًا فَمَا بَقِيَ فَهُوَ أُسْوَةُ الْغُرَمَاءِ وَأَيُّمَا امْرِئٍ هَلَكَ وَعِنْدَهُ مَتَاعُ امْرِئٍ بِعَيْنِهِ اقْتَضَى مِنْهُ شَيْئًا أَوْ لَمْ يَقْتَضِ فَهُوَ أُسْوَةُ الْغُرَمَاءِ قَالَ أَبُو دَاوُد حَدِيثُ مَالِكٍ أَصَحُّ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lelaki mana saja yang menjual suatu barang kemudian orang yang membelinya bangkrut, dan orang yang menjualnya belum mengambil uang penjualannya sedikitpun kemudian mendapatkan barangnya, maka ia lebih berhak terhadapnya. Dan apabila orang yang membeli meninggal, maka pemilik barang sama dengan para pemilik piutang.\" Telah menceritakan kepada kami [Sulaiman bin Daud] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] bahwa Rasulullah shallallahu 'alaihi wasallam …kemudian ia menyebutkan makna hadits Malik. Ia menambahkan, \"Apabila ia telah mengambil sebagian uang hasil penjualannya, maka ia sama dengan para pemilik piutang.\" Telah menceritakan kepada kami [Muhammad bin 'Auf Ath Thai] telah menceritakan kepada kami [Abdullah bin Abdul Jabbar Al Khabaryiri] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dan [Az Zubaidi]. Abu Daud berkata, \"Ia adalah Muhammad bin Al Walid Abu Al Hudzail Al Himshi, dari [Az Zuhri] dari [Abu Bakr bin Abdurrahman] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu. Ia menyebutkan, \"Apabila ia telah membayar sebagian harganya, maka sisanya pemilik barang tersebut adalah sama dengan para pemilik piutang. Dan siapapun orang yang meninggal dan padanya terdapat barang seseorang yang telah ia bayar sebagiannya, atau belum ia bayar, maka pemilik barang tersebut seperti para pemilik piutang.\" Abu Daud berkata, \"Hadits Malik lebih shahih.\""},"2978":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ هُوَ الطَّيَالِسِيُّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ أَبِي الْمُعْتَمِرِ عَنْ عُمَرَ بْنِ خَلْدَةَ قَالَأَتَيْنَا أَبَا هُرَيْرَةَ فِي صَاحِبٍ لَنَا أَفْلَسَ فَقَالَ لَأَقْضِيَنَّ فِيكُمْ بِقَضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَفْلَسَ أَوْ مَاتَ فَوَجَدَ رَجُلٌ مَتَاعَهُ بِعَيْنِهِ فَهُوَ أَحَقُّ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud Ath Thayalisi] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Abu Al Mu'tamir] dari [Umar bin Khaldah] ia berkata, \"Kami datang kepada [Abu Hurairah] bertanya mengenai sahabat kami yang mengalami kebangkrutan, kemudian ia berkata, \"Sungguh aku akan memberikan keputusan di antara kalian dengan keputusan Rasulullah shallallahu 'alaihi wasallam. Barangsiapa mengalami kebangkrutan, atau ia meninggal lalu ada seseorang yang mendapati barangnya ada dirinya, maka orang tersebut lebih berhak terhadap barang tersebut.\""},"2979":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا مُوسَى حَدَّثَنَا أَبَانُ عَنْ عُبَيْدِ اللَّهِ بْنِ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيِّ عَنْ الشَّعْبِيِّ وَقَالَ عَنْ أَبَانَ أَنَّ عَامِرًا الشَّعْبِيَّ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ وَجَدَ دَابَّةً قَدْ عَجَزَ عَنْهَا أَهْلُهَا أَنْ يَعْلِفُوهَا فَسَيَّبُوهَا فَأَخَذَهَا فَأَحْيَاهَا فَهِيَ لَهُقَالَ فِي حَدِيثِ أَبَانَ قَالَ عُبَيْدُ اللَّهِ فَقُلْتُ عَمَّنْ قَالَ عَنْ غَيْرِ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد وَهَذَا حَدِيثُ حَمَّادٍ وَهُوَ أَبْيَنُ وَأَتَمُّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Aban] dari ['Ubaidullah bin Humaid bin Abdurrahman Al Himyari] dari [Asy Sya'bi] dan ia berkata dari [Aban] bahwa [Amir Asy Sya'bi] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapati hewan kendaraan yang pemiliknya sudah tidak mampu untuk memberinya makan, kemudian mereka membiarkannya pergi kemanapun hewan itu, lalu orang tersebut mengambilnya dan merawatnya maka hewan kendaraan tersebut adalah miliknya.\" Ia menyebutkan dalam hadits Aban, Ubaidullah berkata, \"Kemudian aku katakan, \"Dari siapa?\" Ia menjawab, \"Berasal lebih dari satu orang sahabat Nabi shallallahu 'alaihi wasallam.\" Abu Daud berkata, \"Ini adalah hadits Hammad, dan hadits tersebut lebih jelas dan lebih sempurna.\""},"2980":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ حَمَّادٍ يَعْنِي ابْنَ زَيْدٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عُبَيْدِ اللَّهِ بْنِ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الشَّعْبِيِّيَرْفَعُ الْحَدِيثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ تَرَكَ دَابَّةً بِمَهْلَكٍ فَأَحْيَاهَا رَجُلٌ فَهِيَ لِمَنْ أَحْيَاهَا","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] dari [Hammad bin Zaid] dari [Khalid Al Hadzdza`] dari ['Ubaidullah bin Humaid bin Abdurrahman] dari [Asy Sya'bi] dan ia memarfu'kan hadits tersebut kepada Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa meninggalkan hewan kendaraan dalam kondisi kritis, kemudian seseorang merawat hewan tersebut, maka hewan itu adalah milik orang yang telah merawatnya.\""},"2981":{"ar":"حَدَّثَنَا هَنَّادٌ عَنْ ابْنِ الْمُبَارَكِ عَنْ زَكَرِيَّا عَنْ الشَّعْبِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَبَنُ الدَّرِّ يُحْلَبُ بِنَفَقَتِهِ إِذَا كَانَ مَرْهُونًا وَالظَّهْرُ يُرْكَبُ بِنَفَقَتِهِ إِذَا كَانَ مَرْهُونًا وَعَلَى الَّذِي يَرْكَبُ وَيَحْلِبُ النَّفَقَةُقَالَ أَبُو دَاوُد وَهُوَ عِنْدَنَا صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] dari [Ibnu Al Mubarak] dari [Zakaria] dari [Asy Sya'bi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika digadaikan maka susu hewan boleh diperah sesuai dengan nafkah yang diberikan kepada hewan tersebut, dan punggung hewan boleh dinaiki. Orang yang menaiki dan memerah wajib memberikan nafkahnya.\" Abu Daud berkata, \"Menurut kami hadits ini lebih shahih.\""},"2982":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ عِبَادِ اللَّهِ لَأُنَاسًا مَا هُمْ بِأَنْبِيَاءَ وَلَا شُهَدَاءَ يَغْبِطُهُمْ الْأَنْبِيَاءُ وَالشُّهَدَاءُ يَوْمَ الْقِيَامَةِ بِمَكَانِهِمْ مِنْ اللَّهِ تَعَالَى قَالُوا يَا رَسُولَ اللَّهِ تُخْبِرُنَا مَنْ هُمْ قَالَ هُمْ قَوْمٌ تَحَابُّوا بِرُوحِ اللَّهِ عَلَى غَيْرِ أَرْحَامٍ بَيْنَهُمْ وَلَا أَمْوَالٍ يَتَعَاطَوْنَهَا فَوَاللَّهِ إِنَّ وُجُوهَهُمْ لَنُورٌ وَإِنَّهُمْ عَلَى نُورٍ لَا يَخَافُونَ إِذَا خَافَ النَّاسُ وَلَا يَحْزَنُونَ إِذَا حَزِنَ النَّاسُ وَقَرَأَ هَذِهِ الْآيَةَ{ أَلَا إِنَّ أَوْلِيَاءَ اللَّهِ لَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ }","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Utsman bin Abu Syaibah] mereka berkata; telah menceritakan kepada kami [Jarir] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah bin 'Amru bin Jarir] bahwa [Umar bin Al Khathab] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara hamba-hamba Allah terdapat beberapa manusia yang bukan para nabi dan orang-orang yang mati syahid. Para nabi dan orang-orang yang mati syahid merasa iri kepada mereka pada Hari Kiamat karena kedudukan mereka di sisi Allah Ta'ala.\" Mereka berkata, \"Wahai Rasulullah, apakah anda akan mengabarkan kepada kami siapakah mereka? Beliau bersabda: \"Mereka adalah orang-orang yang saling mencintai dengan ruh dari Allah tanpa ada hubungan kekerabatan di antara mereka, dan tanpa adanya harta yang saling mereka berikan. Demi Allah, sesungguhnya wajah mereka adalah cahaya, dan sesungguhnya mereka berada di atas cahaya, tidak merasa takut ketika orang-orang merasa takut, dan tidak bersedih ketika orang-orang merasa bersedih.\" Dan beliau membaca ayat ini: \"Ingatlah, sesungguhnya wali-wali Allah itu, tidak ada kekhawatiran terhadap mereka dan tidak (pula) mereka bersedih hati.\""},"2983":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ عَمَّتِهِ أَنَّهَا سَأَلَتْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَافِي حِجْرِي يَتِيمٌ أَفَآكُلُ مِنْ مَالِهِ فَقَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَطْيَبِ مَا أَكَلَ الرَّجُلُ مِنْ كَسْبِهِ وَوَلَدُهُ مِنْ كَسْبِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Umarah bin 'Umair] dari [Bibinya] bahwa ia pernah bertanya kepada [Aisyah] radliallahu 'anha, \"Dalam asuhanku terdapat seorang anak yatim. Apakah aku boleh memakan sebagian dari hartanya? Aisyah menjawab, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik dari apa yang dimakan oleh seorang laki-laki adalah yang berasal dari hasil usahanya, dan anak adalah hasil dari usahanya.\""},"2984":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أُمِّهِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ وَلَدُ الرَّجُلِ مِنْ كَسْبِهِ مِنْ أَطْيَبِ كَسْبِهِ فَكُلُوا مِنْ أَمْوَالِهِمْقَالَ أَبُو دَاوُد حَمَّادُ بْنُ أَبِي سُلَيْمَانَ زَادَ فِيهِ إِذَا احْتَجْتُمْ وَهُوَ مُنْكَرٌ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah] dan [Utsman bin Abu Syaibah] secara makna, mereka berkata; telah menceritakan kepada kami [Muhammad Ja'far] dari [Syu'bah] dari [Al Hakam] dari ['Umarah bin 'Umair] dari [Ibunya] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Anak seseorang merupakan hasil dari usahanya, dan sebaik-baik hasil usahanya. Maka makanlah sebagian dari harta mereka!\" Abu Daud berkata; Hammad bin Abu Sulaiman menambahkan pada hadits tersebut, 'Apabila kalian membutuhkan'. dan perkataan tersebut adalah munkar.\""},"2985":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حَبِيبٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي مَالًا وَوَلَدًا وَإِنَّ وَالِدِي يَحْتَاجُ مَالِي قَالَ أَنْتَ وَمَالُكَ لِوَالِدِكَ إِنَّ أَوْلَادَكُمْ مِنْ أَطْيَبِ كَسْبِكُمْ فَكُلُوا مِنْ كَسْبِ أَوْلَادِكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Habib Al Mu'allim] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, saya memiliki harta dan anak, sementara orang tuaku membutuhkan hartaku?\" Beliau bersabda: \"Kamu dan hartamu adalah milik orang tuamu, sesungguhnya anak-anak kalian termasuk hasil usaha kalian yang terbaik. Maka makanlah dari usaha anak-anak kalian.\""},"2986":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا هُشَيْمٌ عَنْ مُوسَى بْنِ السَّائِبِ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَجَدَ عَيْنَ مَالِهِ عِنْدَ رَجُلٍ فَهُوَ أَحَقُّ بِهِ وَيَتَّبِعُ الْبَيِّعُ مَنْ بَاعَهُ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Husyaim] dari [Musa bin As Saib] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan barangnya ada pada seseorang maka ia lebih berhak terhadap barang tersebut, dan orang yang membeli menuntut orang yang menjual kepadanya.\""},"2987":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ هِنْدًا أُمَّ مُعَاوِيَةَ جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ أَبَا سُفْيَانَ رَجُلٌ شَحِيحٌ وَإِنَّهُ لَا يُعْطِينِي مَا يَكْفِينِي وَبَنِيَّ فَهَلْ عَلَيَّ جُنَاحٌ أَنْ آخُذَ مِنْ مَالِهِ شَيْئًا قَالَ خُذِي مَا يَكْفِيكِ وَبَنِيكِ بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari ['Urwah] dari [Aisyah] bahwa Hindun, ibu Mu'awiyah, datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Abu Sufyan adalah orang yang pelit, ia tidak memberikan kepadaku apa yang mencukupiku dan anakku. Apakah saya berdosa apabila mengambil sebagian dari hartanya?\" Beliau bersabda: \"Ambillah apa yang cukup untuk kamu dan anakmu dengan baik.\""},"2988":{"ar":"حَدَّثَنَا خُشَيْشُ بْنُ أَصْرَمَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْجَاءَتْ هِنْدٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ مُمْسِكٌ فَهَلْ عَلَيَّ مِنْ حَرَجٍ أَنْ أُنْفِقَ عَلَى عِيَالِهِ مِنْ مَالِهِ بِغَيْرِ إِذْنِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَرَجَ عَلَيْكِ أَنْ تُنْفِقِي بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Khusyaisy bin Ashram] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dan [Aisyah] ia berkata, \"Hindun datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, sesungguhnya Abu Sufyan adalah orang yang suka menahan pemberian, apakah aku berdosa untuk memberikan nafkah kepada keluargaku dari hartanya tanpa seizinnya?\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Engkau tidak berdosa untuk memberikan nafkah dengan cara yang baik.\""},"2989":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ أَنَّ يَزِيدَ بْنَ زُرَيْعٍ حَدَّثَهُمْ حَدَّثَنَا حُمَيْدٌ يَعْنِي الطَّوِيلَ عَنْ يُوسُفَ بْنِ مَاهَكَ الْمَكِّيِّ قَالَ كُنْتُ أَكْتُبُ لِفُلَانٍ نَفَقَةَ أَيْتَامٍ كَانَ وَلِيَّهُمْ فَغَالَطُوهُ بِأَلْفِ دِرْهَمٍ فَأَدَّاهَا إِلَيْهِمْ فَأَدْرَكْتُ لَهُمْ مِنْ مَالِهِمْ مِثْلَيْهَا قَالَ قُلْتُ أَقْبِضُ الْأَلْفَ الَّذِي ذَهَبُوا بِهِ مِنْكَ قَالَ لَا حَدَّثَنِي أَبِيأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَدِّ الْأَمَانَةَ إِلَى مَنْ ائْتَمَنَكَ وَلَا تَخُنْ مَنْ خَانَكَ","id":"Telah menceritakan kepada kami [Abu Kamil] bahwa [Yazid bin Zurai'] telah menceritakan kepada mereka, telah menceritakan kepada kami [Humaid Ath Thawil] dari [Yusuf bin Mahik Al Makki] dia berkata, \"Aku pernah mencatatkan untuk [seseorang] nafkah orang-orang yatim yang ia asuh. Kemudian anak asuh itu menipunya sebanyak seribu dirham. Lalu fulan itu memberikannya kepada anak-anak yatim. Setelah itu aku mendapati harta anak-anak yatim itu dua kali lipatnya. Yusuf melanjutkan; \"Aku akan mengambil seribu (dirham) yang telah di bawa kabur oleh mereka darimu.\" Fulan berkata, \"Tidak! Aku telah mendengar ayahku bahwa ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tunaikanlah amanah kepada orang yang mempercayaimu dan janganlah engkau mengkhianati orang yang mengkhianatimu!\""},"2990":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَأَحْمَدُ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ عَنْ شَرِيكٍ قَالَ ابْنُ الْعَلَاءِ وَقَيْسٌ عَنْ أَبِي حُصَيْنٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدِّ الْأَمَانَةَ إِلَى مَنْ ائْتَمَنَكَ وَلَا تَخُنْ مَنْ خَانَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala] dan [Ahmad bin Ibrahim] mereka berkata; telah menceritakan kepada kami [Thalq bin Ghannam] dari [Syarik] [Ibnu Al 'Ala] dan [Qais] berkata dari [Abu Hushain] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tunaikanlah amanah kepada orang yang mempercayaimu dan jangan engkau mengkhianati orang yang mengkhianatimu!\""},"2991":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ وَعَبْدُ الرَّحِيمِ بْنُ مُطَرِّفٍ الرُّؤَاسِيُّ قَالَا حَدَّثَنَا عِيسَى وَهُوَ ابْنُ يُونُسَ بْنِ أَبِي إِسْحَقَ السَّبِيعِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْبَلُ الْهَدِيَّةَ وَيُثِيبُ عَلَيْهَا","id":"Telah menceritakan kepada kami [Ali bin Bahr] dan [Abdurrahim bin Mutharrif Ar Ruasai] mereka berkata; telah menceritakan kepada kami [Isa bin Yunus bin Abu Ishaq As Sabi'i] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, bahwa Nabi shallallahu 'alaihi wasallam menerima hadiah, dan beliau membalas orang yang memberi hadiah dengan lebih baik.\""},"2992":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ الْفَضْلِ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ ع��نْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَايْمُ اللَّهِ لَا أَقْبَلُ بَعْدَ يَوْمِي هَذَا مِنْ أَحَدٍ هَدِيَّةً إِلَّا أَنْ يَكُونَ مُهَاجِرًا قُرَشِيًّا أَوْ أَنْصَارِيًّا أَوْ دَوْسِيًّا أَوْ ثَقَفِيًّا","id":"Telah menceritakan kepada kami [Muhammad bin 'Urwah Ar Razi] telah menceritakan kepada kami [Salamah bin Al Fadl] telah menceritakan kepadaku [Muhammad bin Ishaq] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Ayahnya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah, aku tidak akan menerima hadiah dari seorangpun setelah hari ini, kecuali ia seorang Muhajir dari Quraisy, atau orang Anshar, atau orang Daus, atau orang Tsaqif.\""},"2993":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ وَهَمَّامٌ وَشُعْبَةُ قَالُوا حَدَّثَنَا قَتَادَةُ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِقَالَ هَمَّامٌ وَقَالَ قَتَادَةُ وَلَا نَعْلَمُ الْقَيْءَ إِلَّا حَرَامًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban] dan [Hammam] dan [Syu'bah] mereka berkata; telah menceritakan kepada kami [Qatadah] dari [Sa'id bin Al Musayyab] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang meminta kembali apa yang telah ia berikan seperti orang yang menelan kembali muntahnya.\" [Hammam] berkata; [Qatadah] berkata, \"Kami tidak mengetahui kecuali bahwa muntahan adalah haram.\""},"2994":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِرَجُلٍ أَنْ يُعْطِيَ عَطِيَّةً أَوْ يَهَبَ هِبَةً فَيَرْجِعَ فِيهَا إِلَّا الْوَالِدَ فِيمَا يُعْطِي وَلَدَهُ وَمَثَلُ الَّذِي يُعْطِي الْعَطِيَّةَ ثُمَّ يَرْجِعُ فِيهَا كَمَثَلِ الْكَلْبِ يَأْكُلُ فَإِذَا شَبِعَ قَاءَ ثُمَّ عَادَ فِي قَيْئِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amru bin Syu'aib] dari [Thawus] dari [Ibnu Umar] dan [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal bagi seorang laki-laki yang memberi suatu pemberian kemudian mengambilnya kembali, kecuali orang tua mengambil apa yang ia berikan kepada anaknya. Dan permisalan orang yang memberi suatu pemberian kemudian mengambilnya seperti anjing yang makan, maka setelah kenyang ia muntah kemudian menelan muntahannya kembali.\""},"2995":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ أَنَّ عَمْرَو بْنَ شُعَيْبٍ حَدَّثَهُ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الَّذِي يَسْتَرِدُّ مَا وَهَبَ كَمَثَلِ الْكَلْبِ يَقِيءُ فَيَأْكُلُ قَيْئَهُ فَإِذَا اسْتَرَدَّ الْوَاهِبُ فَلْيُوَقَّفْ فَلْيُعَرَّفْ بِمَا اسْتَرَدَّ ثُمَّ لِيُدْفَعْ إِلَيْهِ مَا وَهَبَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Usamah bin Zaid] bahwa ['Amru bin Syu'aib] telah menceritakan kepadanya dari [Ayahnya] dari [Abdullah bin 'Amru] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Permisalan orang yang meminta kembali apa yang telah ia berikan seperti anjing yang muntah lalu ia makan lagi. Apabila orang yang telah memberi meminta kembali pemberiannya, maka hendaknya diwakafkan dan diumumkan apa yang ia minta kembali kemudian hendaknya diserahkan kepadanya apa yang telah ia berikan.\""},"2996":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عُمَرَ بْنِ مَالِكٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ خَالِدِ بْنِ أَبِي عِمْرَانَ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَفَعَ لِأَخِيهِ بِشَفَاعَةٍ فَأَهْدَى لَهُ هَدِيَّةً عَلَيْهَا فَقَبِلَهَا فَقَدْ أَتَى بَابًا عَظِيمًا مِنْ أَبْوَابِ الرِّبَا","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh] telah menceritakan kepada kami [Ibnu Wahb] dari [Umar bin Malik] dari ['Ubaidullah bin Abu Ja'far] dari [Khalid bin Abu Imran] dari [Al Qasim] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa memohonkan untuk saudaranya dengan sebuah permohonan, kemudian saudaranya tersebut memberikan hadiah kepadanya lantaran permohonan tersebut lalu ia menerimanya, maka sungguh ia telah mendatangi salah satu pintu besar di antara pintu-pintu riba.\""},"2997":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا سَيَّارٌ وَأَخْبَرَنَا مُغِيرَةُ وَأَخْبَرَنَا دَاوُدُ عَنْ الشَّعْبِيِّ وَأَخْبَرَنَا مُجَالِدٌ وَإِسْمَعِيلُ بْنُ سَالِمٍ عَنْ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَأَنْحَلَنِي أَبِي نُحْلًا قَالَ إِسْمَعِيلُ بْنُ سَالِمٍ مِنْ بَيْنِ الْقَوْمِ نِحْلَةً غُلَامًا لَهُ قَالَ فَقَالَتْ لَهُ أُمِّي عَمْرَةُ بِنْتُ رَوَاحَةَ ائْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَشْهِدْهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَشْهَدَهُ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ لَهُ إِنِّي نَحَلْتُ ابْنِي النُّعْمَانَ نُحْلًا وَإِنَّ عَمْرَةَ سَأَلَتْنِي أَنْ أُشْهِدَكَ عَلَى ذَلِكَ قَالَ فَقَالَ أَلَكَ وَلَدٌ سِوَاهُ قَالَ قُلْتُ نَعَمْ قَالَ فَكُلَّهُمْ أَعْطَيْتَ مِثْلَ مَا أَعْطَيْتَ النُّعْمَانَ قَالَ لَا قَالَ فَقَالَ بَعْضُ هَؤُلَاءِ الْمُحَدِّثِينَ هَذَا جَوْرٌ وَقَالَ بَعْضُهُمْ هَذَا تَلْجِئَةٌ فَأَشْهِدْ عَلَى هَذَا غَيْرِي قَالَ مُغِيرَةُ فِي حَدِيثِهِ أَلَيْسَ يَسُرُّكَ أَنْ يَكُونُوا لَكَ فِي الْبِرِّ وَاللُّطْفِ سَوَاءٌ قَالَ نَعَمْ قَالَ فَأَشْهِدْ عَلَى هَذَا غَيْرِي وَذَكَرَ مُجَالِدٌ فِي حَدِيثِهِ إِنَّ لَهُمْ عَلَيْكَ مِنْ الْحَقِّ أَنْ تَعْدِلَ بَيْنَهُمْ كَمَا أَنَّ لَكَ عَلَيْهِمْ مِنْ الْحَقِّ أَنْ يَبَرُّوكَ قَالَ أَبُو دَاوُد فِي حَدِيثِ الزُّهْرِيِّ قَالَ بَعْضُهُمْ أَكُلَّ بَنِيكَ وَقَالَ بَعْضُهُمْ وَلَدِكَ وَقَالَ ابْنُ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ فِيهِ أَلَكَ بَنُونَ سِوَاهُ وَقَالَ أَبُو الضُّحَى عَنْ النُّعْمَانِ بْنِ بَشِيرٍ أَلَكَ وَلَدٌ غَيْرُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Sayyar] dan telah mengabarkan kepada kami [Mughirah] telah mengabarkan kepada kami [Daud] dari [Asy Sya'bi] telah mengabarkan kepada kami [Mujalid] dan [Isma'il bin Salim] dari [Asy Sya'bi] dari [An Nu'man bin Basyir] ia berkata, \"Ayahku memberi aku suatu pemberian -Isma'il bin Salim berkata; di antara orang-orang berupa seorang budak miliknya-.\" Nu'man berkata, \"Kemudian ibuku, 'Umrah binti Rawahah, berkata kepadanya, \"Datanglah kepada Rasulullah shallallahu 'alaihi wasallam dan mintalah persaksian kepada beliau.\" Basyir lalu datang kepada Nabi shallallahu 'alaihi wasallam dan meminta persaksian beliau. Ia lantas ceritakan hal tersebut kepada beliau, ia katakan, \"Sesungguhnya aku telah memberikan suatu pemberian kepada anakku, An Nu'man. Dan 'Amrah meminta agar aku meminta persaksian anda atas hal tersebut?\" An Nu'man melanjutkkan, \"Kemudian beliau bertanya: \"Apakah engkau memiliki anak selainnya?\" Ia menjawab, \"Ya.\" Beliau bertanya: \"Apakah semua kamu beri sebagaimana yang telah diberikan kepada Nu'man?\" maka dia menjawab; \"Tidak.\" Maka sebagaian orang yang melaporkan menyatakan; \"Itu adalah perbuatan aniaya!\" sedang yang lainnya menyatakan; \"Itu adalah paksaan Mintalah persaksian atas hal ini kepada selainku!\" [Mughirah] menyebutkan dalam haditsnya, \"Tidakkah kamu suka jika mereka sama dalam berbuat baik dan berkasih sayang terhadapmu?\" maka dia menjawab; \"Ya.\" Maka dia menambahkan; \"Maka saksikanlah hal itu pada selainku.\" [Mujalid] menyebutkan; \"Sesungguhnya mereka memiliki hak atas dirimu untuk berbuat adil di antara mereka sebagaimana engkau memiliki hak atas mereka agar mereka berbakti kepadamu.\" Abu Daud berkata dalam hadits Az Zuhri, \"Sebagian ahli menyebutkan, \"Apakah kepada seluruh anak laki-lakimu?\" Sedangkan sebagian ahli hadits menyebutkan, \"Apakah kepada seluruh anakmu?\" [Ibnu Abu Khalid] menyebutkan dari [Asy Sya'bi] mengenai hadits tersebut, \"Apakah engkau memiliki anak laki-laki selainnya?\" [Abu Adl Dluha] menyebutkan dari [An Nu'man bin Basyir], \"Apakah engkau memiliki anak selainnya?\""},"2998":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ حَدَّثَنِي النُّعْمَانُ بْنُ بَشِيرٍ قَالَأَعْطَاهُ أَبُوهُ غُلَامًا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذَا الْغُلَامُ قَالَ غُلَامِي أَعْطَانِيهِ أَبِي قَالَ فَكُلَّ إِخْوَتِكَ أَعْطَى كَمَا أَعْطَاكَ قَالَ لَا قَالَ فَارْدُدْهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Hisyam bin 'Urwah] dari [Ayahnya] telah menceritakan kepadaku [An Nu'man bin Basyir] ia berkata, \"Ayahnya telah memberikan kepadanya seorang budak, kemudian Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya: \"Siapakah budak ini?\" Ia menjawab, \"Budakku. Ayahkulah yang telah memberikannya kepadaku.\" Rasulullah bertanya: \"Apakah ia memberikan kepada seluruh saudaramu, sebagaimana ia memberikan kepadamu?\" Nu'man menjawab, \"Tidak.\" Beliau bersabda: \"Kembalikanlah kepadanya!\""},"2999":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ حَاجِبِ بْنِ الْمُفَضَّلِ بْنِ الْمُهَلَّبِ عَنْ أَبِيهِ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْدِلُوا بَيْنَ أَوْلَادِكُمْ اعْدِلُوا بَيْنَ أَبْنَائِكُمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Hajib bin Al Mufadldlal bin Al Muhallab] dari [Ayahnya] ia berkata, \"Aku mendengar [An Nu'man bin Basyir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berlakulah adil kepada anak-anakmu, berlakulah adil kepada anak-anakmu.\""},"3000":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَتْ امْرَأَةُ بَشِيرٍ انْحَلْ ابْنِي غُلَامَكَ وَأَشْهِدْ لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ ابْنَةَ فُلَانٍ سَأَلَتْنِي أَنْ أَنْحَلَ ابْنَهَا غُلَامًا وَقَالَتْ لِي أَشْهِدْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ إِخْوَةٌ فَقَالَ نَعَمْ قَالَ فَكُلَّهُمْ أَعْطَيْتَ مِثْلَ مَا أَعْطَيْتَهُ قَالَ لَا قَالَ فَلَيْسَ يَصْلُحُ هَذَا وَإِنِّي لَا أَشْهَدُ إِلَّا عَلَى حَقٍّ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Zuhair] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Isteri Basyir berkata, 'Berilah anakku seorang pembantu dari budak milikmu, dan mintalah persaksian untukku kepada Rasulullah shallallahu 'alaihi wasallam! ' Kemudian Basyir datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya puteri Fulan meminta agar aku memberikan seorang budak kepada anak laki-lakinya, dan ia berkata kepadaku, 'Mintalah persaksian Rasulullah shallallahu 'alaihi wasallam! ' Kemudian beliau bertanya: \"Apakah ia memiliki saudara?\" Basyir menjawab, \"Ya.\" Beliau bertanya lagi: \"Apakah engkau memberikan kepada seluruh mereka seperti yang engkau berikan kepadanya?\" Basyir menjawab, \"Tidak.\" Beliau pun bersabda: \"Ini tidak baik, aku tidak akan bersaksi kecuali terhadap sesuatu yang hak.\""}};
